package legacy

// Scripts contains the de-Pythonized legacy shell implementations used by rtk-cloud while commands are ported to native Go packages.
var Scripts = map[string]string{
	"cloud-bind-devices.sh":                     "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nSTART_EPOCH=\"$(date +%s)\"\nBRANDNAME=\"\"\nUSERS_FILE=\"\"\nDEVICES_DIR=\"\"\nCOUNT=\"\"\nSKIP_BOOTSTRAP=0\nDRY_RUN=0\nCLAIM_TTL_HOURS=24\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-bind-devices %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-bind-devices.sh --env-root cloud_env/staging --brandname RTK [options]\n\nOptions:\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --brandname NAME       Required brand cloud name.\n  --users-file FILE      Credentials artifact from cloud-create-users.sh. Default: latest <brand>-users-*.json.\n  --devices-dir DIR      Generated/factory-enrolled devices directory. Default: <env-root>/devices/test_device.\n  --count N              Optional number of devices to bind. Default: all devices in manifests/devices.json.\n  --claim-ttl-hours N    Claim Token lifetime. Default: 24.\n  --dry-run              Print planned assignments without calling APIs or writing artifacts.\n  --skip-bootstrap       Do not update/restart the remote platform-admin bootstrap env.\n  -h, --help             Show this help.\n\nBinds factory-enrolled devices to brand users through Account Manager APIs only.\nstdout contains a redacted summary. Passwords, bearer tokens, raw Claim Tokens,\nand device private key paths are never printed or written to the output artifact.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--brandname) BRANDNAME=\"$2\"; shift 2 ;;\n\t--users-file) USERS_FILE=\"$2\"; shift 2 ;;\n\t--devices-dir) DEVICES_DIR=\"$2\"; shift 2 ;;\n\t--count) COUNT=\"$2\"; shift 2 ;;\n\t--claim-ttl-hours) CLAIM_TTL_HOURS=\"$2\"; shift 2 ;;\n\t--dry-run) DRY_RUN=1; shift ;;\n\t--skip-bootstrap) SKIP_BOOTSTRAP=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"required env file not found: $path\"\n\tset -a\n\t# shellcheck source=/dev/null\n\t. \"$path\"\n\tset +a\n}\n\ncurl_json_status() {\n\tlocal out=\"$1\"\n\tshift\n\tcurl -sS -o \"$out\" -w '%{http_code}' \"$@\"\n}\n\nvalidate_args() {\n\tBRANDNAME=\"$(printf '%s' \"$BRANDNAME\" | awk '{$1=$1; print}')\"\n\t[[ -n \"$BRANDNAME\" ]] || die \"--brandname is required\"\n\t[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\tif [[ -n \"$COUNT\" ]]; then\n\t\t[[ \"$COUNT\" =~ ^[0-9]+$ ]] || die \"--count must be a positive integer\"\n\t\t((COUNT > 0)) || die \"--count must be greater than zero\"\n\tfi\n\t[[ \"$CLAIM_TTL_HOURS\" =~ ^[0-9]+$ ]] || die \"--claim-ttl-hours must be a positive integer\"\n\t((CLAIM_TTL_HOURS > 0)) || die \"--claim-ttl-hours must be greater than zero\"\n\tif printf '%s' \"$BRANDNAME\" | LC_ALL=C grep -q '[[:cntrl:]]'; then\n\t\tdie \"--brandname must not contain control characters\"\n\tfi\n}\n\nbrand_slug() {\n\tprintf '%s' \"$BRANDNAME\" |\n\t\ttr '[:upper:]' '[:lower:]' |\n\t\tsed -E 's/[^a-z0-9]+/-/g; s/^-+//; s/-+$//' |\n\t\tawk '{ if ($0 == \"\") print \"brand\"; else print }'\n}\n\nremote_target() {\n\tAM_HOST=\"${ACCOUNT_MANAGER_LINODE_HOST:-${ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4:-}}\"\n\tAM_SSH_USER=\"${ACCOUNT_MANAGER_LINODE_SSH_USER:-root}\"\n\tAM_SSH_KEY=\"${ACCOUNT_MANAGER_LINODE_SSH_KEY:-$HOME/.ssh/id_ed25519_rtkcloud}\"\n\t[[ -n \"$AM_HOST\" ]] || die \"ACCOUNT_MANAGER_LINODE_HOST or ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4 is required\"\n\t[[ -n \"$AM_SSH_KEY\" ]] || die \"ACCOUNT_MANAGER_LINODE_SSH_KEY is required\"\n}\n\nensure_platform_admin_bootstrap() {\n\tif [[ \"$SKIP_BOOTSTRAP\" != \"0\" ]]; then\n\t\tlog \"skip bootstrap admin env update\"\n\t\treturn 0\n\tfi\n\tremote_target\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL is required\"\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD is required\"\n\tlog \"updating platform-admin bootstrap env on account-manager host=$AM_HOST\"\n\t{\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\"\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\"\n\t} | ssh -i \"$AM_SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new \"$AM_SSH_USER@$AM_HOST\" 'set -euo pipefail\n\t\tenv_file=/etc/rtk-account-manager/account-manager.env\n\t\ttest -f \"$env_file\"\n\t\tcp -p \"$env_file\" \"$env_file.bootstrap-admin.bak.$(date -u +%Y%m%dT%H%M%SZ)\"\n\t\ttmp=\"$(mktemp)\"\n\t\tgrep -vE \"^ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_(EMAIL|PASSWORD)=\" \"$env_file\" > \"$tmp\"\n\t\tcat >> \"$tmp\"\n\t\tinstall -m 0600 -o root -g root \"$tmp\" \"$env_file\"\n\t\trm -f \"$tmp\"\n\t\tsystemctl restart rtk-account-manager.service\n\t\tfor _ in $(seq 1 30); do\n\t\t\tif curl -fsS http://127.0.0.1:18081/v1/health >/dev/null 2>&1; then\n\t\t\t\techo \"bootstrap admin env applied and account-manager is healthy\" >&2\n\t\t\t\texit 0\n\t\t\tfi\n\t\t\tsleep 1\n\t\tdone\n\t\tjournalctl -u rtk-account-manager.service -n 80 --no-pager >&2 || true\n\t\texit 1\n\t'\n\tlog \"platform-admin bootstrap env ready\"\n}\n\nlogin() {\n\tlocal email=\"$1\"\n\tlocal password=\"$2\"\n\tlocal out=\"$TMPDIR/login.out\"\n\tlocal payload=\"$TMPDIR/login-payload.json\"\n\tjq -cn --arg email \"$email\" --arg password \"$password\" '{email:$email,password:$password}' > \"$payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/auth/login\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"login failed: email=$email HTTP $status\"\n\tjq -r '.tokens.access_token // empty' \"$out\"\n}\n\nlogin_platform_admin() {\n\tlog \"logging in platform admin: $AM_BASE_URL/v1/auth/login\"\n\tACCESS_TOKEN=\"$(login \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\" \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\")\"\n\t[[ -n \"$ACCESS_TOKEN\" ]] || die \"platform admin login response did not include an access token\"\n\tlog \"platform admin login ok\"\n}\n\nfind_brand_cloud() {\n\tlocal out=\"$TMPDIR/brand-clouds.out\"\n\tlocal status\n\tlog \"checking brand cloud: name=$BRANDNAME\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds?limit=200\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"brand cloud list failed: HTTP $status\"\n\tBRAND_CLOUD_JSON=\"$(jq -c --arg name \"$BRANDNAME\" '.brand_clouds[]? | select((.name == $name or .metadata.brandname == $name) and (.organization_kind == \"brand_cloud\" or .organization_kind == null))' \"$out\" | head -n 1)\"\n\t[[ -n \"$BRAND_CLOUD_JSON\" ]] || die \"brand cloud not found: $BRANDNAME\"\n\tBRAND_CLOUD_ID=\"$(jq -r '.id' <<<\"$BRAND_CLOUD_JSON\")\"\n\t[[ -n \"$BRAND_CLOUD_ID\" && \"$BRAND_CLOUD_ID\" != \"null\" ]] || die \"brand cloud response did not include id\"\n\tlog \"brand cloud found: id=$BRAND_CLOUD_ID\"\n}\n\nabs_existing_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"file not found: $path\"\n\t(cd \"$(dirname \"$path\")\" && printf '%s/%s\\n' \"$(pwd)\" \"$(basename \"$path\")\")\n}\n\nabs_existing_dir() {\n\tlocal path=\"$1\"\n\t[[ -d \"$path\" ]] || die \"directory not found: $path\"\n\t(cd \"$path\" && pwd)\n}\n\nresolve_default_inputs() {\n\tlocal slug users_dir latest_users\n\tif [[ -z \"$DEVICES_DIR\" ]]; then\n\t\tDEVICES_DIR=\"$(cloud_env_test_devices_dir \"$ENV_ROOT\")\"\n\tfi\n\tif [[ -z \"$USERS_FILE\" ]]; then\n\t\tslug=\"$(brand_slug)\"\n\t\tusers_dir=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/users\"\n\t\t[[ -d \"$users_dir\" ]] || die \"--users-file was not provided and users artifact directory was not found: $users_dir\"\n\t\tlatest_users=\"$(find \"$users_dir\" -type f -name \"$slug-users-*.json\" -print | sort | tail -n 1)\"\n\t\t[[ -n \"$latest_users\" ]] || die \"--users-file was not provided and no users artifact matched: $users_dir/$slug-users-*.json\"\n\t\tUSERS_FILE=\"$latest_users\"\n\tfi\n}\n\nvalidate_users_and_devices() {\n\tUSERS_FILE=\"$(abs_existing_file \"$USERS_FILE\")\"\n\tDEVICES_DIR=\"$(abs_existing_dir \"$DEVICES_DIR\")\"\n\tDEVICES_MANIFEST=\"$DEVICES_DIR/manifests/devices.json\"\n\t[[ -f \"$DEVICES_MANIFEST\" ]] || die \"device manifest not found: $DEVICES_MANIFEST\"\n\tUSER_COUNT=\"$(jq '.users | length' \"$USERS_FILE\")\"\n\tDEVICE_COUNT=\"$(jq 'length' \"$DEVICES_MANIFEST\")\"\n\t[[ \"$USER_COUNT\" =~ ^[0-9]+$ && \"$USER_COUNT\" -gt 0 ]] || die \"--users-file must contain at least one user\"\n\t[[ \"$DEVICE_COUNT\" =~ ^[0-9]+$ && \"$DEVICE_COUNT\" -gt 0 ]] || die \"devices manifest must contain at least one device\"\n\tif [[ -z \"$COUNT\" ]]; then\n\t\tCOUNT=\"$DEVICE_COUNT\"\n\tfi\n\t((COUNT <= DEVICE_COUNT)) || die \"--count $COUNT exceeds device manifest count $DEVICE_COUNT\"\n\tUSERS_BRAND=\"$(jq -r '.brandname // empty' \"$USERS_FILE\")\"\n\t[[ -z \"$USERS_BRAND\" || \"$USERS_BRAND\" == \"$BRANDNAME\" ]] || die \"--users-file brandname $USERS_BRAND does not match --brandname $BRANDNAME\"\n\tUSERS_BRAND_CLOUD_ID=\"$(jq -r '.brand_cloud_id // empty' \"$USERS_FILE\")\"\n\tjq -e '\n\t\tall(.users[]; (.email | type == \"string\" and length > 0) and (.password | type == \"string\" and length > 0))\n\t' \"$USERS_FILE\" >/dev/null || die \"--users-file users require email and password\"\n\tjq -e '\n\t\tall(.[]; (.device_id | type == \"string\" and length > 0) and (.device_type | type == \"string\" and length > 0) and (.service_options | type == \"array\" and length > 0))\n\t' \"$DEVICES_MANIFEST\" >/dev/null || die \"devices manifest requires device_id, device_type, and service_options\"\n\tjq -e '\n\t\tall(.[]; all(.service_options[]; . == \"mqtt\" or . == \"video_streaming\" or . == \"video_storage\"))\n\t' \"$DEVICES_MANIFEST\" >/dev/null || die \"devices manifest has unsupported service_options\"\n}\n\nbuild_assignments() {\n\tlocal devices=\"$TMPDIR/devices-selected.json\"\n\tjq --argjson count \"$COUNT\" '.[0:$count]' \"$DEVICES_MANIFEST\" > \"$devices\"\n\tjq -n \\\n\t\t--slurpfile users \"$USERS_FILE\" \\\n\t\t--slurpfile devices \"$devices\" '\n\t\t($users[0].users) as $users |\n\t\t($devices[0]) as $devices |\n\t\t($users | length) as $user_count |\n\t\t[$devices[].device_type] | unique as $types |\n\t\t(reduce $types[] as $type (\n\t\t\t{offset: 0, by_id: {}};\n\t\t\t([range(0; $devices|length) as $i | select($devices[$i].device_type == $type) | $i]) as $idxs |\n\t\t\treduce range(0; $idxs|length) as $j (\n\t\t\t\t.;\n\t\t\t\t($idxs[$j]) as $device_index |\n\t\t\t\t((.offset + $j) % $user_count) as $user_index |\n\t\t\t\t.by_id[$devices[$device_index].device_id] = {\n\t\t\t\t\tassignment_index: $device_index,\n\t\t\t\t\tdevice_id: $devices[$device_index].device_id,\n\t\t\t\t\tdevice_type: $devices[$device_index].device_type,\n\t\t\t\t\tcategory: (if (($devices[$device_index].service_options // []) | index(\"video_streaming\") or index(\"video_storage\")) then \"ip_camera\" else \"mqtt_device\" end),\n\t\t\t\t\tdisplay_name: ($devices[$device_index].display_name // $devices[$device_index].device_id),\n\t\t\t\t\tservice_options: $devices[$device_index].service_options,\n\t\t\t\t\tassigned_email: $users[$user_index].email,\n\t\t\t\t\tassigned_display_name: ($users[$user_index].display_name // $users[$user_index].email)\n\t\t\t\t}\n\t\t\t)\n\t\t\t| .offset = ((.offset + ($idxs | length)) % $user_count)\n\t\t)) as $assigned |\n\t\t[$devices[] | $assigned.by_id[.device_id]]\n\t'\n}\n\nwrite_secret_user_tokens() {\n\tlocal users_jsonl=\"$TMPDIR/user-tokens.jsonl\"\n\t: > \"$users_jsonl\"\n\tlocal email password token row\n\twhile IFS= read -r row; do\n\t\temail=\"$(jq -r '.email' <<<\"$row\")\"\n\t\tpassword=\"$(jq -r '.password' <<<\"$row\")\"\n\t\tlog \"logging in assigned user: email=$email\"\n\t\ttoken=\"$(login \"$email\" \"$password\")\"\n\t\t[[ -n \"$token\" ]] || die \"user login response did not include an access token: $email\"\n\t\tjq -cn --arg email \"$email\" --arg token \"$token\" '{email:$email, token:$token}' >> \"$users_jsonl\"\n\tdone < <(jq -rc '.users[]' \"$USERS_FILE\")\n\tjq -s . \"$users_jsonl\" > \"$USER_TOKENS_FILE\"\n}\n\nuser_token_for_email() {\n\tlocal email=\"$1\"\n\tjq -r --arg email \"$email\" '.[] | select(.email == $email) | .token' \"$USER_TOKENS_FILE\" | head -n 1\n}\n\ncreate_claim_token() {\n\tlocal assignment=\"$1\"\n\tlocal device_id device_type category service_options_json payload out status expires activity_id\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$assignment\")\"\n\tdevice_type=\"$(jq -r '.device_type' <<<\"$assignment\")\"\n\tservice_options_json=\"$(jq -c '.service_options' <<<\"$assignment\")\"\n\tcategory=\"$(jq -r '.category' <<<\"$assignment\")\"\n\texpires=\"$(date -u -v+\"${CLAIM_TTL_HOURS}\"H +%Y-%m-%dT%H:%M:%SZ 2>/dev/null || date -u -d \"+${CLAIM_TTL_HOURS} hours\" +%Y-%m-%dT%H:%M:%SZ)\"\n\tactivity_id=\"bulk-bind-$RUN_ID-$device_id\"\n\tpayload=\"$TMPDIR/claim-$device_id.json\"\n\tout=\"$TMPDIR/claim-$device_id.out\"\n\tjq -cn \\\n\t\t--arg organization_id \"$BRAND_CLOUD_ID\" \\\n\t\t--arg category \"$category\" \\\n\t\t--arg video_cloud_devid \"$device_id\" \\\n\t\t--arg activity_id \"$activity_id\" \\\n\t\t--arg clip_public_key \"bulk-bind-placeholder-public-key\" \\\n\t\t--arg expires_at \"$expires\" \\\n\t\t--arg device_type \"$device_type\" \\\n\t\t--arg source \"cloud-bind-devices\" \\\n\t\t--argjson service_options \"$service_options_json\" \\\n\t\t'{\n\t\t\torganization_id: $organization_id,\n\t\t\tcategory: $category,\n\t\t\tvideo_cloud_devid: $video_cloud_devid,\n\t\t\tactivity_id: $activity_id,\n\t\t\tclip_public_key: $clip_public_key,\n\t\t\texpires_at: $expires_at,\n\t\t\tservice_options: $service_options,\n\t\t\tmetadata: {\n\t\t\t\tsource: $source,\n\t\t\t\tdevice_type: $device_type,\n\t\t\t\tservice_options: $service_options\n\t\t\t}\n\t\t}' > \"$payload\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/admin/device-claim-tokens\")\"\n\tif [[ \"$status\" != \"200\" && \"$status\" != \"201\" ]]; then\n\t\tprintf 'claim token create failed: device=%s HTTP %s\\n' \"$device_id\" \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tjq -c --arg status \"$status\" '{claim_id:(.id // .claim_id), claim_token:(.claim_token // .token), http_status:($status|tonumber)}' \"$out\"\n}\n\nresolve_claim() {\n\tlocal assignment=\"$1\"\n\tlocal claim_token=\"$2\"\n\tlocal user_token=\"$3\"\n\tlocal device_id device_name payload out status\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$assignment\")\"\n\tdevice_name=\"$(jq -r '.display_name' <<<\"$assignment\")\"\n\tpayload=\"$TMPDIR/resolve-$device_id.json\"\n\tout=\"$TMPDIR/resolve-$device_id.out\"\n\tjq -cn --arg claim_token \"$claim_token\" --arg device_name \"$device_name\" '{claim_token:$claim_token,device_name:$device_name}' > \"$payload\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $user_token\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/orgs/$BRAND_CLOUD_ID/devices/claim/resolve\")\"\n\tif [[ \"$status\" != \"200\" && \"$status\" != \"201\" ]]; then\n\t\tprintf 'claim resolve failed: device=%s HTTP %s\\n' \"$device_id\" \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tjq -c --arg status \"$status\" '. + {http_status:($status|tonumber)}' \"$out\"\n}\n\nstart_provision() {\n\tlocal assignment=\"$1\"\n\tlocal resolve_json=\"$2\"\n\tlocal user_token=\"$3\"\n\tlocal device_id account_device_id operation_id service_options_json payload out status\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$assignment\")\"\n\taccount_device_id=\"$(jq -r '.device.id // empty' <<<\"$resolve_json\")\"\n\t[[ -n \"$account_device_id\" && \"$account_device_id\" != \"null\" ]] || die \"claim resolve missing account device id: $device_id\"\n\toperation_id=\"bulk-bind-$RUN_ID-$device_id\"\n\tservice_options_json=\"$(jq -c '.provision_input.service_options // empty' <<<\"$resolve_json\")\"\n\tif [[ -z \"$service_options_json\" ]]; then\n\t\tservice_options_json=\"$(jq -c '.service_options' <<<\"$assignment\")\"\n\tfi\n\tpayload=\"$TMPDIR/provision-$device_id.json\"\n\tout=\"$TMPDIR/provision-$device_id.out\"\n\tjq -cn \\\n\t\t--arg video_cloud_devid \"$(jq -r '.provision_input.video_cloud_devid // .device.video_cloud_devid // empty' <<<\"$resolve_json\")\" \\\n\t\t--arg activity_id \"$(jq -r '.provision_input.activity_id // empty' <<<\"$resolve_json\")\" \\\n\t\t--arg clip_public_key \"$(jq -r '.provision_input.clip_public_key // empty' <<<\"$resolve_json\")\" \\\n\t\t--arg operation_id \"$operation_id\" \\\n\t\t--argjson service_options \"$service_options_json\" \\\n\t\t'{\n\t\t\tvideo_cloud_devid: $video_cloud_devid,\n\t\t\tactivity_id: $activity_id,\n\t\t\tclip_public_key: $clip_public_key,\n\t\t\toperation_id: $operation_id,\n\t\t\tservice_options: $service_options\n\t\t}' > \"$payload\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $user_token\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/orgs/$BRAND_CLOUD_ID/devices/$account_device_id/provision\")\"\n\tif [[ \"$status\" != \"200\" && \"$status\" != \"201\" && \"$status\" != \"202\" ]]; then\n\t\tprintf 'provision start failed: device=%s account_device=%s HTTP %s\\n' \"$device_id\" \"$account_device_id\" \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tjq -c --arg operation_id \"$operation_id\" --arg status \"$status\" '. + {operation_id: (.operation.id // .id // $operation_id), http_status:($status|tonumber)}' \"$out\"\n}\n\nvalidate_args\nneed_cmd curl\nneed_cmd jq\nneed_cmd ssh\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nTMPDIR=\"$(mktemp -d /tmp/rtk-bind-devices.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nresolve_default_inputs\nvalidate_users_and_devices\n\nASSIGNMENTS_JSON=\"$(build_assignments)\"\n\nif [[ \"$DRY_RUN\" == \"1\" ]]; then\n\tjq -cn \\\n\t\t--arg brandname \"$BRANDNAME\" \\\n\t\t--arg users_file \"$USERS_FILE\" \\\n\t\t--arg devices_dir \"$DEVICES_DIR\" \\\n\t\t--argjson count \"$COUNT\" \\\n\t\t--argjson assignments \"$ASSIGNMENTS_JSON\" \\\n\t\t'{action:\"dry_run\", brandname:$brandname, count:$count, users_file:$users_file, devices_dir:$devices_dir, assignments:$assignments}'\n\texit 0\nfi\n\nlog \"workspace=$WORKSPACE\"\nlog \"env_root=$ENV_ROOT\"\nlog \"users_file=$USERS_FILE\"\nlog \"devices_dir=$DEVICES_DIR\"\n\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nAM_PLATFORM_ADMIN_ENV=\"$(cloud_env_account_manager_platform_admin_env \"$ENV_ROOT\")\"\n\nlog \"loading Account Manager env/state\"\nload_env_file \"$AM_ENV\"\nload_env_file \"$AM_STATE\"\nload_env_file \"$AM_PLATFORM_ADMIN_ENV\"\n\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-account-manager.video-cloud-staging.realtekconnect.com}\"\nAM_BASE_URL=\"https://$AM_DOMAIN\"\nUSER_TOKENS_FILE=\"$TMPDIR/user-tokens.json\"\nRUN_ID=\"$(date -u +%Y%m%dT%H%M%SZ)\"\n\nensure_platform_admin_bootstrap\nlogin_platform_admin\nfind_brand_cloud\nif [[ -n \"$USERS_BRAND_CLOUD_ID\" && \"$USERS_BRAND_CLOUD_ID\" != \"$BRAND_CLOUD_ID\" ]]; then\n\tdie \"--users-file brand_cloud_id $USERS_BRAND_CLOUD_ID does not match resolved brand cloud $BRAND_CLOUD_ID\"\nfi\nwrite_secret_user_tokens\n\nRESULTS_JSONL=\"$TMPDIR/results.jsonl\"\n: > \"$RESULTS_JSONL\"\nCREATED_CLAIMS=0\nRESOLVED_CLAIMS=0\nPROVISION_STARTED=0\n\nwhile IFS= read -r row; do\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$row\")\"\n\temail=\"$(jq -r '.assigned_email' <<<\"$row\")\"\n\tlog \"binding device: device=$device_id user=$email\"\n\tuser_token=\"$(user_token_for_email \"$email\")\"\n\t[[ -n \"$user_token\" ]] || die \"no login token for assigned user: $email\"\n\tclaim_json=\"$(create_claim_token \"$row\")\"\n\tCREATED_CLAIMS=$((CREATED_CLAIMS + 1))\n\tclaim_token=\"$(jq -r '.claim_token // empty' <<<\"$claim_json\")\"\n\tclaim_id=\"$(jq -r '.claim_id // empty' <<<\"$claim_json\")\"\n\t[[ -n \"$claim_token\" && \"$claim_token\" != \"null\" ]] || die \"claim token create response missing raw token: $device_id\"\n\tresolve_json=\"$(resolve_claim \"$row\" \"$claim_token\" \"$user_token\")\"\n\tRESOLVED_CLAIMS=$((RESOLVED_CLAIMS + 1))\n\tprovision_json=\"$(start_provision \"$row\" \"$resolve_json\" \"$user_token\")\"\n\tPROVISION_STARTED=$((PROVISION_STARTED + 1))\n\tjq -cn \\\n\t\t--argjson assignment \"$row\" \\\n\t\t--arg claim_id \"$claim_id\" \\\n\t\t--arg account_device_id \"$(jq -r '.device.id' <<<\"$resolve_json\")\" \\\n\t\t--arg operation_id \"$(jq -r '.operation_id' <<<\"$provision_json\")\" \\\n\t\t'{\n\t\t\tassignment_index: $assignment.assignment_index,\n\t\t\tassigned_email: $assignment.assigned_email,\n\t\t\tdevice_id: $assignment.device_id,\n\t\t\tdevice_type: $assignment.device_type,\n\t\t\tcategory: $assignment.category,\n\t\t\tservice_options: $assignment.service_options,\n\t\t\tclaim_id: $claim_id,\n\t\t\taccount_device_id: $account_device_id,\n\t\t\toperation_id: $operation_id,\n\t\t\tstatus: \"provision_requested\"\n\t\t}' >> \"$RESULTS_JSONL\"\ndone < <(jq -rc '.[]' <<<\"$ASSIGNMENTS_JSON\")\n\nSLUG=\"$(brand_slug)\"\nARTIFACT_DIR=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/device-bind\"\nmkdir -p \"$ARTIFACT_DIR\"\nARTIFACT_FILE=\"$ARTIFACT_DIR/$SLUG-device-bind-$RUN_ID.json\"\nARTIFACT_TMP=\"$TMPDIR/artifact.json\"\njq -s \\\n\t--arg schema \"rtk-cloud-workspace.bulk-device-bind/v1\" \\\n\t--arg generated_at \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg users_file \"$USERS_FILE\" \\\n\t--arg devices_dir \"$DEVICES_DIR\" \\\n\t--argjson count \"$COUNT\" \\\n\t'{schema:$schema, generated_at:$generated_at, brandname:$brandname, brand_cloud_id:$brand_cloud_id, count:$count, inputs:{users_file:$users_file, devices_dir:$devices_dir}, assignments:.}' \\\n\t\"$RESULTS_JSONL\" > \"$ARTIFACT_TMP\"\ninstall -m 0600 \"$ARTIFACT_TMP\" \"$ARTIFACT_FILE\"\nlog \"bind artifact written: $ARTIFACT_FILE\"\n\njq -cn \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg artifact_file \"$ARTIFACT_FILE\" \\\n\t--argjson count \"$COUNT\" \\\n\t--argjson created_claims \"$CREATED_CLAIMS\" \\\n\t--argjson resolved_claims \"$RESOLVED_CLAIMS\" \\\n\t--argjson provision_started \"$PROVISION_STARTED\" \\\n\t'{action:\"bound\", brandname:$brandname, brand_cloud_id:$brand_cloud_id, count:$count, created_claims:$created_claims, resolved_claims:$resolved_claims, provision_started:$provision_started, artifact_file:$artifact_file}'\n",
	"cloud-check-certificates.sh":               "#!/usr/bin/env bash\nif [ -z \"${BASH_VERSION:-}\" ]; then\n\texec /usr/bin/env bash \"$0\" \"$@\"\nfi\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nDNS_ROOT_DOMAIN=\"realtekconnect.com\"\nMIN_VALID_DAYS=\"${STAGING_CERT_CHECK_MIN_VALID_DAYS:-7}\"\nJSON_OUTPUT=0\nSKIP_LIVE=0\nSKIP_CACHE=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-check-certificates.sh --env-root PATH [options]\n\nOptions:\n  --workspace PATH        Default: script parent workspace.\n  --env-root PATH         Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH     Deprecated alias for --env-root.\n  --dns-root-domain NAME  Default: realtekconnect.com.\n  --min-valid-days N      Required remaining validity. Default: 7.\n  --skip-live             Do not connect to live HTTPS endpoints.\n  --skip-cache            Do not check local cloud_env certificate cache.\n  --json                  Print JSON result.\n  -h, --help              Show this help.\n\nChecks staging HTTPS certificates for:\n  - video-cloud-staging.<root-domain>\n  - certissuer.video-cloud-staging.<root-domain>\n  - account-manager.video-cloud-staging.<root-domain>\n  - admin.video-cloud-staging.<root-domain>\n\nThe script checks both local cloud_env certificate cache and live HTTPS\nendpoints unless skipped. It exits nonzero when any checked certificate is\nmissing, expired, hostname-invalid, chain-invalid on live HTTPS, or below the\nminimum remaining validity threshold.\nUSAGE\n}\n\nrequire_value() {\n\tlocal opt=\"$1\"\n\tlocal value=\"${2:-}\"\n\t[[ -n \"$value\" ]] || die \"$opt requires a value\"\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) require_value \"$1\" \"${2:-}\"; WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) require_value \"$1\" \"${2:-}\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--secrets-root) require_value \"$1\" \"${2:-}\"; DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--dns-root-domain) require_value \"$1\" \"${2:-}\"; DNS_ROOT_DOMAIN=\"$2\"; shift 2 ;;\n\t--min-valid-days) require_value \"$1\" \"${2:-}\"; MIN_VALID_DAYS=\"$2\"; shift 2 ;;\n\t--skip-live) SKIP_LIVE=1; shift ;;\n\t--skip-cache) SKIP_CACHE=1; shift ;;\n\t--json) JSON_OUTPUT=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n[[ \"$MIN_VALID_DAYS\" =~ ^[0-9]+$ ]] || die \"--min-valid-days must be a non-negative integer\"\n[[ \"$SKIP_LIVE\" == \"0\" || \"$SKIP_CACHE\" == \"0\" ]] || die \"at least one of live or cache checks must be enabled\"\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file_if_exists() {\n\tlocal path=\"$1\"\n\tif [[ -f \"$path\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$path\"\n\t\tset +a\n\tfi\n}\n\nneed_cmd jq\nneed_cmd openssl\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\n\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nADMIN_ENV=\"$(cloud_env_admin_env \"$ENV_ROOT\")\"\nCERT_ROOT=\"$(cloud_env_certificates_dir \"$ENV_ROOT\")\"\nload_env_file_if_exists \"$AM_ENV\"\nload_env_file_if_exists \"$ADMIN_ENV\"\n\nVC_GATEWAY_DOMAIN=\"video-cloud-staging.$DNS_ROOT_DOMAIN\"\nVC_CERTISSUER_DOMAIN=\"certissuer.video-cloud-staging.$DNS_ROOT_DOMAIN\"\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-account-manager.video-cloud-staging.$DNS_ROOT_DOMAIN}\"\nADMIN_DOMAIN=\"${ADMIN_LINODE_DOMAIN:-admin.video-cloud-staging.$DNS_ROOT_DOMAIN}\"\n\nTMPDIR=\"$(mktemp -d /tmp/rtk-staging-cert-check.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\nTARGETS_TSV=\"$TMPDIR/targets.tsv\"\nRESULT_JSON=\"$TMPDIR/results.json\"\nRESULTS_JSONL=\"$TMPDIR/results.jsonl\"\n\n: > \"$TARGETS_TSV\"\nprintf '%s\\t%s\\t%s\\t%s\\n' \"video-cloud\" \"$VC_GATEWAY_DOMAIN\" \"$CERT_ROOT/$VC_GATEWAY_DOMAIN/fullchain.pem\" \"gateway\" >> \"$TARGETS_TSV\"\nprintf '%s\\t%s\\t%s\\t%s\\n' \"certissuer\" \"$VC_CERTISSUER_DOMAIN\" \"$CERT_ROOT/$VC_GATEWAY_DOMAIN/fullchain.pem\" \"video-cloud-cache\" >> \"$TARGETS_TSV\"\nprintf '%s\\t%s\\t%s\\t%s\\n' \"account-manager\" \"$AM_DOMAIN\" \"$CERT_ROOT/$AM_DOMAIN/fullchain.pem\" \"account-manager\" >> \"$TARGETS_TSV\"\nprintf '%s\\t%s\\t%s\\t%s\\n' \"cloud-admin\" \"$ADMIN_DOMAIN\" \"$CERT_ROOT/$ADMIN_DOMAIN/fullchain.pem\" \"cloud-admin\" >> \"$TARGETS_TSV\"\n\nasn1_epoch() {\n\tlocal value=\"$1\"\n\tif date -u -d \"$value\" +%s >/dev/null 2>&1; then\n\t\tdate -u -d \"$value\" +%s\n\telse\n\t\tLC_ALL=C date -j -u -f '%b %e %T %Y %Z' \"$value\" +%s\n\tfi\n}\n\nasn1_iso() {\n\tlocal value=\"$1\"\n\tif date -u -d \"$value\" +%Y-%m-%dT%H:%M:%SZ >/dev/null 2>&1; then\n\t\tdate -u -d \"$value\" +%Y-%m-%dT%H:%M:%SZ\n\telse\n\t\tLC_ALL=C date -j -u -f '%b %e %T %Y %Z' \"$value\" +%Y-%m-%dT%H:%M:%SZ\n\tfi\n}\n\njson_error_result() {\n\tlocal target=\"$1\"\n\tlocal domain=\"$2\"\n\tlocal source=\"$3\"\n\tlocal detail=\"$4\"\n\tjq -cn \\\n\t\t--arg target \"$target\" \\\n\t\t--arg domain \"$domain\" \\\n\t\t--arg source \"$source\" \\\n\t\t--arg detail \"$detail\" \\\n\t\t'{target:$target,domain:$domain,source:$source,status:\"fail\",days_left:null,expires_at:\"\",subject:\"\",issuer:\"\",detail:$detail}'\n}\n\njson_cert_result() {\n\tlocal target=\"$1\"\n\tlocal domain=\"$2\"\n\tlocal source=\"$3\"\n\tlocal cert_path=\"$4\"\n\tlocal detail=\"${5:-}\"\n\tlocal not_after expires_at expires_epoch now_epoch seconds_left days_left subject issuer status failures checkend_seconds\n\tnot_after=\"$(openssl x509 -in \"$cert_path\" -noout -enddate | sed 's/^notAfter=//')\"\n\texpires_at=\"$(asn1_iso \"$not_after\")\"\n\texpires_epoch=\"$(asn1_epoch \"$not_after\")\"\n\tnow_epoch=\"$(date -u +%s)\"\n\tseconds_left=$((expires_epoch - now_epoch))\n\tdays_left=$((seconds_left / 86400))\n\tstatus=\"pass\"\n\tfailures=\"\"\n\tif ! cert_matches_host \"$cert_path\" \"$domain\"; then\n\t\tfailures=\"hostname: $domain does not match certificate\"\n\tfi\n\tif [[ \"$seconds_left\" -lt 0 ]]; then\n\t\tfailures=\"${failures:+$failures; }expired\"\n\telse\n\t\tcheckend_seconds=$((MIN_VALID_DAYS * 86400))\n\t\tif ! openssl x509 -in \"$cert_path\" -noout -checkend \"$checkend_seconds\" >/dev/null 2>&1; then\n\t\t\tfailures=\"${failures:+$failures; }expires within $MIN_VALID_DAYS days\"\n\t\tfi\n\tfi\n\tif [[ -n \"$failures\" ]]; then\n\t\tstatus=\"fail\"\n\t\tdetail=\"$failures\"\n\tfi\n\tsubject=\"$(openssl x509 -in \"$cert_path\" -noout -subject | sed 's/^subject=//')\"\n\tissuer=\"$(openssl x509 -in \"$cert_path\" -noout -issuer | sed 's/^issuer=//')\"\n\tjq -cn \\\n\t\t--arg target \"$target\" \\\n\t\t--arg domain \"$domain\" \\\n\t\t--arg source \"$source\" \\\n\t\t--arg status \"$status\" \\\n\t\t--arg expires_at \"$expires_at\" \\\n\t\t--arg subject \"$subject\" \\\n\t\t--arg issuer \"$issuer\" \\\n\t\t--arg detail \"$detail\" \\\n\t\t--argjson days_left \"$days_left\" \\\n\t\t'{target:$target,domain:$domain,source:$source,status:$status,days_left:$days_left,expires_at:$expires_at,subject:$subject,issuer:$issuer,detail:$detail}'\n}\n\ncert_matches_host() {\n\tlocal cert_path=\"$1\"\n\tlocal domain=\"$2\"\n\tlocal names name cn\n\tnames=\"$(openssl x509 -in \"$cert_path\" -noout -text 2>/dev/null |\n\t\tsed -n '/Subject Alternative Name/{n;p;}' |\n\t\tsed 's/DNS://g' |\n\t\ttr ',' '\\n' |\n\t\tsed 's/^[[:space:]]*//; s/[[:space:]]*$//')\"\n\tif [[ -z \"$names\" ]]; then\n\t\tcn=\"$(openssl x509 -in \"$cert_path\" -noout -subject | sed -n 's/.*CN *= *//p' | sed 's/[ ,/].*$//')\"\n\t\tnames=\"$cn\"\n\tfi\n\twhile IFS= read -r name; do\n\t\t[[ -n \"$name\" ]] || continue\n\t\tcase \"$name\" in\n\t\t\"*.\"*)\n\t\t\tlocal suffix=\"${name#\\*}\"\n\t\t\tif [[ \"$domain\" == *\"$suffix\" && \"${domain%\"$suffix\"}\" != *.* && -n \"${domain%\"$suffix\"}\" ]]; then\n\t\t\t\treturn 0\n\t\t\tfi\n\t\t\t;;\n\t\t\"$domain\") return 0 ;;\n\t\tesac\n\tdone <<< \"$names\"\n\treturn 1\n}\n\ncheck_cache() {\n\tlocal target=\"$1\"\n\tlocal domain=\"$2\"\n\tlocal cert_path=\"$3\"\n\tif [[ ! -s \"$cert_path\" ]]; then\n\t\tjson_error_result \"$target\" \"$domain\" \"local-cache\" \"missing $cert_path\"\n\t\treturn\n\tfi\n\tif ! openssl x509 -in \"$cert_path\" -noout >/dev/null 2>&1; then\n\t\tjson_error_result \"$target\" \"$domain\" \"local-cache\" \"invalid certificate\"\n\t\treturn\n\tfi\n\tjson_cert_result \"$target\" \"$domain\" \"local-cache\" \"$cert_path\"\n}\n\ncheck_live() {\n\tlocal target=\"$1\"\n\tlocal domain=\"$2\"\n\tlocal live_cert=\"$TMPDIR/live-$target.pem\"\n\tif ! openssl s_client -connect \"$domain:443\" -servername \"$domain\" -verify_hostname \"$domain\" </dev/null 2>/dev/null |\n\t\tawk '/-----BEGIN CERTIFICATE-----/{in_cert=1} in_cert{print} /-----END CERTIFICATE-----/{exit}' > \"$live_cert\"; then\n\t\tjson_error_result \"$target\" \"$domain\" \"live-443\" \"TLS connection failed\"\n\t\treturn\n\tfi\n\tif [[ ! -s \"$live_cert\" ]]; then\n\t\tjson_error_result \"$target\" \"$domain\" \"live-443\" \"no certificate returned\"\n\t\treturn\n\tfi\n\tjson_cert_result \"$target\" \"$domain\" \"live-443\" \"$live_cert\"\n}\n\n: > \"$RESULTS_JSONL\"\nwhile IFS=$'\\t' read -r target domain cache_path _cache_label; do\n\tif [[ \"$SKIP_CACHE\" != \"1\" ]]; then\n\t\tcheck_cache \"$target\" \"$domain\" \"$cache_path\" >> \"$RESULTS_JSONL\"\n\tfi\n\tif [[ \"$SKIP_LIVE\" != \"1\" ]]; then\n\t\tcheck_live \"$target\" \"$domain\" >> \"$RESULTS_JSONL\"\n\tfi\ndone < \"$TARGETS_TSV\"\n\ngenerated_at=\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"\njq -s \\\n\t--arg generated_at \"$generated_at\" \\\n\t--argjson min_valid_days \"$MIN_VALID_DAYS\" \\\n\t'{\n\t\tgenerated_at: $generated_at,\n\t\tmin_valid_days: $min_valid_days,\n\t\tstatus: (if all(.status == \"pass\") then \"pass\" else \"fail\" end),\n\t\tresults: .\n\t}' \"$RESULTS_JSONL\" > \"$RESULT_JSON\"\nstatus=0\nif [[ \"$(jq -r '.status' \"$RESULT_JSON\")\" != \"pass\" ]]; then\n\tstatus=3\nfi\n\nif [[ \"$JSON_OUTPUT\" == \"1\" ]]; then\n\tjq . \"$RESULT_JSON\"\nelse\n\tprintf 'cloud_certificates status=%s min_valid_days=%s env_root=%s\\n' \\\n\t\t\"$(jq -r '.status' \"$RESULT_JSON\")\" \"$MIN_VALID_DAYS\" \"$ENV_ROOT\"\n\tprintf '%-16s  %-55s  %-12s  %-6s  %-9s  %-20s  %-32s  %s\\n' \\\n\t\t'target' 'domain' 'source' 'status' 'days_left' 'expires_at' 'issuer' 'detail'\n\tjq -r '.results[] | [.target,.domain,.source,.status,(.days_left // \"n/a\"),.expires_at,.issuer,.detail] | @tsv' \"$RESULT_JSON\" |\n\t\tawk -F '\\t' '{\n\t\t\tprintf \"%-16s  %-55s  %-12s  %-6s  %-9s  %-20s  %-32s  %s\\n\", $1, $2, $3, $4, $5, $6, substr($7, 1, 32), $8\n\t\t}'\nfi\n\nexit \"$status\"\n",
	"cloud-create-brandname-cloud.sh":           "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nSTART_EPOCH=\"$(date +%s)\"\nBRANDNAME=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nSKIP_BOOTSTRAP=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-brand-cloud %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-create-brandname-cloud.sh --brandname NAME [options]\n\nOptions:\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH    Deprecated alias for --env-root.\n  --skip-bootstrap       Do not update/restart the remote platform-admin bootstrap env.\n  -h, --help             Show this help.\n\nCreates an Account Manager brand cloud named NAME on the Linode staging\ndeployment. The script is idempotent: if the brand cloud already exists, it\nprints the existing record.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--brandname) BRANDNAME=\"$2\"; shift 2 ;;\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--secrets-root) DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--skip-bootstrap) SKIP_BOOTSTRAP=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"required env file not found: $path\"\n\tset -a\n\t# shellcheck source=/dev/null\n\t. \"$path\"\n\tset +a\n}\n\njson_string() {\n\tjq -Rn --arg value \"$1\" '$value'\n}\n\ncurl_json_status() {\n\tlocal out=\"$1\"\n\tshift\n\tcurl -sS -o \"$out\" -w '%{http_code}' \"$@\"\n}\n\nvalidate_brandname() {\n\tBRANDNAME=\"$(printf '%s' \"$BRANDNAME\" | awk '{$1=$1; print}')\"\n\t[[ -n \"$BRANDNAME\" ]] || die \"--brandname is required\"\n\tif printf '%s' \"$BRANDNAME\" | LC_ALL=C grep -q '[[:cntrl:]]'; then\n\t\tdie \"--brandname must not contain control characters\"\n\tfi\n}\n\nremote_target() {\n\tAM_HOST=\"${ACCOUNT_MANAGER_LINODE_HOST:-${ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4:-}}\"\n\tAM_SSH_USER=\"${ACCOUNT_MANAGER_LINODE_SSH_USER:-root}\"\n\tAM_SSH_KEY=\"${ACCOUNT_MANAGER_LINODE_SSH_KEY:-$HOME/.ssh/id_ed25519_rtkcloud}\"\n\t[[ -n \"$AM_HOST\" ]] || die \"ACCOUNT_MANAGER_LINODE_HOST or ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4 is required\"\n\t[[ -n \"$AM_SSH_KEY\" ]] || die \"ACCOUNT_MANAGER_LINODE_SSH_KEY is required\"\n}\n\nensure_platform_admin_bootstrap() {\n\tif [[ \"$SKIP_BOOTSTRAP\" != \"0\" ]]; then\n\t\tlog \"skip bootstrap admin env update\"\n\t\treturn 0\n\tfi\n\tremote_target\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL is required\"\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD is required\"\n\tlog \"updating platform-admin bootstrap env on account-manager host=$AM_HOST\"\n\t{\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\"\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\"\n\t} | ssh -i \"$AM_SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new \"$AM_SSH_USER@$AM_HOST\" 'set -euo pipefail\n\t\tenv_file=/etc/rtk-account-manager/account-manager.env\n\t\ttest -f \"$env_file\"\n\t\tcp -p \"$env_file\" \"$env_file.bootstrap-admin.bak.$(date -u +%Y%m%dT%H%M%SZ)\"\n\t\ttmp=\"$(mktemp)\"\n\t\tgrep -vE \"^ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_(EMAIL|PASSWORD)=\" \"$env_file\" > \"$tmp\"\n\t\tcat >> \"$tmp\"\n\t\tinstall -m 0600 -o root -g root \"$tmp\" \"$env_file\"\n\t\trm -f \"$tmp\"\n\t\tsystemctl restart rtk-account-manager.service\n\t\tfor _ in $(seq 1 30); do\n\t\t\tif curl -fsS http://127.0.0.1:18081/v1/health >/dev/null 2>&1; then\n\t\t\t\techo \"bootstrap admin env applied and account-manager is healthy\" >&2\n\t\t\t\texit 0\n\t\t\tfi\n\t\t\tsleep 1\n\t\tdone\n\t\tjournalctl -u rtk-account-manager.service -n 80 --no-pager >&2 || true\n\t\texit 1\n\t'\n\tlog \"platform-admin bootstrap env ready\"\n}\n\nlogin_platform_admin() {\n\tlocal login_payload=\"$TMPDIR/login.json\"\n\tlocal login_out=\"$TMPDIR/login.out\"\n\tlog \"logging in platform admin: $AM_BASE_URL/v1/auth/login\"\n\tjq -cn \\\n\t\t--arg email \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\" \\\n\t\t--arg password \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\" \\\n\t\t'{email:$email,password:$password}' > \"$login_payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$login_out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t--data-binary \"@$login_payload\" \\\n\t\t\"$AM_BASE_URL/v1/auth/login\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"platform admin login failed: HTTP $status\"\n\tACCESS_TOKEN=\"$(jq -r '.tokens.access_token // empty' \"$login_out\")\"\n\t[[ -n \"$ACCESS_TOKEN\" ]] || die \"platform admin login response did not include an access token\"\n\tlog \"platform admin login ok\"\n}\n\nfind_existing_brand_cloud() {\n\tlocal out=\"$TMPDIR/list.out\"\n\tlocal status\n\tlog \"checking existing brand clouds for name=$BRANDNAME\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds?limit=200\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"brand cloud list failed: HTTP $status\"\n\tEXISTING_ID=\"$(jq -r --arg name \"$BRANDNAME\" '.brand_clouds[]? | select(.name == $name) | .id' \"$out\" | head -n 1)\"\n\tif [[ -n \"$EXISTING_ID\" ]]; then\n\t\tlog \"brand cloud already exists: id=$EXISTING_ID\"\n\t\tjq --arg id \"$EXISTING_ID\" \\\n\t\t\t'{action:\"exists\", brand_cloud:(.brand_clouds[] | select(.id == $id))}' \"$out\"\n\t\treturn 0\n\tfi\n\tlog \"brand cloud not found; will create it\"\n\treturn 1\n}\n\ncreate_via_api() {\n\tlocal payload=\"$TMPDIR/create.json\"\n\tlocal out=\"$TMPDIR/create.out\"\n\tlog \"creating brand cloud via Account Manager API: name=$BRANDNAME\"\n\tjq -cn --arg name \"$BRANDNAME\" '{name:$name, metadata:{brandname:$name}}' > \"$payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds\")\"\n\tif [[ \"$status\" == \"201\" ]]; then\n\t\tlog \"brand cloud created via API\"\n\t\tjq '{action:\"created\", brand_cloud:.brand_cloud}' \"$out\"\n\t\treturn 0\n\tfi\n\tif [[ \"$status\" != \"500\" ]]; then\n\t\tprintf 'brand cloud create failed: HTTP %s\\n' \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tlog \"API create returned HTTP 500; falling back to direct PostgreSQL upsert\"\n\treturn 2\n}\n\ncreate_via_postgres_fallback() {\n\tremote_target\n\tlocal email_b64 brand_b64\n\tlog \"creating brand cloud via PostgreSQL fallback on account-manager host=$AM_HOST\"\n\temail_b64=\"$(printf '%s' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\" | base64)\"\n\tbrand_b64=\"$(printf '%s' \"$BRANDNAME\" | base64)\"\n\tssh -i \"$AM_SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new \"$AM_SSH_USER@$AM_HOST\" bash -s -- \"$email_b64\" \"$brand_b64\" <<'REMOTE'\nset -euo pipefail\nemail=\"$(printf '%s' \"$1\" | base64 -d)\"\nbrand=\"$(printf '%s' \"$2\" | base64 -d)\"\nsudo -u postgres psql -d rtk_account_manager -v ON_ERROR_STOP=1 -v email=\"$email\" -v brand=\"$brand\" -At <<'SQL'\nWITH existing AS (\n\tSELECT id::text, name, organization_kind, status, tier, evaluation_device_quota, metadata, created_at, updated_at, false AS created\n\tFROM organizations\n\tWHERE organization_kind = 'brand_cloud' AND name = :'brand'\n\tORDER BY created_at ASC\n\tLIMIT 1\n), actor AS (\n\tSELECT id::text AS id FROM users WHERE email = :'email'\n), inserted AS (\n\tINSERT INTO organizations (name, organization_kind, status, tier, evaluation_device_quota, metadata)\n\tSELECT :'brand', 'brand_cloud', 'active', 'commercial', 5, jsonb_build_object('brandname', :'brand')\n\tWHERE NOT EXISTS (SELECT 1 FROM existing)\n\tRETURNING id::text, name, organization_kind, status, tier, evaluation_device_quota, metadata, created_at, updated_at, true AS created\n), selected AS (\n\tSELECT * FROM inserted\n\tUNION ALL\n\tSELECT * FROM existing\n), member_upsert AS (\n\tINSERT INTO organization_members (organization_id, user_id, role)\n\tSELECT selected.id::uuid, actor.id::uuid, 'owner'\n\tFROM selected, actor\n\tON CONFLICT (organization_id, user_id)\n\tDO UPDATE SET role = 'owner', updated_at = now()\n\tRETURNING organization_id\n), audit AS (\n\tINSERT INTO audit_events (event_type, actor_user_id, organization_id, subject_type, subject_id, payload)\n\tSELECT 'brand_cloud_created', actor.id::uuid, selected.id::uuid, 'brand_cloud', selected.id,\n\t\tjsonb_build_object('name', selected.name, 'organization_kind', selected.organization_kind, 'status', selected.status, 'initial_owner_user_id', actor.id)\n\tFROM selected, actor\n\tWHERE selected.created\n\tRETURNING id\n)\nSELECT jsonb_build_object(\n\t'action', CASE WHEN created THEN 'created' ELSE 'exists' END,\n\t'brand_cloud', jsonb_build_object(\n\t\t'id', id,\n\t\t'name', name,\n\t\t'organization_kind', organization_kind,\n\t\t'status', status,\n\t\t'tier', tier,\n\t\t'evaluation_device_quota', evaluation_device_quota,\n\t\t'metadata', metadata,\n\t\t'created_at', created_at,\n\t\t'updated_at', updated_at\n\t)\n)::text\nFROM selected;\nSQL\nREMOTE\n}\n\nverify_created_with_api() {\n\tlocal expected_json=\"$1\"\n\tlocal expected_id\n\texpected_id=\"$(jq -r '.brand_cloud.id' <<<\"$expected_json\")\"\n\t[[ -n \"$expected_id\" && \"$expected_id\" != \"null\" ]] || die \"fallback did not return a brand cloud id\"\n\tlocal out=\"$TMPDIR/verify-list.out\"\n\tlocal status\n\tlog \"verifying brand cloud through Account Manager API: id=$expected_id\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds?limit=200\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"post-create brand cloud verification failed: HTTP $status\"\n\tjq -e --arg id \"$expected_id\" '.brand_clouds[]? | select(.id == $id)' \"$out\" >/dev/null ||\n\t\tdie \"post-create brand cloud verification did not find $expected_id\"\n\tlog \"brand cloud verified: id=$expected_id\"\n\tprintf '%s\\n' \"$expected_json\"\n}\n\nvalidate_brandname\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\nlog \"start staging brand cloud create: brandname=$BRANDNAME\"\nneed_cmd curl\nneed_cmd jq\nneed_cmd ssh\nneed_cmd base64\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\nlog \"workspace=$WORKSPACE\"\nAM_REPO=\"$WORKSPACE/repos/rtk_account_manager\"\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nAM_PLATFORM_ADMIN_ENV=\"$(cloud_env_account_manager_platform_admin_env \"$ENV_ROOT\")\"\n\nlog \"loading Account Manager staging env/state\"\nload_env_file \"$AM_ENV\"\nload_env_file \"$AM_STATE\"\nload_env_file \"$AM_PLATFORM_ADMIN_ENV\"\n\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-account-manager.video-cloud-staging.realtekconnect.com}\"\nAM_BASE_URL=\"https://$AM_DOMAIN\"\nTMPDIR=\"$(mktemp -d /tmp/rtk-brand-cloud.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\n\nensure_platform_admin_bootstrap\nlogin_platform_admin\nif find_existing_brand_cloud; then\n\tlog \"complete: brand cloud exists\"\n\texit 0\nfi\nif created_json=\"$(create_via_api)\"; then\n\tprintf '%s\\n' \"$created_json\"\n\tlog \"complete: brand cloud created\"\n\texit 0\nfi\nfallback_json=\"$(create_via_postgres_fallback)\"\nverify_created_with_api \"$fallback_json\"\nlog \"complete: brand cloud created through fallback\"\n",
	"cloud-create-users.sh":                     "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nSTART_EPOCH=\"$(date +%s)\"\nBRANDNAME=\"\"\nCOUNT=10\nROLE=\"member\"\nSKIP_BOOTSTRAP=0\nDRY_RUN=0\nROTATE_PASSWORD=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-create-users %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-create-users.sh --env-root cloud_env/staging --brandname RTK [options]\n\nOptions:\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --brandname NAME       Required brand cloud name.\n  --count N              Number of users to create. Default: 10.\n  --role ROLE            owner, admin, or member. Default: member.\n  --rotate-password      Rotate passwords for existing users.\n  --dry-run              Print planned users without creating accounts or writing credentials.\n  --skip-bootstrap       Do not update/restart the remote platform-admin bootstrap env.\n  -h, --help             Show this help.\n\nCreates activated Account Manager users under an existing brand cloud through\nthe platform-admin API. Passwords are written only to a local credentials JSON\nfile under the resolved environment root; stdout contains a summary only.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--brandname) BRANDNAME=\"$2\"; shift 2 ;;\n\t--count) COUNT=\"$2\"; shift 2 ;;\n\t--role) ROLE=\"$2\"; shift 2 ;;\n\t--rotate-password) ROTATE_PASSWORD=1; shift ;;\n\t--dry-run) DRY_RUN=1; shift ;;\n\t--skip-bootstrap) SKIP_BOOTSTRAP=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"required env file not found: $path\"\n\tset -a\n\t# shellcheck source=/dev/null\n\t. \"$path\"\n\tset +a\n}\n\ncurl_json_status() {\n\tlocal out=\"$1\"\n\tshift\n\tcurl -sS -o \"$out\" -w '%{http_code}' \"$@\"\n}\n\nvalidate_args() {\n\tBRANDNAME=\"$(printf '%s' \"$BRANDNAME\" | awk '{$1=$1; print}')\"\n\t[[ -n \"$BRANDNAME\" ]] || die \"--brandname is required\"\n\t[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\t[[ \"$COUNT\" =~ ^[0-9]+$ ]] || die \"--count must be a positive integer\"\n\t((COUNT > 0)) || die \"--count must be greater than zero\"\n\tcase \"$ROLE\" in\n\towner|admin|member) ;;\n\t*) die \"--role must be owner, admin, or member\" ;;\n\tesac\n\tif printf '%s' \"$BRANDNAME\" | LC_ALL=C grep -q '[[:cntrl:]]'; then\n\t\tdie \"--brandname must not contain control characters\"\n\tfi\n}\n\nbrand_slug() {\n\tprintf '%s' \"$BRANDNAME\" |\n\t\ttr '[:upper:]' '[:lower:]' |\n\t\tsed -E 's/[^a-z0-9]+/-/g; s/^-+//; s/-+$//' |\n\t\tawk '{ if ($0 == \"\") print \"brand\"; else print }'\n}\n\nremote_target() {\n\tAM_HOST=\"${ACCOUNT_MANAGER_LINODE_HOST:-${ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4:-}}\"\n\tAM_SSH_USER=\"${ACCOUNT_MANAGER_LINODE_SSH_USER:-root}\"\n\tAM_SSH_KEY=\"${ACCOUNT_MANAGER_LINODE_SSH_KEY:-$HOME/.ssh/id_ed25519_rtkcloud}\"\n\t[[ -n \"$AM_HOST\" ]] || die \"ACCOUNT_MANAGER_LINODE_HOST or ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4 is required\"\n\t[[ -n \"$AM_SSH_KEY\" ]] || die \"ACCOUNT_MANAGER_LINODE_SSH_KEY is required\"\n}\n\nensure_platform_admin_bootstrap() {\n\tif [[ \"$SKIP_BOOTSTRAP\" != \"0\" ]]; then\n\t\tlog \"skip bootstrap admin env update\"\n\t\treturn 0\n\tfi\n\tremote_target\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL is required\"\n\t[[ -n \"${ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD:-}\" ]] || die \"ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD is required\"\n\tlog \"updating platform-admin bootstrap env on account-manager host=$AM_HOST\"\n\t{\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\"\n\t\tprintf 'ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD=%s\\n' \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\"\n\t} | ssh -i \"$AM_SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new \"$AM_SSH_USER@$AM_HOST\" 'set -euo pipefail\n\t\tenv_file=/etc/rtk-account-manager/account-manager.env\n\t\ttest -f \"$env_file\"\n\t\tcp -p \"$env_file\" \"$env_file.bootstrap-admin.bak.$(date -u +%Y%m%dT%H%M%SZ)\"\n\t\ttmp=\"$(mktemp)\"\n\t\tgrep -vE \"^ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_(EMAIL|PASSWORD)=\" \"$env_file\" > \"$tmp\"\n\t\tcat >> \"$tmp\"\n\t\tinstall -m 0600 -o root -g root \"$tmp\" \"$env_file\"\n\t\trm -f \"$tmp\"\n\t\tsystemctl restart rtk-account-manager.service\n\t\tfor _ in $(seq 1 30); do\n\t\t\tif curl -fsS http://127.0.0.1:18081/v1/health >/dev/null 2>&1; then\n\t\t\t\techo \"bootstrap admin env applied and account-manager is healthy\" >&2\n\t\t\t\texit 0\n\t\t\tfi\n\t\t\tsleep 1\n\t\tdone\n\t\tjournalctl -u rtk-account-manager.service -n 80 --no-pager >&2 || true\n\t\texit 1\n\t'\n\tlog \"platform-admin bootstrap env ready\"\n}\n\nlogin_platform_admin() {\n\tlocal login_payload=\"$TMPDIR/login.json\"\n\tlocal login_out=\"$TMPDIR/login.out\"\n\tlog \"logging in platform admin: $AM_BASE_URL/v1/auth/login\"\n\tjq -cn \\\n\t\t--arg email \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\" \\\n\t\t--arg password \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\" \\\n\t\t'{email:$email,password:$password}' > \"$login_payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$login_out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t--data-binary \"@$login_payload\" \\\n\t\t\"$AM_BASE_URL/v1/auth/login\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"platform admin login failed: HTTP $status\"\n\tACCESS_TOKEN=\"$(jq -r '.tokens.access_token // empty' \"$login_out\")\"\n\t[[ -n \"$ACCESS_TOKEN\" ]] || die \"platform admin login response did not include an access token\"\n\tlog \"platform admin login ok\"\n}\n\nfind_brand_cloud() {\n\tlocal out=\"$TMPDIR/brand-clouds.out\"\n\tlocal status\n\tlog \"checking brand cloud: name=$BRANDNAME\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds?limit=200\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"brand cloud list failed: HTTP $status\"\n\tBRAND_CLOUD_JSON=\"$(jq -c --arg name \"$BRANDNAME\" '.brand_clouds[]? | select(.name == $name or .metadata.brandname == $name)' \"$out\" | head -n 1)\"\n\t[[ -n \"$BRAND_CLOUD_JSON\" ]] || die \"brand cloud not found: $BRANDNAME\"\n\tBRAND_CLOUD_ID=\"$(jq -r '.id' <<<\"$BRAND_CLOUD_JSON\")\"\n\t[[ -n \"$BRAND_CLOUD_ID\" && \"$BRAND_CLOUD_ID\" != \"null\" ]] || die \"brand cloud response did not include id\"\n\tlog \"brand cloud found: id=$BRAND_CLOUD_ID\"\n}\n\nplanned_users_json() {\n\tlocal slug=\"$1\"\n\tjq -cn --arg brand \"$BRANDNAME\" --arg slug \"$slug\" --arg role \"$ROLE\" --argjson count \"$COUNT\" '\n\t\t{\n\t\t\tbrandname: $brand,\n\t\t\trole: $role,\n\t\t\tusers: [range(1; $count + 1) as $i | {\n\t\t\t\temail: ($slug + \"+\" + ($i | tostring | if length < 3 then (\"000\"[0:(3-length)] + .) else . end) + \"@users.local\"),\n\t\t\t\tdisplay_name: ($brand + \" User \" + ($i | tostring | if length < 3 then (\"000\"[0:(3-length)] + .) else . end))\n\t\t\t}]\n\t\t}'\n}\n\nrandom_password() {\n\topenssl rand -base64 24 | tr -d '\\n'\n}\n\ncreate_user() {\n\tlocal email=\"$1\"\n\tlocal display_name=\"$2\"\n\tlocal password=\"$3\"\n\tlocal payload=\"$TMPDIR/user-payload.json\"\n\tlocal out=\"$TMPDIR/user.out\"\n\tlocal rotate_json=false\n\tif [[ \"$ROTATE_PASSWORD\" == \"1\" ]]; then\n\t\trotate_json=true\n\tfi\n\tjq -cn \\\n\t\t--arg email \"$email\" \\\n\t\t--arg password \"$password\" \\\n\t\t--arg display_name \"$display_name\" \\\n\t\t--arg role \"$ROLE\" \\\n\t\t--argjson rotate_password \"$rotate_json\" \\\n\t\t'{email:$email,password:$password,display_name:$display_name,role:$role,rotate_password:$rotate_password}' > \"$payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds/$BRAND_CLOUD_ID/users\")\"\n\tif [[ \"$status\" != \"200\" && \"$status\" != \"201\" ]]; then\n\t\tprintf 'brand user create failed: email=%s HTTP %s\\n' \"$email\" \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tjq -r '.action // \"assigned\"' \"$out\"\n}\n\nvalidate_args\nneed_cmd curl\nneed_cmd jq\nneed_cmd ssh\nneed_cmd openssl\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nlog \"workspace=$WORKSPACE\"\nlog \"env_root=$ENV_ROOT\"\n\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nAM_PLATFORM_ADMIN_ENV=\"$(cloud_env_account_manager_platform_admin_env \"$ENV_ROOT\")\"\n\nlog \"loading Account Manager env/state\"\nload_env_file \"$AM_ENV\"\nload_env_file \"$AM_STATE\"\nload_env_file \"$AM_PLATFORM_ADMIN_ENV\"\n\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-account-manager.video-cloud-staging.realtekconnect.com}\"\nAM_BASE_URL=\"https://$AM_DOMAIN\"\nTMPDIR=\"$(mktemp -d /tmp/rtk-create-users.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\n\nensure_platform_admin_bootstrap\nlogin_platform_admin\nfind_brand_cloud\n\nSLUG=\"$(brand_slug)\"\nPLAN_JSON=\"$(planned_users_json \"$SLUG\")\"\n\nif [[ \"$DRY_RUN\" == \"1\" ]]; then\n\tjq -cn --argjson brand_cloud \"$BRAND_CLOUD_JSON\" --argjson plan \"$PLAN_JSON\" \\\n\t\t'{action:\"dry_run\", brand_cloud:$brand_cloud, role:$plan.role, users:$plan.users}'\n\texit 0\nfi\n\nARTIFACT_DIR=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/users\"\nmkdir -p \"$ARTIFACT_DIR\"\nCREDENTIALS_FILE=\"$ARTIFACT_DIR/$SLUG-users-$(date -u +%Y%m%dT%H%M%SZ).json\"\nCREDENTIALS_TMP=\"$TMPDIR/credentials.json\"\nCREATED=0\nASSIGNED=0\nUSERS_JSONL=\"$TMPDIR/users.jsonl\"\n: > \"$USERS_JSONL\"\n\nfor i in $(seq 1 \"$COUNT\"); do\n\tsuffix=\"$(printf '%03d' \"$i\")\"\n\temail=\"$SLUG+$suffix@users.local\"\n\tdisplay_name=\"$BRANDNAME User $suffix\"\n\tpassword=\"$(random_password)\"\n\tlog \"ensuring brand user: email=$email role=$ROLE\"\n\taction=\"$(create_user \"$email\" \"$display_name\" \"$password\")\"\n\tcase \"$action\" in\n\tcreated) CREATED=$((CREATED + 1)) ;;\n\t*)\n\t\tif [[ \"$ROTATE_PASSWORD\" != \"1\" ]]; then\n\t\t\tdie \"brand user already exists and password was not rotated: email=$email; use the previous credentials artifact or rerun with --rotate-password\"\n\t\tfi\n\t\tASSIGNED=$((ASSIGNED + 1))\n\t\t;;\n\tesac\n\tjq -cn \\\n\t\t--arg email \"$email\" \\\n\t\t--arg display_name \"$display_name\" \\\n\t\t--arg role \"$ROLE\" \\\n\t\t--arg password \"$password\" \\\n\t\t--arg action \"$action\" \\\n\t\t'{email:$email,display_name:$display_name,role:$role,password:$password,action:$action}' >> \"$USERS_JSONL\"\ndone\n\njq -s \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg role \"$ROLE\" \\\n\t'{brandname:$brandname,brand_cloud_id:$brand_cloud_id,role:$role,users:.}' \\\n\t\"$USERS_JSONL\" > \"$CREDENTIALS_TMP\"\ninstall -m 0600 \"$CREDENTIALS_TMP\" \"$CREDENTIALS_FILE\"\nlog \"credentials written: $CREDENTIALS_FILE\"\n\njq -cn \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg role \"$ROLE\" \\\n\t--arg credentials_file \"$CREDENTIALS_FILE\" \\\n\t--argjson count \"$COUNT\" \\\n\t--argjson created \"$CREATED\" \\\n\t--argjson assigned \"$ASSIGNED\" \\\n\t'{action:\"created\", brandname:$brandname, brand_cloud_id:$brand_cloud_id, role:$role, count:$count, created:$created, assigned:$assigned, credentials_file:$credentials_file}'\n",
	"cloud-deploy.sh":                           "#!/usr/bin/env bash\nif [ -z \"${BASH_VERSION:-}\" ]; then\n\texec /usr/bin/env bash \"$0\" \"$@\"\nfi\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nOPERATOR_ENV=\"\"\nSSH_KEY=\"$HOME/.ssh/id_ed25519_rtkcloud\"\nDNS_ROOT_DOMAIN=\"realtekconnect.com\"\nDNS_ROOT_DOMAIN_EXPLICIT=0\nGODADDY_ENVIRONMENT=\"prod\"\nDNS_TTL=\"${GODADDY_RECORD_TTL:-600}\"\nARTIFACT_BASE=\"\"\nCERT_CACHE_ROOT=\"\"\nCERT_CACHE_MIN_VALID_SECONDS=\"${CLOUD_CERT_CACHE_MIN_VALID_SECONDS:-604800}\"\nVIDEO_RELEASE=\"\"\nACCOUNT_RELEASE=\"\"\nADMIN_RELEASE=\"\"\nADMIN_RELEASE_BUNDLE=\"${ADMIN_RELEASE_BUNDLE:-}\"\nACCOUNT_RELEASE_BUNDLE=\"${ACCOUNT_RELEASE_BUNDLE:-}\"\nOBJECT_STORAGE_BIN=\"\"\nVERBOSE=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tprintf '[cloud-deploy] %s\\n' \"$*\" >&2\n}\n\ndebug() {\n\tif [[ \"$VERBOSE\" == \"1\" ]]; then\n\t\tprintf '[cloud-deploy:debug] %s\\n' \"$*\" >&2\n\tfi\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-deploy.sh --video-release VERSION --account-release VERSION --admin-release VERSION [options]\n\nRequired:\n  --video-release VERSION             Explicit Video Cloud Object Storage release. \"latest\" is not allowed.\n  --account-release VERSION           Explicit Account Manager release label. \"latest\" is not allowed.\n  --admin-release VERSION             Explicit Cloud Admin release label. \"latest\" is not allowed.\n\nOptions:\n  --workspace PATH                    Default: script parent workspace.\n  --operator-env PATH                 Default: <env-root>/env/operator.env.\n  --env-root PATH                     Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH                 Deprecated alias for --env-root.\n  --ssh-key PATH                      Default: ~/.ssh/id_ed25519_rtkcloud.\n  --dns-root-domain NAME              Default: realtekconnect.com.\n  --godaddy-env ENV                   Default: prod.\n  --dns-ttl SECONDS                   Default: GODADDY_RECORD_TTL or 600.\n  --artifact-dir PATH                 Default: <env-root>/artifacts.\n  --cert-cache-root PATH              Default: <env-root>/certificates.\n  --cert-cache-min-valid-seconds N    Default: CLOUD_CERT_CACHE_MIN_VALID_SECONDS or 604800.\n  --account-release-bundle PATH       Optional local Account Manager release bundle override.\n  --admin-release-bundle PATH         Optional local Cloud Admin release bundle override.\n  --verbose                           Print extra diagnostics.\n  -h, --help                          Show this help.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--video-release) VIDEO_RELEASE=\"$2\"; shift 2 ;;\n\t--account-release) ACCOUNT_RELEASE=\"$2\"; shift 2 ;;\n\t--admin-release) ADMIN_RELEASE=\"$2\"; shift 2 ;;\n\t--account-release-bundle) ACCOUNT_RELEASE_BUNDLE=\"$2\"; shift 2 ;;\n\t--admin-release-bundle) ADMIN_RELEASE_BUNDLE=\"$2\"; shift 2 ;;\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--operator-env) OPERATOR_ENV=\"$2\"; shift 2 ;;\n\t--secrets-root) DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--ssh-key) SSH_KEY=\"$2\"; shift 2 ;;\n\t--dns-root-domain) DNS_ROOT_DOMAIN=\"$2\"; DNS_ROOT_DOMAIN_EXPLICIT=1; shift 2 ;;\n\t--godaddy-env) GODADDY_ENVIRONMENT=\"$2\"; shift 2 ;;\n\t--dns-ttl) DNS_TTL=\"$2\"; shift 2 ;;\n\t--artifact-dir) ARTIFACT_BASE=\"$2\"; shift 2 ;;\n\t--cert-cache-root) CERT_CACHE_ROOT=\"$2\"; shift 2 ;;\n\t--cert-cache-min-valid-seconds) CERT_CACHE_MIN_VALID_SECONDS=\"$2\"; shift 2 ;;\n\t--verbose) VERBOSE=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nfor value_name in VIDEO_RELEASE ACCOUNT_RELEASE ADMIN_RELEASE; do\n\tvalue=\"${!value_name}\"\n\t[[ -n \"$value\" ]] || die \"--$(tr '[:upper:]_' '[:lower:]-' <<<\"$value_name\") is required\"\n\t[[ \"$value\" != \"latest\" ]] || die \"$value_name must be explicit; latest is not allowed\"\ndone\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\n[[ \"$DNS_TTL\" =~ ^[0-9]+$ && \"$DNS_TTL\" -gt 0 ]] || die \"--dns-ttl must be a positive integer\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nif [[ \"$DNS_ROOT_DOMAIN_EXPLICIT\" == \"1\" ]]; then\n\tcloud_env_load_environment \"$ENV_ROOT\" \"$DNS_ROOT_DOMAIN\"\nelse\n\tcloud_env_load_environment \"$ENV_ROOT\" \"\"\nfi\nDNS_ROOT_DOMAIN=\"$CLOUD_DNS_ROOT_DOMAIN\"\ncloud_env_validate_environment \"$ENV_ROOT\"\ncloud_env_export_filter_vars\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\nOPERATOR_ENV=\"${OPERATOR_ENV:-$(cloud_env_operator_env \"$ENV_ROOT\")}\"\nARTIFACT_BASE=\"${ARTIFACT_BASE:-$(cloud_env_artifacts_dir \"$ENV_ROOT\")}\"\nCERT_CACHE_ROOT=\"${CERT_CACHE_ROOT:-$(cloud_env_certificates_dir \"$ENV_ROOT\")}\"\nCERT_CACHE_ROOT=\"$(cloud_env_abs_path \"$CERT_CACHE_ROOT\")\"\n[[ \"$CERT_CACHE_MIN_VALID_SECONDS\" =~ ^[0-9]+$ ]] || die \"--cert-cache-min-valid-seconds must be a non-negative integer\"\n\nVC_REPO=\"$WORKSPACE/repos/rtk_video_cloud\"\nAM_REPO=\"$WORKSPACE/repos/rtk_account_manager\"\nADMIN_REPO=\"$WORKSPACE/repos/rtk_cloud_admin\"\n\nVC_CONFIG=\"$(cloud_env_video_config \"$ENV_ROOT\")\"\nVC_STATE=\"$(cloud_env_video_state \"$ENV_ROOT\")\"\nVC_SECRET_STATE=\"$VC_STATE\"\nVC_SECRETS_FILE=\"$(cloud_env_video_env \"$ENV_ROOT\")\"\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nADMIN_ENV=\"$(cloud_env_admin_env \"$ENV_ROOT\")\"\nADMIN_STATE=\"$(cloud_env_admin_state \"$ENV_ROOT\")\"\n\nVC_GATEWAY_DOMAIN=\"$VIDEO_CLOUD_DOMAIN\"\nVC_CERTISSUER_DOMAIN=\"$VIDEO_CLOUD_CERTISSUER_DOMAIN\"\nAM_DOMAIN=\"$ACCOUNT_MANAGER_DOMAIN\"\nADMIN_DOMAIN=\"$CLOUD_ADMIN_DOMAIN\"\nVC_CERT_CACHE_DIR=\"$CERT_CACHE_ROOT/$VC_GATEWAY_DOMAIN\"\nAM_CERT_CACHE_DIR=\"$CERT_CACHE_ROOT/$AM_DOMAIN\"\nADMIN_CERT_CACHE_DIR=\"$CERT_CACHE_ROOT/$ADMIN_DOMAIN\"\n\nREADY_DIR=\"$ARTIFACT_BASE/readiness-$(date -u +%Y%m%dT%H%M%SZ)\"\nREPORT=\"$READY_DIR/readiness-report.md\"\nSTATUS_FILE=\"$READY_DIR/status.tsv\"\nDEPLOY_STEPS=(\n\taccount-manager-deploy\n\taccount-manager-verify\n\tvideo-cloud-deploy-verify\n\tcloud-admin-deploy\n\tcloud-admin-verify\n)\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\ncert_cache_valid() {\n\tlocal domain=\"$1\"\n\tlocal dir=\"$2\"\n\t[[ -s \"$dir/fullchain.pem\" && -s \"$dir/privkey.pem\" ]] || return 1\n\tif ! openssl x509 -in \"$dir/fullchain.pem\" -noout -checkend \"$CERT_CACHE_MIN_VALID_SECONDS\" >/dev/null 2>&1; then\n\t\treturn 1\n\tfi\n\tif ! openssl x509 -in \"$dir/fullchain.pem\" -noout -subject -issuer -enddate >/dev/null 2>&1; then\n\t\treturn 1\n\tfi\n\tdebug \"certificate cache valid: domain=$domain dir=$dir\"\n\treturn 0\n}\n\ncert_cache_env_value() {\n\tlocal domain=\"$1\"\n\tlocal dir=\"$2\"\n\tif cert_cache_valid \"$domain\" \"$dir\"; then\n\t\tprintf '%s\\n' \"$dir\"\n\telse\n\t\tprintf '\\n'\n\tfi\n}\n\ncache_remote_certificate() {\n\tlocal label=\"$1\"\n\tlocal host=\"$2\"\n\tlocal domain=\"$3\"\n\tlocal dir=\"$4\"\n\t[[ -n \"$host\" ]] || return 0\n\tmkdir -p \"$dir\"\n\tlocal tmp\n\ttmp=\"$(mktemp -d)\"\n\tlocal remote=\"$host\"\n\tif [[ \"$remote\" != *@* ]]; then\n\t\tremote=\"root@$remote\"\n\tfi\n\tlocal ssh_opts=(-i \"$SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new)\n\tif ! ssh \"${ssh_opts[@]}\" \"$remote\" \"test -s /etc/letsencrypt/live/$domain/fullchain.pem -a -s /etc/letsencrypt/live/$domain/privkey.pem\"; then\n\t\tdebug \"certificate not present on remote: label=$label domain=$domain host=$host\"\n\t\trm -rf \"$tmp\"\n\t\treturn 0\n\tfi\n\tlog \"caching certificate: $label domain=$domain\"\n\tif ! ssh \"${ssh_opts[@]}\" \"$remote\" \"cat /etc/letsencrypt/live/$domain/fullchain.pem\" > \"$tmp/fullchain.pem\"; then\n\t\trm -rf \"$tmp\"\n\t\treturn 1\n\tfi\n\tif ! ssh \"${ssh_opts[@]}\" \"$remote\" \"cat /etc/letsencrypt/live/$domain/privkey.pem\" > \"$tmp/privkey.pem\"; then\n\t\trm -rf \"$tmp\"\n\t\treturn 1\n\tfi\n\tfor name in cert.pem chain.pem; do\n\t\tssh \"${ssh_opts[@]}\" \"$remote\" \"cat /etc/letsencrypt/live/$domain/$name\" > \"$tmp/$name\" 2>/dev/null || true\n\tdone\n\tif ! cert_cache_valid \"$domain\" \"$tmp\"; then\n\t\tlog \"warning: remote certificate was not cached because it is invalid or expires too soon: $domain\"\n\t\trm -rf \"$tmp\"\n\t\treturn 0\n\tfi\n\tinstall -m 0644 \"$tmp/fullchain.pem\" \"$dir/fullchain.pem\"\n\tinstall -m 0600 \"$tmp/privkey.pem\" \"$dir/privkey.pem\"\n\tfor name in cert.pem chain.pem; do\n\t\tif [[ -s \"$tmp/$name\" ]]; then\n\t\t\tinstall -m 0644 \"$tmp/$name\" \"$dir/$name\"\n\t\tfi\n\tdone\n\topenssl x509 -in \"$dir/fullchain.pem\" -noout -enddate > \"$dir/metadata.txt\"\n\tprintf 'domain=%s\\ncached_at=%s\\nsource_host=%s\\n' \"$domain\" \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \"$host\" >> \"$dir/metadata.txt\"\n\trm -rf \"$tmp\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\tif [[ -f \"$path\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$path\"\n\t\tset +a\n\tfi\n}\n\nload_operator_env() {\n\t[[ -f \"$OPERATOR_ENV\" ]] || die \"operator env not found: $OPERATOR_ENV\"\n\tload_env_file \"$OPERATOR_ENV\"\n\t[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n}\n\nlinode_api() {\n\tlocal method=\"$1\"\n\tlocal path=\"$2\"\n\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t-H 'Content-Type: application/json'\n}\n\nobject_storage_go() {\n\tif [[ -z \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\tOBJECT_STORAGE_BIN=\"${TMPDIR:-/tmp}/rtk-linode-object-storage\"\n\t\tif [[ ! -x \"$OBJECT_STORAGE_BIN\" || \"$SCRIPT_DIR/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\t\t(\n\t\t\t\tlock=\"$OBJECT_STORAGE_BIN.lock\"\n\t\t\t\twhile ! mkdir \"$lock\" 2>/dev/null; do\n\t\t\t\t\tsleep 0.2\n\t\t\t\tdone\n\t\t\t\ttrap 'rmdir \"$lock\" 2>/dev/null || true' EXIT\n\t\t\t\tif [[ -x \"$OBJECT_STORAGE_BIN\" && ! \"$SCRIPT_DIR/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\t\t\t\texit 0\n\t\t\t\tfi\n\t\t\t\tcd \"$SCRIPT_DIR/go/linode-object-storage\"\n\t\t\t\tgo build -o \"$OBJECT_STORAGE_BIN.$$\" .\n\t\t\t\tmv \"$OBJECT_STORAGE_BIN.$$\" \"$OBJECT_STORAGE_BIN\"\n\t\t\t)\n\t\tfi\n\tfi\n\t\"$OBJECT_STORAGE_BIN\" \"$@\"\n}\n\ndownload_admin_release_bundle() {\n\tif [[ -n \"$ADMIN_RELEASE_BUNDLE\" ]]; then\n\t\t[[ -s \"$ADMIN_RELEASE_BUNDLE\" ]] || die \"Cloud Admin release bundle not found: $ADMIN_RELEASE_BUNDLE\"\n\t\treturn\n\tfi\n\t[[ -n \"${LINODE_OBJ_BUCKET:-}\" ]] || die \"LINODE_OBJ_BUCKET is required\"\n\t[[ -n \"${LINODE_OBJ_ENDPOINT:-}\" ]] || die \"LINODE_OBJ_ENDPOINT is required\"\n\tneed_cmd go\n\tlocal manifest_key manifest version object_key expected_sha bundle_dir checksum\n\tmanifest_key=\"releases/rtk_cloud_admin-$ADMIN_RELEASE/manifest.json\"\n\tmanifest=\"$(object_storage_go cat --key \"$manifest_key\")\"\n\tversion=\"$(jq -r '.version // empty' <<<\"$manifest\")\"\n\tobject_key=\"$(jq -r '.artifact_path // empty' <<<\"$manifest\")\"\n\texpected_sha=\"$(jq -r '.sha256 // empty' <<<\"$manifest\")\"\n\t[[ \"$version\" == \"$ADMIN_RELEASE\" ]] || die \"Cloud Admin manifest version mismatch: requested=$ADMIN_RELEASE manifest=${version:-<empty>}\"\n\t[[ -n \"$object_key\" ]] || die \"Cloud Admin manifest missing artifact_path: $manifest_key\"\n\t[[ -n \"$expected_sha\" ]] || die \"Cloud Admin manifest missing sha256: $manifest_key\"\n\tbundle_dir=\"$READY_DIR/releases/rtk_cloud_admin-$ADMIN_RELEASE\"\n\tmkdir -p \"$bundle_dir\"\n\tADMIN_RELEASE_BUNDLE=\"$bundle_dir/rtk_cloud_admin-$ADMIN_RELEASE.tar.gz\"\n\tlog \"downloading Cloud Admin release artifact: $object_key\"\n\tobject_storage_go download --key \"$object_key\" --out \"$ADMIN_RELEASE_BUNDLE\"\n\tif command -v shasum >/dev/null 2>&1; then\n\t\tchecksum=\"$(shasum -a 256 \"$ADMIN_RELEASE_BUNDLE\" | awk '{print $1}')\"\n\telse\n\t\tchecksum=\"$(sha256sum \"$ADMIN_RELEASE_BUNDLE\" | awk '{print $1}')\"\n\tfi\n\t[[ \"$checksum\" == \"$expected_sha\" ]] || die \"Cloud Admin artifact checksum mismatch: expected=$expected_sha got=$checksum\"\n\tlog \"Cloud Admin release artifact ready: $ADMIN_RELEASE_BUNDLE\"\n}\n\ndownload_account_release_bundle() {\n\tif [[ -n \"$ACCOUNT_RELEASE_BUNDLE\" ]]; then\n\t\t[[ -s \"$ACCOUNT_RELEASE_BUNDLE\" ]] || die \"Account Manager release bundle not found: $ACCOUNT_RELEASE_BUNDLE\"\n\t\treturn\n\tfi\n\t[[ -n \"${LINODE_OBJ_BUCKET:-}\" ]] || die \"LINODE_OBJ_BUCKET is required\"\n\t[[ -n \"${LINODE_OBJ_ENDPOINT:-}\" ]] || die \"LINODE_OBJ_ENDPOINT is required\"\n\tneed_cmd go\n\tlocal manifest_key manifest version object_key expected_sha bundle_dir checksum\n\tmanifest_key=\"releases/rtk_account_manager-$ACCOUNT_RELEASE/manifest.json\"\n\tmanifest=\"$(object_storage_go cat --key \"$manifest_key\")\"\n\tversion=\"$(jq -r '.version // empty' <<<\"$manifest\")\"\n\tobject_key=\"$(jq -r '.artifact_path // empty' <<<\"$manifest\")\"\n\texpected_sha=\"$(jq -r '.sha256 // empty' <<<\"$manifest\")\"\n\t[[ \"$version\" == \"$ACCOUNT_RELEASE\" ]] || die \"Account Manager manifest version mismatch: requested=$ACCOUNT_RELEASE manifest=${version:-<empty>}\"\n\t[[ -n \"$object_key\" ]] || die \"Account Manager manifest missing artifact_path: $manifest_key\"\n\t[[ -n \"$expected_sha\" ]] || die \"Account Manager manifest missing sha256: $manifest_key\"\n\tbundle_dir=\"$READY_DIR/releases/rtk_account_manager-$ACCOUNT_RELEASE\"\n\tmkdir -p \"$bundle_dir\"\n\tACCOUNT_RELEASE_BUNDLE=\"$bundle_dir/rtk_account_manager-$ACCOUNT_RELEASE.tar.gz\"\n\tlog \"downloading Account Manager release artifact: $object_key\"\n\tobject_storage_go download --key \"$object_key\" --out \"$ACCOUNT_RELEASE_BUNDLE\"\n\tif command -v shasum >/dev/null 2>&1; then\n\t\tchecksum=\"$(shasum -a 256 \"$ACCOUNT_RELEASE_BUNDLE\" | awk '{print $1}')\"\n\telse\n\t\tchecksum=\"$(sha256sum \"$ACCOUNT_RELEASE_BUNDLE\" | awk '{print $1}')\"\n\tfi\n\t[[ \"$checksum\" == \"$expected_sha\" ]] || die \"Account Manager artifact checksum mismatch: expected=$expected_sha got=$checksum\"\n\tlog \"Account Manager release artifact ready: $ACCOUNT_RELEASE_BUNDLE\"\n}\n\nresolve_dns() {\n\tlocal server=\"$1\"\n\tlocal domain=\"$2\"\n\tdig +short \"@$server\" \"$domain\" | tail -n 1 || true\n}\n\nauthoritative_ns() {\n\tdig NS \"$DNS_ROOT_DOMAIN\" +short | head -n 1\n}\n\nrequire_files() {\n\t[[ -d \"$VC_REPO\" ]] || die \"missing submodule: $VC_REPO\"\n\t[[ -d \"$AM_REPO\" ]] || die \"missing submodule: $AM_REPO\"\n\t[[ -d \"$ADMIN_REPO\" ]] || die \"missing submodule: $ADMIN_REPO\"\n\t[[ -f \"$VC_CONFIG\" ]] || die \"missing Video Cloud config: $VC_CONFIG\"\n\t[[ -f \"$VC_SECRETS_FILE\" ]] || die \"missing Video Cloud secrets: $VC_SECRETS_FILE\"\n\t[[ -f \"$VC_STATE\" || -f \"$VC_SECRET_STATE\" ]] || die \"missing Video Cloud state\"\n\t[[ -f \"$AM_ENV\" ]] || die \"missing Account Manager env: $AM_ENV\"\n\t[[ -f \"$AM_STATE\" ]] || die \"missing Account Manager state: $AM_STATE\"\n\t[[ -f \"$ADMIN_ENV\" ]] || die \"missing Cloud Admin env: $ADMIN_ENV\"\n\t[[ -f \"$ADMIN_STATE\" ]] || die \"missing Cloud Admin state: $ADMIN_STATE\"\n\t[[ -f \"$SSH_KEY\" ]] || die \"missing SSH key: $SSH_KEY\"\n}\n\ntarget_instance_filter='\n\t.data[]\n\t| select(\n\t\t.label == env.ADMIN_LINODE_LABEL\n\t\tor .label == env.ACCOUNT_MANAGER_LINODE_LABEL\n\t\tor ((.label | startswith(env.VIDEO_CLOUD_LABEL_PREFIX + \"-\")) and ((.tags // []) | index(env.CLOUD_STACK_NAME)))\n\t)\n'\n\nensure_live_targets() {\n\tlocal instances count\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tcount=\"$(jq -r \"[$target_instance_filter] | length\" <<<\"$instances\")\"\n\t[[ \"$count\" == \"7\" ]] || die \"expected 7 target VMs, found $count\"\n\thydrate_video_state_from_live \"$instances\"\n}\n\nhydrate_video_state_from_live() {\n\tlocal instances=\"$1\"\n\tlocal current\n\tcurrent=\"{}\"\n\tif [[ -f \"$VC_STATE\" ]]; then\n\t\tcurrent=\"$(cat \"$VC_STATE\")\"\n\tfi\n\tmkdir -p \"$(dirname \"$VC_STATE\")\"\n\tjq -n \\\n\t\t--arg stack \"$CLOUD_STACK_NAME\" \\\n\t\t--arg region \"$CLOUD_REGION\" \\\n\t\t--arg label_prefix \"$VIDEO_CLOUD_LABEL_PREFIX\" \\\n\t\t--argjson current \"$current\" \\\n\t\t--argjson instances \"$instances\" '\n\t\tdef role_instance($role; $private):\n\t\t\t($instances.data[] | select(.label == ($label_prefix + \"-\" + $role))) as $i\n\t\t\t| {\n\t\t\t\tid: $i.id,\n\t\t\t\trole: $role,\n\t\t\t\tlabel: $i.label,\n\t\t\t\tpublic_ipv4: (($i.ipv4 // []) | .[0] // \"\"),\n\t\t\t\tpublic_ipv6: ($i.ipv6 // \"\"),\n\t\t\t\tprivate_ip: $private,\n\t\t\t\ttags: ($i.tags // [])\n\t\t\t};\n\t\t($current // {})\n\t\t| .stack = $stack\n\t\t| .region = $region\n\t\t| .instances = {\n\t\t\tedge: role_instance(\"edge\"; \"10.42.1.5\"),\n\t\t\tapi: role_instance(\"api\"; \"10.42.1.10\"),\n\t\t\tinfra: role_instance(\"infra\"; \"10.42.1.30\"),\n\t\t\tmqtt: role_instance(\"mqtt\"; \"10.42.1.40\"),\n\t\t\tcoturn: role_instance(\"coturn\"; \"\")\n\t\t}\n\t\t| .tags = [$stack, \"managed-by:linode-deploy\"]\n\t' > \"$VC_STATE\"\n}\n\nload_states() {\n\tif [[ ! -f \"$VC_STATE\" && -f \"$VC_SECRET_STATE\" ]]; then\n\t\tVC_STATE=\"$VC_SECRET_STATE\"\n\tfi\n\tload_env_file \"$AM_STATE\"\n\tload_env_file \"$ADMIN_STATE\"\n}\n\nensure_dns_converged() {\n\tlocal edge_ip ns failures=0\n\tedge_ip=\"$(jq -r '.instances.edge.public_ipv4' \"$VC_STATE\")\"\n\tns=\"$(authoritative_ns)\"\n\t[[ -n \"$ns\" ]] || die \"could not resolve authoritative NS for $DNS_ROOT_DOMAIN\"\n\tfor item in \\\n\t\t\"$VC_GATEWAY_DOMAIN $edge_ip\" \\\n\t\t\"$VC_CERTISSUER_DOMAIN $edge_ip\" \\\n\t\t\"$AM_DOMAIN $ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \\\n\t\t\"$ADMIN_DOMAIN $ADMIN_LINODE_PUBLIC_IPV4\"; do\n\t\tlocal domain=\"${item% *}\"\n\t\tlocal ip=\"${item#* }\"\n\t\tlocal google auth\n\t\tgoogle=\"$(resolve_dns 8.8.8.8 \"$domain\")\"\n\t\tauth=\"$(resolve_dns \"$ns\" \"$domain\")\"\n\t\tdebug \"dns $domain expected=$ip google=${google:-<empty>} auth=${auth:-<empty>}\"\n\t\tif [[ \"$google\" != \"$ip\" || \"$auth\" != \"$ip\" ]]; then\n\t\t\tprintf 'DNS mismatch: %s expected=%s google=%s auth=%s\\n' \"$domain\" \"$ip\" \"${google:-<empty>}\" \"${auth:-<empty>}\" >&2\n\t\t\tfailures=$((failures + 1))\n\t\tfi\n\tdone\n\t[[ \"$failures\" == \"0\" ]] || die \"DNS is not converged\"\n}\n\ninit_report() {\n\tmkdir -p \"$READY_DIR\"\n\t: > \"$STATUS_FILE\"\n\tcat > \"$REPORT\" <<EOF_REPORT\n# Workspace Staging Readiness Report\n\n- generated_at: $(date -u +%Y-%m-%dT%H:%M:%SZ)\n- video_release: $VIDEO_RELEASE\n- account_release: $ACCOUNT_RELEASE\n- admin_release: $ADMIN_RELEASE\n- status: running\n\n## Steps\n\nEOF_REPORT\n}\n\nappend_report_line() {\n\tprintf '%s\\n' \"$*\" >> \"$REPORT\"\n}\n\nrun_step() {\n\tlocal name=\"$1\"\n\tshift\n\tlocal log_file=\"$READY_DIR/${name//[^A-Za-z0-9_.-]/_}.log\"\n\tlog \"step start: $name\"\n\tif \"$@\" > >(tee \"$log_file\") 2>&1; then\n\t\tprintf '%s\\tPASS\\t%s\\n' \"$name\" \"$log_file\" >> \"$STATUS_FILE\"\n\t\tappend_report_line \"- PASS \\`$name\\` log: \\`$log_file\\`\"\n\t\tlog \"step pass: $name\"\n\telse\n\t\tlocal code=$?\n\t\tprintf '%s\\tFAIL\\t%s\\n' \"$name\" \"$log_file\" >> \"$STATUS_FILE\"\n\t\tappend_report_line \"- FAIL \\`$name\\` exit=$code log: \\`$log_file\\`\"\n\t\tmark_skipped_after_failure \"$name\"\n\t\tfinalize_report \"failed\"\n\t\tlog \"readiness report: $REPORT\"\n\t\tdie \"step failed: $name; see $log_file\"\n\tfi\n}\n\nmark_skipped_after_failure() {\n\tlocal failed=\"$1\"\n\tlocal step seen_failed=0\n\tfor step in \"${DEPLOY_STEPS[@]}\"; do\n\t\tif [[ \"$seen_failed\" == \"1\" ]]; then\n\t\t\tprintf '%s\\tSKIP\\tblocked_by=%s\\n' \"$step\" \"$failed\" >> \"$STATUS_FILE\"\n\t\t\tappend_report_line \"- SKIP \\`$step\\` blocked_by=\\`$failed\\`\"\n\t\t\tlog \"step skip: $step blocked_by=$failed\"\n\t\tfi\n\t\tif [[ \"$step\" == \"$failed\" ]]; then\n\t\t\tseen_failed=1\n\t\tfi\n\tdone\n}\n\nfinalize_report() {\n\tlocal status=\"$1\"\n\tlocal tmp\n\ttmp=\"$(mktemp)\"\n\tawk -v status=\"$status\" '{gsub(/status: running/, \"status: \" status)} {print}' \"$REPORT\" > \"$tmp\"\n\tmv \"$tmp\" \"$REPORT\"\n\t{\n\t\tprintf '\\n## DNS\\n\\n'\n\t\tlocal edge_ip ns\n\t\tedge_ip=\"$(jq -r '.instances.edge.public_ipv4' \"$VC_STATE\")\"\n\t\tns=\"$(authoritative_ns)\"\n\t\tprintf '| Domain | Expected | 8.8.8.8 | %s |\\n| --- | --- | --- | --- |\\n' \"$ns\"\n\t\tfor item in \\\n\t\t\t\"$VC_GATEWAY_DOMAIN $edge_ip\" \\\n\t\t\t\"$VC_CERTISSUER_DOMAIN $edge_ip\" \\\n\t\t\t\"$AM_DOMAIN $ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \\\n\t\t\t\"$ADMIN_DOMAIN $ADMIN_LINODE_PUBLIC_IPV4\"; do\n\t\t\tlocal domain=\"${item% *}\"\n\t\t\tlocal ip=\"${item#* }\"\n\t\t\tprintf '| `%s` | `%s` | `%s` | `%s` |\\n' \"$domain\" \"$ip\" \"$(resolve_dns 8.8.8.8 \"$domain\")\" \"$(resolve_dns \"$ns\" \"$domain\")\"\n\t\tdone\n\t\tprintf '\\n## Service Artifact Paths\\n\\n'\n\t\tprintf -- '- account_manager_verify: `%s/.artifacts/linode-account-manager-verify`\\n' \"$AM_REPO\"\n\t\tprintf -- '- video_cloud_verify_report: `%s`\\n' \"$READY_DIR/video-cloud-runtime-health.md\"\n\t\tprintf -- '- cloud_admin_verify: `%s/.artifacts/linode-admin-verify`\\n' \"$ADMIN_REPO\"\n\t} >> \"$REPORT\"\n}\n\naccount_manager_deploy() {\n\tdownload_account_release_bundle\n\t(\n\t\tcd \"$AM_REPO\"\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$OPERATOR_ENV\"\n\t\t# shellcheck source=/dev/null\n\t\t. \"$AM_ENV\"\n\t\t# shellcheck source=/dev/null\n\t\t. \"$AM_STATE\"\n\t\tset +a\n\t\tlocal cert_cache_dir\n\t\tcert_cache_dir=\"$(cert_cache_env_value \"$AM_DOMAIN\" \"$AM_CERT_CACHE_DIR\")\"\n\t\tif [[ -n \"$cert_cache_dir\" ]]; then\n\t\t\tlog \"using cached certificate for Account Manager: $AM_DOMAIN\"\n\t\tfi\n\t\tset +e\n\t\tACCOUNT_MANAGER_LINODE_RELEASE=\"$ACCOUNT_RELEASE\" \\\n\t\t\tACCOUNT_MANAGER_LINODE_RELEASE_BUNDLE=\"$ACCOUNT_RELEASE_BUNDLE\" \\\n\t\t\tACCOUNT_MANAGER_LINODE_CERT_CACHE_DIR=\"$cert_cache_dir\" \\\n\t\t\tlinode_deploy/scripts/deploy-public-vm.sh\n\t\tlocal status=$?\n\t\tset -e\n\t\tcache_remote_certificate \"account-manager\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"$AM_DOMAIN\" \"$AM_CERT_CACHE_DIR\"\n\t\treturn \"$status\"\n\t)\n}\n\naccount_manager_verify() {\n\t(\n\t\tcd \"$AM_REPO\"\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$AM_ENV\"\n\t\t# shellcheck source=/dev/null\n\t\t. \"$AM_STATE\"\n\t\tset +a\n\t\tlinode_deploy/scripts/verify-public-vm.sh\n\t)\n}\n\nvideo_cloud_deploy_and_verify() {\n\t(\n\t\tcd \"$VC_REPO\"\n\t\tlocal cert_cache_dir edge_ip\n\t\tcert_cache_dir=\"$(cert_cache_env_value \"$VC_GATEWAY_DOMAIN\" \"$VC_CERT_CACHE_DIR\")\"\n\t\tedge_ip=\"$(jq -r '.instances.edge.public_ipv4' \"$VC_STATE\")\"\n\t\tif [[ -n \"$cert_cache_dir\" ]]; then\n\t\t\tlog \"using cached certificate for Video Cloud gateway: $VC_GATEWAY_DOMAIN\"\n\t\tfi\n\t\tset +e\n\t\tDEPLOY_SECRETS_DIR=\"$ENV_ROOT\" \\\n\t\t\tLINODE_DEPLOY_CERT_CACHE_DIR=\"$cert_cache_dir\" \\\n\t\t\tlinode_deploy/scripts/deploy-staging.sh \\\n\t\t\t\t--stack \"$CLOUD_STACK_NAME\" \\\n\t\t\t\t--config \"$VC_CONFIG\" \\\n\t\t\t\t--secrets-file \"$VC_SECRETS_FILE\" \\\n\t\t\t\t--env-file \"$OPERATOR_ENV\" \\\n\t\t\t\t--release \"$VIDEO_RELEASE\" \\\n\t\t\t\t--gateway-domain \"$VC_GATEWAY_DOMAIN\" \\\n\t\t\t\t--dns-domain \"$DNS_ROOT_DOMAIN\" \\\n\t\t\t\t--dns-name \"${VC_GATEWAY_DOMAIN%.$DNS_ROOT_DOMAIN}\" \\\n\t\t\t\t--report \"$READY_DIR/video-cloud-runtime-health.md\"\n\t\tlocal status=$?\n\t\tset -e\n\t\tcache_remote_certificate \"video-cloud\" \"$edge_ip\" \"$VC_GATEWAY_DOMAIN\" \"$VC_CERT_CACHE_DIR\"\n\t\treturn \"$status\"\n\t)\n}\n\ncloud_admin_deploy() {\n\tdownload_admin_release_bundle\n\t(\n\t\tcd \"$ADMIN_REPO\"\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$ADMIN_ENV\"\n\t\t# shellcheck source=/dev/null\n\t\t. \"$ADMIN_STATE\"\n\t\tset +a\n\t\tlocal cert_cache_dir\n\t\tcert_cache_dir=\"$(cert_cache_env_value \"$ADMIN_DOMAIN\" \"$ADMIN_CERT_CACHE_DIR\")\"\n\t\tif [[ -n \"$cert_cache_dir\" ]]; then\n\t\t\tlog \"using cached certificate for Cloud Admin: $ADMIN_DOMAIN\"\n\t\tfi\n\t\tset +e\n\t\tADMIN_LINODE_RELEASE=\"$ADMIN_RELEASE\" \\\n\t\t\tADMIN_LINODE_RELEASE_BUNDLE=\"$ADMIN_RELEASE_BUNDLE\" \\\n\t\t\tADMIN_LINODE_CERT_CACHE_DIR=\"$cert_cache_dir\" \\\n\t\t\tACCOUNT_MANAGER_BASE_URL=\"https://$AM_DOMAIN\" \\\n\t\t\tVIDEO_CLOUD_BASE_URL=\"https://$VC_GATEWAY_DOMAIN\" \\\n\t\t\tdeploy/linode/deploy-admin.sh\n\t\tlocal status=$?\n\t\tset -e\n\t\tcache_remote_certificate \"cloud-admin\" \"$ADMIN_LINODE_PUBLIC_IPV4\" \"$ADMIN_DOMAIN\" \"$ADMIN_CERT_CACHE_DIR\"\n\t\treturn \"$status\"\n\t)\n}\n\ncloud_admin_verify() {\n\t(\n\t\tcd \"$ADMIN_REPO\"\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$ADMIN_ENV\"\n\t\t# shellcheck source=/dev/null\n\t\t. \"$ADMIN_STATE\"\n\t\tset +a\n\t\tADMIN_LINODE_BASE_URL=\"https://$ADMIN_DOMAIN\" \\\n\t\t\tdeploy/linode/verify-admin.sh\n\t)\n}\n\nfor cmd in curl jq dig ssh go tar openssl; do\n\tneed_cmd \"$cmd\"\ndone\nrequire_files\nload_operator_env\nload_states\nmkdir -p \"$READY_DIR\"\nensure_live_targets\nensure_dns_converged\ninit_report\n\nrun_step account-manager-deploy account_manager_deploy\nrun_step account-manager-verify account_manager_verify\nrun_step video-cloud-deploy-verify video_cloud_deploy_and_verify\nrun_step cloud-admin-deploy cloud_admin_deploy\nrun_step cloud-admin-verify cloud_admin_verify\nfinalize_report \"passed\"\nlog \"readiness report: $REPORT\"\n",
	"cloud-generate-load-devices.sh":            "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nSTART_EPOCH=\"$(date +%s)\"\nENV_ROOT=\"\"\nCOUNT=100\nMIX=\"camera=40,light=25,air_conditioner=20,smart_meter=15\"\nPREFIX=\"load-device\"\nOUT_DIR=\"\"\nFORCE=0\nGENERATE_ONLY=0\nCA_VALID_DAYS=365\nDEVICE_VALID_DAYS=180\nFACTORY_ENROLL_URL=\"${FACTORY_ENROLL_URL:-}\"\nFACTORY_ENROLL_AUTH_KEY=\"${FACTORY_ENROLL_AUTH_KEY:-}\"\nFACTORY_ID=\"${FACTORY_ENROLL_FACTORY_ID:-staging-loadtest}\"\nLINE_ID=\"${FACTORY_ENROLL_LINE_ID:-loadtest-line}\"\nSTATION_ID=\"${FACTORY_ENROLL_STATION_ID:-loadtest-station}\"\nFIXTURE_ID=\"${FACTORY_ENROLL_FIXTURE_ID:-loadtest-fixture}\"\nOPERATOR_ID=\"${FACTORY_ENROLL_OPERATOR_ID:-loadtest-operator}\"\nBATCH_ID=\"${FACTORY_ENROLL_BATCH_ID:-}\"\nSERIAL_PREFIX=\"${FACTORY_ENROLL_SERIAL_PREFIX:-LOAD}\"\nRUN_ID=\"${FACTORY_ENROLL_RUN_ID:-}\"\nENROLL_TIMEOUT=\"${FACTORY_ENROLL_TIMEOUT:-30}\"\nENROLL_SUCCEEDED=0\nENROLL_FAILURES=0\n\nDEVICE_TYPES=(camera light air_conditioner smart_meter)\nWEIGHT_camera=0\nWEIGHT_light=0\nWEIGHT_air_conditioner=0\nWEIGHT_smart_meter=0\nALLOC_camera=0\nALLOC_light=0\nALLOC_air_conditioner=0\nALLOC_smart_meter=0\nREM_camera=0\nREM_light=0\nREM_air_conditioner=0\nREM_smart_meter=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-load-devices %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-generate-load-devices.sh [options]\n\nOptions:\n  --count N              Number of devices to generate. Default: 100.\n  --mix SPEC             Device type weights. Default: camera=40,light=25,air_conditioner=20,smart_meter=15.\n  --prefix PREFIX        Device id prefix. Default: load-device.\n  --out-dir PATH         Output directory. Default: <env-root>/devices/test_device.\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --factory-url URL      Override factory enrollment base URL. Default: env-root metadata.\n  --factory-auth-key KEY Override factory enrollment HMAC key. Default: env-root service env.\n  --factory-id ID        Factory id sent to enrollment. Default: staging-loadtest.\n  --line-id ID           Line id sent to enrollment. Default: loadtest-line.\n  --station-id ID        Station id sent to enrollment. Default: loadtest-station.\n  --fixture-id ID        Fixture id sent to enrollment. Default: loadtest-fixture.\n  --operator-id ID       Operator id sent to enrollment. Default: loadtest-operator.\n  --batch-id ID          Batch id sent to enrollment. Default: generated run id.\n  --serial-prefix PREFIX Serial number prefix. Default: LOAD.\n  --run-id ID            Run id for request ids and serial numbers. Default: UTC timestamp.\n  --enroll-timeout SEC   Curl timeout per device enrollment. Default: 30.\n  --generate-only        Offline mode: generate locally signed simulation credentials only.\n  --ca-valid-days N      Dev CA certificate validity. Default: 365.\n  --device-valid-days N  Device certificate validity. Default: 180.\n  --force                Remove existing output directory before generation.\n  -h, --help             Show this help.\n\nSupported device types match the currently implemented load-test simulator:\ncamera, light, air_conditioner, smart_meter.\n\nBy default this script generates a keypair/CSR for each simulated device and\nthen runs the real factory enrollment API. Use --generate-only only for offline\ntests that need locally signed simulation credentials.\nUSAGE\n}\n\nrequire_value() {\n\tlocal opt=\"$1\"\n\tlocal value=\"${2:-}\"\n\t[[ -n \"$value\" ]] || die \"$opt requires a value\"\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--count) require_value \"$1\" \"${2:-}\"; COUNT=\"$2\"; shift 2 ;;\n\t--mix) require_value \"$1\" \"${2:-}\"; MIX=\"$2\"; shift 2 ;;\n\t--prefix) require_value \"$1\" \"${2:-}\"; PREFIX=\"$2\"; shift 2 ;;\n\t--out-dir) require_value \"$1\" \"${2:-}\"; OUT_DIR=\"$2\"; shift 2 ;;\n\t--workspace) require_value \"$1\" \"${2:-}\"; WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) require_value \"$1\" \"${2:-}\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--factory-url) require_value \"$1\" \"${2:-}\"; FACTORY_ENROLL_URL=\"$2\"; shift 2 ;;\n\t--factory-auth-key) require_value \"$1\" \"${2:-}\"; FACTORY_ENROLL_AUTH_KEY=\"$2\"; shift 2 ;;\n\t--factory-id) require_value \"$1\" \"${2:-}\"; FACTORY_ID=\"$2\"; shift 2 ;;\n\t--line-id) require_value \"$1\" \"${2:-}\"; LINE_ID=\"$2\"; shift 2 ;;\n\t--station-id) require_value \"$1\" \"${2:-}\"; STATION_ID=\"$2\"; shift 2 ;;\n\t--fixture-id) require_value \"$1\" \"${2:-}\"; FIXTURE_ID=\"$2\"; shift 2 ;;\n\t--operator-id) require_value \"$1\" \"${2:-}\"; OPERATOR_ID=\"$2\"; shift 2 ;;\n\t--batch-id) require_value \"$1\" \"${2:-}\"; BATCH_ID=\"$2\"; shift 2 ;;\n\t--serial-prefix) require_value \"$1\" \"${2:-}\"; SERIAL_PREFIX=\"$2\"; shift 2 ;;\n\t--run-id) require_value \"$1\" \"${2:-}\"; RUN_ID=\"$2\"; shift 2 ;;\n\t--enroll-timeout) require_value \"$1\" \"${2:-}\"; ENROLL_TIMEOUT=\"$2\"; shift 2 ;;\n\t--generate-only) GENERATE_ONLY=1; shift ;;\n\t--ca-valid-days) require_value \"$1\" \"${2:-}\"; CA_VALID_DAYS=\"$2\"; shift 2 ;;\n\t--device-valid-days) require_value \"$1\" \"${2:-}\"; DEVICE_VALID_DAYS=\"$2\"; shift 2 ;;\n\t--force) FORCE=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nis_supported_type() {\n\tlocal candidate=\"$1\"\n\tlocal type\n\tfor type in \"${DEVICE_TYPES[@]}\"; do\n\t\t[[ \"$candidate\" == \"$type\" ]] && return 0\n\tdone\n\treturn 1\n}\n\nrequire_positive_int() {\n\tlocal name=\"$1\"\n\tlocal value=\"$2\"\n\t[[ \"$value\" =~ ^[0-9]+$ && \"$value\" -gt 0 ]] || die \"$name must be a positive integer\"\n}\n\nshell_quote() {\n\tprintf \"'%s'\" \"$(printf '%s' \"$1\" | sed \"s/'/'\\\\\\\\''/g\")\"\n}\n\nload_factory_enroll_defaults() {\n\tlocal video_env configured_url configured_key\n\tvideo_env=\"$(cloud_env_video_env \"$ENV_ROOT\")\"\n\tconfigured_url=\"$(cloud_env_file_var \"$video_env\" FACTORY_ENROLL_URL)\"\n\tconfigured_key=\"$(cloud_env_file_var \"$video_env\" FACTORY_ENROLL_AUTH_KEY)\"\n\tif [[ -z \"$FACTORY_ENROLL_URL\" && -n \"$configured_url\" ]]; then\n\t\tFACTORY_ENROLL_URL=\"$configured_url\"\n\tfi\n\tif [[ -z \"$FACTORY_ENROLL_URL\" && -n \"${VIDEO_CLOUD_DOMAIN:-}\" ]]; then\n\t\tFACTORY_ENROLL_URL=\"https://$VIDEO_CLOUD_DOMAIN\"\n\tfi\n\tif [[ -z \"$FACTORY_ENROLL_AUTH_KEY\" && -n \"$configured_key\" ]]; then\n\t\tFACTORY_ENROLL_AUTH_KEY=\"$configured_key\"\n\tfi\n}\n\ntype_model() {\n\tcase \"$1\" in\n\tcamera) printf 'RTC-CAM-PRO2-SIM' ;;\n\tlight) printf 'RTC-LIGHT-SIM' ;;\n\tair_conditioner) printf 'RTC-AC-SIM' ;;\n\tsmart_meter) printf 'RTC-METER-SIM' ;;\n\tesac\n}\n\ntype_display_name() {\n\tlocal type=\"$1\"\n\tlocal ordinal=\"$2\"\n\tcase \"$type\" in\n\tcamera) printf 'PRO2 Camera Simulator %03d' \"$ordinal\" ;;\n\tlight) printf 'Light Simulator %03d' \"$ordinal\" ;;\n\tair_conditioner) printf 'Air Conditioner Simulator %03d' \"$ordinal\" ;;\n\tsmart_meter) printf 'Smart Meter Simulator %03d' \"$ordinal\" ;;\n\tesac\n}\n\ntype_capability() {\n\tcase \"$1\" in\n\tcamera) printf 'camera' ;;\n\tlight) printf 'light' ;;\n\tair_conditioner) printf 'air_conditioner' ;;\n\tsmart_meter) printf 'smart_meter' ;;\n\tesac\n}\n\ntype_capabilities_json() {\n\tcase \"$1\" in\n\tcamera)\n\t\tprintf '%s\\n' '[\"camera_event\",\"status_report\",\"snapshot\",\"websocket_owner\",\"webrtc\",\"recording_clip\",\"mqtt_legacy_snapshot\"]'\n\t\t;;\n\tlight)\n\t\tprintf '%s\\n' '[\"mqtt\",\"power\",\"brightness\",\"color_temperature\",\"state_report\",\"command_result\"]'\n\t\t;;\n\tair_conditioner)\n\t\tprintf '%s\\n' '[\"mqtt\",\"power\",\"target_temperature\",\"mode\",\"fan\",\"state_report\",\"command_result\"]'\n\t\t;;\n\tsmart_meter)\n\t\tprintf '%s\\n' '[\"mqtt\",\"status_report\",\"telemetry_report\",\"power_watts\",\"energy_kwh\",\"voltage\",\"current\"]'\n\t\t;;\n\tesac\n}\n\ntype_service_options_json() {\n\tcase \"$1\" in\n\tcamera)\n\t\tprintf '%s\\n' '[\"mqtt\",\"video_streaming\",\"video_storage\"]'\n\t\t;;\n\tlight|air_conditioner|smart_meter)\n\t\tprintf '%s\\n' '[\"mqtt\"]'\n\t\t;;\n\tesac\n}\n\nsign_factory_request() {\n\tlocal timestamp=\"$1\"\n\tlocal request_id=\"$2\"\n\tlocal body_path=\"$3\"\n\tlocal body_hash signature\n\tbody_hash=\"$(openssl dgst -sha256 -r \"$body_path\" | awk '{print $1}')\"\n\tsignature=\"$(\n\t\t{\n\t\t\tprintf '%s\\n' \"POST\"\n\t\t\tprintf '%s\\n' \"/v1/factory/enroll\"\n\t\t\tprintf '%s\\n' \"$timestamp\"\n\t\t\tprintf '%s\\n' \"$request_id\"\n\t\t\tprintf '%s' \"$body_hash\"\n\t\t} | openssl dgst -sha256 -hmac \"$FACTORY_ENROLL_AUTH_KEY\" | awk '{print $NF}'\n\t)\"\n\tprintf 'v1=%s\\n' \"$signature\"\n}\n\nwrite_enroll_request() {\n\tlocal out_path=\"$1\"\n\tlocal request_id=\"$2\"\n\tlocal device_id=\"$3\"\n\tlocal type=\"$4\"\n\tlocal model=\"$5\"\n\tlocal display=\"$6\"\n\tlocal capability=\"$7\"\n\tlocal serial_number=\"$8\"\n\tlocal service_options_json=\"$9\"\n\tlocal capabilities_json=\"${10}\"\n\tlocal csr_path=\"${11}\"\n\tjq -n \\\n\t\t--arg request_id \"$request_id\" \\\n\t\t--arg device_id \"$device_id\" \\\n\t\t--arg type \"$type\" \\\n\t\t--arg model \"$model\" \\\n\t\t--arg display_name \"$display\" \\\n\t\t--arg capability \"$capability\" \\\n\t\t--arg serial_number \"$serial_number\" \\\n\t\t--arg factory_id \"$FACTORY_ID\" \\\n\t\t--arg line_id \"$LINE_ID\" \\\n\t\t--arg station_id \"$STATION_ID\" \\\n\t\t--arg fixture_id \"$FIXTURE_ID\" \\\n\t\t--arg operator_id \"$OPERATOR_ID\" \\\n\t\t--arg batch_id \"$BATCH_ID\" \\\n\t\t--arg run_id \"$RUN_ID\" \\\n\t\t--rawfile csr_pem \"$csr_path\" \\\n\t\t--argjson service_options \"$service_options_json\" \\\n\t\t--argjson capabilities \"$capabilities_json\" \\\n\t\t'{\n\t\t\trequest_id: $request_id,\n\t\t\tdevid: $device_id,\n\t\t\tcsr_pem: $csr_pem,\n\t\t\tserial_number: $serial_number,\n\t\t\tfactory_id: $factory_id,\n\t\t\tline_id: $line_id,\n\t\t\tstation_id: $station_id,\n\t\t\tfixture_id: $fixture_id,\n\t\t\toperator_id: $operator_id,\n\t\t\tbatch_id: $batch_id,\n\t\t\tservice_options: $service_options,\n\t\t\tmetadata: {\n\t\t\t\tsource: \"cloud-generate-load-devices\",\n\t\t\t\trun_id: $run_id,\n\t\t\t\tdevice_type: $type,\n\t\t\t\tmodel: $model,\n\t\t\t\tdisplay_name: $display_name,\n\t\t\t\tmqtt_capability: $capability,\n\t\t\t\tcapabilities: $capabilities,\n\t\t\t\tservice_options: $service_options\n\t\t\t}\n\t\t}' > \"$out_path\"\n}\n\nrecord_enroll_result() {\n\tlocal status=\"$1\"\n\tlocal index=\"$2\"\n\tlocal device_id=\"$3\"\n\tlocal type=\"$4\"\n\tlocal service_options_csv=\"$5\"\n\tlocal http_status=\"$6\"\n\tlocal request_id=\"$7\"\n\tlocal serial_number=\"$8\"\n\tlocal error=\"$9\"\n\tjq -cn \\\n\t\t--arg status \"$status\" \\\n\t\t--argjson index \"$index\" \\\n\t\t--arg device_id \"$device_id\" \\\n\t\t--arg device_type \"$type\" \\\n\t\t--arg service_options \"$service_options_csv\" \\\n\t\t--arg http_status \"$http_status\" \\\n\t\t--arg request_id \"$request_id\" \\\n\t\t--arg serial_number \"$serial_number\" \\\n\t\t--arg error \"$error\" \\\n\t\t'{status: $status, index: $index, device_id: $device_id, device_type: $device_type, service_options: ($service_options | split(\",\")), http_status: $http_status, request_id: $request_id, serial_number: $serial_number, error: $error}' >> \"$ENROLL_RESULTS_FILE\"\n}\n\nvalidate_device_certificate() {\n\tlocal cert_path=\"$1\"\n\tlocal chain_path=\"$2\"\n\tlocal key_path=\"$3\"\n\tlocal device_dir=\"$4\"\n\tlocal cert_pub key_pub\n\topenssl x509 -in \"$cert_path\" -noout >>\"$OPENSSL_LOG\" 2>&1 || return 1\n\topenssl x509 -in \"$chain_path\" -noout >>\"$OPENSSL_LOG\" 2>&1 || return 1\n\topenssl x509 -in \"$cert_path\" -pubkey -noout > \"$device_dir/device.cert.pub.pem\" 2>>\"$OPENSSL_LOG\" || return 1\n\topenssl pkey -in \"$key_path\" -pubout > \"$device_dir/device.key.pub.pem\" 2>>\"$OPENSSL_LOG\" || return 1\n\tcert_pub=\"$(openssl pkey -pubin -in \"$device_dir/device.cert.pub.pem\" -outform DER 2>>\"$OPENSSL_LOG\" | openssl dgst -sha256 -r | awk '{print $1}')\"\n\tkey_pub=\"$(openssl pkey -pubin -in \"$device_dir/device.key.pub.pem\" -outform DER 2>>\"$OPENSSL_LOG\" | openssl dgst -sha256 -r | awk '{print $1}')\"\n\t[[ -n \"$cert_pub\" && \"$cert_pub\" == \"$key_pub\" ]]\n}\n\nfactory_enroll_device() {\n\tlocal index=\"$1\"\n\tlocal type=\"$2\"\n\tlocal device_id=\"$3\"\n\tlocal model=\"$4\"\n\tlocal display=\"$5\"\n\tlocal capability=\"$6\"\n\tlocal capabilities_json=\"$7\"\n\tlocal service_options_json=\"$8\"\n\tlocal device_dir=\"$9\"\n\tlocal request_id serial_number service_options_csv timestamp signature status error_summary server_serial\n\trequest_id=\"$RUN_ID-$device_id\"\n\tserial_number=\"$(printf '%s-%s-%04d' \"$SERIAL_PREFIX\" \"$RUN_ID\" \"$index\")\"\n\tservice_options_csv=\"$(printf '%s' \"$service_options_json\" | jq -r 'join(\",\")')\"\n\n\tlog \"enroll start: index=$(printf '%03d' \"$index\") device=$device_id type=$type service_options=$service_options_csv\"\n\twrite_enroll_request \"$device_dir/factory-enroll-request.json\" \"$request_id\" \"$device_id\" \"$type\" \"$model\" \"$display\" \"$capability\" \"$serial_number\" \"$service_options_json\" \"$capabilities_json\" \"$device_dir/device.csr.pem\"\n\ttimestamp=\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"\n\tsignature=\"$(sign_factory_request \"$timestamp\" \"$request_id\" \"$device_dir/factory-enroll-request.json\")\"\n\tstatus=\"$(curl -sS -o \"$device_dir/factory-enroll-response.json\" -w '%{http_code}' \\\n\t\t--max-time \"$ENROLL_TIMEOUT\" \\\n\t\t-H 'Content-Type: application/json' \\\n\t\t-H \"X-Video-Cloud-Request-ID: $request_id\" \\\n\t\t-H \"X-Video-Cloud-Timestamp: $timestamp\" \\\n\t\t-H \"X-Video-Cloud-Signature: $signature\" \\\n\t\t--data-binary \"@$device_dir/factory-enroll-request.json\" \\\n\t\t\"$FACTORY_ENROLL_URL/v1/factory/enroll\" || true)\"\n\n\tcase \"$status\" in\n\t\t2??) ;;\n\t\t*)\n\t\t\terror_summary=\"$(jq -r '.error // .message // .error_message // empty' \"$device_dir/factory-enroll-response.json\" 2>/dev/null || true)\"\n\t\t\t[[ -n \"$error_summary\" ]] || error_summary=\"factory enrollment HTTP $status\"\n\t\t\tlog \"enroll failed: index=$(printf '%03d' \"$index\") device=$device_id type=$type status=$status error=$error_summary\"\n\t\t\trecord_enroll_result failed \"$index\" \"$device_id\" \"$type\" \"$service_options_csv\" \"$status\" \"$request_id\" \"$serial_number\" \"$error_summary\"\n\t\t\treturn 1\n\t\t\t;;\n\tesac\n\n\tif ! jq -er '.certificate_pem | select(length > 0)' \"$device_dir/factory-enroll-response.json\" > \"$device_dir/device.cert.pem\"; then\n\t\terror_summary=\"factory enrollment response missing certificate_pem\"\n\t\tlog \"enroll failed: index=$(printf '%03d' \"$index\") device=$device_id type=$type status=$status error=$error_summary\"\n\t\trecord_enroll_result failed \"$index\" \"$device_id\" \"$type\" \"$service_options_csv\" \"$status\" \"$request_id\" \"$serial_number\" \"$error_summary\"\n\t\treturn 1\n\tfi\n\tif ! jq -er '.certificate_chain_pem | select(length > 0)' \"$device_dir/factory-enroll-response.json\" > \"$device_dir/device.chain.pem\"; then\n\t\terror_summary=\"factory enrollment response missing certificate_chain_pem\"\n\t\tlog \"enroll failed: index=$(printf '%03d' \"$index\") device=$device_id type=$type status=$status error=$error_summary\"\n\t\trecord_enroll_result failed \"$index\" \"$device_id\" \"$type\" \"$service_options_csv\" \"$status\" \"$request_id\" \"$serial_number\" \"$error_summary\"\n\t\treturn 1\n\tfi\n\tif ! validate_device_certificate \"$device_dir/device.cert.pem\" \"$device_dir/device.chain.pem\" \"$device_dir/device.key.pem\" \"$device_dir\"; then\n\t\terror_summary=\"factory enrollment response certificate is invalid or does not match generated key\"\n\t\tlog \"enroll failed: index=$(printf '%03d' \"$index\") device=$device_id type=$type status=$status error=$error_summary\"\n\t\trecord_enroll_result failed \"$index\" \"$device_id\" \"$type\" \"$service_options_csv\" \"$status\" \"$request_id\" \"$serial_number\" \"$error_summary\"\n\t\treturn 1\n\tfi\n\tjq 'del(.certificate_pem, .certificate_chain_pem)' \"$device_dir/factory-enroll-response.json\" > \"$device_dir/factory-enroll-response.redacted.json\"\n\trm -f \"$device_dir/factory-enroll-response.json\"\n\tserver_serial=\"$(jq -r '.serial_number // empty' \"$device_dir/factory-enroll-response.redacted.json\")\"\n\t[[ -n \"$server_serial\" ]] || server_serial=\"$serial_number\"\n\tlog \"enroll ok: index=$(printf '%03d' \"$index\") device=$device_id type=$type status=$status serial=$server_serial\"\n\trecord_enroll_result ok \"$index\" \"$device_id\" \"$type\" \"$service_options_csv\" \"$status\" \"$request_id\" \"$server_serial\" \"\"\n}\n\nset_weight() {\n\tcase \"$1\" in\n\tcamera) WEIGHT_camera=\"$2\" ;;\n\tlight) WEIGHT_light=\"$2\" ;;\n\tair_conditioner) WEIGHT_air_conditioner=\"$2\" ;;\n\tsmart_meter) WEIGHT_smart_meter=\"$2\" ;;\n\tesac\n}\n\nget_weight() {\n\tcase \"$1\" in\n\tcamera) printf '%s' \"$WEIGHT_camera\" ;;\n\tlight) printf '%s' \"$WEIGHT_light\" ;;\n\tair_conditioner) printf '%s' \"$WEIGHT_air_conditioner\" ;;\n\tsmart_meter) printf '%s' \"$WEIGHT_smart_meter\" ;;\n\tesac\n}\n\nset_allocated() {\n\tcase \"$1\" in\n\tcamera) ALLOC_camera=\"$2\" ;;\n\tlight) ALLOC_light=\"$2\" ;;\n\tair_conditioner) ALLOC_air_conditioner=\"$2\" ;;\n\tsmart_meter) ALLOC_smart_meter=\"$2\" ;;\n\tesac\n}\n\nget_allocated() {\n\tcase \"$1\" in\n\tcamera) printf '%s' \"$ALLOC_camera\" ;;\n\tlight) printf '%s' \"$ALLOC_light\" ;;\n\tair_conditioner) printf '%s' \"$ALLOC_air_conditioner\" ;;\n\tsmart_meter) printf '%s' \"$ALLOC_smart_meter\" ;;\n\tesac\n}\n\nset_remainder() {\n\tcase \"$1\" in\n\tcamera) REM_camera=\"$2\" ;;\n\tlight) REM_light=\"$2\" ;;\n\tair_conditioner) REM_air_conditioner=\"$2\" ;;\n\tsmart_meter) REM_smart_meter=\"$2\" ;;\n\tesac\n}\n\nget_remainder() {\n\tcase \"$1\" in\n\tcamera) printf '%s' \"$REM_camera\" ;;\n\tlight) printf '%s' \"$REM_light\" ;;\n\tair_conditioner) printf '%s' \"$REM_air_conditioner\" ;;\n\tsmart_meter) printf '%s' \"$REM_smart_meter\" ;;\n\tesac\n}\n\nparse_mix() {\n\tlocal raw=\"$1\"\n\tlocal item type weight\n\t[[ -n \"$raw\" ]] || die \"--mix must not be empty\"\n\tfor item in ${raw//,/ }; do\n\t\t[[ -n \"$item\" ]] || continue\n\t\t[[ \"$item\" == *=* ]] || die \"invalid --mix item: $item\"\n\t\ttype=\"${item%%=*}\"\n\t\tweight=\"${item#*=}\"\n\t\tis_supported_type \"$type\" || die \"unsupported device type in --mix: $type\"\n\t\t[[ \"$weight\" =~ ^[0-9]+$ ]] || die \"invalid weight for $type: $weight\"\n\t\tset_weight \"$type\" \"$weight\"\n\tdone\n\tlocal total=0\n\tfor type in \"${DEVICE_TYPES[@]}\"; do\n\t\ttotal=$((total + $(get_weight \"$type\")))\n\tdone\n\t[[ \"$total\" -gt 0 ]] || die \"--mix must include at least one positive weight\"\n\tMIX_TOTAL=\"$total\"\n}\n\nallocate_counts() {\n\tlocal type weight base remainder allocated_total leftover selected selected_remainder\n\tallocated_total=0\n\tfor type in \"${DEVICE_TYPES[@]}\"; do\n\t\tweight=\"$(get_weight \"$type\")\"\n\t\tbase=$((COUNT * weight / MIX_TOTAL))\n\t\tremainder=$((COUNT * weight % MIX_TOTAL))\n\t\tset_allocated \"$type\" \"$base\"\n\t\tset_remainder \"$type\" \"$remainder\"\n\t\tallocated_total=$((allocated_total + base))\n\tdone\n\tleftover=$((COUNT - allocated_total))\n\twhile [[ \"$leftover\" -gt 0 ]]; do\n\t\tselected=\"\"\n\t\tselected_remainder=-1\n\t\tfor type in \"${DEVICE_TYPES[@]}\"; do\n\t\t\tweight=\"$(get_weight \"$type\")\"\n\t\t\t[[ \"$weight\" -gt 0 ]] || continue\n\t\t\tremainder=\"$(get_remainder \"$type\")\"\n\t\t\tif [[ \"$remainder\" -gt \"$selected_remainder\" ]]; then\n\t\t\t\tselected=\"$type\"\n\t\t\t\tselected_remainder=\"$remainder\"\n\t\t\tfi\n\t\tdone\n\t\t[[ -n \"$selected\" ]] || die \"could not allocate device count from --mix\"\n\t\tset_allocated \"$selected\" \"$(($(get_allocated \"$selected\") + 1))\"\n\t\tset_remainder \"$selected\" -1\n\t\tleftover=$((leftover - 1))\n\tdone\n}\n\nwrite_ca() {\n\tlog \"generating simulation device CA\"\n\tmkdir -p \"$OUT_DIR/ca\"\n\topenssl ecparam -name prime256v1 -genkey -noout -out \"$OUT_DIR/ca/sim-device-ca.key.pem\" >>\"$OPENSSL_LOG\" 2>&1\n\tchmod 0600 \"$OUT_DIR/ca/sim-device-ca.key.pem\"\n\tcat > \"$OUT_DIR/ca/ca.conf\" <<'EOF_CA'\n[ req ]\nprompt = no\ndistinguished_name = dn\nx509_extensions = v3_ca\n\n[ dn ]\nC = TW\nO = Realtek Connect Plus Simulation\nOU = Load Test Device Factory\nCN = Realtek Connect Plus Simulation Device CA\n\n[ v3_ca ]\nbasicConstraints = critical, CA:TRUE, pathlen:0\nkeyUsage = critical, keyCertSign, cRLSign\nsubjectKeyIdentifier = hash\nauthorityKeyIdentifier = keyid:always,issuer\nEOF_CA\n\topenssl req -x509 -new -sha256 \\\n\t\t-key \"$OUT_DIR/ca/sim-device-ca.key.pem\" \\\n\t\t-days \"$CA_VALID_DAYS\" \\\n\t\t-out \"$OUT_DIR/ca/sim-device-ca.cert.pem\" \\\n\t\t-config \"$OUT_DIR/ca/ca.conf\" >>\"$OPENSSL_LOG\" 2>&1\n}\n\nwrite_device_material() {\n\tlocal index=\"$1\"\n\tlocal type=\"$2\"\n\tlocal ordinal=\"$3\"\n\tlocal device_id model display capability capabilities_json service_options_json service_options_csv device_dir bundle_dir certificate_profile production warning\n\tdevice_id=\"$(printf '%s-%04d' \"$PREFIX\" \"$index\")\"\n\tmodel=\"$(type_model \"$type\")\"\n\tdisplay=\"$(type_display_name \"$type\" \"$ordinal\")\"\n\tcapability=\"$(type_capability \"$type\")\"\n\tcapabilities_json=\"$(type_capabilities_json \"$type\")\"\n\tservice_options_json=\"$(type_service_options_json \"$type\")\"\n\tservice_options_csv=\"$(printf '%s' \"$service_options_json\" | jq -r 'join(\",\")')\"\n\tdevice_dir=\"$OUT_DIR/devices/$type/$device_id\"\n\tbundle_dir=\"$OUT_DIR/bundles/$type\"\n\tmkdir -p \"$device_dir\" \"$bundle_dir\"\n\n\topenssl ecparam -name prime256v1 -genkey -noout -out \"$device_dir/device.key.pem\" >>\"$OPENSSL_LOG\" 2>&1\n\tchmod 0600 \"$device_dir/device.key.pem\"\n\n\tcat > \"$device_dir/csr.conf\" <<EOF_CSR\n[ req ]\nprompt = no\ndistinguished_name = dn\nreq_extensions = req_ext\n\n[ dn ]\nC = TW\nO = Realtek Connect Plus Simulation\nOU = $type\nCN = $device_id\n\n[ req_ext ]\nsubjectAltName = @alt_names\n\n[ alt_names ]\nDNS.1 = $device_id.simulated.realtek-connect.local\nURI.1 = urn:realtek-connect:simulated-device:$device_id\nEOF_CSR\n\topenssl req -new -sha256 \\\n\t\t-key \"$device_dir/device.key.pem\" \\\n\t\t-out \"$device_dir/device.csr.pem\" \\\n\t\t-config \"$device_dir/csr.conf\" >>\"$OPENSSL_LOG\" 2>&1\n\n\tif [[ \"$GENERATE_ONLY\" == \"1\" ]]; then\n\t\tlog \"generate-only: index=$(printf '%03d' \"$index\") device=$device_id type=$type service_options=$service_options_csv\"\n\t\tcat > \"$device_dir/cert-ext.conf\" <<EOF_EXT\nbasicConstraints = CA:FALSE\nkeyUsage = critical, digitalSignature\nextendedKeyUsage = clientAuth\nsubjectAltName = DNS:$device_id.simulated.realtek-connect.local,URI:urn:realtek-connect:simulated-device:$device_id\nEOF_EXT\n\t\topenssl x509 -req -sha256 \\\n\t\t\t-in \"$device_dir/device.csr.pem\" \\\n\t\t\t-CA \"$OUT_DIR/ca/sim-device-ca.cert.pem\" \\\n\t\t\t-CAkey \"$OUT_DIR/ca/sim-device-ca.key.pem\" \\\n\t\t\t-CAserial \"$OUT_DIR/ca/sim-device-ca.srl\" \\\n\t\t\t-CAcreateserial \\\n\t\t\t-days \"$DEVICE_VALID_DAYS\" \\\n\t\t\t-out \"$device_dir/device.cert.pem\" \\\n\t\t\t-extfile \"$device_dir/cert-ext.conf\" >>\"$OPENSSL_LOG\" 2>&1\n\t\tcp \"$OUT_DIR/ca/sim-device-ca.cert.pem\" \"$device_dir/device.chain.pem\"\n\t\tcertificate_profile=\"simulation-device-mtls-client\"\n\t\tproduction=false\n\t\twarning=\"Simulation-only generated credential. Do not use as a production or customer device identity.\"\n\telse\n\t\tif ! factory_enroll_device \"$index\" \"$type\" \"$device_id\" \"$model\" \"$display\" \"$capability\" \"$capabilities_json\" \"$service_options_json\" \"$device_dir\"; then\n\t\t\treturn 1\n\t\tfi\n\t\tcertificate_profile=\"factory-enrolled-device-mtls-client\"\n\t\tproduction=false\n\t\twarning=\"Factory-enrolled staging load-test credential. Keep private key material out of source control.\"\n\tfi\n\n\tcat \"$device_dir/device.cert.pem\" \"$device_dir/device.key.pem\" > \"$bundle_dir/$device_id.pem\"\n\tchmod 0600 \"$bundle_dir/$device_id.pem\"\n\n\tjq -n \\\n\t\t--arg device_id \"$device_id\" \\\n\t\t--arg type \"$type\" \\\n\t\t--arg capability \"$capability\" \\\n\t\t--arg model \"$model\" \\\n\t\t--arg display_name \"$display\" \\\n\t\t--arg cert \"devices/$type/$device_id/device.cert.pem\" \\\n\t\t--arg chain \"devices/$type/$device_id/device.chain.pem\" \\\n\t\t--arg key \"devices/$type/$device_id/device.key.pem\" \\\n\t\t--arg csr \"devices/$type/$device_id/device.csr.pem\" \\\n\t\t--arg bundle \"bundles/$type/$device_id.pem\" \\\n\t\t--arg certificate_profile \"$certificate_profile\" \\\n\t\t--argjson production \"$production\" \\\n\t\t--arg warning \"$warning\" \\\n\t\t--argjson capabilities \"$capabilities_json\" \\\n\t\t--argjson service_options \"$service_options_json\" \\\n\t\t'{\n\t\t\tdevice_id: $device_id,\n\t\t\tdevice_type: $type,\n\t\t\tmqtt_capability: $capability,\n\t\t\tservice_options: $service_options,\n\t\t\tmodel: $model,\n\t\t\tdisplay_name: $display_name,\n\t\t\tfirmware_version: \"0.0.0-loadtest\",\n\t\t\tcapabilities: $capabilities,\n\t\t\tcertificate_profile: $certificate_profile,\n\t\t\tcertificate_path: $cert,\n\t\t\tcertificate_chain_path: $chain,\n\t\t\tkey_path: $key,\n\t\t\tcsr_path: $csr,\n\t\t\tbundle_path: $bundle,\n\t\t\tproduction: $production,\n\t\t\twarning: $warning\n\t\t}' > \"$device_dir/metadata.json\"\n\n\tprintf '%s,%s,%s,%s,%s,%s,%s,%s\\n' \\\n\t\t\"$device_id\" \"$type\" \"$capability\" \"$(printf '%s' \"$service_options_json\" | jq -r 'join(\";\")')\" \"$model\" \\\n\t\t\"devices/$type/$device_id/device.cert.pem\" \\\n\t\t\"devices/$type/$device_id/device.key.pem\" \\\n\t\t\"bundles/$type/$device_id.pem\" >> \"$CSV_MANIFEST\"\n\tprintf '%s\\n' \"$device_id\" >> \"$DEVICE_IDS_FILE\"\n\tprintf '%s\\n' \"$device_dir/metadata.json\" >> \"$METADATA_FILES\"\n}\n\nwrite_manifests() {\n\tlocal type count profile iot_mix device_ids_csv enroll_mode\n\tmkdir -p \"$OUT_DIR/manifests\"\n\tCSV_MANIFEST=\"$OUT_DIR/manifests/devices.csv\"\n\tDEVICE_IDS_FILE=\"$OUT_DIR/manifests/device_ids.txt\"\n\tMETADATA_FILES=\"$OUT_DIR/manifests/metadata_files.txt\"\n\tENROLL_RESULTS_FILE=\"$OUT_DIR/manifests/factory-enroll-results.jsonl\"\n\tprintf 'device_id,device_type,mqtt_capability,service_options,model,certificate_path,key_path,bundle_path\\n' > \"$CSV_MANIFEST\"\n\t: > \"$DEVICE_IDS_FILE\"\n\t: > \"$METADATA_FILES\"\n\t: > \"$ENROLL_RESULTS_FILE\"\n\n\tlocal index=1\n\tfor type in \"${DEVICE_TYPES[@]}\"; do\n\t\tcount=\"$(get_allocated \"$type\")\"\n\t\t[[ \"$count\" -gt 0 ]] || continue\n\t\tlog \"generating devices: type=$type count=$count\"\n\t\tfor ordinal in $(seq 1 \"$count\"); do\n\t\t\tif write_device_material \"$index\" \"$type\" \"$ordinal\"; then\n\t\t\t\tENROLL_SUCCEEDED=$((ENROLL_SUCCEEDED + 1))\n\t\t\telse\n\t\t\t\tENROLL_FAILURES=$((ENROLL_FAILURES + 1))\n\t\t\tfi\n\t\t\tindex=$((index + 1))\n\t\tdone\n\tdone\n\n\tif [[ -s \"$METADATA_FILES\" ]]; then\n\t\tjq -s . $(cat \"$METADATA_FILES\") > \"$OUT_DIR/manifests/devices.json\"\n\telse\n\t\tprintf '[]\\n' > \"$OUT_DIR/manifests/devices.json\"\n\tfi\n\n\tdevice_ids_csv=\"\"\n\tif [[ -s \"$DEVICE_IDS_FILE\" ]]; then\n\t\tdevice_ids_csv=\"$(paste -sd, \"$DEVICE_IDS_FILE\")\"\n\tfi\n\tprofile=\"mixed\"\n\tif [[ \"$ALLOC_camera\" -eq \"$COUNT\" ]]; then\n\t\tprofile=\"camera\"\n\telif [[ \"$ALLOC_camera\" -eq 0 ]]; then\n\t\tprofile=\"iot\"\n\tfi\n\tiot_mix=\"light=$ALLOC_light,air_conditioner=$ALLOC_air_conditioner,smart_meter=$ALLOC_smart_meter\"\n\n\t{\n\t\tprintf '# Source this file before e2e_test/video_cloud/load/scripts/run_video_loadtest.sh.\\n'\n\t\tprintf '# It contains no bearer tokens; provide VIDEO_CLOUD_LOAD_*_TOKEN separately.\\n'\n\t\tprintf 'export VIDEO_CLOUD_LOAD_DEVICE_PREFIX=%s\\n' \"$(shell_quote \"$PREFIX\")\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_VIRTUAL_DEVICES=%s\\n' \"$COUNT\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_DEVICE_IDS=%s\\n' \"$(shell_quote \"$device_ids_csv\")\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_MQTT_DEVICE_PROFILE=%s\\n' \"$(shell_quote \"$profile\")\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_MQTT_IOT_MIX=%s\\n' \"$(shell_quote \"$iot_mix\")\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_DEVICE_MANIFEST=%s\\n' \"$(shell_quote \"$OUT_DIR/manifests/devices.json\")\"\n\t\tprintf 'export VIDEO_CLOUD_LOAD_DEVICE_CERT_ROOT=%s\\n' \"$(shell_quote \"$OUT_DIR\")\"\n\t} > \"$OUT_DIR/loadtest.env\"\n\n\tenroll_mode=\"factory_enroll\"\n\tif [[ \"$GENERATE_ONLY\" == \"1\" ]]; then\n\t\tenroll_mode=\"generate_only\"\n\tfi\n\tjq -n \\\n\t\t--arg generated_at \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \\\n\t\t--arg prefix \"$PREFIX\" \\\n\t\t--arg mix \"$MIX\" \\\n\t\t--arg out_dir \"$OUT_DIR\" \\\n\t\t--arg enroll_mode \"$enroll_mode\" \\\n\t\t--arg factory_url \"$FACTORY_ENROLL_URL\" \\\n\t\t--arg loadtest_env \"loadtest.env\" \\\n\t\t--arg device_ids \"manifests/device_ids.txt\" \\\n\t\t--arg devices_csv \"manifests/devices.csv\" \\\n\t\t--arg devices_json \"manifests/devices.json\" \\\n\t\t--arg enroll_results \"manifests/factory-enroll-results.jsonl\" \\\n\t\t--arg ca_cert \"ca/sim-device-ca.cert.pem\" \\\n\t\t--argjson count \"$COUNT\" \\\n\t\t--argjson enroll_succeeded \"$ENROLL_SUCCEEDED\" \\\n\t\t--argjson enroll_failures \"$ENROLL_FAILURES\" \\\n\t\t--argjson camera \"$ALLOC_camera\" \\\n\t\t--argjson light \"$ALLOC_light\" \\\n\t\t--argjson air_conditioner \"$ALLOC_air_conditioner\" \\\n\t\t--argjson smart_meter \"$ALLOC_smart_meter\" \\\n\t\t'{\n\t\t\tgenerated_at: $generated_at,\n\t\t\tcount: $count,\n\t\t\tprefix: $prefix,\n\t\t\trequested_mix: $mix,\n\t\t\tallocated: {\n\t\t\t\tcamera: $camera,\n\t\t\t\tlight: $light,\n\t\t\t\tair_conditioner: $air_conditioner,\n\t\t\t\tsmart_meter: $smart_meter\n\t\t\t},\n\t\t\tenrollment: {\n\t\t\t\tmode: $enroll_mode,\n\t\t\t\tfactory_url: $factory_url,\n\t\t\t\tsucceeded: $enroll_succeeded,\n\t\t\t\tfailed: $enroll_failures,\n\t\t\t\tresults: $enroll_results\n\t\t\t},\n\t\t\tpaths: {\n\t\t\t\toutput_dir: $out_dir,\n\t\t\t\tloadtest_env: $loadtest_env,\n\t\t\t\tdevice_ids: $device_ids,\n\t\t\t\tdevices_csv: $devices_csv,\n\t\t\t\tdevices_json: $devices_json,\n\t\t\t\tca_cert: $ca_cert\n\t\t\t}\n\t\t}' > \"$OUT_DIR/summary.json\"\n}\n\nwrite_readme() {\n\tlocal mode_description credential_source\n\tif [[ \"$GENERATE_ONLY\" == \"1\" ]]; then\n\t\tmode_description=\"offline generate-only\"\n\t\tcredential_source=\"locally signed by the simulation CA\"\n\telse\n\t\tmode_description=\"factory enrollment\"\n\t\tcredential_source=\"issued by $FACTORY_ENROLL_URL/v1/factory/enroll\"\n\tfi\n\tcat > \"$OUT_DIR/README.md\" <<EOF_README\n# Staging Load-Test Device Factory Output\n\nThis directory contains staging load-test device identities generated for\nfactory/provisioning flow rehearsal.\n\n- Device count: $COUNT\n- Requested mix: $MIX\n- Mode: $mode_description\n- Device key type: EC P-256\n- Device certificate profile: clientAuth\n- Credential source: $credential_source\n- CA validity days: $CA_VALID_DAYS\n- Device validity days: $DEVICE_VALID_DAYS\n\n## Files\n\n- \\`ca/sim-device-ca.cert.pem\\`: simulation CA certificate, present only with \\`--generate-only\\`.\n- \\`ca/sim-device-ca.key.pem\\`: simulation CA private key, present only with \\`--generate-only\\`.\n- \\`devices/<type>/<device_id>/device.key.pem\\`: per-device private key.\n- \\`devices/<type>/<device_id>/device.csr.pem\\`: per-device CSR.\n- \\`devices/<type>/<device_id>/device.cert.pem\\`: per-device client certificate.\n- \\`devices/<type>/<device_id>/device.chain.pem\\`: issuing certificate chain.\n- \\`devices/<type>/<device_id>/factory-enroll-response.redacted.json\\`: non-secret enrollment response details, present with factory enrollment mode.\n- \\`devices/<type>/<device_id>/metadata.json\\`: per-device metadata.\n- \\`bundles/<type>/<device_id>.pem\\`: certificate + private key bundle.\n- \\`manifests/devices.csv\\`: compact inventory.\n- \\`manifests/devices.json\\`: full inventory.\n- \\`manifests/device_ids.txt\\`: one device id per line.\n- \\`manifests/factory-enroll-results.jsonl\\`: per-device enrollment status.\n- \\`loadtest.env\\`: environment variables for the current load-test runner.\n\n## Usage\n\n\\`\\`\\`sh\nset -a\n. \"$OUT_DIR/loadtest.env\"\nset +a\n\n# Then provide API URL and bearer tokens separately before running:\n# e2e_test/video_cloud/load/scripts/run_video_loadtest.sh\n\\`\\`\\`\n\nThese credentials are not production credentials. Do not register them against\nproduction or customer environments.\nEOF_README\n}\n\nrequire_positive_int \"--count\" \"$COUNT\"\nrequire_positive_int \"--ca-valid-days\" \"$CA_VALID_DAYS\"\nrequire_positive_int \"--device-valid-days\" \"$DEVICE_VALID_DAYS\"\nrequire_positive_int \"--enroll-timeout\" \"$ENROLL_TIMEOUT\"\n[[ \"$PREFIX\" =~ ^[A-Za-z0-9][A-Za-z0-9_.-]*$ ]] || die \"--prefix contains unsupported characters\"\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\nif [[ -z \"$RUN_ID\" ]]; then\n\tRUN_ID=\"$(date -u +%Y%m%dT%H%M%SZ)\"\nfi\nif [[ -z \"$BATCH_ID\" ]]; then\n\tBATCH_ID=\"$RUN_ID\"\nfi\n\nneed_cmd openssl\nneed_cmd jq\nneed_cmd paste\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\ncloud_env_load_environment \"$ENV_ROOT\"\nload_factory_enroll_defaults\nif [[ \"$GENERATE_ONLY\" != \"1\" ]]; then\n\t[[ -n \"$FACTORY_ENROLL_URL\" ]] || die \"factory enrollment URL missing; set FACTORY_ENROLL_URL in $(cloud_env_video_env \"$ENV_ROOT\") or pass --factory-url\"\n\t[[ -n \"$FACTORY_ENROLL_AUTH_KEY\" ]] || die \"factory enrollment auth key missing; set FACTORY_ENROLL_AUTH_KEY in $(cloud_env_video_env \"$ENV_ROOT\") or pass --factory-auth-key\"\n\tneed_cmd curl\n\tFACTORY_ENROLL_URL=\"${FACTORY_ENROLL_URL%/}\"\nfi\nif [[ -z \"$OUT_DIR\" ]]; then\n\tOUT_DIR=\"$(cloud_env_test_devices_dir \"$ENV_ROOT\")\"\nfi\nif [[ -e \"$OUT_DIR\" ]]; then\n\t[[ \"$FORCE\" == \"1\" ]] || die \"$OUT_DIR already exists; use --force to replace it\"\n\trm -rf \"$OUT_DIR\"\nfi\nmkdir -p \"$OUT_DIR\"\nOUT_DIR=\"$(cd \"$OUT_DIR\" && pwd)\"\nOPENSSL_LOG=\"$OUT_DIR/openssl.log\"\n: > \"$OPENSSL_LOG\"\n\nif [[ \"$GENERATE_ONLY\" == \"1\" ]]; then\n\tlog \"start load-test device generation: count=$COUNT mix=$MIX mode=generate_only\"\nelse\n\tlog \"start load-test device generation: count=$COUNT mix=$MIX mode=factory_enroll factory_url=$FACTORY_ENROLL_URL\"\nfi\nlog \"workspace=$WORKSPACE\"\nlog \"output=$OUT_DIR\"\nlog \"run_id=$RUN_ID batch_id=$BATCH_ID\"\nparse_mix \"$MIX\"\nallocate_counts\nif [[ \"$GENERATE_ONLY\" == \"1\" ]]; then\n\twrite_ca\nfi\nwrite_manifests\nwrite_readme\n\nif [[ \"$ENROLL_FAILURES\" -gt 0 ]]; then\n\tlog \"complete with failures: requested=$COUNT succeeded=$ENROLL_SUCCEEDED failed=$ENROLL_FAILURES results=$ENROLL_RESULTS_FILE\"\n\tprintf 'output=%s\\n' \"$OUT_DIR\"\n\tprintf 'summary=%s\\n' \"$OUT_DIR/summary.json\"\n\tprintf 'enroll_results=%s\\n' \"$ENROLL_RESULTS_FILE\"\n\tprintf 'openssl_log=%s\\n' \"$OPENSSL_LOG\"\n\texit 1\nfi\n\nlog \"complete: requested=$COUNT succeeded=$ENROLL_SUCCEEDED failed=$ENROLL_FAILURES\"\nprintf 'output=%s\\n' \"$OUT_DIR\"\nprintf 'summary=%s\\n' \"$OUT_DIR/summary.json\"\nprintf 'enroll_results=%s\\n' \"$ENROLL_RESULTS_FILE\"\nprintf 'loadtest_env=%s\\n' \"$OUT_DIR/loadtest.env\"\nprintf 'openssl_log=%s\\n' \"$OPENSSL_LOG\"\n",
	"cloud-list-brandname-clouds.sh":            "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nSTART_EPOCH=\"$(date +%s)\"\nENV_ROOT=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nBRANDNAME=\"\"\nJSON_OUTPUT=0\nLIMIT=200\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-brand-cloud-list %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-list-brandname-clouds.sh [options]\n\nOptions:\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH    Deprecated alias for --env-root.\n  --brandname NAME       Show only a matching brand cloud name or metadata.brandname.\n  --limit N              API list limit. Default: 200.\n  --json                 Print the full API response JSON.\n  -h, --help             Show this help.\n\nLists Account Manager brand clouds on the selected Linode staging environment.\nThe script logs in with that environment's platform-admin credentials and only\nperforms read-only Account Manager admin API calls.\nUSAGE\n}\n\nrequire_value() {\n\tlocal opt=\"$1\"\n\tlocal value=\"${2:-}\"\n\t[[ -n \"$value\" ]] || die \"$opt requires a value\"\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) require_value \"$1\" \"${2:-}\"; WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) require_value \"$1\" \"${2:-}\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--secrets-root) require_value \"$1\" \"${2:-}\"; DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--brandname) require_value \"$1\" \"${2:-}\"; BRANDNAME=\"$2\"; shift 2 ;;\n\t--limit) require_value \"$1\" \"${2:-}\"; LIMIT=\"$2\"; shift 2 ;;\n\t--json) JSON_OUTPUT=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"required env file not found: $path\"\n\tset -a\n\t# shellcheck source=/dev/null\n\t. \"$path\"\n\tset +a\n}\n\ncurl_json_status() {\n\tlocal out=\"$1\"\n\tshift\n\tcurl -sS -o \"$out\" -w '%{http_code}' \"$@\"\n}\n\nlogin_platform_admin() {\n\tlocal login_payload=\"$TMPDIR/login.json\"\n\tlocal login_out=\"$TMPDIR/login.out\"\n\tlog \"logging in platform admin: $AM_BASE_URL/v1/auth/login\"\n\tjq -cn \\\n\t\t--arg email \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_EMAIL\" \\\n\t\t--arg password \"$ACCOUNT_MANAGER_BOOTSTRAP_PLATFORM_ADMIN_PASSWORD\" \\\n\t\t'{email:$email,password:$password}' > \"$login_payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$login_out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t--data-binary \"@$login_payload\" \\\n\t\t\"$AM_BASE_URL/v1/auth/login\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"platform admin login failed: HTTP $status\"\n\tACCESS_TOKEN=\"$(jq -r '.tokens.access_token // empty' \"$login_out\")\"\n\t[[ -n \"$ACCESS_TOKEN\" ]] || die \"platform admin login response did not include an access token\"\n\tlog \"platform admin login ok\"\n}\n\nlist_brand_clouds() {\n\tlocal out=\"$TMPDIR/brand-clouds.out\"\n\tlocal filtered=\"$TMPDIR/brand-clouds.filtered.json\"\n\tlocal status\n\tlog \"listing brand clouds: limit=$LIMIT\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H \"authorization: Bearer $ACCESS_TOKEN\" \\\n\t\t\"$AM_BASE_URL/v1/admin/brand-clouds?limit=$LIMIT\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"brand cloud list failed: HTTP $status\"\n\n\tif [[ -n \"$BRANDNAME\" ]]; then\n\t\tlog \"filtering brand clouds: brandname=$BRANDNAME\"\n\t\tjq --arg name \"$BRANDNAME\" '\n\t\t\t.brand_clouds = [\n\t\t\t\t.brand_clouds[]?\n\t\t\t\t| select(.name == $name or (.metadata.brandname // \"\") == $name)\n\t\t\t]\n\t\t\t| .pagination.filtered_total = (.brand_clouds | length)\n\t\t' \"$out\" > \"$filtered\"\n\telse\n\t\tcp \"$out\" \"$filtered\"\n\tfi\n\tBRAND_CLOUDS_JSON=\"$filtered\"\n}\n\nprint_human_summary() {\n\tlocal listed_count api_total\n\tlisted_count=\"$(jq -r '.brand_clouds | length' \"$BRAND_CLOUDS_JSON\")\"\n\tapi_total=\"$(jq -r '.pagination.total // (.brand_clouds | length)' \"$BRAND_CLOUDS_JSON\")\"\n\tif [[ -n \"$BRANDNAME\" ]]; then\n\t\tprintf 'brand_clouds=%s api_total=%s filter=%s\\n' \"$listed_count\" \"$api_total\" \"$BRANDNAME\"\n\telse\n\t\tprintf 'brand_clouds=%s api_total=%s\\n' \"$listed_count\" \"$api_total\"\n\tfi\n\tprintf '%-36s  %-24s  %-10s  %-12s  %-5s  %-16s  %-24s  %s\\n' \\\n\t\t'id' 'name' 'status' 'tier' 'quota' 'metadata.brandname' 'created_at' 'metadata'\n\tjq -r '\n\t\t.brand_clouds[]?\n\t\t| [\n\t\t\t.id,\n\t\t\t.name,\n\t\t\t.status,\n\t\t\t.tier,\n\t\t\t(.evaluation_device_quota | tostring),\n\t\t\t(.metadata.brandname // \"\"),\n\t\t\t.created_at,\n\t\t\t(.metadata // {} | tostring)\n\t\t]\n\t\t| @tsv\n\t' \"$BRAND_CLOUDS_JSON\" | awk -F '\\t' '{\n\t\tprintf \"%-36s  %-24s  %-10s  %-12s  %-5s  %-16s  %-24s  %s\\n\", $1, $2, $3, $4, $5, $6, $7, $8\n\t}'\n}\n\n[[ \"$LIMIT\" =~ ^[0-9]+$ ]] || die \"--limit must be a positive integer\"\n[[ \"$LIMIT\" -gt 0 ]] || die \"--limit must be a positive integer\"\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nlog \"start staging brand cloud list\"\nneed_cmd curl\nneed_cmd jq\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\nlog \"workspace=$WORKSPACE\"\nlog \"env_root=$ENV_ROOT\"\nAM_REPO=\"$WORKSPACE/repos/rtk_account_manager\"\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nAM_PLATFORM_ADMIN_ENV=\"$(cloud_env_account_manager_platform_admin_env \"$ENV_ROOT\")\"\n\nlog \"loading Account Manager staging env/state\"\nload_env_file \"$AM_ENV\"\nload_env_file \"$AM_STATE\"\nload_env_file \"$AM_PLATFORM_ADMIN_ENV\"\n\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-account-manager.video-cloud-staging.realtekconnect.com}\"\nAM_BASE_URL=\"https://$AM_DOMAIN\"\nTMPDIR=\"$(mktemp -d /tmp/rtk-brand-cloud-list.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\n\nlogin_platform_admin\nlist_brand_clouds\n\nif [[ \"$JSON_OUTPUT\" == \"1\" ]]; then\n\tjq . \"$BRAND_CLOUDS_JSON\"\nelse\n\tprint_human_summary\nfi\nlog \"complete: listed brand clouds\"\n",
	"cloud-migrate-env.sh":                      "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nFORCE=0\nSTART_EPOCH=\"$(date +%s)\"\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-env-migrate %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-migrate-env.sh [options]\n\nOptions:\n  --workspace PATH   Default: script parent workspace.\n  --env-root PATH    Required environment directory, for example cloud_env/staging.\n  --force            Overwrite existing target files.\n  -h, --help         Show this help.\n\nCopies current local staging environment files from the legacy scattered\nlocations into cloud_env/staging/linode. Source files are left in place. A\ntimestamped backup and migration manifest are written under <env-root>/backups.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--force) FORCE=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nsha256_file() {\n\tlocal file=\"$1\"\n\tif command -v shasum >/dev/null 2>&1; then\n\t\tshasum -a 256 \"$file\" | awk '{print $1}'\n\telse\n\t\tsha256sum \"$file\" | awk '{print $1}'\n\tfi\n}\n\nrel_path() {\n\tlocal path=\"$1\"\n\tcase \"$path\" in\n\t\"$WORKSPACE\"/*) printf '%s\\n' \"${path#$WORKSPACE/}\" ;;\n\t*) printf '%s\\n' \"$path\" ;;\n\tesac\n}\n\nrecord_manifest() {\n\tlocal kind=\"$1\"\n\tlocal src=\"$2\"\n\tlocal dst=\"$3\"\n\tlocal status=\"$4\"\n\tlocal sha=\"${5:-}\"\n\tjq -cn \\\n\t\t--arg ts \"$STAMP\" \\\n\t\t--arg kind \"$kind\" \\\n\t\t--arg src \"$(rel_path \"$src\")\" \\\n\t\t--arg dst \"$(rel_path \"$dst\")\" \\\n\t\t--arg status \"$status\" \\\n\t\t--arg sha \"$sha\" \\\n\t\t'{timestamp:$ts, kind:$kind, source:$src, target:$dst, status:$status, sha256:($sha | select(. != \"\"))}' >> \"$MANIFEST_JSONL\"\n\tprintf '%s\\t%s\\t%s\\t%s\\t%s\\n' \"$kind\" \"$(rel_path \"$src\")\" \"$(rel_path \"$dst\")\" \"$status\" \"$sha\" >> \"$MANIFEST_TSV\"\n}\n\nbackup_source_file() {\n\tlocal src=\"$1\"\n\tlocal backup=\"$BACKUP_DIR/legacy/$(rel_path \"$src\")\"\n\tmkdir -p \"$(dirname \"$backup\")\"\n\tcp -p \"$src\" \"$backup\"\n}\n\ncopy_file() {\n\tlocal src=\"$1\"\n\tlocal dst=\"$2\"\n\tlocal kind=\"${3:-file}\"\n\tif [[ ! -f \"$src\" ]]; then\n\t\trecord_manifest \"$kind\" \"$src\" \"$dst\" \"missing\"\n\t\treturn 0\n\tfi\n\tif [[ -e \"$dst\" && \"$FORCE\" != \"1\" ]]; then\n\t\trecord_manifest \"$kind\" \"$src\" \"$dst\" \"skipped-existing\" \"$(sha256_file \"$dst\")\"\n\t\treturn 0\n\tfi\n\tmkdir -p \"$(dirname \"$dst\")\"\n\tcp -p \"$src\" \"$dst\"\n\tbackup_source_file \"$src\"\n\trecord_manifest \"$kind\" \"$src\" \"$dst\" \"copied\" \"$(sha256_file \"$dst\")\"\n}\n\ncopy_dir_contents() {\n\tlocal src=\"$1\"\n\tlocal dst=\"$2\"\n\tlocal kind=\"$3\"\n\tif [[ ! -d \"$src\" ]]; then\n\t\trecord_manifest \"$kind\" \"$src\" \"$dst\" \"missing\"\n\t\treturn 0\n\tfi\n\tfind \"$src\" -type f | sort | while IFS= read -r file; do\n\t\tlocal rel=\"${file#$src/}\"\n\t\tcopy_file \"$file\" \"$dst/$rel\" \"$kind\"\n\tdone\n}\n\nenv_file_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\t(\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$file\"\n\t\tset +a\n\t\tprintf '%s\\n' \"${!key:-}\"\n\t)\n}\n\nyaml_top_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk -F ':' -v key=\"$key\" '$1 == key {sub(/^[[:space:]]+/, \"\", $2); print $2; exit}' \"$file\"\n}\n\nyaml_path_value() {\n\tlocal file=\"$1\"\n\tlocal path=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk -v path=\"$path\" '\n\tBEGIN {\n\t\tn = split(path, want, \".\")\n\t}\n\t/^[[:space:]]*#/ || /^[[:space:]]*$/ { next }\n\t{\n\t\tmatch($0, /^[ ]*/)\n\t\tindent = RLENGTH / 2\n\t\tline = $0\n\t\tsub(/^[ ]*/, \"\", line)\n\t\tkey = line\n\t\tsub(/:.*/, \"\", key)\n\t\tstack[indent + 1] = key\n\t\tfor (i = indent + 2; i <= 16; i++) {\n\t\t\tdelete stack[i]\n\t\t}\n\t\tif (line !~ /^[^:]+:[[:space:]]*[^[:space:]]/) {\n\t\t\tnext\n\t\t}\n\t\tif (indent + 1 != n) {\n\t\t\tnext\n\t\t}\n\t\tfor (i = 1; i <= n; i++) {\n\t\t\tif (stack[i] != want[i]) {\n\t\t\t\tnext\n\t\t\t}\n\t\t}\n\t\tsub(/^[^:]+:[[:space:]]*/, \"\", line)\n\t\tprint line\n\t\texit\n\t}' \"$file\"\n}\n\nmetadata_env_name() {\n\tif [[ \"$(basename \"$ENV_ROOT\")\" == \"linode\" ]]; then\n\t\tbasename \"$(dirname \"$ENV_ROOT\")\"\n\telse\n\t\tbasename \"$ENV_ROOT\"\n\tfi\n}\n\nwrite_environment_metadata() {\n\tlocal dst\n\tdst=\"$(cloud_env_stack_env \"$ENV_ROOT\")\"\n\tif [[ -e \"$dst\" && \"$FORCE\" != \"1\" ]]; then\n\t\trecord_manifest \"stack-metadata\" \"$dst\" \"$dst\" \"skipped-existing\" \"$(sha256_file \"$dst\")\"\n\t\treturn 0\n\tfi\n\n\tlocal video_config am_env admin_env env_name provider region root_domain stack\n\tlocal video_domain certissuer_domain am_domain admin_domain\n\tlocal label_prefix vpc_label subnet_label am_label am_fw_label admin_label admin_fw_label\n\tvideo_config=\"$(cloud_env_video_config \"$ENV_ROOT\")\"\n\tam_env=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\n\tadmin_env=\"$(cloud_env_admin_env \"$ENV_ROOT\")\"\n\n\tenv_name=\"$(metadata_env_name)\"\n\tprovider=\"linode\"\n\tregion=\"$(yaml_top_value \"$video_config\" region)\"\n\tregion=\"${region:-us-sea}\"\n\troot_domain=\"${CLOUD_DNS_ROOT_DOMAIN:-realtekconnect.com}\"\n\tstack=\"$(yaml_top_value \"$video_config\" stack)\"\n\tstack=\"${stack:-video-cloud-$env_name}\"\n\n\tvideo_domain=\"$(yaml_path_value \"$video_config\" instances.edge.letsencrypt.domain)\"\n\tvideo_domain=\"${video_domain:-$stack.$root_domain}\"\n\tcertissuer_domain=\"$(yaml_path_value \"$video_config\" deploy.certissuer_domain)\"\n\tcertissuer_domain=\"${certissuer_domain:-certissuer.$stack.$root_domain}\"\n\tam_domain=\"$(env_file_value \"$am_env\" ACCOUNT_MANAGER_LINODE_DOMAIN)\"\n\tam_domain=\"${am_domain:-account-manager.$stack.$root_domain}\"\n\tadmin_domain=\"$(env_file_value \"$admin_env\" ADMIN_LINODE_DOMAIN)\"\n\tadmin_domain=\"${admin_domain:-admin.$stack.$root_domain}\"\n\n\tlabel_prefix=\"$stack\"\n\tvpc_label=\"$(yaml_path_value \"$video_config\" vpc.label)\"\n\tvpc_label=\"${vpc_label:-$label_prefix-vpc}\"\n\tsubnet_label=\"$(yaml_path_value \"$video_config\" vpc.subnet.label)\"\n\tsubnet_label=\"${subnet_label:-$label_prefix-subnet}\"\n\tam_label=\"$(env_file_value \"$am_env\" ACCOUNT_MANAGER_LINODE_LABEL)\"\n\tam_label=\"${am_label:-rtk-account-manager-$env_name}\"\n\tam_fw_label=\"$(env_file_value \"$am_env\" ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL)\"\n\tam_fw_label=\"${am_fw_label:-$am_label-fw}\"\n\tadmin_label=\"$(env_file_value \"$admin_env\" ADMIN_LINODE_LABEL)\"\n\tadmin_label=\"${admin_label:-rtk-cloud-admin-$env_name}\"\n\tadmin_fw_label=\"$(env_file_value \"$admin_env\" ADMIN_LINODE_FIREWALL_LABEL)\"\n\tadmin_fw_label=\"${admin_fw_label:-$admin_label-firewall}\"\n\n\tmkdir -p \"$(dirname \"$dst\")\"\n\t{\n\t\tprintf 'CLOUD_ENV_NAME=%s\\n' \"$env_name\"\n\t\tprintf 'CLOUD_PROVIDER=%s\\n' \"$provider\"\n\t\tprintf 'CLOUD_REGION=%s\\n' \"$region\"\n\t\tprintf 'CLOUD_DNS_ROOT_DOMAIN=%s\\n' \"$root_domain\"\n\t\tprintf 'CLOUD_STACK_NAME=%s\\n' \"$stack\"\n\t\tprintf '\\n'\n\t\tprintf 'VIDEO_CLOUD_DOMAIN=%s\\n' \"$video_domain\"\n\t\tprintf 'VIDEO_CLOUD_CERTISSUER_DOMAIN=%s\\n' \"$certissuer_domain\"\n\t\tprintf 'ACCOUNT_MANAGER_DOMAIN=%s\\n' \"$am_domain\"\n\t\tprintf 'CLOUD_ADMIN_DOMAIN=%s\\n' \"$admin_domain\"\n\t\tprintf '\\n'\n\t\tprintf 'VIDEO_CLOUD_LABEL_PREFIX=%s\\n' \"$label_prefix\"\n\t\tprintf 'VIDEO_CLOUD_VPC_LABEL=%s\\n' \"$vpc_label\"\n\t\tprintf 'VIDEO_CLOUD_SUBNET_LABEL=%s\\n' \"$subnet_label\"\n\t\tprintf 'ACCOUNT_MANAGER_LINODE_LABEL=%s\\n' \"$am_label\"\n\t\tprintf 'ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL=%s\\n' \"$am_fw_label\"\n\t\tprintf 'ADMIN_LINODE_LABEL=%s\\n' \"$admin_label\"\n\t\tprintf 'ADMIN_LINODE_FIREWALL_LABEL=%s\\n' \"$admin_fw_label\"\n\t} > \"$dst\"\n\trecord_manifest \"stack-metadata\" \"$dst\" \"$dst\" \"generated\" \"$(sha256_file \"$dst\")\"\n}\n\nneed_cmd jq\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nSTAMP=\"$(date -u +%Y%m%dT%H%M%SZ)\"\nBACKUP_DIR=\"$ENV_ROOT/backups/migration-$STAMP\"\nMANIFEST_JSONL=\"$BACKUP_DIR/migration-manifest.jsonl\"\nMANIFEST_TSV=\"$BACKUP_DIR/migration-manifest.tsv\"\nmkdir -p \"$BACKUP_DIR\"\nprintf 'kind\\tsource\\ttarget\\tstatus\\tsha256\\n' > \"$MANIFEST_TSV\"\n: > \"$MANIFEST_JSONL\"\n\nlog \"workspace=$WORKSPACE\"\nlog \"env_root=$ENV_ROOT\"\nlog \"backup=$BACKUP_DIR\"\n\ncopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/operator.env\" \"$(cloud_env_operator_env \"$ENV_ROOT\")\" \"operator-env\"\ncopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/config/video-cloud-staging.yaml\" \"$(cloud_env_video_config \"$ENV_ROOT\")\" \"topology\"\ncopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/video-cloud-staging.env\" \"$(cloud_env_video_env \"$ENV_ROOT\")\" \"service-env\"\ncopy_file \"$WORKSPACE/repos/rtk_account_manager/linode_deploy/secrets/account-manager-public-staging.env\" \"$(cloud_env_account_manager_env \"$ENV_ROOT\")\" \"service-env\"\ncopy_file \"$WORKSPACE/repos/rtk_account_manager/linode_deploy/secrets/account-manager-platform-admin.env\" \"$(cloud_env_account_manager_platform_admin_env \"$ENV_ROOT\")\" \"service-env\"\ncopy_file \"$WORKSPACE/repos/rtk_cloud_admin/deploy/linode/admin-staging.env\" \"$(cloud_env_admin_env \"$ENV_ROOT\")\" \"service-env\"\nif [[ -f \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/stack.env\" ]]; then\n\tcopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/stack.env\" \"$(cloud_env_stack_env \"$ENV_ROOT\")\" \"stack-metadata\"\nelif [[ -f \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/environment.env\" ]]; then\n\tcopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/env/environment.env\" \"$(cloud_env_stack_env \"$ENV_ROOT\")\" \"stack-metadata\"\nelse\n\twrite_environment_metadata\nfi\n\nif [[ -f \"$WORKSPACE/repos/rtk_video_cloud/linode_deploy/state/video-cloud-staging.state.json\" ]]; then\n\tcopy_file \"$WORKSPACE/repos/rtk_video_cloud/linode_deploy/state/video-cloud-staging.state.json\" \"$(cloud_env_video_state \"$ENV_ROOT\")\" \"state\"\nelse\n\tcopy_file \"$WORKSPACE/.secrets/staging/linode/video-cloud/state/video-cloud-staging.state.json\" \"$(cloud_env_video_state \"$ENV_ROOT\")\" \"state\"\nfi\ncopy_file \"$WORKSPACE/repos/rtk_account_manager/linode_deploy/state/rtk-account-manager-staging.env\" \"$(cloud_env_account_manager_state \"$ENV_ROOT\")\" \"state\"\ncopy_file \"$WORKSPACE/repos/rtk_cloud_admin/deploy/linode/rtk-cloud-admin-staging.state\" \"$(cloud_env_admin_state \"$ENV_ROOT\")\" \"state\"\n\ncopy_dir_contents \"$WORKSPACE/keys/staging/linode\" \"$(cloud_env_keys_dir \"$ENV_ROOT\")\" \"keys\"\ncopy_dir_contents \"$WORKSPACE/keys/test_device\" \"$(cloud_env_test_devices_dir \"$ENV_ROOT\")\" \"devices\"\ncopy_dir_contents \"$WORKSPACE/.secrets/staging/linode/video-cloud/artifacts\" \"$(cloud_env_artifacts_dir \"$ENV_ROOT\")\" \"artifacts\"\n\nlog \"migration manifest: $MANIFEST_TSV\"\nprintf 'env_root=%s\\n' \"$ENV_ROOT\"\nprintf 'backup=%s\\n' \"$BACKUP_DIR\"\nprintf 'manifest=%s\\n' \"$MANIFEST_TSV\"\n",
	"cloud-provision.sh":                        "#!/usr/bin/env bash\nif [ -z \"${BASH_VERSION:-}\" ]; then\n\texec /usr/bin/env bash \"$0\" \"$@\"\nfi\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nOPERATOR_ENV=\"\"\nSSH_KEY=\"$HOME/.ssh/id_ed25519_rtkcloud\"\nDNS_ROOT_DOMAIN=\"realtekconnect.com\"\nDNS_ROOT_DOMAIN_EXPLICIT=0\nGODADDY_ENVIRONMENT=\"prod\"\nDNS_WAIT_TTL=\"${GODADDY_WAIT_TTL:-${GODADDY_RECORD_WAIT_TTL:-600}}\"\nDNS_FINAL_TTL=\"${GODADDY_RECORD_TTL:-600}\"\nGODADDY_MIN_TTL=600\nDNS_WAIT_MAX_SECONDS=\"${DNS_WAIT_MAX_SECONDS:-700}\"\nDNS_WAIT_INTERVAL_SECONDS=\"${DNS_WAIT_INTERVAL_SECONDS:-10}\"\nARTIFACT_BASE=\"\"\nCONFIRM=\"\"\nVERBOSE=0\nVIDEO_RELEASE=\"${VIDEO_RELEASE:-}\"\nACCOUNT_RELEASE=\"${ACCOUNT_RELEASE:-}\"\nADMIN_RELEASE=\"${ADMIN_RELEASE:-}\"\nOBJECT_STORAGE_BIN=\"\"\n\nDO_PREFLIGHT=0\nDO_PLAN=0\nDO_RESET=0\nDO_APPLY=0\nDO_DNS=0\nDO_DEPLOY=0\nDO_ARTIFACTS=0\nDO_E2E=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tprintf '[cloud-provision] %s\\n' \"$*\" >&2\n}\n\ndebug() {\n\tif [[ \"$VERBOSE\" == \"1\" ]]; then\n\t\tprintf '[cloud-provision:debug] %s\\n' \"$*\" >&2\n\tfi\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-provision.sh [modes] [options]\n  scripts/cloud-provision.sh --env-root cloud_env/staging  # default: --plan\n\nModes:\n  default                            Same as --plan; read-only.\n  --preflight                         Check local tools, env, credentials, SSH key, and optional release artifact.\n  --plan                              Print current and intended cloud resources without mutation.\n  --reset --confirm <stack-name>       Delete the 7 target VMs, 7 firewalls, and Video Cloud VPC.\n  --apply                             Create/recreate the 7 target VMs and Video Cloud VPC.\n  --dns                               Upsert and wait for the 4 staging A records.\n  --deploy                            Deploy Video Cloud, Account Manager, and Cloud Admin releases.\n  --artifacts                         Write combined provision artifacts.\n  --e2e                               Run public endpoint smoke checks and write an E2E report.\n  --all                               preflight -> plan -> apply -> dns -> deploy -> artifacts -> e2e.\n  --reset-and-all --confirm ...       preflight -> plan -> reset -> apply -> dns -> deploy -> artifacts -> e2e.\n\nOptions:\n  --workspace PATH                    Default: script parent workspace.\n  --operator-env PATH                 Default: <env-root>/env/operator.env.\n  --env-root PATH                     Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH                 Deprecated alias for --env-root.\n  --ssh-key PATH                      Default: ~/.ssh/id_ed25519_rtkcloud.\n  --dns-root-domain NAME              Default: realtekconnect.com.\n  --godaddy-env ENV                   Default: prod.\n  --dns-wait-ttl SECONDS              TTL used while waiting for DNS convergence. Default: GODADDY_WAIT_TTL, GODADDY_RECORD_WAIT_TTL, or 600.\n  --dns-final-ttl SECONDS             TTL restored after DNS convergence. Default: GODADDY_RECORD_TTL or 600.\n  --dns-ttl SECONDS                   Backward-compatible alias for --dns-final-ttl.\n  --dns-wait-max-seconds SECONDS      Max DNS convergence wait per hostname. Default: 700.\n  --artifact-dir PATH                 Default: <env-root>/artifacts.\n  --video-release VERSION             Optional; otherwise select from Object Storage releases.\n  --account-release VERSION           Optional; otherwise select from Object Storage releases.\n  --admin-release VERSION             Optional; otherwise select from Object Storage releases.\n  --verbose                           Print extra diagnostics.\n  -h, --help                          Show this help.\n\nSafety:\n  reset requires --confirm matching CLOUD_STACK_NAME. DNS and Object Storage are never deleted.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--preflight) DO_PREFLIGHT=1; shift ;;\n\t--plan) DO_PLAN=1; shift ;;\n\t--reset) DO_RESET=1; shift ;;\n\t--apply) DO_APPLY=1; shift ;;\n\t--dns) DO_DNS=1; shift ;;\n\t--deploy) DO_DEPLOY=1; shift ;;\n\t--artifacts) DO_ARTIFACTS=1; shift ;;\n\t--e2e) DO_E2E=1; shift ;;\n\t--all)\n\t\tDO_PREFLIGHT=1; DO_PLAN=1; DO_APPLY=1; DO_DNS=1; DO_DEPLOY=1; DO_ARTIFACTS=1; DO_E2E=1; shift ;;\n\t--reset-and-all)\n\t\tDO_PREFLIGHT=1; DO_PLAN=1; DO_RESET=1; DO_APPLY=1; DO_DNS=1; DO_DEPLOY=1; DO_ARTIFACTS=1; DO_E2E=1; shift ;;\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--operator-env) OPERATOR_ENV=\"$2\"; shift 2 ;;\n\t--secrets-root) DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--ssh-key) SSH_KEY=\"$2\"; shift 2 ;;\n\t--dns-root-domain) DNS_ROOT_DOMAIN=\"$2\"; DNS_ROOT_DOMAIN_EXPLICIT=1; shift 2 ;;\n\t--godaddy-env) GODADDY_ENVIRONMENT=\"$2\"; shift 2 ;;\n\t--dns-wait-ttl) DNS_WAIT_TTL=\"$2\"; shift 2 ;;\n\t--dns-final-ttl|--dns-ttl) DNS_FINAL_TTL=\"$2\"; shift 2 ;;\n\t--dns-wait-max-seconds) DNS_WAIT_MAX_SECONDS=\"$2\"; shift 2 ;;\n\t--artifact-dir) ARTIFACT_BASE=\"$2\"; shift 2 ;;\n\t--video-release) VIDEO_RELEASE=\"$2\"; shift 2 ;;\n\t--account-release) ACCOUNT_RELEASE=\"$2\"; shift 2 ;;\n\t--admin-release) ADMIN_RELEASE=\"$2\"; shift 2 ;;\n\t--confirm) CONFIRM=\"$2\"; shift 2 ;;\n\t--verbose) VERBOSE=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nif [[ \"$DO_PREFLIGHT$DO_PLAN$DO_RESET$DO_APPLY$DO_DNS$DO_DEPLOY$DO_ARTIFACTS$DO_E2E\" == \"00000000\" ]]; then\n\tDO_PLAN=1\nfi\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\n[[ \"$DNS_WAIT_TTL\" =~ ^[0-9]+$ && \"$DNS_WAIT_TTL\" -gt 0 ]] || die \"--dns-wait-ttl must be a positive integer\"\n[[ \"$DNS_FINAL_TTL\" =~ ^[0-9]+$ && \"$DNS_FINAL_TTL\" -gt 0 ]] || die \"--dns-final-ttl must be a positive integer\"\n[[ \"$DNS_WAIT_MAX_SECONDS\" =~ ^[0-9]+$ && \"$DNS_WAIT_MAX_SECONDS\" -gt 0 ]] || die \"--dns-wait-max-seconds must be a positive integer\"\n[[ \"$DNS_WAIT_INTERVAL_SECONDS\" =~ ^[0-9]+$ && \"$DNS_WAIT_INTERVAL_SECONDS\" -gt 0 ]] || die \"DNS_WAIT_INTERVAL_SECONDS must be a positive integer\"\n[[ \"$DNS_WAIT_TTL\" -ge \"$GODADDY_MIN_TTL\" ]] || die \"--dns-wait-ttl must be >= $GODADDY_MIN_TTL for GoDaddy DNS records\"\n[[ \"$DNS_FINAL_TTL\" -ge \"$GODADDY_MIN_TTL\" ]] || die \"--dns-final-ttl must be >= $GODADDY_MIN_TTL for GoDaddy DNS records\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nif [[ \"$DNS_ROOT_DOMAIN_EXPLICIT\" == \"1\" ]]; then\n\tcloud_env_load_environment \"$ENV_ROOT\" \"$DNS_ROOT_DOMAIN\"\nelse\n\tcloud_env_load_environment \"$ENV_ROOT\" \"\"\nfi\nDNS_ROOT_DOMAIN=\"$CLOUD_DNS_ROOT_DOMAIN\"\ncloud_env_validate_environment \"$ENV_ROOT\"\ncloud_env_export_filter_vars\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\nOPERATOR_ENV=\"${OPERATOR_ENV:-$(cloud_env_operator_env \"$ENV_ROOT\")}\"\nARTIFACT_BASE=\"${ARTIFACT_BASE:-$(cloud_env_artifacts_dir \"$ENV_ROOT\")}\"\n\nVC_REPO=\"$WORKSPACE/repos/rtk_video_cloud\"\nAM_REPO=\"$WORKSPACE/repos/rtk_account_manager\"\nADMIN_REPO=\"$WORKSPACE/repos/rtk_cloud_admin\"\n\nVC_CONFIG=\"$(cloud_env_video_config \"$ENV_ROOT\")\"\nVC_STATE=\"$(cloud_env_video_state \"$ENV_ROOT\")\"\nVC_SECRET_STATE=\"$VC_STATE\"\nVC_SECRETS_FILE=\"$(cloud_env_video_env \"$ENV_ROOT\")\"\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nADMIN_ENV=\"$(cloud_env_admin_env \"$ENV_ROOT\")\"\nADMIN_STATE=\"$(cloud_env_admin_state \"$ENV_ROOT\")\"\nCLOUD_DEPLOY_SCRIPT=\"${CLOUD_DEPLOY_SCRIPT:-${STAGING_DEPLOY_SCRIPT:-$SCRIPT_DIR/cloud-deploy.sh}}\"\n\nVC_GATEWAY_DOMAIN=\"$VIDEO_CLOUD_DOMAIN\"\nVC_CERTISSUER_DOMAIN=\"$VIDEO_CLOUD_CERTISSUER_DOMAIN\"\nAM_DOMAIN=\"$ACCOUNT_MANAGER_DOMAIN\"\nADMIN_DOMAIN=\"$CLOUD_ADMIN_DOMAIN\"\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\tif [[ -f \"$path\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$path\"\n\t\tset +a\n\tfi\n}\n\nenv_file_has_key() {\n\tlocal path=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$path\" ]] && grep -Eq \"^${key}=\" \"$path\"\n}\n\nappend_secret_if_missing() {\n\tlocal path=\"$1\"\n\tlocal key=\"$2\"\n\tlocal value=\"$3\"\n\tif ! env_file_has_key \"$path\" \"$key\"; then\n\t\tprintf '%s=%s\\n' \"$key\" \"$value\" >> \"$path\"\n\t\tlog \"generated Video Cloud secret: $key\"\n\tfi\n}\n\nensure_video_cloud_factory_enroll_secrets() {\n\tmkdir -p \"$(dirname \"$VC_SECRETS_FILE\")\"\n\ttouch \"$VC_SECRETS_FILE\"\n\tchmod 0600 \"$VC_SECRETS_FILE\"\n\tlocal key_dir=\"$WORKSPACE/keys/staging/linode/video-cloud\"\n\tlocal edge_private_ip\n\tedge_private_ip=\"$(cloud_env_yaml_path_value \"$VC_CONFIG\" instances.edge.private_ip)\"\n\tedge_private_ip=\"${edge_private_ip:-10.42.1.5}\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_URL \"https://$VC_GATEWAY_DOMAIN\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_AUTH_KEY \"$(openssl rand -hex 32)\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_AUDIT_LOG_PATH \"/var/log/video_cloud/factoryenroll-audit.jsonl\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_CERT_ISSUER_URL \"https://$VC_CERTISSUER_DOMAIN\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_CERT_ISSUER_PROXY_URL \"http://$edge_private_ip:3128\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_CERT_ISSUER_CLIENT_CERT_SOURCE \"$key_dir/factoryenroll-client.ed25519.cert.pem\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_CERT_ISSUER_CLIENT_KEY_SOURCE \"$key_dir/factoryenroll-client.ed25519.key.pem\"\n\tappend_secret_if_missing \"$VC_SECRETS_FILE\" FACTORY_ENROLL_CERT_ISSUER_CA_SOURCE \"$key_dir/root-ca.ed25519.cert.pem\"\n}\n\nload_operator_env() {\n\t[[ -f \"$OPERATOR_ENV\" ]] || die \"operator env not found: $OPERATOR_ENV\"\n\tload_env_file \"$OPERATOR_ENV\"\n\t[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n}\n\nlinode_api() {\n\tlocal method=\"$1\"\n\tlocal path=\"$2\"\n\tlocal data=\"${3:-}\"\n\tif [[ -n \"$data\" ]]; then\n\t\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t\t-H 'Content-Type: application/json' \\\n\t\t\t--data-binary \"$data\"\n\telse\n\t\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t\t-H 'Content-Type: application/json'\n\tfi\n}\n\nlinode_delete_ignore_missing() {\n\tlocal path=\"$1\"\n\tlocal err\n\tif err=\"$(linode_api DELETE \"$path\" 2>&1 >/dev/null)\"; then\n\t\treturn 0\n\tfi\n\tif [[ \"$err\" == *\"404\"* || \"$err\" == *\"provided ID did not match\"* || \"$err\" == *\"not found\"* ]]; then\n\t\tlog \"delete skipped; already gone: $path\"\n\t\treturn 0\n\tfi\n\tprintf '%s\\n' \"$err\" >&2\n\treturn 1\n}\n\nobject_storage_go() {\n\tif [[ -z \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\tOBJECT_STORAGE_BIN=\"${TMPDIR:-/tmp}/rtk-linode-object-storage\"\n\t\tif [[ ! -x \"$OBJECT_STORAGE_BIN\" || \"$SCRIPT_DIR/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\t\t(\n\t\t\t\tlock=\"$OBJECT_STORAGE_BIN.lock\"\n\t\t\t\twhile ! mkdir \"$lock\" 2>/dev/null; do\n\t\t\t\t\tsleep 0.2\n\t\t\t\tdone\n\t\t\t\ttrap 'rmdir \"$lock\" 2>/dev/null || true' EXIT\n\t\t\t\tif [[ -x \"$OBJECT_STORAGE_BIN\" && ! \"$SCRIPT_DIR/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n\t\t\t\t\texit 0\n\t\t\t\tfi\n\t\t\t\tcd \"$SCRIPT_DIR/go/linode-object-storage\"\n\t\t\t\tgo build -o \"$OBJECT_STORAGE_BIN.$$\" .\n\t\t\t\tmv \"$OBJECT_STORAGE_BIN.$$\" \"$OBJECT_STORAGE_BIN\"\n\t\t\t)\n\t\tfi\n\tfi\n\t\"$OBJECT_STORAGE_BIN\" \"$@\"\n}\n\nlist_release_manifest_keys() {\n\tlocal prefix=\"$1\"\n\tobject_storage_go list-manifests --release-prefix \"$prefix\"\n}\n\nversion_from_manifest_key() {\n\tlocal prefix=\"$1\"\n\tlocal key=\"$2\"\n\tkey=\"${key#releases/$prefix-}\"\n\tprintf '%s\\n' \"${key%/manifest.json}\"\n}\n\nselect_release_manifest_key() {\n\tlocal display=\"$1\"\n\tlocal prefix=\"$2\"\n\tlocal list_file count i line modified key version choice\n\tlist_file=\"$(mktemp \"/tmp/${prefix}-releases.XXXXXX\")\"\n\tlist_release_manifest_keys \"$prefix\" > \"$list_file\"\n\tcount=\"$(wc -l < \"$list_file\" | tr -d ' ')\"\n\tif [[ \"$count\" == \"0\" ]]; then\n\t\trm -f \"$list_file\"\n\t\tdie \"no $prefix release manifest found in Object Storage under releases/\"\n\tfi\n\tprintf 'Available %s releases in Object Storage:\\n' \"$display\" >&2\n\ti=1\n\twhile IFS=$'\\t' read -r modified key; do\n\t\tversion=\"$(version_from_manifest_key \"$prefix\" \"$key\")\"\n\t\tprintf '  %d) %s  %s\\n' \"$i\" \"$version\" \"$modified\" >&2\n\t\ti=$((i + 1))\n\tdone < \"$list_file\"\n\tif [[ -t 0 ]]; then\n\t\tprintf 'Select %s release [1]: ' \"$display\" >&2\n\t\tread -r choice\n\t\tchoice=\"${choice:-1}\"\n\telse\n\t\tchoice=1\n\t\tlog \"non-interactive shell; selecting newest $display Object Storage release\"\n\tfi\n\tif ! [[ \"$choice\" =~ ^[0-9]+$ ]] || (( choice < 1 || choice > count )); then\n\t\trm -f \"$list_file\"\n\t\tdie \"invalid release selection: $choice\"\n\tfi\n\tline=\"$(sed -n \"${choice}p\" \"$list_file\")\"\n\trm -f \"$list_file\"\n\tprintf '%s\\n' \"${line#*$'\\t'}\"\n}\n\ncheck_object_storage_release() {\n\tlocal display=\"$1\"\n\tlocal prefix=\"$2\"\n\tlocal requested=\"$3\"\n\t[[ -n \"${LINODE_OBJ_BUCKET:-}\" ]] || die \"LINODE_OBJ_BUCKET is required\"\n\t[[ -n \"${LINODE_OBJ_ENDPOINT:-}\" ]] || die \"LINODE_OBJ_ENDPOINT is required\"\n\tneed_cmd go\n\tlocal manifest_key manifest version object_key\n\tif [[ -n \"$requested\" ]]; then\n\t\tmanifest_key=\"releases/$prefix-$requested/manifest.json\"\n\telse\n\t\tmanifest_key=\"$(select_release_manifest_key \"$display\" \"$prefix\")\"\n\tfi\n\tmanifest=\"$(object_storage_go cat --key \"$manifest_key\")\"\n\tversion=\"$(jq -r '.version // empty' <<<\"$manifest\")\"\n\tobject_key=\"$(jq -r '.artifact_path // empty' <<<\"$manifest\")\"\n\t[[ -n \"$version\" ]] || die \"latest Object Storage manifest missing version: $manifest_key\"\n\t[[ -n \"$object_key\" ]] || die \"latest Object Storage manifest missing artifact_path: $manifest_key\"\n\t[[ -z \"$requested\" || \"$requested\" == \"$version\" ]] || die \"$display manifest version mismatch: requested $requested but $manifest_key contains $version\"\n\tlog \"selected $display Object Storage release: $version\"\n\tobject_storage_go exists --key \"$object_key\"\n\tlog \"$display Object Storage release readable: $object_key\"\n\tprintf '%s\\n' \"$version\"\n}\n\ncheck_latest_video_release() {\n\tlocal release\n\trelease=\"$(check_object_storage_release \"Video Cloud\" \"rtk_video_cloud\" \"$VIDEO_RELEASE\")\" || return\n\tVIDEO_RELEASE=\"$release\"\n}\n\ncheck_latest_account_release() {\n\tlocal release\n\trelease=\"$(check_object_storage_release \"Account Manager\" \"rtk_account_manager\" \"$ACCOUNT_RELEASE\")\" || return\n\tACCOUNT_RELEASE=\"$release\"\n}\n\ncheck_latest_admin_release() {\n\tlocal release\n\trelease=\"$(check_object_storage_release \"Cloud Admin\" \"rtk_cloud_admin\" \"$ADMIN_RELEASE\")\" || return\n\tADMIN_RELEASE=\"$release\"\n}\n\nresolve_deploy_releases() {\n\tif [[ -z \"$VIDEO_RELEASE\" ]]; then\n\t\tcheck_latest_video_release\n\tfi\n\tif [[ -z \"$ACCOUNT_RELEASE\" ]]; then\n\t\tcheck_latest_account_release\n\tfi\n\tif [[ -z \"$ADMIN_RELEASE\" ]]; then\n\t\tcheck_latest_admin_release\n\tfi\n\tlog \"deploy releases: video=$VIDEO_RELEASE account=$ACCOUNT_RELEASE admin=$ADMIN_RELEASE\"\n}\n\nexpand_path() {\n\tlocal path=\"$1\"\n\tcase \"$path\" in\n\t~/*) printf '%s/%s\\n' \"$HOME\" \"${path#~/}\" ;;\n\t*) printf '%s\\n' \"$path\" ;;\n\tesac\n}\n\ncurrent_public_cidr() {\n\tlocal ip\n\tip=\"$(curl -fsS https://api.ipify.org || true)\"\n\t[[ -n \"$ip\" ]] || return 1\n\tprintf '%s/32\\n' \"$ip\"\n}\n\nrecord_name_for_domain() {\n\tlocal domain=\"$1\"\n\tif [[ \"$domain\" == \"$DNS_ROOT_DOMAIN\" ]]; then\n\t\tprintf '@\\n'\n\t\treturn\n\tfi\n\t[[ \"$domain\" == *\".$DNS_ROOT_DOMAIN\" ]] || die \"domain is not under $DNS_ROOT_DOMAIN: $domain\"\n\tprintf '%s\\n' \"${domain%.$DNS_ROOT_DOMAIN}\"\n}\n\ngodaddy_tool() {\n\tprintf '%s/tools/godaddy-dns\\n' \"$VC_REPO\"\n}\n\ngodaddy_upsert_a() {\n\tlocal domain=\"$1\"\n\tlocal ip=\"$2\"\n\tlocal ttl=\"$3\"\n\tlocal purpose=\"${4:-update}\"\n\tlocal name\n\tlocal attempt delay=5\n\tname=\"$(record_name_for_domain \"$domain\")\"\n\tfor attempt in $(seq 1 5); do\n\t\tlog \"GoDaddy upsert $purpose attempt $attempt/5: $domain A $ip ttl=$ttl\"\n\t\tif (\n\t\t\tcd \"$(godaddy_tool)\"\n\t\t\tGODADDY_ENV=\"$GODADDY_ENVIRONMENT\" go run ./cmd/godaddy-dns \\\n\t\t\t\t--env-file \"$OPERATOR_ENV\" \\\n\t\t\t\trecords upsert \"$DNS_ROOT_DOMAIN\" --type A --name \"$name\" --data \"$ip\" --ttl \"$ttl\"\n\t\t); then\n\t\t\treturn 0\n\t\tfi\n\t\tlog \"GoDaddy upsert $purpose failed for $domain attempt $attempt/5; retrying in ${delay}s\"\n\t\tsleep \"$delay\"\n\t\tdelay=$((delay * 2))\n\tdone\n\treturn 1\n}\n\nresolve_dns() {\n\tlocal server=\"$1\"\n\tlocal domain=\"$2\"\n\tdig +short \"@$server\" \"$domain\" | tail -n 1 || true\n}\n\nauthoritative_ns() {\n\tdig NS \"$DNS_ROOT_DOMAIN\" +short | head -n 1\n}\n\nwait_dns() {\n\tlocal domain=\"$1\"\n\tlocal ip=\"$2\"\n\tlocal ns\n\tlocal got_google got_auth attempt max_attempts\n\tmax_attempts=$(((DNS_WAIT_MAX_SECONDS + DNS_WAIT_INTERVAL_SECONDS - 1) / DNS_WAIT_INTERVAL_SECONDS))\n\tns=\"$(authoritative_ns)\"\n\t[[ -n \"$ns\" ]] || die \"could not resolve authoritative NS for $DNS_ROOT_DOMAIN\"\n\tfor attempt in $(seq 1 \"$max_attempts\"); do\n\t\tgot_google=\"$(resolve_dns 8.8.8.8 \"$domain\")\"\n\t\tgot_auth=\"$(resolve_dns \"$ns\" \"$domain\")\"\n\t\tif [[ \"$got_google\" == \"$ip\" && \"$got_auth\" == \"$ip\" ]]; then\n\t\t\tlog \"DNS converged: $domain -> $ip\"\n\t\t\treturn 0\n\t\tfi\n\t\tlog \"waiting DNS attempt $attempt/$max_attempts: $domain expected=$ip google=${got_google:-<empty>} auth=${got_auth:-<empty>}\"\n\t\tsleep \"$DNS_WAIT_INTERVAL_SECONDS\"\n\tdone\n\tdie \"DNS did not converge: $domain expected=$ip google=${got_google:-<empty>} auth=${got_auth:-<empty>}\"\n}\n\ntarget_instance_filter='\n\t.data[]\n\t| select(\n\t\t.label == env.ADMIN_LINODE_LABEL\n\t\tor .label == env.ACCOUNT_MANAGER_LINODE_LABEL\n\t\tor ((.label | startswith(env.VIDEO_CLOUD_LABEL_PREFIX + \"-\")) and ((.tags // []) | index(env.CLOUD_STACK_NAME)))\n\t)\n'\n\ntarget_firewall_filter='\n\t.data[]\n\t| select(\n\t\t.label == env.ADMIN_LINODE_FIREWALL_LABEL\n\t\tor .label == env.ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL\n\t\tor ((.label | startswith(env.VIDEO_CLOUD_LABEL_PREFIX + \"-\")) and ((.tags // []) | index(env.CLOUD_STACK_NAME)))\n\t)\n'\n\npreflight() {\n\tlog \"preflight\"\n\tfor cmd in curl jq dig ssh openssl go tar; do\n\t\tneed_cmd \"$cmd\"\n\tdone\n\tensure_video_cloud_factory_enroll_secrets\n\t[[ -d \"$VC_REPO\" ]] || die \"missing submodule: $VC_REPO\"\n\t[[ -d \"$AM_REPO\" ]] || die \"missing submodule: $AM_REPO\"\n\t[[ -d \"$ADMIN_REPO\" ]] || die \"missing submodule: $ADMIN_REPO\"\n\t[[ -f \"$VC_CONFIG\" ]] || die \"missing Video Cloud config: $VC_CONFIG\"\n\t[[ -f \"$VC_SECRETS_FILE\" ]] || die \"missing Video Cloud secrets file: $VC_SECRETS_FILE\"\n\t[[ -f \"$AM_ENV\" ]] || die \"missing Account Manager env: $AM_ENV\"\n\t[[ -f \"$ADMIN_ENV\" ]] || die \"missing Cloud Admin env: $ADMIN_ENV\"\n\t[[ -f \"$SSH_KEY\" ]] || die \"missing SSH key: $SSH_KEY\"\n\t[[ -f \"$SSH_KEY.pub\" ]] || die \"missing SSH public key: $SSH_KEY.pub\"\n\tload_operator_env\n\t[[ -n \"${GODADDY_KEY:-${GODADDY_API_KEY:-}}\" ]] || die \"GoDaddy key is required\"\n\t[[ -n \"${GODADDY_SECRET:-${GODADDY_API_SECRET:-}}\" ]] || die \"GoDaddy secret is required\"\n\tlocal cidr\n\tcidr=\"$(current_public_cidr)\" || die \"could not determine current public IP\"\n\tlog \"operator public CIDR: $cidr\"\n\tcheck_latest_video_release\n\tcheck_latest_account_release\n\tcheck_latest_admin_release\n\tif [[ \"$DO_DEPLOY\" == \"1\" ]]; then\n\t\tresolve_deploy_releases\n\tfi\n}\n\nplan() {\n\tlog \"plan\"\n\tload_operator_env\n\tlocal instances firewalls vpcs\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\tvpcs=\"$(linode_api GET '/vpcs?page_size=500')\"\n\tprintf 'Target instances:\\n'\n\tjq -r \"$target_instance_filter | [.id,.label,.region,.type,.status,((.ipv4 // []) | join(\\\",\\\")),((.tags // []) | join(\\\",\\\"))] | @tsv\" <<<\"$instances\" || true\n\tprintf '\\nTarget firewalls:\\n'\n\tjq -r \"$target_firewall_filter | [.id,.label,.status,((.tags // []) | join(\\\",\\\"))] | @tsv\" <<<\"$firewalls\" || true\n\tprintf '\\nTarget VPCs:\\n'\n\tjq -r --arg label \"$VIDEO_CLOUD_VPC_LABEL\" '.data[] | select(.label == $label) | [.id,.label,.region] | @tsv' <<<\"$vpcs\" || true\n\tprintf '\\nIntended resources:\\n'\n\tcat <<EOF_PLAN\n- instances: $VIDEO_CLOUD_LABEL_PREFIX-edge/api/infra/mqtt/coturn, $ACCOUNT_MANAGER_LINODE_LABEL, $ADMIN_LINODE_LABEL\n- firewalls: $VIDEO_CLOUD_LABEL_PREFIX-edge/api/infra/mqtt/coturn, $ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL, $ADMIN_LINODE_FIREWALL_LABEL\n- vpc/subnet: $VIDEO_CLOUD_VPC_LABEL / $VIDEO_CLOUD_SUBNET_LABEL\n- dns: $VC_GATEWAY_DOMAIN, $VC_CERTISSUER_DOMAIN, $AM_DOMAIN, $ADMIN_DOMAIN\nEOF_PLAN\n}\n\nbackup_state_files() {\n\tlocal ts backup_dir\n\tts=\"$(date -u +%Y%m%dT%H%M%SZ)\"\n\tbackup_dir=\"$DEPRECATED_ENV_ROOT/full-reset-backup-$ts\"\n\tmkdir -p \"$backup_dir\"\n\tfor file in \"$VC_STATE\" \"$VC_SECRET_STATE\" \"$AM_STATE\" \"$ADMIN_STATE\"; do\n\t\tif [[ -f \"$file\" ]]; then\n\t\t\tmkdir -p \"$backup_dir/$(dirname \"${file#$WORKSPACE/}\")\"\n\t\t\tcp \"$file\" \"$backup_dir/${file#$WORKSPACE/}\"\n\t\tfi\n\tdone\n\tprintf '%s\\n' \"$backup_dir\"\n}\n\nreset_stack() {\n\t[[ \"$CONFIRM\" == \"$CLOUD_STACK_NAME\" ]] || die \"reset requires --confirm $CLOUD_STACK_NAME\"\n\tlog \"reset\"\n\tload_operator_env\n\tlocal backup_dir tmp instances firewalls vpcs count remaining\n\tbackup_dir=\"$(backup_state_files)\"\n\tlog \"state backup: $backup_dir\"\n\ttmp=\"$(mktemp -d /tmp/rtk-staging-reset.XXXXXX)\"\n\ttrap 'rm -rf \"$tmp\"' RETURN\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tjq -r \"$target_instance_filter | .id\" <<<\"$instances\" > \"$tmp/instance_ids\"\n\tjq -r \"$target_instance_filter | .label\" <<<\"$instances\" > \"$tmp/instance_labels\"\n\tcount=\"$(wc -l < \"$tmp/instance_ids\" | tr -d ' ')\"\n\tif [[ \"$count\" != \"0\" && \"$count\" != \"7\" ]]; then\n\t\tcat \"$tmp/instance_labels\" >&2\n\t\tdie \"partial target instance set found: $count/7. Refusing reset.\"\n\tfi\n\tif [[ \"$count\" == \"7\" ]]; then\n\t\tlog \"deleting instances: $(paste -sd ' ' \"$tmp/instance_labels\")\"\n\t\twhile IFS= read -r id; do\n\t\t\t[[ -n \"$id\" ]] && linode_delete_ignore_missing \"/linode/instances/$id\"\n\t\tdone < \"$tmp/instance_ids\"\n\t\tfor _ in $(seq 1 60); do\n\t\t\tremaining=\"$(linode_api GET '/linode/instances?page_size=500' | jq -r \"[$target_instance_filter] | length\")\"\n\t\t\t[[ \"$remaining\" == \"0\" ]] && break\n\t\t\tsleep 10\n\t\tdone\n\t\t[[ \"$remaining\" == \"0\" ]] || die \"timed out waiting for instance deletion\"\n\tfi\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\tjq -r \"$target_firewall_filter | .id\" <<<\"$firewalls\" > \"$tmp/firewall_ids\"\n\tlog \"deleting firewalls: $(paste -sd ' ' \"$tmp/firewall_ids\")\"\n\twhile IFS= read -r id; do\n\t\t[[ -n \"$id\" ]] && linode_delete_ignore_missing \"/networking/firewalls/$id\"\n\tdone < \"$tmp/firewall_ids\"\n\tvpcs=\"$(linode_api GET '/vpcs?page_size=500')\"\n\tjq -r --arg label \"$VIDEO_CLOUD_VPC_LABEL\" '.data[] | select(.label == $label) | .id' <<<\"$vpcs\" > \"$tmp/vpc_ids\"\n\tlog \"deleting VPCs: $(paste -sd ' ' \"$tmp/vpc_ids\")\"\n\twhile IFS= read -r id; do\n\t\t[[ -n \"$id\" ]] && linode_delete_ignore_missing \"/vpcs/$id\"\n\tdone < \"$tmp/vpc_ids\"\n\trm -f \"$VC_STATE\" \"$VC_SECRET_STATE\" \"$AM_STATE\" \"$ADMIN_STATE\"\n}\n\ndelete_firewalls_matching_filter() {\n\tlocal filter=\"$1\"\n\tlocal firewalls tmp id label\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\ttmp=\"$(mktemp /tmp/rtk-firewalls.XXXXXX)\"\n\tjq -r \"$filter | [.id,.label] | @tsv\" <<<\"$firewalls\" > \"$tmp\"\n\twhile IFS=$'\\t' read -r id label; do\n\t\t[[ -n \"$id\" ]] || continue\n\t\tlog \"deleting orphan firewall $label ($id)\"\n\t\tlinode_delete_ignore_missing \"/networking/firewalls/$id\"\n\tdone < \"$tmp\"\n\trm -f \"$tmp\"\n}\n\ndelete_vpcs_matching_label() {\n\tlocal label=\"$1\"\n\tlocal vpcs tmp id vpc_label\n\tvpcs=\"$(linode_api GET '/vpcs?page_size=500')\"\n\ttmp=\"$(mktemp /tmp/rtk-vpcs.XXXXXX)\"\n\tjq -r --arg label \"$label\" '.data[] | select(.label == $label) | [.id,.label] | @tsv' <<<\"$vpcs\" > \"$tmp\"\n\twhile IFS=$'\\t' read -r id vpc_label; do\n\t\t[[ -n \"$id\" ]] || continue\n\t\tlog \"deleting orphan VPC $vpc_label ($id)\"\n\t\tlinode_delete_ignore_missing \"/vpcs/$id\"\n\tdone < \"$tmp\"\n\trm -f \"$tmp\"\n}\n\ncleanup_orphan_video_cloud_infra() {\n\tlog \"cleaning orphan Video Cloud firewalls/VPC/state before fresh apply\"\n\tdelete_firewalls_matching_filter \"$target_firewall_filter | select(.label | startswith(env.VIDEO_CLOUD_LABEL_PREFIX + \\\"-\\\"))\"\n\tdelete_vpcs_matching_label \"$VIDEO_CLOUD_VPC_LABEL\"\n\trm -f \"$VC_STATE\" \"$VC_SECRET_STATE\"\n}\n\ncleanup_orphan_public_service() {\n\tlocal label=\"$1\"\n\tlocal firewall_label=\"$2\"\n\tlocal state_path=\"$3\"\n\tlog \"cleaning orphan firewall/state for missing VM $label\"\n\tdelete_firewalls_matching_filter \".data[] | select(.label == \\\"$firewall_label\\\")\"\n\trm -f \"$state_path\"\n}\n\nrun_video_cloud_apply() {\n\tlocal repo_state repo_backup_dir repo_backup\n\trepo_state=\"$VC_REPO/linode_deploy/state/$CLOUD_STACK_NAME.state.json\"\n\trepo_backup_dir=\"$ARTIFACT_BASE/legacy-state-backup-$(date -u +%Y%m%dT%H%M%SZ)\"\n\tif [[ -e \"$repo_state\" || -L \"$repo_state\" ]]; then\n\t\tmkdir -p \"$repo_backup_dir\"\n\t\trepo_backup=\"$repo_backup_dir/$CLOUD_STACK_NAME.state.json\"\n\t\tmv \"$repo_state\" \"$repo_backup\"\n\t\tlog \"moved legacy Video Cloud repo state backup: $repo_backup\"\n\tfi\n\t(\n\t\tcd \"$VC_REPO/linode_deploy\"\n\t\tgo run ./cmd/linode-deploy apply --config \"$VC_CONFIG\"\n\t)\n\tif [[ -f \"$repo_state\" ]]; then\n\t\tmkdir -p \"$(dirname \"$VC_STATE\")\"\n\t\tcp \"$repo_state\" \"$VC_STATE\"\n\t\trm -f \"$repo_state\"\n\tfi\n}\n\nload_service_envs() {\n\tload_env_file \"$AM_ENV\"\n\tload_env_file \"$ADMIN_ENV\"\n}\n\ncreate_admin_vm() {\n\tload_service_envs\n\tlocal label=\"${ADMIN_LINODE_LABEL:-$ADMIN_LINODE_LABEL}\"\n\tlocal region=\"${ADMIN_LINODE_REGION:-$CLOUD_REGION}\"\n\tlocal type=\"${ADMIN_LINODE_TYPE:-g6-standard-2}\"\n\tlocal image=\"${ADMIN_LINODE_IMAGE:-linode/ubuntu24.04}\"\n\tlocal public_key_path\n\tlocal allowed_ssh_cidrs=\"${ADMIN_LINODE_ALLOWED_SSH_CIDRS:-}\"\n\tlocal firewall_label=\"${ADMIN_LINODE_FIREWALL_LABEL:-${label}-firewall}\"\n\tpublic_key_path=\"$(expand_path \"${ADMIN_LINODE_PUBLIC_KEY_PATH:-$SSH_KEY.pub}\")\"\n\t[[ -s \"$public_key_path\" ]] || die \"admin public key not found: $public_key_path\"\n\t[[ -n \"$allowed_ssh_cidrs\" ]] || die \"ADMIN_LINODE_ALLOWED_SSH_CIDRS is required\"\n\tif linode_api GET '/linode/instances?page_size=500' | jq -e --arg label \"$label\" '.data[] | select(.label == $label)' >/dev/null; then\n\t\tdie \"Cloud Admin Linode already exists: $label\"\n\tfi\n\tlocal current_cidr merged_cidrs root_pass ssh_key create_payload create_json linode_id public_ipv4 firewall_payload firewall_json firewall_id\n\tcurrent_cidr=\"$(current_public_cidr || true)\"\n\tmerged_cidrs=\"$allowed_ssh_cidrs\"\n\tif [[ -n \"$current_cidr\" && \",$merged_cidrs,\" != *\",$current_cidr,\"* ]]; then\n\t\tmerged_cidrs=\"$merged_cidrs,$current_cidr\"\n\tfi\n\troot_pass=\"$(openssl rand -base64 36)\"\n\tssh_key=\"$(cat \"$public_key_path\")\"\n\tcreate_payload=\"$(jq -cn \\\n\t\t--arg label \"$label\" --arg region \"$region\" --arg type \"$type\" --arg image \"$image\" \\\n\t\t--arg root_pass \"$root_pass\" --arg ssh_key \"$ssh_key\" \\\n\t\t--arg env_tag \"$CLOUD_STACK_NAME\" \\\n\t\t'{label:$label, region:$region, type:$type, image:$image, root_pass:$root_pass, authorized_keys:[$ssh_key], tags:[$env_tag,\"admin-deploy\"]}')\"\n\tlog \"creating Cloud Admin Linode $label\"\n\tcreate_json=\"$(linode_api POST /linode/instances \"$create_payload\")\"\n\tlinode_id=\"$(jq -r '.id' <<<\"$create_json\")\"\n\tpublic_ipv4=\"$(jq -r '.ipv4[0]' <<<\"$create_json\")\"\n\tfirewall_payload=\"$(jq -cn --arg label \"$firewall_label\" --arg cidrs \"$merged_cidrs\" '{\n\t\tlabel:$label,\n\t\trules:{\n\t\t\tinbound_policy:\"DROP\",\n\t\t\toutbound_policy:\"ACCEPT\",\n\t\t\tinbound:[\n\t\t\t\t{label:\"ssh\",action:\"ACCEPT\",protocol:\"TCP\",ports:\"22\",addresses:{ipv4:($cidrs|split(\",\"))}},\n\t\t\t\t{label:\"http\",action:\"ACCEPT\",protocol:\"TCP\",ports:\"80\",addresses:{ipv4:[\"0.0.0.0/0\"],ipv6:[\"::/0\"]}},\n\t\t\t\t{label:\"https\",action:\"ACCEPT\",protocol:\"TCP\",ports:\"443\",addresses:{ipv4:[\"0.0.0.0/0\"],ipv6:[\"::/0\"]}}\n\t\t\t],\n\t\t\toutbound:[]\n\t\t}\n\t}')\"\n\tlog \"creating Cloud Admin firewall $firewall_label\"\n\tfirewall_json=\"$(linode_api POST /networking/firewalls \"$firewall_payload\")\"\n\tfirewall_id=\"$(jq -r '.id' <<<\"$firewall_json\")\"\n\tlinode_api POST \"/networking/firewalls/$firewall_id/devices\" \"$(jq -cn --argjson id \"$linode_id\" '{id:$id,type:\"linode\"}')\" >/dev/null\n\tmkdir -p \"$(dirname \"$ADMIN_STATE\")\"\n\tcat > \"$ADMIN_STATE\" <<STATE\nADMIN_LINODE_ID=$linode_id\nADMIN_LINODE_LABEL=$label\nADMIN_LINODE_PUBLIC_IPV4=$public_ipv4\nADMIN_LINODE_HOST=$public_ipv4\nADMIN_LINODE_FIREWALL_ID=$firewall_id\nADMIN_LINODE_FIREWALL_LABEL=$firewall_label\nSTATE\n\tchmod 0600 \"$ADMIN_STATE\"\n}\n\nhydrate_video_state_from_live() {\n\tlocal instances firewalls vpcs vpc_id subnet_id\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\tvpcs=\"$(linode_api GET '/vpcs?page_size=500')\"\n\tvpc_id=\"$(jq -r --arg label \"$VIDEO_CLOUD_VPC_LABEL\" '.data[] | select(.label == $label) | .id' <<<\"$vpcs\")\"\n\t[[ -n \"$vpc_id\" && \"$vpc_id\" != \"null\" ]] || die \"cannot hydrate Video Cloud state: missing $VIDEO_CLOUD_VPC_LABEL\"\n\tsubnet_id=\"$(linode_api GET \"/vpcs/$vpc_id/subnets\" | jq -r --arg label \"$VIDEO_CLOUD_SUBNET_LABEL\" '.data[] | select(.label == $label) | .id' | head -n 1)\"\n\t[[ -n \"$subnet_id\" && \"$subnet_id\" != \"null\" ]] || die \"cannot hydrate Video Cloud state: missing $VIDEO_CLOUD_SUBNET_LABEL\"\n\tmkdir -p \"$(dirname \"$VC_STATE\")\" \"$(dirname \"$VC_SECRET_STATE\")\"\n\tjq -n \\\n\t\t--arg stack \"$CLOUD_STACK_NAME\" \\\n\t\t--arg region \"$CLOUD_REGION\" \\\n\t\t--arg label_prefix \"$VIDEO_CLOUD_LABEL_PREFIX\" \\\n\t\t--arg stack_tag \"$CLOUD_STACK_NAME\" \\\n\t\t--argjson vpc_id \"$vpc_id\" \\\n\t\t--argjson subnet_id \"$subnet_id\" \\\n\t\t--argjson instances \"$instances\" \\\n\t\t--argjson firewalls \"$firewalls\" '{\n\t\tstack:$stack,\n\t\tregion:$region,\n\t\tvpc_id:$vpc_id,\n\t\tsubnet_id:$subnet_id,\n\t\tfirewalls:(\n\t\t\t$firewalls.data\n\t\t\t| map(select((.label | startswith($label_prefix + \"-\")) and ((.tags // []) | index($stack_tag))))\n\t\t\t| map({role: ((.tags // []) | map(select(startswith(\"role:\"))) | .[0] | sub(\"^role:\";\"\")), id})\n\t\t\t| map(select(.role != null and .role != \"\"))\n\t\t\t| map({key:.role, value:.id})\n\t\t\t| from_entries\n\t\t),\n\t\tinstances:(\n\t\t\t$instances.data\n\t\t\t| map(select((.label | startswith($label_prefix + \"-\")) and ((.tags // []) | index($stack_tag))))\n\t\t\t| map({\n\t\t\t\trole: ((.tags // []) | map(select(startswith(\"role:\"))) | .[0] | sub(\"^role:\";\"\")),\n\t\t\t\tvalue: {\n\t\t\t\t\tid,\n\t\t\t\t\trole: ((.tags // []) | map(select(startswith(\"role:\"))) | .[0] | sub(\"^role:\";\"\")),\n\t\t\t\t\tlabel,\n\t\t\t\t\tpublic_ipv4: ((.ipv4 // []) | .[0] // \"\"),\n\t\t\t\t\tpublic_ipv6: (.ipv6 // \"\"),\n\t\t\t\t\tprivate_ip: (\n\t\t\t\t\t\tif (.label | endswith(\"-edge\")) then \"10.42.1.5\"\n\t\t\t\t\t\telif (.label | endswith(\"-api\")) then \"10.42.1.10\"\n\t\t\t\t\t\telif (.label | endswith(\"-infra\")) then \"10.42.1.30\"\n\t\t\t\t\t\telif (.label | endswith(\"-mqtt\")) then \"10.42.1.40\"\n\t\t\t\t\t\telse \"\" end\n\t\t\t\t\t),\n\t\t\t\t\ttags: (.tags // [])\n\t\t\t\t}\n\t\t\t})\n\t\t\t| map(select(.role != null and .role != \"\"))\n\t\t\t| map({key:.role, value:.value})\n\t\t\t| from_entries\n\t\t),\n\t\ttags:[$stack_tag,\"managed-by:linode-deploy\"]\n\t}' > \"$VC_STATE\"\n\tif [[ \"$VC_STATE\" != \"$VC_SECRET_STATE\" ]]; then\n\t\tcp \"$VC_STATE\" \"$VC_SECRET_STATE\"\n\tfi\n}\n\nensure_video_cloud_state_or_apply() {\n\tlocal instances count\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tcount=\"$(jq -r --arg label_prefix \"$VIDEO_CLOUD_LABEL_PREFIX\" --arg stack_tag \"$CLOUD_STACK_NAME\" '[.data[] | select((.label | startswith($label_prefix + \"-\")) and ((.tags // []) | index($stack_tag)))] | length' <<<\"$instances\")\"\n\tif [[ \"$count\" == \"5\" ]]; then\n\t\tlog \"Video Cloud instances already exist; hydrating state and skipping apply\"\n\t\thydrate_video_state_from_live\n\telif [[ \"$count\" == \"0\" ]]; then\n\t\tcleanup_orphan_video_cloud_infra\n\t\trun_video_cloud_apply\n\t\tmkdir -p \"$(dirname \"$VC_SECRET_STATE\")\"\n\t\tif [[ \"$VC_STATE\" != \"$VC_SECRET_STATE\" ]]; then\n\t\t\tcp \"$VC_STATE\" \"$VC_SECRET_STATE\"\n\t\tfi\n\telse\n\t\tdie \"partial Video Cloud instance set found: $count/5\"\n\tfi\n}\n\nhydrate_public_state_from_live() {\n\tlocal label=\"$1\"\n\tlocal firewall_label=\"$2\"\n\tlocal state_path=\"$3\"\n\tlocal prefix=\"$4\"\n\tlocal instances firewalls id ip firewall_id\n\tinstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\tid=\"$(jq -r --arg label \"$label\" '.data[] | select(.label == $label) | .id' <<<\"$instances\")\"\n\tip=\"$(jq -r --arg label \"$label\" '.data[] | select(.label == $label) | .ipv4[0]' <<<\"$instances\")\"\n\tfirewall_id=\"$(jq -r --arg label \"$firewall_label\" '.data[] | select(.label == $label) | .id' <<<\"$firewalls\")\"\n\t[[ -n \"$id\" && \"$id\" != \"null\" && -n \"$ip\" && \"$ip\" != \"null\" ]] || die \"cannot hydrate state for $label\"\n\t[[ -n \"$firewall_id\" && \"$firewall_id\" != \"null\" ]] || die \"cannot hydrate firewall state for $firewall_label\"\n\tmkdir -p \"$(dirname \"$state_path\")\"\n\tcat > \"$state_path\" <<STATE\n${prefix}_LINODE_ID=$id\n${prefix}_LINODE_LABEL=$label\n${prefix}_LINODE_PUBLIC_IPV4=$ip\n${prefix}_LINODE_HOST=$ip\n${prefix}_LINODE_FIREWALL_ID=$firewall_id\n${prefix}_LINODE_FIREWALL_LABEL=$firewall_label\nSTATE\n\tchmod 0600 \"$state_path\"\n}\n\nupdate_public_firewall_ssh_allowlist() {\n\tlocal firewall_id=\"$1\"\n\tlocal cidrs_csv=\"$2\"\n\tlocal current_cidr rules updated\n\tcurrent_cidr=\"$(current_public_cidr || true)\"\n\tif [[ -n \"$current_cidr\" && \",$cidrs_csv,\" != *\",$current_cidr,\"* ]]; then\n\t\tcidrs_csv=\"$cidrs_csv,$current_cidr\"\n\tfi\n\trules=\"$(linode_api GET \"/networking/firewalls/$firewall_id/rules\")\"\n\tupdated=\"$(jq --arg cidrs \"$cidrs_csv\" '.inbound |= map(if .label == \"ssh\" then .addresses.ipv4 = ($cidrs | split(\",\") | unique) else . end)' <<<\"$rules\")\"\n\tlinode_api PUT \"/networking/firewalls/$firewall_id/rules\" \"$updated\" >/dev/null\n}\n\naccount_manager_private_ipv4() {\n\tprintf '%s\\n' \"${ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4:-10.42.1.50}\"\n}\n\naccount_manager_vpc_cidr() {\n\tlocal cidr\n\tcidr=\"$(cloud_env_yaml_path_value \"$VC_CONFIG\" vpc.subnet.cidr)\"\n\tprintf '%s\\n' \"${cidr:-10.42.1.0/24}\"\n}\n\nwrite_state_var() {\n\tlocal path=\"$1\"\n\tlocal key=\"$2\"\n\tlocal value=\"$3\"\n\tlocal tmp\n\ttmp=\"$(mktemp)\"\n\tif [[ -f \"$path\" ]]; then\n\t\tgrep -vE \"^${key}=\" \"$path\" > \"$tmp\"\n\tfi\n\tprintf '%s=%s\\n' \"$key\" \"$value\" >> \"$tmp\"\n\tinstall -m 0600 \"$tmp\" \"$path\"\n\trm -f \"$tmp\"\n}\n\nensure_account_manager_vpc_interface() {\n\tlocal private_ip subnet_id linode_id configs config_id config updated\n\tprivate_ip=\"$(account_manager_private_ipv4)\"\n\tsubnet_id=\"$(jq -r '.subnet_id // empty' \"$VC_STATE\")\"\n\tlinode_id=\"${ACCOUNT_MANAGER_LINODE_ID:-}\"\n\t[[ -n \"$linode_id\" && \"$linode_id\" != \"null\" ]] || die \"ACCOUNT_MANAGER_LINODE_ID is required before VPC interface ensure\"\n\t[[ -n \"$subnet_id\" && \"$subnet_id\" != \"null\" ]] || die \"Video Cloud subnet_id is required before Account Manager VPC interface ensure\"\n\tconfigs=\"$(linode_api GET \"/linode/instances/$linode_id/configs\")\"\n\tconfig_id=\"$(jq -r '.data[0].id // empty' <<<\"$configs\")\"\n\t[[ -n \"$config_id\" && \"$config_id\" != \"null\" ]] || die \"cannot find Account Manager Linode config for $linode_id\"\n\tconfig=\"$(linode_api GET \"/linode/instances/$linode_id/configs/$config_id\")\"\n\tif jq -e --arg private_ip \"$private_ip\" '.interfaces[]? | select(.purpose == \"vpc\" and .ipv4.vpc == $private_ip)' <<<\"$config\" >/dev/null; then\n\t\twrite_state_var \"$AM_STATE\" ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4 \"$private_ip\"\n\t\treturn 0\n\tfi\n\tlog \"adding Account Manager VPC interface: linode=$linode_id subnet=$subnet_id private_ip=$private_ip\"\n\tupdated=\"$(jq --argjson subnet_id \"$subnet_id\" --arg private_ip \"$private_ip\" '\n\t\t.interfaces = [\n\t\t\t{purpose:\"public\", primary:true},\n\t\t\t{purpose:\"vpc\", subnet_id:$subnet_id, ipv4:{vpc:$private_ip}}\n\t\t]\n\t' <<<\"$config\")\"\n\tlinode_api PUT \"/linode/instances/$linode_id/configs/$config_id\" \"$updated\" >/dev/null\n\twrite_state_var \"$AM_STATE\" ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4 \"$private_ip\"\n\tlog \"rebooting Account Manager to activate VPC interface\"\n\tlinode_api POST \"/linode/instances/$linode_id/reboot\" '{}' >/dev/null\n}\n\napply_stack() {\n\tlog \"apply\"\n\tload_operator_env\n\tensure_video_cloud_factory_enroll_secrets\n\tload_service_envs\n\tensure_video_cloud_state_or_apply\n\tif linode_api GET '/linode/instances?page_size=500' | jq -e --arg label \"$ACCOUNT_MANAGER_LINODE_LABEL\" '.data[] | select(.label == $label)' >/dev/null; then\n\t\tlog \"Account Manager VM already exists; hydrating state and skipping provision\"\n\t\thydrate_public_state_from_live \"$ACCOUNT_MANAGER_LINODE_LABEL\" \"$ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL\" \"$AM_STATE\" \"ACCOUNT_MANAGER\"\n\telse\n\t\tcleanup_orphan_public_service \"$ACCOUNT_MANAGER_LINODE_LABEL\" \"$ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL\" \"$AM_STATE\"\n\t\t(\n\t\t\tcd \"$AM_REPO\"\n\t\t\tACCOUNT_MANAGER_LINODE_VPC_SUBNET_ID=\"$(jq -r '.subnet_id' \"$VC_STATE\")\" \\\n\t\t\t\tACCOUNT_MANAGER_LINODE_PRIVATE_IPV4=\"$(account_manager_private_ipv4)\" \\\n\t\t\t\tACCOUNT_MANAGER_LINODE_VPC_CIDR=\"$(account_manager_vpc_cidr)\" \\\n\t\t\tACCOUNT_MANAGER_LINODE_STATE_PATH=\"$AM_STATE\" \\\n\t\t\t\tlinode_deploy/scripts/provision-public-vm.sh\n\t\t)\n\tfi\n\tload_env_file \"$AM_STATE\"\n\tensure_account_manager_vpc_interface\n\tif linode_api GET '/linode/instances?page_size=500' | jq -e --arg label \"$ADMIN_LINODE_LABEL\" '.data[] | select(.label == $label)' >/dev/null; then\n\t\tlog \"Cloud Admin VM already exists; hydrating state and skipping provision\"\n\t\thydrate_public_state_from_live \"$ADMIN_LINODE_LABEL\" \"$ADMIN_LINODE_FIREWALL_LABEL\" \"$ADMIN_STATE\" \"ADMIN\"\n\telse\n\t\tcleanup_orphan_public_service \"$ADMIN_LINODE_LABEL\" \"$ADMIN_LINODE_FIREWALL_LABEL\" \"$ADMIN_STATE\"\n\t\tcreate_admin_vm\n\tfi\n\tload_env_file \"$AM_STATE\"\n\tload_env_file \"$ADMIN_STATE\"\n\tupdate_public_firewall_ssh_allowlist \"$ACCOUNT_MANAGER_LINODE_FIREWALL_ID\" \"${ACCOUNT_MANAGER_LINODE_ALLOWED_SSH_CIDRS:-}\"\n\tupdate_public_firewall_ssh_allowlist \"$ADMIN_LINODE_FIREWALL_ID\" \"${ADMIN_LINODE_ALLOWED_SSH_CIDRS:-}\"\n}\n\nrequire_state() {\n\t[[ -f \"$VC_STATE\" ]] || die \"missing Video Cloud state: $VC_STATE\"\n\t[[ -f \"$AM_STATE\" ]] || die \"missing Account Manager state: $AM_STATE\"\n\t[[ -f \"$ADMIN_STATE\" ]] || die \"missing Cloud Admin state: $ADMIN_STATE\"\n}\n\ndns_stack() {\n\tlog \"dns\"\n\tload_operator_env\n\trequire_state\n\tload_env_file \"$AM_STATE\"\n\tload_env_file \"$ADMIN_STATE\"\n\tlocal edge_ip\n\tedge_ip=\"$(jq -r '.instances.edge.public_ipv4' \"$VC_STATE\")\"\n\tlog \"DNS wait TTL: $DNS_WAIT_TTL\"\n\tgodaddy_upsert_a \"$VC_GATEWAY_DOMAIN\" \"$edge_ip\" \"$DNS_WAIT_TTL\" \"wait-ttl\"\n\tgodaddy_upsert_a \"$VC_CERTISSUER_DOMAIN\" \"$edge_ip\" \"$DNS_WAIT_TTL\" \"wait-ttl\"\n\tgodaddy_upsert_a \"$AM_DOMAIN\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"$DNS_WAIT_TTL\" \"wait-ttl\"\n\tgodaddy_upsert_a \"$ADMIN_DOMAIN\" \"$ADMIN_LINODE_PUBLIC_IPV4\" \"$DNS_WAIT_TTL\" \"wait-ttl\"\n\twait_dns \"$VC_GATEWAY_DOMAIN\" \"$edge_ip\"\n\twait_dns \"$VC_CERTISSUER_DOMAIN\" \"$edge_ip\"\n\twait_dns \"$AM_DOMAIN\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\"\n\twait_dns \"$ADMIN_DOMAIN\" \"$ADMIN_LINODE_PUBLIC_IPV4\"\n\tlog \"restoring DNS final TTL: $DNS_FINAL_TTL\"\n\tgodaddy_upsert_a \"$VC_GATEWAY_DOMAIN\" \"$edge_ip\" \"$DNS_FINAL_TTL\" \"final-ttl\"\n\tgodaddy_upsert_a \"$VC_CERTISSUER_DOMAIN\" \"$edge_ip\" \"$DNS_FINAL_TTL\" \"final-ttl\"\n\tgodaddy_upsert_a \"$AM_DOMAIN\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"$DNS_FINAL_TTL\" \"final-ttl\"\n\tgodaddy_upsert_a \"$ADMIN_DOMAIN\" \"$ADMIN_LINODE_PUBLIC_IPV4\" \"$DNS_FINAL_TTL\" \"final-ttl\"\n}\n\ndeploy_stack() {\n\tlog \"deploy\"\n\tload_operator_env\n\tensure_video_cloud_factory_enroll_secrets\n\trequire_state\n\t[[ -x \"$CLOUD_DEPLOY_SCRIPT\" || -f \"$CLOUD_DEPLOY_SCRIPT\" ]] || die \"missing cloud deploy implementation: $CLOUD_DEPLOY_SCRIPT\"\n\tresolve_deploy_releases\n\tlocal args=(\n\t\t--workspace \"$WORKSPACE\"\n\t\t--operator-env \"$OPERATOR_ENV\"\n\t\t--secrets-root \"$DEPRECATED_ENV_ROOT\"\n\t\t--ssh-key \"$SSH_KEY\"\n\t\t--dns-root-domain \"$DNS_ROOT_DOMAIN\"\n\t\t--godaddy-env \"$GODADDY_ENVIRONMENT\"\n\t\t--dns-ttl \"$DNS_FINAL_TTL\"\n\t\t--artifact-dir \"$ARTIFACT_BASE\"\n\t\t--video-release \"$VIDEO_RELEASE\"\n\t\t--account-release \"$ACCOUNT_RELEASE\"\n\t\t--admin-release \"$ADMIN_RELEASE\"\n\t)\n\tif [[ \"$VERBOSE\" == \"1\" ]]; then\n\t\targs+=(--verbose)\n\tfi\n\tlog \"deploy start: Video Cloud release=$VIDEO_RELEASE\"\n\tlog \"deploy start: Account Manager release=$ACCOUNT_RELEASE\"\n\tlog \"deploy start: Cloud Admin release=$ADMIN_RELEASE\"\n\tif ! bash \"$CLOUD_DEPLOY_SCRIPT\" \"${args[@]}\"; then\n\t\tdie \"deploy failed; artifacts and e2e were not run\"\n\tfi\n\tlog \"deploy complete\"\n}\n\nssh_ready() {\n\tlocal host=\"$1\"\n\tlocal proxy=\"${2:-}\"\n\tlocal args=(-i \"$SSH_KEY\" -o BatchMode=yes -o ConnectTimeout=8 -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR)\n\tif [[ -n \"$proxy\" ]]; then\n\t\targs+=(-o ProxyCommand=\"$proxy\")\n\tfi\n\tssh \"${args[@]}\" \"root@$host\" true >/dev/null 2>&1\n}\n\ncheck_ssh_with_retries() {\n\tlocal role=\"$1\"\n\tlocal host=\"$2\"\n\tlocal proxy=\"${3:-}\"\n\tlocal ok=\"no\"\n\tlocal attempt route=\"direct\"\n\tif [[ -n \"$proxy\" ]]; then\n\t\troute=\"proxy_jump via ${proxy##* }\"\n\tfi\n\tfor attempt in $(seq 1 30); do\n\t\tlog \"SSH readiness attempt $attempt/30: role=$role host=$host route=$route\"\n\t\tif ssh_ready \"$host\" \"$proxy\"; then\n\t\t\tok=\"yes\"\n\t\t\tlog \"SSH readiness ok: role=$role host=$host attempt=$attempt/30\"\n\t\t\tbreak\n\t\tfi\n\t\tlog \"SSH readiness pending: role=$role host=$host attempt=$attempt/30; retrying in 10s\"\n\t\tsleep 10\n\tdone\n\tif [[ \"$ok\" != \"yes\" ]]; then\n\t\tlog \"SSH readiness failed: role=$role host=$host attempts=30\"\n\tfi\n\tprintf '%s\\n' \"$ok\"\n}\n\nreport_value() {\n\tlocal value=\"${1:-}\"\n\tif [[ -n \"$value\" && \"$value\" != \"null\" ]]; then\n\t\tprintf '%s\\n' \"$value\"\n\telse\n\t\tprintf 'N/A\\n'\n\tfi\n}\n\nnetwork_profile() {\n\tlocal public_ip=\"${1:-}\"\n\tlocal private_ip=\"${2:-}\"\n\tif [[ -n \"$public_ip\" && \"$public_ip\" != \"null\" && -n \"$private_ip\" && \"$private_ip\" != \"null\" ]]; then\n\t\tprintf 'public+vpc\\n'\n\telif [[ -n \"$public_ip\" && \"$public_ip\" != \"null\" ]]; then\n\t\tprintf 'public\\n'\n\telse\n\t\tprintf 'private\\n'\n\tfi\n}\n\nwrite_video_vm_config_rows() {\n\tlocal role edge_public label id firewall public_ip private_ip profile access proxy\n\tedge_public=\"$(jq -r '.instances.edge.public_ipv4 // \"\"' \"$VC_STATE\")\"\n\tfor role in edge api infra mqtt coturn; do\n\t\tlabel=\"$(jq -r --arg role \"$role\" '.instances[$role].label // \"\"' \"$VC_STATE\")\"\n\t\tid=\"$(jq -r --arg role \"$role\" '.instances[$role].id // \"\"' \"$VC_STATE\")\"\n\t\tfirewall=\"$(jq -r --arg role \"$role\" '.firewalls[$role] // \"\"' \"$VC_STATE\")\"\n\t\tpublic_ip=\"$(jq -r --arg role \"$role\" '.instances[$role].public_ipv4 // \"\"' \"$VC_STATE\")\"\n\t\tprivate_ip=\"$(jq -r --arg role \"$role\" '.instances[$role].private_ip // \"\"' \"$VC_STATE\")\"\n\t\tprofile=\"$(network_profile \"$public_ip\" \"$private_ip\")\"\n\t\taccess=\"direct public SSH\"\n\t\tproxy=\"N/A\"\n\t\tif [[ \"$role\" == \"api\" || \"$role\" == \"infra\" || \"$role\" == \"mqtt\" ]]; then\n\t\t\taccess=\"VPC via edge ProxyJump\"\n\t\t\tproxy=\"root@$edge_public\"\n\t\tfi\n\t\tprintf '| `%s` | `%s` | `%s` | `%s` | `%s` | `%s` | `%s` | `%s` | `%s` |\\n' \\\n\t\t\t\"$role\" \\\n\t\t\t\"$(report_value \"$label\")\" \\\n\t\t\t\"$(report_value \"$id\")\" \\\n\t\t\t\"$(report_value \"$firewall\")\" \\\n\t\t\t\"$profile\" \\\n\t\t\t\"$(report_value \"$public_ip\")\" \\\n\t\t\t\"$(report_value \"$private_ip\")\" \\\n\t\t\t\"$access\" \\\n\t\t\t\"$proxy\"\n\tdone\n}\n\nwrite_public_vm_config_row() {\n\tlocal role=\"$1\"\n\tlocal label=\"$2\"\n\tlocal id=\"$3\"\n\tlocal firewall=\"$4\"\n\tlocal public_ip=\"$5\"\n\tlocal private_ip=\"${6:-}\"\n\tlocal profile\n\tprofile=\"$(network_profile \"$public_ip\" \"$private_ip\")\"\n\tprintf '| `%s` | `%s` | `%s` | `%s` | `%s` | `%s` | `%s` | `direct public SSH` | `N/A` |\\n' \\\n\t\t\"$role\" \\\n\t\t\"$(report_value \"$label\")\" \\\n\t\t\"$(report_value \"$id\")\" \\\n\t\t\"$(report_value \"$firewall\")\" \\\n\t\t\"$profile\" \\\n\t\t\"$(report_value \"$public_ip\")\" \\\n\t\t\"$(report_value \"$private_ip\")\"\n}\n\nwrite_artifacts() {\n\tlog \"artifacts\"\n\tload_operator_env\n\trequire_state\n\tload_env_file \"$AM_STATE\"\n\tload_env_file \"$ADMIN_STATE\"\n\tmkdir -p \"$ARTIFACT_BASE\"\n\tlocal ts art edge_ip coturn_ip api_ip infra_ip mqtt_ip ns tmp proxy_cmd\n\tts=\"$(date -u +%Y%m%dT%H%M%SZ)\"\n\tart=\"$ARTIFACT_BASE/provision-$ts\"\n\tmkdir -p \"$art\"\n\tedge_ip=\"$(jq -r '.instances.edge.public_ipv4' \"$VC_STATE\")\"\n\tcoturn_ip=\"$(jq -r '.instances.coturn.public_ipv4' \"$VC_STATE\")\"\n\tapi_ip=\"$(jq -r '.instances.api.private_ip' \"$VC_STATE\")\"\n\tinfra_ip=\"$(jq -r '.instances.infra.private_ip' \"$VC_STATE\")\"\n\tmqtt_ip=\"$(jq -r '.instances.mqtt.private_ip' \"$VC_STATE\")\"\n\tns=\"$(authoritative_ns)\"\n\ttmp=\"$(mktemp -d /tmp/rtk-provision-artifacts.XXXXXX)\"\n\ttrap 'rm -rf \"$tmp\"' RETURN\n\tjq --arg stack \"$CLOUD_STACK_NAME\" \\\n\t\t--arg am_id \"$ACCOUNT_MANAGER_LINODE_ID\" --arg am_label \"$ACCOUNT_MANAGER_LINODE_LABEL\" --arg am_ip \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" --arg am_private \"${ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4:-}\" --arg am_fw \"$ACCOUNT_MANAGER_LINODE_FIREWALL_ID\" \\\n\t\t--arg ad_id \"$ADMIN_LINODE_ID\" --arg ad_label \"$ADMIN_LINODE_LABEL\" --arg ad_ip \"$ADMIN_LINODE_PUBLIC_IPV4\" --arg ad_fw \"$ADMIN_LINODE_FIREWALL_ID\" \\\n\t\t'{stack:$stack, generated_at:(now|todate), video_cloud:., account_manager:{id:($am_id|tonumber),label:$am_label,public_ipv4:$am_ip,private_ip:$am_private,firewall_id:($am_fw|tonumber)}, cloud_admin:{id:($ad_id|tonumber),label:$ad_label,public_ipv4:$ad_ip,firewall_id:($ad_fw|tonumber)}}' \\\n\t\t\"$VC_STATE\" > \"$art/inventory.json\"\n\tjq -n --slurpfile vc \"$VC_STATE\" --arg am \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" --arg am_private \"${ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4:-}\" --arg ad \"$ADMIN_LINODE_PUBLIC_IPV4\" '{\n\t\tgenerated_at:(now|todate),\n\t\ttargets:{\n\t\t\tedge:{host:$vc[0].instances.edge.public_ipv4,user:\"root\"},\n\t\t\tapi:{host:$vc[0].instances.api.private_ip,user:\"root\",proxy_jump:(\"root@\"+$vc[0].instances.edge.public_ipv4)},\n\t\t\tinfra:{host:$vc[0].instances.infra.private_ip,user:\"root\",proxy_jump:(\"root@\"+$vc[0].instances.edge.public_ipv4)},\n\t\t\tmqtt:{host:$vc[0].instances.mqtt.private_ip,user:\"root\",proxy_jump:(\"root@\"+$vc[0].instances.edge.public_ipv4)},\n\t\t\tcoturn:{host:$vc[0].instances.coturn.public_ipv4,user:\"root\"},\n\t\t\taccount_manager:{host:$am,user:\"root\",private_ip:$am_private},\n\t\t\tcloud_admin:{host:$ad,user:\"root\"}\n\t\t}\n\t}' > \"$art/deployment-targets.json\"\n\t: > \"$art/known_hosts\"\n\tfor host in \"$edge_ip\" \"$coturn_ip\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"$ADMIN_LINODE_PUBLIC_IPV4\"; do\n\t\tssh-keyscan -T 10 \"$host\" >> \"$art/known_hosts\" 2>/dev/null || true\n\tdone\n\tproxy_cmd=\"ssh -i $SSH_KEY -o BatchMode=yes -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR -W %h:%p root@$edge_ip\"\n\t{\n\t\tprintf 'edge\\t%s\\t%s\\n' \"$edge_ip\" \"$(check_ssh_with_retries edge \"$edge_ip\")\"\n\t\tprintf 'coturn\\t%s\\t%s\\n' \"$coturn_ip\" \"$(check_ssh_with_retries coturn \"$coturn_ip\")\"\n\t\tprintf 'account-manager\\t%s\\t%s\\n' \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"$(check_ssh_with_retries account-manager \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\")\"\n\t\tprintf 'cloud-admin\\t%s\\t%s\\n' \"$ADMIN_LINODE_PUBLIC_IPV4\" \"$(check_ssh_with_retries cloud-admin \"$ADMIN_LINODE_PUBLIC_IPV4\")\"\n\t\tprintf 'api\\t%s\\t%s\\n' \"$api_ip\" \"$(check_ssh_with_retries api \"$api_ip\" \"$proxy_cmd\")\"\n\t\tprintf 'infra\\t%s\\t%s\\n' \"$infra_ip\" \"$(check_ssh_with_retries infra \"$infra_ip\" \"$proxy_cmd\")\"\n\t\tprintf 'mqtt\\t%s\\t%s\\n' \"$mqtt_ip\" \"$(check_ssh_with_retries mqtt \"$mqtt_ip\" \"$proxy_cmd\")\"\n\t} > \"$tmp/ssh.tsv\"\n\tfor item in \\\n\t\t\"$VC_GATEWAY_DOMAIN $edge_ip\" \\\n\t\t\"$VC_CERTISSUER_DOMAIN $edge_ip\" \\\n\t\t\"$AM_DOMAIN $ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \\\n\t\t\"$ADMIN_DOMAIN $ADMIN_LINODE_PUBLIC_IPV4\"; do\n\t\tlocal domain=\"${item% *}\"\n\t\tlocal ip=\"${item#* }\"\n\t\tprintf '%s\\t%s\\t%s\\t%s\\n' \"$domain\" \"$ip\" \"$(resolve_dns 8.8.8.8 \"$domain\")\" \"$(resolve_dns \"$ns\" \"$domain\")\" >> \"$tmp/dns.tsv\"\n\tdone\n\t{\n\t\tprintf '# Provision Report\\n\\n'\n\t\tprintf -- '- generated_at: %s\\n' \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"\n\t\tprintf -- '- scope: Video Cloud five-role stack + Account Manager public VM + Cloud Admin public VM\\n'\n\t\tprintf -- '- video_cloud_vpc_id: %s\\n' \"$(jq -r '.vpc_id' \"$VC_STATE\")\"\n\t\tprintf -- '- video_cloud_subnet_id: %s\\n' \"$(jq -r '.subnet_id' \"$VC_STATE\")\"\n\t\tprintf -- '- artifact_dir: %s\\n\\n' \"$art\"\n\t\tprintf '## VM Configuration\\n\\n'\n\t\tprintf -- '- VPN: not configured by this script; private service access uses edge SSH ProxyJump over the Linode VPC.\\n\\n'\n\t\tprintf '| Role | Label | Linode ID | Firewall ID | Network | Public IPv4 | Private/VPC IPv4 | Access / VPN | ProxyJump |\\n'\n\t\tprintf '| --- | --- | --- | --- | --- | --- | --- | --- | --- |\\n'\n\t\twrite_video_vm_config_rows\n\t\twrite_public_vm_config_row \"account-manager\" \"$ACCOUNT_MANAGER_LINODE_LABEL\" \"$ACCOUNT_MANAGER_LINODE_ID\" \"$ACCOUNT_MANAGER_LINODE_FIREWALL_ID\" \"$ACCOUNT_MANAGER_LINODE_PUBLIC_IPV4\" \"${ACCOUNT_MANAGER_LINODE_PRIVATE_IPV4:-}\"\n\t\twrite_public_vm_config_row \"cloud-admin\" \"$ADMIN_LINODE_LABEL\" \"$ADMIN_LINODE_ID\" \"$ADMIN_LINODE_FIREWALL_ID\" \"$ADMIN_LINODE_PUBLIC_IPV4\"\n\t\tprintf '\\n'\n\t\tprintf '## DNS Status\\n\\n| Domain | Expected | 8.8.8.8 | %s |\\n| --- | --- | --- | --- |\\n' \"$ns\"\n\t\tawk -F '\\t' '{printf \"| `%s` | `%s` | `%s` | `%s` |\\n\", $1, $2, $3, $4}' \"$tmp/dns.tsv\"\n\t\tprintf '\\n## SSH Readiness\\n\\n| Role | Host | Status |\\n| --- | --- | --- |\\n'\n\t\tawk -F '\\t' '{printf \"| `%s` | `%s` | `%s` |\\n\", $1, $2, $3}' \"$tmp/ssh.tsv\"\n\t} > \"$art/provision-report.md\"\n\tprintf '%s\\n' \"$art\"\n}\n\ninit_e2e_report() {\n\tlocal report=\"$1\"\n\tcat > \"$report\" <<EOF_REPORT\n# Staging Provision E2E Smoke Report\n\n- generated_at: $(date -u +%Y-%m-%dT%H:%M:%SZ)\n- status: running\n\n## Checks\n\nEOF_REPORT\n}\n\nfinalize_e2e_report() {\n\tlocal report=\"$1\"\n\tlocal status=\"$2\"\n\tlocal tmp\n\ttmp=\"$(mktemp)\"\n\tawk -v status=\"$status\" '{gsub(/status: running/, \"status: \" status)} {print}' \"$report\" > \"$tmp\"\n\tmv \"$tmp\" \"$report\"\n}\n\nrun_e2e_check() {\n\tlocal name=\"$1\"\n\tlocal url=\"$2\"\n\tlocal out=\"$3\"\n\tlocal report=\"$4\"\n\tlog \"e2e check: $name $url\"\n\tif curl -fsS \"$url\" > \"$out\"; then\n\t\tprintf -- '- PASS `%s` `%s` output: `%s`\\n' \"$name\" \"$url\" \"$out\" >> \"$report\"\n\t\tlog \"e2e pass: $name\"\n\telse\n\t\tlocal code=$?\n\t\tprintf -- '- FAIL `%s` `%s` exit=%s output: `%s`\\n' \"$name\" \"$url\" \"$code\" \"$out\" >> \"$report\"\n\t\tlog \"e2e fail: $name exit=$code\"\n\t\treturn \"$code\"\n\tfi\n}\n\ne2e_smoke() {\n\tlog \"e2e\"\n\tload_operator_env\n\trequire_state\n\tload_env_file \"$AM_STATE\"\n\tload_env_file \"$ADMIN_STATE\"\n\tneed_cmd curl\n\tlocal ts dir report failures=0\n\tts=\"$(date -u +%Y%m%dT%H%M%SZ)\"\n\tdir=\"$ARTIFACT_BASE/e2e-$ts\"\n\tmkdir -p \"$dir\"\n\treport=\"$dir/e2e-report.md\"\n\tinit_e2e_report \"$report\"\n\trun_e2e_check \"video-cloud-healthz\" \"https://$VC_GATEWAY_DOMAIN/healthz\" \"$dir/video-cloud-healthz.out\" \"$report\" || failures=$((failures + 1))\n\trun_e2e_check \"video-cloud-version\" \"https://$VC_GATEWAY_DOMAIN/version\" \"$dir/video-cloud-version.out\" \"$report\" || failures=$((failures + 1))\n\trun_e2e_check \"account-manager-health\" \"https://$AM_DOMAIN/v1/health\" \"$dir/account-manager-health.out\" \"$report\" || failures=$((failures + 1))\n\trun_e2e_check \"admin-healthz\" \"https://$ADMIN_DOMAIN/healthz\" \"$dir/admin-healthz.out\" \"$report\" || failures=$((failures + 1))\n\trun_e2e_check \"admin-service-health\" \"https://$ADMIN_DOMAIN/api/service-health\" \"$dir/admin-service-health.out\" \"$report\" || failures=$((failures + 1))\n\tif [[ \"$failures\" == \"0\" ]]; then\n\t\tfinalize_e2e_report \"$report\" \"passed\"\n\t\tlog \"e2e report: $dir\"\n\t\treturn 0\n\tfi\n\tfinalize_e2e_report \"$report\" \"failed\"\n\tlog \"e2e report: $dir\"\n\tdie \"e2e smoke failed: $failures check(s) failed\"\n}\n\nif [[ \"$DO_PREFLIGHT\" == \"1\" ]]; then preflight; fi\nif [[ \"$DO_PLAN\" == \"1\" ]]; then plan; fi\nif [[ \"$DO_RESET\" == \"1\" ]]; then reset_stack; fi\nif [[ \"$DO_APPLY\" == \"1\" ]]; then apply_stack; fi\nif [[ \"$DO_DNS\" == \"1\" ]]; then dns_stack; fi\nif [[ \"$DO_DEPLOY\" == \"1\" ]]; then deploy_stack; fi\nif [[ \"$DO_ARTIFACTS\" == \"1\" ]]; then write_artifacts; fi\nif [[ \"$DO_E2E\" == \"1\" ]]; then e2e_smoke; fi\n",
	"cloud-remove-all-vm.sh":                    "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nOPERATOR_ENV=\"\"\nMATCH_TEXT=\"staging\"\nVPC_LABEL=\"video-cloud-staging-vpc\"\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tprintf '[cloud-remove-all-vm] %s\\n' \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-remove-all-vm.sh [options]\n\nOptions:\n  --workspace PATH      Default: script parent workspace.\n  --env-root PATH       Required environment directory, for example cloud_env/staging.\n  --operator-env PATH   Default: <env-root>/env/operator.env.\n  -h, --help            Show this help.\n\nSafety:\n  The script asks for an interactive \"yes\" before reading credentials or calling\n  the Linode API. It deletes Linode VMs whose label contains \"staging\", then\n  deletes the matching staging firewalls and Video Cloud staging VPC.\n  After delete requests are submitted, active local state files for the staging\n  VMs are moved to <env-root>/backups/remove-vm-<timestamp>/state.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--operator-env) OPERATOR_ENV=\"$2\"; shift 2 ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nprintf 'Delete all Linode VMs whose label contains \"%s\"? Type yes to continue: ' \"$MATCH_TEXT\" >&2\nread -r answer\nif [[ \"$answer\" != \"yes\" ]]; then\n\tlog \"cancelled\"\n\texit 0\nfi\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\tif [[ -f \"$path\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$path\"\n\t\tset +a\n\tfi\n}\n\nlinode_api() {\n\tlocal method=\"$1\"\n\tlocal path=\"$2\"\n\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t-H 'Content-Type: application/json'\n}\n\nlinode_delete_ignore_missing() {\n\tlocal path=\"$1\"\n\tlocal err\n\tif err=\"$(linode_api DELETE \"$path\" 2>&1 >/dev/null)\"; then\n\t\treturn 0\n\tfi\n\tif [[ \"$err\" == *\"404\"* || \"$err\" == *\"provided ID did not match\"* || \"$err\" == *\"not found\"* ]]; then\n\t\tlog \"delete skipped; already gone: $path\"\n\t\treturn 0\n\tfi\n\tprintf '%s\\n' \"$err\" >&2\n\treturn 1\n}\n\nwait_for_vm_deletion() {\n\tlocal remaining\n\tfor _ in $(seq 1 60); do\n\t\tremaining=\"$(linode_api GET '/linode/instances?page_size=500' | jq -r --arg text \"$MATCH_TEXT\" '[.data[] | select(.label | contains($text))] | length')\"\n\t\t[[ \"$remaining\" == \"0\" ]] && return 0\n\t\tsleep 10\n\tdone\n\tdie \"timed out waiting for staging VM deletion\"\n}\n\nremove_orphan_firewalls() {\n\tlocal firewalls tmp id label\n\tfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\n\ttmp=\"$1/firewalls.tsv\"\n\tjq -r '\n\t\t.data[]\n\t\t| select(\n\t\t\t(.label | startswith(\"video-cloud-staging-\"))\n\t\t\tor .label == \"rtk-account-manager-staging-fw\"\n\t\t\tor .label == \"rtk-cloud-admin-staging-firewall\"\n\t\t)\n\t\t| [.id,.label] | @tsv\n\t' <<<\"$firewalls\" > \"$tmp\"\n\tif [[ ! -s \"$tmp\" ]]; then\n\t\tlog \"no staging firewalls found\"\n\t\treturn 0\n\tfi\n\tlog \"deleting staging firewalls:\"\n\tawk -F '\\t' '{printf \"  - %s (%s)\\n\", $2, $1}' \"$tmp\" >&2\n\twhile IFS=$'\\t' read -r id label; do\n\t\t[[ -n \"$id\" ]] || continue\n\t\tlog \"delete firewall $label ($id)\"\n\t\tlinode_delete_ignore_missing \"/networking/firewalls/$id\"\n\tdone < \"$tmp\"\n}\n\nremove_orphan_vpcs() {\n\tlocal vpcs tmp id label\n\tvpcs=\"$(linode_api GET '/vpcs?page_size=500')\"\n\ttmp=\"$1/vpcs.tsv\"\n\tjq -r --arg label \"$VPC_LABEL\" '.data[] | select(.label == $label) | [.id,.label] | @tsv' <<<\"$vpcs\" > \"$tmp\"\n\tif [[ ! -s \"$tmp\" ]]; then\n\t\tlog \"no staging VPCs found\"\n\t\treturn 0\n\tfi\n\tlog \"deleting staging VPCs:\"\n\tawk -F '\\t' '{printf \"  - %s (%s)\\n\", $2, $1}' \"$tmp\" >&2\n\twhile IFS=$'\\t' read -r id label; do\n\t\t[[ -n \"$id\" ]] || continue\n\t\tlog \"delete VPC $label ($id)\"\n\t\tlinode_delete_ignore_missing \"/vpcs/$id\"\n\tdone < \"$tmp\"\n}\n\nbackup_and_remove_state_files() {\n\tlocal backup_dir state_file\n\tbackup_dir=\"$ENV_ROOT/backups/remove-vm-$(date -u +%Y%m%dT%H%M%SZ)/state\"\n\tfor state_file in \\\n\t\t\"$(cloud_env_video_state \"$ENV_ROOT\")\" \\\n\t\t\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\" \\\n\t\t\"$(cloud_env_admin_state \"$ENV_ROOT\")\"\n\tdo\n\t\tif [[ -f \"$state_file\" ]]; then\n\t\t\tmkdir -p \"$backup_dir\"\n\t\t\tcp -p \"$state_file\" \"$backup_dir/$(basename \"$state_file\")\"\n\t\t\trm -f \"$state_file\"\n\t\t\tlog \"removed local state: $state_file\"\n\t\tfi\n\tdone\n\tif [[ -d \"$backup_dir\" ]]; then\n\t\tlog \"local state backup: ${backup_dir%/state}\"\n\tfi\n}\n\nneed_cmd curl\nneed_cmd jq\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nOPERATOR_ENV=\"${OPERATOR_ENV:-$(cloud_env_operator_env \"$ENV_ROOT\")}\"\nload_env_file \"$OPERATOR_ENV\"\n[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n\ntmp=\"$(mktemp -d /tmp/rtk-cloud-remove-vm.XXXXXX)\"\ntrap 'rm -rf \"$tmp\"' EXIT\n\ninstances=\"$(linode_api GET '/linode/instances?page_size=500')\"\njq -r --arg text \"$MATCH_TEXT\" '.data[] | select(.label | contains($text)) | [.id,.label] | @tsv' <<<\"$instances\" > \"$tmp/targets.tsv\"\n\nif [[ ! -s \"$tmp/targets.tsv\" ]]; then\n\tlog \"no VMs found with label containing: $MATCH_TEXT\"\n\texit 0\nfi\n\nlog \"deleting VMs:\"\nawk -F '\\t' '{printf \"  - %s (%s)\\n\", $2, $1}' \"$tmp/targets.tsv\" >&2\n\nwhile IFS=$'\\t' read -r id label; do\n\t[[ -n \"$id\" ]] || continue\n\tlog \"delete $label ($id)\"\n\tlinode_delete_ignore_missing \"/linode/instances/$id\"\ndone < \"$tmp/targets.tsv\"\n\nlog \"VM delete requests submitted\"\nwait_for_vm_deletion\nremove_orphan_firewalls \"$tmp\"\nremove_orphan_vpcs \"$tmp\"\nbackup_and_remove_state_files\nlog \"remove complete\"\n",
	"cloud-run-home-mqtt-loadtest.sh":           "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/..\" && pwd)\"\nexec \"$ROOT/scripts/cloud_mqtt_test.sh\" \"$@\"\n",
	"cloud-staging-e2e-test.sh":                 "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\n# shellcheck source=scripts/lib/cloud-env.sh\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\n\nENV_ROOT=\"\"\nMODE=\"plan\"\nCONFIRM=\"\"\nBRANDNAME=\"RTK\"\nUSER_COUNT=\"10\"\nDEVICE_COUNT=\"100\"\nDEVICE_MIX=\"camera=40,light=25,air_conditioner=20,smart_meter=15\"\nDEVICE_PREFIX=\"load-device\"\nVIDEO_RELEASE=\"${VIDEO_RELEASE:-}\"\nACCOUNT_RELEASE=\"${ACCOUNT_RELEASE:-}\"\nADMIN_RELEASE=\"${ADMIN_RELEASE:-}\"\nSKIP_REMOVE=0\nSKIP_MQTT_PROBE=0\nOUT_DIR=\"\"\n\nREMOVE_SCRIPT=\"${CLOUD_STAGING_E2E_REMOVE_SCRIPT:-$SCRIPT_DIR/cloud-remove-all-vm.sh}\"\nPROVISION_SCRIPT=\"${CLOUD_STAGING_E2E_PROVISION_SCRIPT:-$SCRIPT_DIR/cloud-provision.sh}\"\nCREATE_BRAND_SCRIPT=\"${CLOUD_STAGING_E2E_CREATE_BRAND_SCRIPT:-$SCRIPT_DIR/cloud-create-brandname-cloud.sh}\"\nCREATE_USERS_SCRIPT=\"${CLOUD_STAGING_E2E_CREATE_USERS_SCRIPT:-$SCRIPT_DIR/cloud-create-users.sh}\"\nGENERATE_DEVICES_SCRIPT=\"${CLOUD_STAGING_E2E_GENERATE_DEVICES_SCRIPT:-$SCRIPT_DIR/cloud-generate-load-devices.sh}\"\nBIND_DEVICES_SCRIPT=\"${CLOUD_STAGING_E2E_BIND_DEVICES_SCRIPT:-$SCRIPT_DIR/cloud-bind-devices.sh}\"\nVALIDATE_BIND_SCRIPT=\"${CLOUD_STAGING_E2E_VALIDATE_BIND_SCRIPT:-$SCRIPT_DIR/cloud-validate-device-bind.sh}\"\nMQTT_TEST_SCRIPT=\"${CLOUD_STAGING_E2E_MQTT_TEST_SCRIPT:-$SCRIPT_DIR/cloud_mqtt_test.sh}\"\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tprintf '[cloud-staging-e2e] %s\\n' \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-staging-e2e-test.sh --env-root cloud_env/staging --plan\n  scripts/cloud-staging-e2e-test.sh --env-root cloud_env/staging --run --confirm <stack-name> [options]\n\nOptions:\n  --workspace PATH          Default: script parent workspace.\n  --env-root PATH           Required environment directory, for example cloud_env/staging.\n  --plan                    Print the execution plan without mutating cloud resources. Default.\n  --run                     Execute the one-stop staging E2E flow.\n  --confirm STACK           Required with --run. Must match CLOUD_STACK_NAME.\n  --skip-remove             Do not call cloud-remove-all-vm.sh before provisioning.\n  --brandname NAME          Default: RTK.\n  --user-count N            Default: 10.\n  --device-count N          Default: 100.\n  --device-mix SPEC         Default: camera=40,light=25,air_conditioner=20,smart_meter=15.\n  --device-prefix PREFIX    Default: load-device.\n  --video-release VERSION   Forwarded to cloud-provision.sh.\n  --account-release VERSION Forwarded to cloud-provision.sh.\n  --admin-release VERSION   Forwarded to cloud-provision.sh.\n  --out-dir PATH            Default: <env-root>/artifacts/staging-e2e/<timestamp>.\n  --skip-mqtt-probe         Run simulation without the live MQTT TLS/mTLS socket probe.\n  -h, --help                Show this help.\n\nFlow:\n  remove VM -> provision all -> create brand -> create users -> create devices\n  -> bind/provision devices -> validate bind -> live home MQTT E2E.\n\nSafety:\n  --run requires --confirm matching CLOUD_STACK_NAME. Reports are sanitized and\n  do not include passwords, bearer tokens, raw secrets, private keys, or cert bodies.\nUSAGE\n}\n\nrequire_value() {\n\tlocal opt=\"$1\"\n\tlocal value=\"${2:-}\"\n\t[[ -n \"$value\" ]] || die \"$opt requires a value\"\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) require_value \"$1\" \"${2:-}\"; WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) require_value \"$1\" \"${2:-}\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--plan) MODE=\"plan\"; shift ;;\n\t--run) MODE=\"run\"; shift ;;\n\t--confirm) require_value \"$1\" \"${2:-}\"; CONFIRM=\"$2\"; shift 2 ;;\n\t--skip-remove) SKIP_REMOVE=1; shift ;;\n\t--brandname) require_value \"$1\" \"${2:-}\"; BRANDNAME=\"$2\"; shift 2 ;;\n\t--user-count) require_value \"$1\" \"${2:-}\"; USER_COUNT=\"$2\"; shift 2 ;;\n\t--device-count) require_value \"$1\" \"${2:-}\"; DEVICE_COUNT=\"$2\"; shift 2 ;;\n\t--device-mix) require_value \"$1\" \"${2:-}\"; DEVICE_MIX=\"$2\"; shift 2 ;;\n\t--device-prefix) require_value \"$1\" \"${2:-}\"; DEVICE_PREFIX=\"$2\"; shift 2 ;;\n\t--video-release) require_value \"$1\" \"${2:-}\"; VIDEO_RELEASE=\"$2\"; shift 2 ;;\n\t--account-release) require_value \"$1\" \"${2:-}\"; ACCOUNT_RELEASE=\"$2\"; shift 2 ;;\n\t--admin-release) require_value \"$1\" \"${2:-}\"; ADMIN_RELEASE=\"$2\"; shift 2 ;;\n\t--out-dir) require_value \"$1\" \"${2:-}\"; OUT_DIR=\"$2\"; shift 2 ;;\n\t--skip-mqtt-probe) SKIP_MQTT_PROBE=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required\"\n[[ \"$USER_COUNT\" =~ ^[0-9]+$ && \"$USER_COUNT\" -gt 0 ]] || die \"--user-count must be a positive integer\"\n[[ \"$DEVICE_COUNT\" =~ ^[0-9]+$ && \"$DEVICE_COUNT\" -gt 0 ]] || die \"--device-count must be a positive integer\"\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\ncloud_env_load_environment \"$ENV_ROOT\" \"\"\nSTACK_NAME=\"$CLOUD_STACK_NAME\"\n\nif [[ \"$MODE\" == \"run\" && \"$CONFIRM\" != \"$STACK_NAME\" ]]; then\n\tdie \"--confirm $CONFIRM does not match CLOUD_STACK_NAME=$STACK_NAME\"\nfi\n\nif [[ -z \"$OUT_DIR\" ]]; then\n\tOUT_DIR=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/staging-e2e/$(date -u '+%Y%m%dT%H%M%SZ')\"\nfi\n\nbrand_slug() {\n\tprintf '%s' \"$BRANDNAME\" | tr '[:upper:]' '[:lower:]' | sed -E 's/[^a-z0-9]+/-/g; s/^-+//; s/-+$//' | awk '{if ($0==\"\") print \"brand\"; else print}'\n}\n\nlatest_file() {\n\tlocal pattern=\"$1\"\n\tfind \"$(dirname \"$pattern\")\" -maxdepth 1 -type f -name \"$(basename \"$pattern\")\" 2>/dev/null | sort | tail -1\n}\n\nprint_plan() {\n\tcat <<EOF\ncloud-staging-e2e-test plan\nworkspace: $WORKSPACE\nenv_root: $ENV_ROOT\nstack: $STACK_NAME\nbrandname: $BRANDNAME\nuser_count: $USER_COUNT\ndevice_count: $DEVICE_COUNT\ndevice_mix: $DEVICE_MIX\nskip_remove: $SKIP_REMOVE\nsteps:\nEOF\n\tif [[ \"$SKIP_REMOVE\" != \"1\" ]]; then\n\t\tprintf '  - remove VMs with %s\\n' \"$REMOVE_SCRIPT\"\n\tfi\n\tcat <<EOF\n  - provision all with $PROVISION_SCRIPT\n  - create brand cloud with $CREATE_BRAND_SCRIPT\n  - create users with $CREATE_USERS_SCRIPT\n  - generate/factory-enroll devices with $GENERATE_DEVICES_SCRIPT\n  - bind/provision devices with $BIND_DEVICES_SCRIPT\n  - validate bind artifact with $VALIDATE_BIND_SCRIPT\n  - run live home MQTT E2E with $MQTT_TEST_SCRIPT\nEOF\n}\n\nif [[ \"$MODE\" == \"plan\" ]]; then\n\tprint_plan\n\texit 0\nfi\n\nmkdir -p \"$OUT_DIR/logs\"\nSUMMARY_FILE=\"$OUT_DIR/summary.json\"\nREPORT_FILE=\"$OUT_DIR/TEST_REPORT.md\"\nSTEPS_JSONL=\"$OUT_DIR/steps.jsonl\"\n: > \"$STEPS_JSONL\"\n\nrun_step() {\n\tlocal name=\"$1\"\n\tshift\n\tlocal start end rc log_file\n\tstart=\"$(date +%s)\"\n\tlog_file=\"$OUT_DIR/logs/$name.log\"\n\tlog \"start: $name\"\n\tset +e\n\t\"$@\" >\"$log_file\" 2>&1\n\trc=$?\n\tset -e\n\tend=\"$(date +%s)\"\n\tjq -cn \\\n\t\t--arg name \"$name\" \\\n\t\t--arg status \"$([[ \"$rc\" == \"0\" ]] && printf PASS || printf FAIL)\" \\\n\t\t--arg log_file \"$log_file\" \\\n\t\t--argjson exit_code \"$rc\" \\\n\t\t--argjson duration_seconds \"$((end - start))\" \\\n\t\t'{name:$name,status:$status,exit_code:$exit_code,duration_seconds:$duration_seconds,log_file:$log_file}' >> \"$STEPS_JSONL\"\n\tif [[ \"$rc\" != \"0\" ]]; then\n\t\tlog \"fail: $name (see $log_file)\"\n\t\treturn \"$rc\"\n\tfi\n\tlog \"pass: $name\"\n}\n\nprovision_args=(--workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\" --reset-and-all --confirm \"$STACK_NAME\")\n[[ -n \"$VIDEO_RELEASE\" ]] && provision_args+=(--video-release \"$VIDEO_RELEASE\")\n[[ -n \"$ACCOUNT_RELEASE\" ]] && provision_args+=(--account-release \"$ACCOUNT_RELEASE\")\n[[ -n \"$ADMIN_RELEASE\" ]] && provision_args+=(--admin-release \"$ADMIN_RELEASE\")\n\nif [[ \"$SKIP_REMOVE\" != \"1\" ]]; then\n\trun_step remove_vm bash -c 'printf \"yes\\n\" | \"$@\"' _ \"$REMOVE_SCRIPT\" --workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\"\nfi\nrun_step provision_all \"$PROVISION_SCRIPT\" \"${provision_args[@]}\"\nrun_step create_brand \"$CREATE_BRAND_SCRIPT\" --workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\" --brandname \"$BRANDNAME\"\nrun_step create_users \"$CREATE_USERS_SCRIPT\" --workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\" --brandname \"$BRANDNAME\" --count \"$USER_COUNT\"\nrun_step create_devices \"$GENERATE_DEVICES_SCRIPT\" --workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\" --count \"$DEVICE_COUNT\" --mix \"$DEVICE_MIX\" --prefix \"$DEVICE_PREFIX\" --force\n\nslug=\"$(brand_slug)\"\nusers_file=\"$(latest_file \"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/users/$slug-users-*.json\")\"\n[[ -n \"$users_file\" ]] || die \"no users artifact found for brand slug $slug\"\n\nrun_step bind_devices \"$BIND_DEVICES_SCRIPT\" --workspace \"$WORKSPACE\" --env-root \"$ENV_ROOT\" --brandname \"$BRANDNAME\" --users-file \"$users_file\" --devices-dir \"$(cloud_env_test_devices_dir \"$ENV_ROOT\")\" --count \"$DEVICE_COUNT\"\n\nbind_file=\"$(latest_file \"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/device-bind/$slug-device-bind-*.json\")\"\n[[ -n \"$bind_file\" ]] || die \"no device-bind artifact found for brand slug $slug\"\nexpected_per_user=\"$(( (DEVICE_COUNT + USER_COUNT - 1) / USER_COUNT ))\"\nrun_step validate_bind \"$VALIDATE_BIND_SCRIPT\" --bind-artifact \"$bind_file\" --out-dir \"$OUT_DIR/bind-validation\" --expected-count \"$DEVICE_COUNT\" --expected-devices-per-user \"$expected_per_user\"\n\nmqtt_args=(--env-root \"$ENV_ROOT\" --brandname \"$BRANDNAME\" --profile smoke --out-dir \"$OUT_DIR/home-mqtt\")\nif [[ \"$SKIP_MQTT_PROBE\" == \"1\" ]]; then\n\tmqtt_args+=(--no-mqtt-probe)\nelse\n\tmqtt_args+=(--mqtt-probe)\nfi\nrun_step cloud_mqtt_test \"$MQTT_TEST_SCRIPT\" \"${mqtt_args[@]}\"\n\noverall=\"pass\"\nif jq -e 'select(.status != \"PASS\")' \"$STEPS_JSONL\" >/dev/null; then\n\toverall=\"fail\"\nfi\n\njq -s \\\n\t--arg overall \"$overall\" \\\n\t--arg generated_at \"$(date -u '+%Y-%m-%dT%H:%M:%SZ')\" \\\n\t--arg env_root \"$ENV_ROOT\" \\\n\t--arg stack \"$STACK_NAME\" \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg users_file \"$users_file\" \\\n\t--arg bind_file \"$bind_file\" \\\n\t--arg report_file \"$REPORT_FILE\" \\\n\t'{\n\t\toverall: $overall,\n\t\tgenerated_at: $generated_at,\n\t\tenv_root: $env_root,\n\t\tstack: $stack,\n\t\tbrandname: $brandname,\n\t\tartifacts: {\n\t\t\tusers_file: $users_file,\n\t\t\tdevice_bind_file: $bind_file,\n\t\t\treport_file: $report_file\n\t\t},\n\t\tsteps: .\n\t}' \"$STEPS_JSONL\" > \"$SUMMARY_FILE\"\n\n{\n\tprintf '# Staging E2E Test Report\\n\\n'\n\tprintf -- '- Overall: %s\\n' \"$overall\"\n\tprintf -- '- Generated: %s\\n' \"$(date -u '+%Y-%m-%dT%H:%M:%SZ')\"\n\tprintf -- '- Env root: `%s`\\n' \"$ENV_ROOT\"\n\tprintf -- '- Stack: `%s`\\n' \"$STACK_NAME\"\n\tprintf -- '- Brand: `%s`\\n\\n' \"$BRANDNAME\"\n\tprintf '## Steps\\n\\n'\n\tprintf '| Step | Status | Duration seconds | Log |\\n'\n\tprintf '| --- | --- | ---: | --- |\\n'\n\tjq -r '. | \"| \\(.name) | \\(.status) | \\(.duration_seconds) | `\\(.log_file)` |\"' \"$STEPS_JSONL\"\n\tprintf '\\n## Artifacts\\n\\n'\n\tprintf -- '- Users artifact: `%s`\\n' \"$users_file\"\n\tprintf -- '- Device bind artifact: `%s`\\n' \"$bind_file\"\n\tprintf -- '- Home MQTT report: `%s`\\n' \"$OUT_DIR/home-mqtt/TEST_REPORT.md\"\n\tprintf -- '- Home MQTT results: `%s`\\n' \"$OUT_DIR/home-mqtt/results.json\"\n} > \"$REPORT_FILE\"\n\nif grep -R -Ei 'password|bearer|raw-token|-----BEGIN|PRIVATE KEY|JWT_ACCESS_SECRET|VIDEO_CLOUD_AUTH_SECRET' \"$SUMMARY_FILE\" \"$REPORT_FILE\" >/dev/null; then\n\tdie \"sanitized report contains sensitive terms\"\nfi\n\njq -cn --arg overall \"$overall\" --arg summary_file \"$SUMMARY_FILE\" --arg report_file \"$REPORT_FILE\" \\\n\t'{overall:$overall,summary_file:$summary_file,report_file:$report_file}'\n[[ \"$overall\" == \"pass\" ]]\n",
	"cloud-unprovision-devices.sh":              "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nSTART_EPOCH=\"$(date +%s)\"\nBRANDNAME=\"\"\nBIND_ARTIFACT=\"\"\nCOUNT=\"\"\nDRY_RUN=0\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tlocal now elapsed\n\tnow=\"$(date +%H:%M:%S)\"\n\telapsed=$(($(date +%s) - START_EPOCH))\n\tprintf '[cloud-unprovision-devices %s +%03ds] %s\\n' \"$now\" \"$elapsed\" \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-unprovision-devices.sh --env-root cloud_env/staging --brandname RTK [options]\n\nOptions:\n  --workspace PATH       Default: script parent workspace.\n  --env-root PATH        Required environment directory, for example cloud_env/staging.\n  --brandname NAME       Required brand cloud name.\n  --bind-artifact FILE   Device bind artifact. Default: latest <brand>-device-bind-*.json.\n  --count N              Optional number of bound devices to unprovision. Default: all assignments.\n  --dry-run              Print planned unprovision calls without calling APIs or writing artifacts.\n  -h, --help             Show this help.\n\nReleases user/org bindings through Account Manager user-facing unprovision APIs.\nstdout contains a redacted summary. Passwords, bearer tokens, raw Claim Tokens,\nand device private material are never printed or written to the output artifact.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--brandname) BRANDNAME=\"$2\"; shift 2 ;;\n\t--bind-artifact) BIND_ARTIFACT=\"$2\"; shift 2 ;;\n\t--count) COUNT=\"$2\"; shift 2 ;;\n\t--dry-run) DRY_RUN=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"required env file not found: $path\"\n\tset -a\n\t# shellcheck source=/dev/null\n\t. \"$path\"\n\tset +a\n}\n\ncurl_json_status() {\n\tlocal out=\"$1\"\n\tshift\n\tcurl -sS -o \"$out\" -w '%{http_code}' \"$@\"\n}\n\nvalidate_args() {\n\tBRANDNAME=\"$(printf '%s' \"$BRANDNAME\" | awk '{$1=$1; print}')\"\n\t[[ -n \"$BRANDNAME\" ]] || die \"--brandname is required\"\n\t[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\tif [[ -n \"$COUNT\" ]]; then\n\t\t[[ \"$COUNT\" =~ ^[0-9]+$ ]] || die \"--count must be a positive integer\"\n\t\t((COUNT > 0)) || die \"--count must be greater than zero\"\n\tfi\n\tif printf '%s' \"$BRANDNAME\" | LC_ALL=C grep -q '[[:cntrl:]]'; then\n\t\tdie \"--brandname must not contain control characters\"\n\tfi\n}\n\nbrand_slug() {\n\tprintf '%s' \"$BRANDNAME\" |\n\t\ttr '[:upper:]' '[:lower:]' |\n\t\tsed -E 's/[^a-z0-9]+/-/g; s/^-+//; s/-+$//' |\n\t\tawk '{ if ($0 == \"\") print \"brand\"; else print }'\n}\n\nabs_existing_file() {\n\tlocal path=\"$1\"\n\t[[ -f \"$path\" ]] || die \"file not found: $path\"\n\t(cd \"$(dirname \"$path\")\" && printf '%s/%s\\n' \"$(pwd)\" \"$(basename \"$path\")\")\n}\n\nresolve_default_inputs() {\n\tlocal slug bind_dir latest_bind\n\tif [[ -z \"$BIND_ARTIFACT\" ]]; then\n\t\tslug=\"$(brand_slug)\"\n\t\tbind_dir=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/device-bind\"\n\t\t[[ -d \"$bind_dir\" ]] || die \"--bind-artifact was not provided and bind artifact directory was not found: $bind_dir\"\n\t\tlatest_bind=\"$(find \"$bind_dir\" -type f -name \"$slug-device-bind-*.json\" -print | sort | tail -n 1)\"\n\t\t[[ -n \"$latest_bind\" ]] || die \"--bind-artifact was not provided and no bind artifact matched: $bind_dir/$slug-device-bind-*.json\"\n\t\tBIND_ARTIFACT=\"$latest_bind\"\n\tfi\n}\n\nvalidate_bind_artifact() {\n\tBIND_ARTIFACT=\"$(abs_existing_file \"$BIND_ARTIFACT\")\"\n\tBIND_BRAND=\"$(jq -r '.brandname // empty' \"$BIND_ARTIFACT\")\"\n\t[[ \"$BIND_BRAND\" == \"$BRANDNAME\" ]] || die \"--bind-artifact brandname $BIND_BRAND does not match --brandname $BRANDNAME\"\n\tBRAND_CLOUD_ID=\"$(jq -r '.brand_cloud_id // empty' \"$BIND_ARTIFACT\")\"\n\t[[ -n \"$BRAND_CLOUD_ID\" && \"$BRAND_CLOUD_ID\" != \"null\" ]] || die \"--bind-artifact missing brand_cloud_id\"\n\tUSERS_FILE=\"$(jq -r '.inputs.users_file // empty' \"$BIND_ARTIFACT\")\"\n\t[[ -n \"$USERS_FILE\" && \"$USERS_FILE\" != \"null\" ]] || die \"--bind-artifact missing inputs.users_file\"\n\tUSERS_FILE=\"$(abs_existing_file \"$USERS_FILE\")\"\n\tjq -e '\n\t\t(.assignments | type == \"array\" and length > 0) and\n\t\tall(.assignments[]; (.assigned_email | type == \"string\" and length > 0) and\n\t\t\t(.device_id | type == \"string\" and length > 0) and\n\t\t\t(.account_device_id | type == \"string\" and length > 0))\n\t' \"$BIND_ARTIFACT\" >/dev/null || die \"--bind-artifact assignments require assigned_email, device_id, and account_device_id\"\n\tjq -e '\n\t\tall(.users[]; (.email | type == \"string\" and length > 0) and (.password | type == \"string\" and length > 0))\n\t' \"$USERS_FILE\" >/dev/null || die \"bind artifact users_file users require email and password\"\n\tBIND_COUNT=\"$(jq '.assignments | length' \"$BIND_ARTIFACT\")\"\n\tif [[ -z \"$COUNT\" ]]; then\n\t\tCOUNT=\"$BIND_COUNT\"\n\tfi\n\t((COUNT <= BIND_COUNT)) || die \"--count $COUNT exceeds bind assignment count $BIND_COUNT\"\n}\n\nbuild_plan() {\n\tjq --argjson count \"$COUNT\" '\n\t\t.assignments[0:$count]\n\t\t| map({\n\t\t\tassignment_index,\n\t\t\tassigned_email,\n\t\t\tdevice_id,\n\t\t\tdevice_type,\n\t\t\tcategory,\n\t\t\tservice_options,\n\t\t\tclaim_id,\n\t\t\taccount_device_id,\n\t\t\tprevious_status: (.status // \"unknown\")\n\t\t})\n\t' \"$BIND_ARTIFACT\"\n}\n\nlogin() {\n\tlocal email=\"$1\"\n\tlocal password=\"$2\"\n\tlocal out=\"$TMPDIR/login.out\"\n\tlocal payload=\"$TMPDIR/login-payload.json\"\n\tjq -cn --arg email \"$email\" --arg password \"$password\" '{email:$email,password:$password}' > \"$payload\"\n\tlocal status\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/auth/login\")\"\n\t[[ \"$status\" == \"200\" ]] || die \"login failed: email=$email HTTP $status\"\n\tjq -r '.tokens.access_token // empty' \"$out\"\n}\n\nwrite_secret_user_tokens() {\n\tlocal users_jsonl=\"$TMPDIR/user-tokens.jsonl\"\n\tlocal emails_file=\"$TMPDIR/plan-emails.txt\"\n\t: > \"$users_jsonl\"\n\tjq -r '.[].assigned_email' <<<\"$PLAN_JSON\" | sort -u > \"$emails_file\"\n\tlocal email password token\n\twhile IFS= read -r email; do\n\t\tpassword=\"$(jq -r --arg email \"$email\" '.users[] | select(.email == $email) | .password' \"$USERS_FILE\" | head -n 1)\"\n\t\t[[ -n \"$password\" && \"$password\" != \"null\" ]] || die \"users_file missing password for assigned user: $email\"\n\t\tlog \"logging in assigned user: email=$email\"\n\t\ttoken=\"$(login \"$email\" \"$password\")\"\n\t\t[[ -n \"$token\" ]] || die \"user login response did not include an access token: $email\"\n\t\tjq -cn --arg email \"$email\" --arg token \"$token\" '{email:$email, token:$token}' >> \"$users_jsonl\"\n\tdone < \"$emails_file\"\n\tjq -s . \"$users_jsonl\" > \"$USER_TOKENS_FILE\"\n}\n\nuser_token_for_email() {\n\tlocal email=\"$1\"\n\tjq -r --arg email \"$email\" '.[] | select(.email == $email) | .token' \"$USER_TOKENS_FILE\" | head -n 1\n}\n\npreflight_unprovision_route() {\n\tlocal email password token payload out status probe_device_id error\n\temail=\"$(jq -r '.[0].assigned_email' <<<\"$PLAN_JSON\")\"\n\tpassword=\"$(jq -r --arg email \"$email\" '.users[] | select(.email == $email) | .password' \"$USERS_FILE\" | head -n 1)\"\n\t[[ -n \"$password\" && \"$password\" != \"null\" ]] || die \"users_file missing password for assigned user: $email\"\n\tlog \"checking Account Manager unprovision API route: email=$email\"\n\ttoken=\"$(login \"$email\" \"$password\")\"\n\t[[ -n \"$token\" ]] || die \"preflight login response did not include an access token: $email\"\n\tprobe_device_id=\"00000000-0000-0000-0000-000000000000\"\n\tpayload=\"$TMPDIR/unprovision-preflight.json\"\n\tout=\"$TMPDIR/unprovision-preflight.out\"\n\tjq -cn --arg reason \"route_preflight\" '{reason:$reason}' > \"$payload\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $token\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/orgs/$BRAND_CLOUD_ID/devices/$probe_device_id/unprovision\")\"\n\tcase \"$status\" in\n\t404)\n\t\terror=\"$(jq -r '.error // empty' \"$out\" 2>/dev/null || true)\"\n\t\tif [[ \"$error\" == \"not_found\" ]]; then\n\t\t\tlog \"Account Manager unprovision API route is available\"\n\t\t\treturn 0\n\t\tfi\n\t\tdie \"Account Manager unprovision API route is not deployed at $AM_BASE_URL; deploy an Account Manager build with /v1/orgs/:orgId/devices/:deviceId/unprovision before running this script\"\n\t\t;;\n\t403)\n\t\tdie \"assigned user lacks device.unprovision permission in brand cloud: email=$email brand_cloud_id=$BRAND_CLOUD_ID\"\n\t\t;;\n\t400|409)\n\t\tlog \"Account Manager unprovision API route is available\"\n\t\treturn 0\n\t\t;;\n\t*)\n\t\tdie \"unexpected Account Manager unprovision API preflight status: HTTP $status\"\n\t\t;;\n\tesac\n}\n\nunprovision_device() {\n\tlocal row=\"$1\"\n\tlocal user_token=\"$2\"\n\tlocal device_id account_device_id payload out status\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$row\")\"\n\taccount_device_id=\"$(jq -r '.account_device_id' <<<\"$row\")\"\n\tpayload=\"$TMPDIR/unprovision-$device_id.json\"\n\tout=\"$TMPDIR/unprovision-$device_id.out\"\n\tjq -cn --arg reason \"user_resale_factory_ready\" '{reason:$reason}' > \"$payload\"\n\tstatus=\"$(curl_json_status \"$out\" \\\n\t\t-H 'content-type: application/json' \\\n\t\t-H \"authorization: Bearer $user_token\" \\\n\t\t--data-binary \"@$payload\" \\\n\t\t\"$AM_BASE_URL/v1/orgs/$BRAND_CLOUD_ID/devices/$account_device_id/unprovision\")\"\n\tif [[ \"$status\" != \"200\" ]]; then\n\t\tprintf 'unprovision failed: device=%s account_device=%s HTTP %s\\n' \"$device_id\" \"$account_device_id\" \"$status\" >&2\n\t\tjq '{error, message}' \"$out\" >&2 2>/dev/null || true\n\t\treturn 1\n\tfi\n\tjq -c --arg status \"$status\" '. + {http_status:($status|tonumber)}' \"$out\"\n}\n\nvalidate_args\nneed_cmd curl\nneed_cmd jq\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nTMPDIR=\"$(mktemp -d /tmp/rtk-unprovision-devices.XXXXXX)\"\ntrap 'rm -rf \"$TMPDIR\"' EXIT\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nresolve_default_inputs\nvalidate_bind_artifact\n\nPLAN_JSON=\"$(build_plan)\"\n\nif [[ \"$DRY_RUN\" == \"1\" ]]; then\n\tjq -cn \\\n\t\t--arg brandname \"$BRANDNAME\" \\\n\t\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t\t--arg bind_artifact \"$BIND_ARTIFACT\" \\\n\t\t--arg users_file \"$USERS_FILE\" \\\n\t\t--argjson count \"$COUNT\" \\\n\t\t--argjson assignments \"$PLAN_JSON\" \\\n\t\t'{action:\"dry_run\", brandname:$brandname, brand_cloud_id:$brand_cloud_id, count:$count, bind_artifact:$bind_artifact, users_file:$users_file, assignments:$assignments}'\n\texit 0\nfi\n\nlog \"workspace=$WORKSPACE\"\nlog \"env_root=$ENV_ROOT\"\nlog \"bind_artifact=$BIND_ARTIFACT\"\n\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\n\nlog \"loading Account Manager env/state\"\nload_env_file \"$AM_ENV\"\nload_env_file \"$AM_STATE\"\n\nAM_DOMAIN=\"${ACCOUNT_MANAGER_LINODE_DOMAIN:-${ACCOUNT_MANAGER_DOMAIN:-account-manager.video-cloud-staging.realtekconnect.com}}\"\nAM_BASE_URL=\"https://$AM_DOMAIN\"\nUSER_TOKENS_FILE=\"$TMPDIR/user-tokens.json\"\nRUN_ID=\"$(date -u +%Y%m%dT%H%M%SZ)\"\n\npreflight_unprovision_route\nwrite_secret_user_tokens\n\nRESULTS_JSONL=\"$TMPDIR/results.jsonl\"\n: > \"$RESULTS_JSONL\"\nUNPROVISIONED=0\n\nwhile IFS= read -r row; do\n\tdevice_id=\"$(jq -r '.device_id' <<<\"$row\")\"\n\temail=\"$(jq -r '.assigned_email' <<<\"$row\")\"\n\taccount_device_id=\"$(jq -r '.account_device_id' <<<\"$row\")\"\n\tlog \"unprovisioning device: device=$device_id account_device=$account_device_id user=$email\"\n\tuser_token=\"$(user_token_for_email \"$email\")\"\n\t[[ -n \"$user_token\" ]] || die \"no login token for assigned user: $email\"\n\tunprovision_json=\"$(unprovision_device \"$row\" \"$user_token\")\"\n\tUNPROVISIONED=$((UNPROVISIONED + 1))\n\tjq -cn \\\n\t\t--argjson assignment \"$row\" \\\n\t\t--arg account_device_id \"$account_device_id\" \\\n\t\t--arg response_device_id \"$(jq -r '.unprovision.device_id // empty' <<<\"$unprovision_json\")\" \\\n\t\t--arg organization_id \"$(jq -r '.unprovision.organization_id // empty' <<<\"$unprovision_json\")\" \\\n\t\t--arg video_cloud_devid \"$(jq -r '.unprovision.video_cloud_devid // empty' <<<\"$unprovision_json\")\" \\\n\t\t--arg unprovisioned_at \"$(jq -r '.unprovision.unprovisioned_at // empty' <<<\"$unprovision_json\")\" \\\n\t\t'{\n\t\t\tassignment_index: $assignment.assignment_index,\n\t\t\tassigned_email: $assignment.assigned_email,\n\t\t\tdevice_id: $assignment.device_id,\n\t\t\tdevice_type: $assignment.device_type,\n\t\t\tcategory: $assignment.category,\n\t\t\tservice_options: $assignment.service_options,\n\t\t\tclaim_id: $assignment.claim_id,\n\t\t\taccount_device_id: $account_device_id,\n\t\t\tresponse_device_id: $response_device_id,\n\t\t\torganization_id: $organization_id,\n\t\t\tvideo_cloud_devid: $video_cloud_devid,\n\t\t\tstatus: \"unprovisioned\",\n\t\t\tunprovisioned_at: $unprovisioned_at\n\t\t}' >> \"$RESULTS_JSONL\"\ndone < <(jq -rc '.[]' <<<\"$PLAN_JSON\")\n\nSLUG=\"$(brand_slug)\"\nARTIFACT_DIR=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/device-unprovision\"\nmkdir -p \"$ARTIFACT_DIR\"\nARTIFACT_FILE=\"$ARTIFACT_DIR/$SLUG-device-unprovision-$RUN_ID.json\"\nARTIFACT_TMP=\"$TMPDIR/artifact.json\"\njq -s \\\n\t--arg schema \"rtk-cloud-workspace.bulk-device-unprovision/v1\" \\\n\t--arg generated_at \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg bind_artifact \"$BIND_ARTIFACT\" \\\n\t--arg users_file \"$USERS_FILE\" \\\n\t--argjson count \"$COUNT\" \\\n\t'{schema:$schema, generated_at:$generated_at, brandname:$brandname, brand_cloud_id:$brand_cloud_id, count:$count, inputs:{bind_artifact:$bind_artifact, users_file:$users_file}, assignments:.}' \\\n\t\"$RESULTS_JSONL\" > \"$ARTIFACT_TMP\"\ninstall -m 0600 \"$ARTIFACT_TMP\" \"$ARTIFACT_FILE\"\nlog \"unprovision artifact written: $ARTIFACT_FILE\"\n\njq -cn \\\n\t--arg brandname \"$BRANDNAME\" \\\n\t--arg brand_cloud_id \"$BRAND_CLOUD_ID\" \\\n\t--arg artifact_file \"$ARTIFACT_FILE\" \\\n\t--argjson count \"$COUNT\" \\\n\t--argjson unprovisioned \"$UNPROVISIONED\" \\\n\t'{action:\"unprovisioned\", brandname:$brandname, brand_cloud_id:$brand_cloud_id, count:$count, unprovisioned:$unprovisioned, artifact_file:$artifact_file}'\n",
	"cloud-update-ssh-whitelist.sh":             "#!/usr/bin/env bash\nif [ -z \"${BASH_VERSION:-}\" ]; then\n\texec /usr/bin/env bash \"$0\" \"$@\"\nfi\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nENV_ROOT=\"\"\nDEPRECATED_ENV_ROOT=\"\"\nOPERATOR_ENV=\"\"\nCIDR=\"\"\nDRY_RUN=0\nMODE=\"\"\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 1\n}\n\nlog() {\n\tprintf '[cloud-ssh-whitelist] %s\\n' \"$*\" >&2\n}\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-update-ssh-whitelist.sh [options]\n\nOptions:\n  --cidr CIDR           CIDR to allow. Default: current public IPv4 /32.\n  --mode MODE           append or replace. Default: append in non-interactive runs.\n  --workspace PATH      Default: script parent workspace.\n  --env-root PATH       Required environment directory, for example cloud_env/staging.\n  --secrets-root PATH   Deprecated alias for --env-root.\n  --operator-env PATH   Default: <env-root>/env/operator.env.\n  --dry-run             Show target firewall updates without calling Linode API.\n  -h, --help            Show this help.\n\nUpdates SSH port 22 allowlists for the staging firewalls:\n  - video-cloud-staging-edge/api/infra/mqtt/coturn\n  - rtk-account-manager-staging-fw\n  - rtk-cloud-admin-staging-firewall\n\nModes:\n  append                Add the CIDR to existing SSH allowlists.\n  replace               Replace SSH allowlists with only the CIDR.\n\nIf --mode is omitted in an interactive terminal, the script asks which mode to\nuse. If --mode is omitted in a non-interactive run, it uses append for backward\ncompatibility. The script also updates ignored local staging config/env files so\nfuture provision runs keep the same allowlist.\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--cidr) CIDR=\"$2\"; shift 2 ;;\n\t--mode) MODE=\"$2\"; shift 2 ;;\n\t--workspace) WORKSPACE=\"$2\"; shift 2 ;;\n\t--env-root) ENV_ROOT=\"$2\"; shift 2 ;;\n\t--secrets-root) DEPRECATED_ENV_ROOT=\"$2\"; ENV_ROOT=\"$2\"; shift 2 ;;\n\t--operator-env) OPERATOR_ENV=\"$2\"; shift 2 ;;\n\t--dry-run) DRY_RUN=1; shift ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required; pass the environment directory explicitly, for example --env-root cloud_env/staging\"\n\nneed_cmd() {\n\tcommand -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"\n}\n\nload_env_file() {\n\tlocal path=\"$1\"\n\tif [[ -f \"$path\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$path\"\n\t\tset +a\n\tfi\n}\n\nlinode_api() {\n\tlocal method=\"$1\"\n\tlocal path=\"$2\"\n\tlocal data=\"${3:-}\"\n\tif [[ -n \"$data\" ]]; then\n\t\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t\t-H 'Content-Type: application/json' \\\n\t\t\t--data-binary \"$data\"\n\telse\n\t\tcurl -fsS -X \"$method\" \"https://api.linode.com/v4$path\" \\\n\t\t\t-H \"Authorization: Bearer $LINODE_TOKEN\" \\\n\t\t\t-H 'Content-Type: application/json'\n\tfi\n}\n\ncurrent_public_cidr() {\n\tlocal ip\n\tip=\"$(curl -fsS https://api.ipify.org)\"\n\t[[ \"$ip\" =~ ^([0-9]{1,3}\\.){3}[0-9]{1,3}$ ]] || die \"cannot detect current public IPv4: $ip\"\n\tprintf '%s/32\\n' \"$ip\"\n}\n\nvalidate_cidr() {\n\tlocal cidr=\"$1\"\n\t[[ \"$cidr\" =~ ^([0-9]{1,3}\\.){3}[0-9]{1,3}/([0-9]|[12][0-9]|3[0-2])$ ]] || die \"invalid IPv4 CIDR: $cidr\"\n}\n\nselect_mode() {\n\tcase \"$MODE\" in\n\tappend|replace) return 0 ;;\n\t\"\") ;;\n\t*) die \"invalid --mode: $MODE; expected append or replace\" ;;\n\tesac\n\tif [[ -t 0 && -t 2 ]]; then\n\t\tprintf 'Select SSH whitelist update mode:\\n' >&2\n\t\tprintf '  1) append current CIDR to existing SSH allowlist\\n' >&2\n\t\tprintf '  2) replace SSH allowlist with only current CIDR\\n' >&2\n\t\tprintf 'Choice [1]: ' >&2\n\t\tlocal choice\n\t\tread -r choice\n\t\tcase \"$choice\" in\n\t\t\"\"|1) MODE=\"append\" ;;\n\t\t2) MODE=\"replace\" ;;\n\t\t*) die \"invalid mode choice: $choice\" ;;\n\t\tesac\n\telse\n\t\tMODE=\"append\"\n\tfi\n}\n\nappend_csv_env_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\tlocal cidr=\"$3\"\n\t[[ -f \"$file\" ]] || return 0\n\tlocal tmp\n\ttmp=\"$(mktemp /tmp/rtk-cloud-env.XXXXXX)\"\n\tawk -v key=\"$key\" -v cidr=\"$cidr\" '\n\t\tBEGIN { updated = 0 }\n\t\tindex($0, key \"=\") == 1 {\n\t\t\tvalue = substr($0, length(key) + 2)\n\t\t\tn = split(value, raw, \",\")\n\t\t\tout = \"\"\n\t\t\tfound = 0\n\t\t\tfor (i = 1; i <= n; i++) {\n\t\t\t\tpart = raw[i]\n\t\t\t\tgsub(/^[[:space:]]+|[[:space:]]+$/, \"\", part)\n\t\t\t\tif (part == \"\") {\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t\tif (part == cidr) {\n\t\t\t\t\tfound = 1\n\t\t\t\t}\n\t\t\t\tout = out (out == \"\" ? \"\" : \",\") part\n\t\t\t}\n\t\t\tif (!found) {\n\t\t\t\tout = out (out == \"\" ? \"\" : \",\") cidr\n\t\t\t}\n\t\t\tprint key \"=\" out\n\t\t\tupdated = 1\n\t\t\tnext\n\t\t}\n\t\t{ print }\n\t\tEND {\n\t\t\tif (!updated) {\n\t\t\t\tprint key \"=\" cidr\n\t\t\t}\n\t\t}\n\t' \"$file\" > \"$tmp\"\n\tmv \"$tmp\" \"$file\"\n}\n\nset_csv_env_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\tlocal cidr=\"$3\"\n\t[[ -f \"$file\" ]] || return 0\n\tlocal tmp\n\ttmp=\"$(mktemp /tmp/rtk-cloud-env.XXXXXX)\"\n\tawk -v key=\"$key\" -v cidr=\"$cidr\" '\n\t\tBEGIN { updated = 0 }\n\t\tindex($0, key \"=\") == 1 {\n\t\t\tprint key \"=\" cidr\n\t\t\tupdated = 1\n\t\t\tnext\n\t\t}\n\t\t{ print }\n\t\tEND {\n\t\t\tif (!updated) {\n\t\t\t\tprint key \"=\" cidr\n\t\t\t}\n\t\t}\n\t' \"$file\" > \"$tmp\"\n\tmv \"$tmp\" \"$file\"\n}\n\nappend_video_config_cidr() {\n\tlocal file=\"$1\"\n\tlocal cidr=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tif grep -Fxq \"    - $cidr\" \"$file\"; then\n\t\treturn 0\n\tfi\n\tlocal tmp\n\ttmp=\"$(mktemp /tmp/rtk-cloud-yaml.XXXXXX)\"\n\tawk -v cidr=\"$cidr\" '\n\t\tBEGIN { inserted = 0; in_allowed = 0 }\n\t\t$0 ~ /^[[:space:]]*allowed_source_cidrs:[[:space:]]*$/ {\n\t\t\tin_allowed = 1\n\t\t\tprint\n\t\t\tnext\n\t\t}\n\t\tin_allowed && !inserted && $0 !~ /^    - / {\n\t\t\tprint \"    - \" cidr\n\t\t\tinserted = 1\n\t\t\tin_allowed = 0\n\t\t}\n\t\t{ print }\n\t\tEND {\n\t\t\tif (in_allowed && !inserted) {\n\t\t\t\tprint \"    - \" cidr\n\t\t\t}\n\t\t}\n\t' \"$file\" > \"$tmp\"\n\tmv \"$tmp\" \"$file\"\n}\n\nreplace_video_config_cidr() {\n\tlocal file=\"$1\"\n\tlocal cidr=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tlocal tmp\n\ttmp=\"$(mktemp /tmp/rtk-cloud-yaml.XXXXXX)\"\n\tawk -v cidr=\"$cidr\" '\n\t\tBEGIN { in_allowed = 0; replaced = 0 }\n\t\t$0 ~ /^[[:space:]]*allowed_source_cidrs:[[:space:]]*$/ {\n\t\t\tin_allowed = 1\n\t\t\treplaced = 1\n\t\t\tprint\n\t\t\tprint \"    - \" cidr\n\t\t\tnext\n\t\t}\n\t\tin_allowed {\n\t\t\tif ($0 ~ /^    - /) {\n\t\t\t\tnext\n\t\t\t}\n\t\t\tin_allowed = 0\n\t\t}\n\t\t{ print }\n\t\tEND {\n\t\t\tif (!replaced) {\n\t\t\t\tprint \"ssh:\"\n\t\t\t\tprint \"  allowed_source_cidrs:\"\n\t\t\t\tprint \"    - \" cidr\n\t\t\t}\n\t\t}\n\t' \"$file\" > \"$tmp\"\n\tmv \"$tmp\" \"$file\"\n}\n\ndiscover_firewall_id() {\n\tlocal label=\"$1\"\n\tlocal firewalls=\"$2\"\n\tjq -r --arg label \"$label\" '.data[]? | select(.label == $label) | .id' <<<\"$firewalls\" | head -n 1\n}\n\nupdate_firewall() {\n\tlocal role=\"$1\"\n\tlocal label=\"$2\"\n\tlocal id=\"$3\"\n\tlocal cidr=\"$4\"\n\tlocal rules updated already exact\n\tif [[ -z \"$id\" || \"$id\" == \"null\" ]]; then\n\t\tlog \"skip: $role firewall id missing label=$label\"\n\t\treturn 0\n\tfi\n\trules=\"$(linode_api GET \"/networking/firewalls/$id/rules\")\"\n\tif [[ \"$MODE\" == \"replace\" ]]; then\n\t\texact=\"$(jq -r --arg cidr \"$cidr\" '\n\t\t\t[.inbound[]? | select(.label == \"ssh\" or (.protocol == \"TCP\" and .ports == \"22\"))] as $ssh\n\t\t\t| (($ssh | length) > 0 and ($ssh | all((.addresses.ipv4 // []) == [$cidr])))\n\t\t' <<<\"$rules\")\"\n\t\tif [[ \"$exact\" == \"true\" ]]; then\n\t\t\tlog \"already restricted: mode=replace role=$role firewall=$label id=$id cidr=$cidr\"\n\t\t\treturn 0\n\t\tfi\n\t\tupdated=\"$(jq --arg cidr \"$cidr\" '\n\t\t\t.inbound |= map(\n\t\t\t\tif (.label == \"ssh\" or (.protocol == \"TCP\" and .ports == \"22\")) then\n\t\t\t\t\t.addresses.ipv4 = [$cidr]\n\t\t\t\telse\n\t\t\t\t\t.\n\t\t\t\tend\n\t\t\t)\n\t\t\t| del(.version, .fingerprint)\n\t\t' <<<\"$rules\")\"\n\t\tif [[ \"$DRY_RUN\" == \"1\" ]]; then\n\t\t\tlog \"dry-run replace: mode=replace role=$role firewall=$label id=$id cidr=$cidr\"\n\t\telse\n\t\t\tlinode_api PUT \"/networking/firewalls/$id/rules\" \"$updated\" >/dev/null\n\t\t\tlog \"replaced: mode=replace role=$role firewall=$label id=$id cidr=$cidr\"\n\t\tfi\n\t\treturn 0\n\tfi\n\talready=\"$(jq -r --arg cidr \"$cidr\" '\n\t\t[.inbound[]? | select((.label == \"ssh\" or (.protocol == \"TCP\" and .ports == \"22\")) and ((.addresses.ipv4 // []) | index($cidr)))] | length\n\t' <<<\"$rules\")\"\n\tif [[ \"$already\" != \"0\" ]]; then\n\t\tlog \"already allowed: mode=append role=$role firewall=$label id=$id cidr=$cidr\"\n\t\treturn 0\n\tfi\n\tupdated=\"$(jq --arg cidr \"$cidr\" '\n\t\t.inbound |= map(\n\t\t\tif (.label == \"ssh\" or (.protocol == \"TCP\" and .ports == \"22\")) then\n\t\t\t\t.addresses.ipv4 = (((.addresses.ipv4 // []) + [$cidr]) | unique)\n\t\t\telse\n\t\t\t\t.\n\t\t\tend\n\t\t)\n\t\t| del(.version, .fingerprint)\n\t' <<<\"$rules\")\"\n\tif [[ \"$DRY_RUN\" == \"1\" ]]; then\n\t\tlog \"dry-run append: mode=append role=$role firewall=$label id=$id cidr=$cidr\"\n\telse\n\t\tlinode_api PUT \"/networking/firewalls/$id/rules\" \"$updated\" >/dev/null\n\t\tlog \"appended: mode=append role=$role firewall=$label id=$id cidr=$cidr\"\n\tfi\n}\n\nneed_cmd curl\nneed_cmd jq\n\nWORKSPACE=\"$(cd \"$WORKSPACE\" && pwd)\"\nsource \"$SCRIPT_DIR/lib/cloud-env.sh\"\nENV_ROOT=\"$(cloud_env_init \"$WORKSPACE\" \"$ENV_ROOT\")\"\nDEPRECATED_ENV_ROOT=\"$ENV_ROOT\"\nOPERATOR_ENV=\"${OPERATOR_ENV:-$(cloud_env_operator_env \"$ENV_ROOT\")}\"\n\nif [[ -z \"$CIDR\" ]]; then\n\tCIDR=\"$(current_public_cidr)\"\nfi\nvalidate_cidr \"$CIDR\"\nselect_mode\n\nload_env_file \"$OPERATOR_ENV\"\n[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n\nVC_STATE=\"$(cloud_env_video_state \"$ENV_ROOT\")\"\nVC_SECRET_STATE=\"$VC_STATE\"\nVC_CONFIG=\"$(cloud_env_video_config \"$ENV_ROOT\")\"\nAM_ENV=\"$(cloud_env_account_manager_env \"$ENV_ROOT\")\"\nAM_STATE=\"$(cloud_env_account_manager_state \"$ENV_ROOT\")\"\nADMIN_ENV=\"$(cloud_env_admin_env \"$ENV_ROOT\")\"\nADMIN_STATE=\"$(cloud_env_admin_state \"$ENV_ROOT\")\"\n\nload_env_file \"$AM_STATE\"\nload_env_file \"$ADMIN_STATE\"\n\nlog \"allowing SSH CIDR: mode=$MODE cidr=$CIDR\"\nfirewalls=\"$(linode_api GET '/networking/firewalls?page_size=500')\"\ntmp=\"$(mktemp /tmp/rtk-cloud-ssh-firewalls.XXXXXX)\"\ntrap 'rm -f \"$tmp\"' EXIT\n\nif [[ -f \"$VC_STATE\" ]]; then\n\tjq -r '.firewalls // {} | to_entries[] | [.key, (\"video-cloud-staging-\" + .key), (.value|tostring)] | @tsv' \"$VC_STATE\" >> \"$tmp\"\nelif [[ -f \"$VC_SECRET_STATE\" ]]; then\n\tjq -r '.firewalls // {} | to_entries[] | [.key, (\"video-cloud-staging-\" + .key), (.value|tostring)] | @tsv' \"$VC_SECRET_STATE\" >> \"$tmp\"\nelse\n\tfor role in edge api infra mqtt coturn; do\n\t\tlabel=\"video-cloud-staging-$role\"\n\t\tid=\"$(discover_firewall_id \"$label\" \"$firewalls\")\"\n\t\tprintf '%s\\t%s\\t%s\\n' \"$role\" \"$label\" \"$id\" >> \"$tmp\"\n\tdone\nfi\n\nprintf 'account-manager\\t%s\\t%s\\n' \\\n\t\"${ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL:-rtk-account-manager-staging-fw}\" \\\n\t\"${ACCOUNT_MANAGER_LINODE_FIREWALL_ID:-$(discover_firewall_id \"${ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL:-rtk-account-manager-staging-fw}\" \"$firewalls\")}\" >> \"$tmp\"\nprintf 'cloud-admin\\t%s\\t%s\\n' \\\n\t\"${ADMIN_LINODE_FIREWALL_LABEL:-rtk-cloud-admin-staging-firewall}\" \\\n\t\"${ADMIN_LINODE_FIREWALL_ID:-$(discover_firewall_id \"${ADMIN_LINODE_FIREWALL_LABEL:-rtk-cloud-admin-staging-firewall}\" \"$firewalls\")}\" >> \"$tmp\"\n\nwhile IFS=$'\\t' read -r role label id; do\n\tupdate_firewall \"$role\" \"$label\" \"$id\" \"$CIDR\"\ndone < \"$tmp\"\n\nif [[ \"$DRY_RUN\" != \"1\" ]]; then\n\tif [[ \"$MODE\" == \"replace\" ]]; then\n\t\treplace_video_config_cidr \"$VC_CONFIG\" \"$CIDR\"\n\t\tset_csv_env_value \"$AM_ENV\" ACCOUNT_MANAGER_LINODE_ALLOWED_SSH_CIDRS \"$CIDR\"\n\t\tset_csv_env_value \"$ADMIN_ENV\" ADMIN_LINODE_ALLOWED_SSH_CIDRS \"$CIDR\"\n\telse\n\t\tappend_video_config_cidr \"$VC_CONFIG\" \"$CIDR\"\n\t\tappend_csv_env_value \"$AM_ENV\" ACCOUNT_MANAGER_LINODE_ALLOWED_SSH_CIDRS \"$CIDR\"\n\t\tappend_csv_env_value \"$ADMIN_ENV\" ADMIN_LINODE_ALLOWED_SSH_CIDRS \"$CIDR\"\n\tfi\n\tlog \"local ignored staging config/env updated: mode=$MODE cidr=$CIDR\"\nfi\n",
	"cloud-validate-device-bind.sh":             "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/..\" && pwd)\"\nBIND_ARTIFACT=\"\"\nOUT_DIR=\"\"\nEXPECTED_COUNT=100\nEXPECTED_DEVICES_PER_USER=10\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud-validate-device-bind.sh --bind-artifact FILE [options]\n\nOptions:\n  --bind-artifact FILE             Required artifact from cloud-bind-devices.sh.\n  --out-dir DIR                    Report directory. Default: .artifacts/e2e_test/provisioning/bulk_bind_validation/<timestamp>.\n  --expected-count N               Expected device assignments. Default: 100.\n  --expected-devices-per-user N    Expected device count per user. Default: 10.\n  -h, --help                       Show this help.\n\nValidates the redacted bulk bind/provision artifact and writes JSON plus\nMarkdown reports. stdout contains only a summary JSON.\nUSAGE\n}\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 2\n}\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--bind-artifact) BIND_ARTIFACT=\"$2\"; shift 2 ;;\n\t--out-dir) OUT_DIR=\"$2\"; shift 2 ;;\n\t--expected-count) EXPECTED_COUNT=\"$2\"; shift 2 ;;\n\t--expected-devices-per-user) EXPECTED_DEVICES_PER_USER=\"$2\"; shift 2 ;;\n\t-h|--help) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$BIND_ARTIFACT\" ]] || die \"--bind-artifact is required\"\n[[ -f \"$BIND_ARTIFACT\" ]] || die \"bind artifact not found: $BIND_ARTIFACT\"\n[[ \"$EXPECTED_COUNT\" =~ ^[0-9]+$ && \"$EXPECTED_COUNT\" -gt 0 ]] || die \"--expected-count must be a positive integer\"\n[[ \"$EXPECTED_DEVICES_PER_USER\" =~ ^[0-9]+$ && \"$EXPECTED_DEVICES_PER_USER\" -gt 0 ]] || die \"--expected-devices-per-user must be a positive integer\"\n\nargs=(\n\t--bind-artifact \"$BIND_ARTIFACT\"\n\t--expected-count \"$EXPECTED_COUNT\"\n\t--expected-devices-per-user \"$EXPECTED_DEVICES_PER_USER\"\n)\nif [[ -n \"$OUT_DIR\" ]]; then\n\targs+=(--out-dir \"$OUT_DIR\")\nfi\n\n(\n\tcd \"$WORKSPACE/e2e_test\"\n\ttmpbin=\"$(mktemp /tmp/rtk-bulk-bind-validate.XXXXXX)\"\n\ttrap 'rm -f \"$tmpbin\"' EXIT\n\tgo build -o \"$tmpbin\" ./provisioning/bulk_bind_validation/cmd/rtk-bulk-bind-validate\n\t\"$tmpbin\" \"${args[@]}\"\n)\n",
	"cloud_mqtt_test.sh":                        "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/..\" && pwd)\"\n# shellcheck source=scripts/lib/cloud-env.sh\nsource \"$ROOT/scripts/lib/cloud-env.sh\"\n\nusage() {\n\tcat <<'USAGE'\nUsage:\n  scripts/cloud_mqtt_test.sh --env-root cloud_env/staging --brandname RTK [options]\n\nOptions:\n  --env-root PATH          Required environment root. cloud_env/staging resolves to cloud_env/staging/linode.\n  --brandname NAME         Required brand name used to discover users and device-bind artifacts.\n  --out-dir PATH           Output directory. Default: <env-root>/artifacts/home-mqtt-loadtest/<timestamp>.\n  --profile NAME           smoke or real-case. Default: smoke.\n  --duration-seconds N     Simulated workload duration for report metadata. Default: 120.\n  --max-users N            Limit selected users. Default: 1 for smoke, all for real-case.\n  --seed N                 Deterministic workload seed. Default: 20260531.\n  --mqtt-probe             Run live MQTT E2E through the broker. Default.\n  --no-mqtt-probe          Only validate local artifacts; result is BLOCKED, not PASS.\n  --help                   Show this help.\n\nThe script never prints passwords, bearer tokens, private keys, certificate bodies, or raw service env values.\nUSAGE\n}\n\ndie() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\texit 2\n}\n\nENV_ROOT=\"\"\nBRANDNAME=\"\"\nOUT_DIR=\"\"\nPROFILE=\"smoke\"\nDURATION_SECONDS=\"120\"\nMAX_USERS=\"\"\nSEED=\"20260531\"\nMQTT_PROBE=\"true\"\n\nwhile [[ $# -gt 0 ]]; do\n\tcase \"$1\" in\n\t--env-root) ENV_ROOT=\"${2:-}\"; shift 2 ;;\n\t--brandname) BRANDNAME=\"${2:-}\"; shift 2 ;;\n\t--out-dir) OUT_DIR=\"${2:-}\"; shift 2 ;;\n\t--profile) PROFILE=\"${2:-}\"; shift 2 ;;\n\t--duration-seconds) DURATION_SECONDS=\"${2:-}\"; shift 2 ;;\n\t--max-users) MAX_USERS=\"${2:-}\"; shift 2 ;;\n\t--seed) SEED=\"${2:-}\"; shift 2 ;;\n\t--mqtt-probe) MQTT_PROBE=\"true\"; shift ;;\n\t--no-mqtt-probe) MQTT_PROBE=\"false\"; shift ;;\n\t--help|-h) usage; exit 0 ;;\n\t*) die \"unknown argument: $1\" ;;\n\tesac\ndone\n\n[[ -n \"$ENV_ROOT\" ]] || die \"--env-root is required\"\n[[ -n \"$BRANDNAME\" ]] || die \"--brandname is required\"\ncase \"$PROFILE\" in\nsmoke|real-case) ;;\n*) die \"--profile must be smoke or real-case\" ;;\nesac\n[[ \"$DURATION_SECONDS\" =~ ^[0-9]+$ ]] || die \"--duration-seconds must be an integer\"\n[[ \"$SEED\" =~ ^[0-9]+$ ]] || die \"--seed must be an integer\"\nif [[ -n \"$MAX_USERS\" && ! \"$MAX_USERS\" =~ ^[0-9]+$ ]]; then\n\tdie \"--max-users must be an integer\"\nfi\n\nENV_ROOT=\"$(cloud_env_init \"$ROOT\" \"$ENV_ROOT\")\"\nif [[ -z \"$MAX_USERS\" && \"$PROFILE\" == \"smoke\" ]]; then\n\tMAX_USERS=\"1\"\nfi\nif [[ -z \"$OUT_DIR\" ]]; then\n\tstamp=\"$(date -u '+%Y%m%dT%H%M%SZ')\"\n\tOUT_DIR=\"$(cloud_env_artifacts_dir \"$ENV_ROOT\")/home-mqtt-loadtest/$stamp\"\nfi\nmkdir -p \"$OUT_DIR\"\n\ncommand -v go >/dev/null 2>&1 || die \"go is required\"\n\n(\n\tcd \"$ROOT/scripts/go/cloud-mqtt-test\"\n\tgo run . \\\n\t\t--root \"$ROOT\" \\\n\t\t--env-root \"$ENV_ROOT\" \\\n\t\t--brandname \"$BRANDNAME\" \\\n\t\t--out-dir \"$OUT_DIR\" \\\n\t\t--profile \"$PROFILE\" \\\n\t\t--duration-seconds \"$DURATION_SECONDS\" \\\n\t\t--max-users \"$MAX_USERS\" \\\n\t\t--seed \"$SEED\" \\\n\t\t--mqtt-probe \"$MQTT_PROBE\"\n)\n",
	"collect-private-cloud-evidence.sh":         "#!/usr/bin/env sh\nset -eu\n\nROOT_DIR=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\nENVIRONMENT=${RTK_EVIDENCE_ENVIRONMENT:-evaluation}\nOUTPUT_ROOT=${RTK_EVIDENCE_OUTPUT_DIR:-$ROOT_DIR/evidence}\nTIMESTAMP=${RTK_EVIDENCE_TIMESTAMP:-$(date -u +%Y%m%dT%H%M%SZ)}\nSTRICT=${RTK_EVIDENCE_STRICT:-0}\nRUN_SERVICE_COLLECTORS=${RTK_EVIDENCE_RUN_SERVICE_COLLECTORS:-0}\nPACKAGE_TARBALL=${RTK_EVIDENCE_TARBALL:-1}\n\ncase \"$ENVIRONMENT\" in\n  *[!A-Za-z0-9._-]* | \"\" | .* | *..*)\n    echo \"invalid RTK_EVIDENCE_ENVIRONMENT: use only letters, digits, dot, underscore, and dash\" >&2\n    exit 1\n    ;;\nesac\ncase \"$TIMESTAMP\" in\n  *[!A-Za-z0-9TZ._-]* | \"\" | .* | *..*)\n    echo \"invalid RTK_EVIDENCE_TIMESTAMP: use only letters, digits, T, Z, dot, underscore, and dash\" >&2\n    exit 1\n    ;;\nesac\ncase \"$STRICT\" in 0|1) ;; *) echo \"RTK_EVIDENCE_STRICT must be 0 or 1\" >&2; exit 1 ;; esac\ncase \"$RUN_SERVICE_COLLECTORS\" in 0|1) ;; *) echo \"RTK_EVIDENCE_RUN_SERVICE_COLLECTORS must be 0 or 1\" >&2; exit 1 ;; esac\ncase \"$PACKAGE_TARBALL\" in 0|1) ;; *) echo \"RTK_EVIDENCE_TARBALL must be 0 or 1\" >&2; exit 1 ;; esac\n\nARTIFACT_NAME=\"realtek-connect-plus-evidence-$ENVIRONMENT-$TIMESTAMP\"\nARTIFACT_DIR=\"$OUTPUT_ROOT/$ARTIFACT_NAME\"\nSTATUS_FILE=\"$ARTIFACT_DIR/status.txt\"\nSUMMARY_FILE=\"$ARTIFACT_DIR/summary.md\"\n\numask 077\nmkdir -p \"$ARTIFACT_DIR\" \"$ARTIFACT_DIR/services\" \"$ARTIFACT_DIR/health\" \"$ARTIFACT_DIR/metrics\" \"$ARTIFACT_DIR/brokers\" \"$ARTIFACT_DIR/backups\" \"$ARTIFACT_DIR/reports\" \"$ARTIFACT_DIR/manufacturing\"\n: > \"$STATUS_FILE\"\n\nfailures=0\nskips=0\npasses=0\nblocked=0\n\nredact_sensitive() {\n  sed -E \\\n    -e 's#([A-Za-z][A-Za-z0-9+.-]*://)[^/@[:space:]]+@#\\1<redacted>@#g' \\\n    -e 's#([?&][^=[:space:]]*[Tt][Oo][Kk][Ee][Nn][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Ss][Ee][Cc][Rr][Ee][Tt][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Pp][Aa][Ss][Ss][Ww][Oo][Rr][Dd][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Pp][Aa][Ss][Ss][Ww][Dd][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Kk][Ee][Yy][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Dd][Ss][Nn][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([?&][^=[:space:]]*[Aa][Uu][Tt][Hh][^=[:space:]]*=)[^&[:space:]]+#\\1<redacted>#g' \\\n    -e 's#(Bearer )[A-Za-z0-9._~+/=-]+#\\1<redacted>#g' \\\n    -e 's#([A-Za-z0-9_]*[Tt][Oo][Kk][Ee][Nn][A-Za-z0-9_]*=)[^[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([A-Za-z0-9_]*[Ss][Ee][Cc][Rr][Ee][Tt][A-Za-z0-9_]*=)[^[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([A-Za-z0-9_]*[Pp][Aa][Ss][Ss][Ww][Oo][Rr][Dd][A-Za-z0-9_]*=)[^[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([A-Za-z0-9_]*[Pp][Aa][Ss][Ss][Ww][Dd][A-Za-z0-9_]*=)[^[:space:]]+#\\1<redacted>#g' \\\n    -e 's#([A-Za-z0-9_]*[Dd][Ss][Nn][A-Za-z0-9_]*=)[^[:space:]]+#\\1<redacted>#g' \\\n    -e 's#(\"[^\"]*[Tt][Oo][Kk][Ee][Nn][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Ss][Ee][Cc][Rr][Ee][Tt][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Pp][Aa][Ss][Ss][Ww][Oo][Rr][Dd][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Pp][Aa][Ss][Ss][Ww][Dd][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Dd][Ss][Nn][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Kk][Ee][Yy][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' \\\n    -e 's#(\"[^\"]*[Aa][Uu][Tt][Hh][^\"]*\"[[:space:]]*:[[:space:]]*\")[^\"]*\"#\\1<redacted>\"#g' |\n  awk '\n    /-----BEGIN (.*PRIVATE KEY|CERTIFICATE|CERTIFICATE REQUEST)-----/ {\n      print $0 \" <redacted>\"\n      in_pem=1\n      next\n    }\n    in_pem {\n      print \"<redacted>\"\n      if ($0 ~ /-----END (.*PRIVATE KEY|CERTIFICATE|CERTIFICATE REQUEST)-----/) {\n        in_pem=0\n      }\n      next\n    }\n    { print }\n  '\n}\n\nsafe_name() {\n  printf '%s' \"$1\" | tr '/: ' '---' | tr -cd 'A-Za-z0-9._-'\n}\n\nrecord() {\n  status=$1\n  area=$2\n  reason=$3\n  case \"$status\" in\n    PASS) passes=$((passes + 1)) ;;\n    FAIL) failures=$((failures + 1)) ;;\n    SKIP) skips=$((skips + 1)) ;;\n    BLOCKED) blocked=$((blocked + 1)) ;;\n    *) echo \"invalid status $status\" >&2; exit 1 ;;\n  esac\n  printf '%s\\t%s\\t%s\\n' \"$status\" \"$area\" \"$reason\" >> \"$STATUS_FILE\"\n}\n\ncapture_text() {\n  out=$1\n  shift\n  {\n    printf '$'\n    for arg in \"$@\"; do printf ' %s' \"$arg\"; done\n    printf '\\n\\n'\n    \"$@\" 2>&1 || printf '\\ncommand_exit=%s\\n' \"$?\"\n  } | redact_sensitive > \"$out\"\n}\n\nwrite_manifest() {\n  {\n    printf 'created_utc=%s\\n' \"$TIMESTAMP\"\n    printf 'environment=%s\\n' \"$ENVIRONMENT\"\n    printf 'workspace_root=%s\\n' \"$ROOT_DIR\"\n    printf 'run_service_collectors=%s\\n' \"$RUN_SERVICE_COLLECTORS\"\n    printf 'strict=%s\\n' \"$STRICT\"\n    printf 'generated_by=%s\\n' \"$(id -un 2>/dev/null || printf unknown)\"\n    printf 'hostname=%s\\n' \"$(hostname 2>/dev/null || printf unknown)\"\n    printf 'uname=%s\\n' \"$(uname -a 2>/dev/null || printf unknown)\"\n  } > \"$ARTIFACT_DIR/manifest.txt\"\n  record PASS manifest \"wrote product evidence manifest\"\n}\n\ncollect_commits() {\n  out=\"$ARTIFACT_DIR/services/commits.tsv\"\n  printf 'path\\tcommit\\tbranch\\tdirty\\n' > \"$out\"\n  while IFS= read -r path; do\n    [ -n \"$path\" ] || continue\n    if [ ! -d \"$ROOT_DIR/$path/.git\" ] && ! git -C \"$ROOT_DIR/$path\" rev-parse --git-dir >/dev/null 2>&1; then\n      printf '%s\\tmissing\\tunknown\\tunknown\\n' \"$path\" >> \"$out\"\n      record FAIL \"commit:$path\" \"repository path missing\"\n      continue\n    fi\n    commit=$(git -C \"$ROOT_DIR/$path\" rev-parse HEAD 2>/dev/null || printf unknown)\n    branch=$(git -C \"$ROOT_DIR/$path\" rev-parse --abbrev-ref HEAD 2>/dev/null || printf unknown)\n    if [ -n \"$(git -C \"$ROOT_DIR/$path\" status --porcelain --untracked-files=no 2>/dev/null || true)\" ]; then\n      dirty=yes\n    else\n      dirty=no\n    fi\n    printf '%s\\t%s\\t%s\\t%s\\n' \"$path\" \"$commit\" \"$branch\" \"$dirty\" >> \"$out\"\n    if [ \"$dirty\" = yes ]; then\n      record FAIL \"commit:$path\" \"repository has uncommitted changes\"\n    else\n      record PASS \"commit:$path\" \"pinned commit captured\"\n    fi\n  done <<'PATHS'\n.\nrepos/rtk_cloud_contracts_doc\nrepos/rtk_account_manager\nrepos/rtk_video_cloud\nrepos/rtk_cloud_client\nrepos/rtk_cloud_frontend\nrepos/rtk_cloud_admin\nPATHS\n}\n\ncollect_versions() {\n  out=\"$ARTIFACT_DIR/services/versions.txt\"\n  : > \"$out\"\n  for path in repos/rtk_account_manager repos/rtk_video_cloud repos/rtk_cloud_client repos/rtk_cloud_frontend repos/rtk_cloud_admin; do\n    printf '== %s ==\\n' \"$path\" >> \"$out\"\n    if [ ! -d \"$ROOT_DIR/$path\" ]; then\n      printf 'SKIP missing repository\\n\\n' >> \"$out\"\n      record SKIP \"version:$path\" \"repository path missing\"\n      continue\n    fi\n    if [ -f \"$ROOT_DIR/$path/package.json\" ]; then\n      sed -n 's/^[[:space:]]*\"version\"[[:space:]]*:[[:space:]]*\"\\([^\"]*\\)\".*/package.json version=\\1/p' \"$ROOT_DIR/$path/package.json\" | head -n 1 >> \"$out\" || true\n    fi\n    if [ -f \"$ROOT_DIR/$path/go.mod\" ]; then\n      sed -n '1p' \"$ROOT_DIR/$path/go.mod\" >> \"$out\" || true\n    fi\n    if [ -f \"$ROOT_DIR/$path/VERSION\" ]; then\n      printf 'VERSION=' >> \"$out\"\n      cat \"$ROOT_DIR/$path/VERSION\" >> \"$out\"\n    fi\n    printf '\\n' >> \"$out\"\n    record PASS \"version:$path\" \"local version metadata captured when present\"\n  done\n}\n\nreport_required() {\n  repo=$1\n  report=$2\n  set -f\n  for selector in ${RTK_EVIDENCE_REQUIRED_REPORTS:-}; do\n    case \"$selector\" in\n      \"$repo:$report\"|\"$repo:*\"|\"*:$report\"|\"*:*\")\n        set +f\n        return 0\n        ;;\n    esac\n  done\n  set +f\n  return 1\n}\n\nmanufacturing_required() {\n  key=$1\n  set -f\n  for selector in ${RTK_EVIDENCE_REQUIRED_DEVICE_PRODUCTION_EVIDENCE:-}; do\n    case \"$selector\" in\n      \"$key\"|\"all\")\n        set +f\n        return 0\n        ;;\n    esac\n  done\n  set +f\n  return 1\n}\n\ncapture_manufacturing_ref() {\n  key=$1\n  label=$2\n  value=$3\n  out=\"$ARTIFACT_DIR/manufacturing/$key.txt\"\n  if [ -z \"$value\" ]; then\n    printf 'status=SKIP\\nreason=%s not configured\\n' \"$label\" > \"$out\"\n    if manufacturing_required \"$key\"; then\n      record BLOCKED \"manufacturing:$key\" \"$label not configured\"\n    else\n      record SKIP \"manufacturing:$key\" \"$label not configured\"\n    fi\n    return\n  fi\n\n  case \"$value\" in\n    http://*|https://*)\n      printf 'status=PASS\\nreference=%s\\n' \"$value\" | redact_sensitive > \"$out\"\n      record PASS \"manufacturing:$key\" \"$label reference captured\"\n      return\n      ;;\n  esac\n\n  if [ ! -f \"$value\" ]; then\n    printf 'status=BLOCKED\\nreason=%s file not found\\npath=%s\\n' \"$label\" \"$value\" | redact_sensitive > \"$out\"\n    record BLOCKED \"manufacturing:$key\" \"$label configured file missing\"\n    return\n  fi\n\n  {\n    printf 'status=PASS\\nsource=%s\\n\\n' \"$value\"\n    cat \"$value\"\n  } | redact_sensitive > \"$out\"\n  record PASS \"manufacturing:$key\" \"$label artifact captured\"\n}\n\ncollect_device_production_evidence() {\n  {\n    printf 'required_device_production_evidence=%s\\n' \"${RTK_EVIDENCE_REQUIRED_DEVICE_PRODUCTION_EVIDENCE:-}\"\n    printf 'factory_enroll_results_ref=%s\\n' \"${RTK_EVIDENCE_FACTORY_ENROLL_RESULTS_REF:-}\"\n    printf 'factory_enroll_report_ref=%s\\n' \"${RTK_EVIDENCE_FACTORY_ENROLL_REPORT_REF:-}\"\n    printf 'account_video_smoke_results_ref=%s\\n' \"${RTK_EVIDENCE_ACCOUNT_VIDEO_SMOKE_RESULTS_REF:-}\"\n    printf 'account_video_smoke_report_ref=%s\\n' \"${RTK_EVIDENCE_ACCOUNT_VIDEO_SMOKE_REPORT_REF:-}\"\n    printf 'device_mtls_token_smoke_ref=%s\\n' \"${RTK_EVIDENCE_DEVICE_MTLS_TOKEN_SMOKE_REF:-}\"\n    printf 'transport_online_smoke_ref=%s\\n' \"${RTK_EVIDENCE_TRANSPORT_ONLINE_SMOKE_REF:-}\"\n  } | redact_sensitive > \"$ARTIFACT_DIR/manufacturing/config.txt\"\n\n  capture_manufacturing_ref factory_enroll_results \"factory enrollment results\" \"${RTK_EVIDENCE_FACTORY_ENROLL_RESULTS_REF:-}\"\n  capture_manufacturing_ref factory_enroll_report \"factory enrollment report\" \"${RTK_EVIDENCE_FACTORY_ENROLL_REPORT_REF:-}\"\n  capture_manufacturing_ref account_video_smoke_results \"account/video provisioning smoke results\" \"${RTK_EVIDENCE_ACCOUNT_VIDEO_SMOKE_RESULTS_REF:-}\"\n  capture_manufacturing_ref account_video_smoke_report \"account/video provisioning smoke report\" \"${RTK_EVIDENCE_ACCOUNT_VIDEO_SMOKE_REPORT_REF:-}\"\n  capture_manufacturing_ref device_mtls_token_smoke \"device mTLS token smoke evidence\" \"${RTK_EVIDENCE_DEVICE_MTLS_TOKEN_SMOKE_REF:-}\"\n  capture_manufacturing_ref transport_online_smoke \"transport online smoke evidence\" \"${RTK_EVIDENCE_TRANSPORT_ONLINE_SMOKE_REF:-}\"\n}\n\ncollect_canonical_reports() {\n  out=\"$ARTIFACT_DIR/reports/canonical-reports.tsv\"\n  printf 'repo_path\\trepo_commit\\treport_file\\tstatus\\tsource_path\\treason\\n' > \"$out\"\n\n  while IFS='|' read -r repo report; do\n    [ -n \"$repo\" ] || continue\n    repo_dir=\"$ROOT_DIR/$repo\"\n    source_path=\"$repo/$report\"\n    if [ ! -d \"$repo_dir\" ]; then\n      printf '%s\\tmissing\\t%s\\tSKIP\\t%s\\trepository path missing\\n' \"$repo\" \"$report\" \"$source_path\" >> \"$out\"\n      record SKIP \"report:$source_path\" \"repository path missing\"\n      continue\n    fi\n    commit=$(git -C \"$repo_dir\" rev-parse HEAD 2>/dev/null || printf unknown)\n    if [ -f \"$ROOT_DIR/$source_path\" ]; then\n      printf '%s\\t%s\\t%s\\tPASS\\t%s\\trepo-owned canonical report present\\n' \"$repo\" \"$commit\" \"$report\" \"$source_path\" >> \"$out\"\n      record PASS \"report:$source_path\" \"repo-owned canonical report present\"\n    elif report_required \"$repo\" \"$report\"; then\n      printf '%s\\t%s\\t%s\\tBLOCKED\\t%s\\trequired canonical report missing\\n' \"$repo\" \"$commit\" \"$report\" \"$source_path\" >> \"$out\"\n      record BLOCKED \"report:$source_path\" \"required canonical report missing\"\n    else\n      printf '%s\\t%s\\t%s\\tSKIP\\t%s\\treport not present or not applicable for this repo/profile\\n' \"$repo\" \"$commit\" \"$report\" \"$source_path\" >> \"$out\"\n      record SKIP \"report:$source_path\" \"report not present or not applicable for this repo/profile\"\n    fi\n  done <<'REPORTS'\nrepos/rtk_cloud_contracts_doc|docs/TEST_REPORT.md\nrepos/rtk_cloud_contracts_doc|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_cloud_contracts_doc|docs/READINESS_TEST_REPORT.md\nrepos/rtk_cloud_contracts_doc|docs/LOAD_TEST_REPORT.md\nrepos/rtk_cloud_contracts_doc|docs/HARDWARE_TEST_REPORT.md\nrepos/rtk_account_manager|docs/TEST_REPORT.md\nrepos/rtk_account_manager|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_account_manager|docs/READINESS_TEST_REPORT.md\nrepos/rtk_account_manager|docs/LOAD_TEST_REPORT.md\nrepos/rtk_account_manager|docs/HARDWARE_TEST_REPORT.md\nrepos/rtk_video_cloud|docs/TEST_REPORT.md\nrepos/rtk_video_cloud|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_video_cloud|docs/READINESS_TEST_REPORT.md\nrepos/rtk_video_cloud|docs/LOAD_TEST_REPORT.md\nrepos/rtk_video_cloud|docs/HARDWARE_TEST_REPORT.md\nrepos/rtk_cloud_client|docs/TEST_REPORT.md\nrepos/rtk_cloud_client|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_cloud_client|docs/READINESS_TEST_REPORT.md\nrepos/rtk_cloud_client|docs/LOAD_TEST_REPORT.md\nrepos/rtk_cloud_client|docs/HARDWARE_TEST_REPORT.md\nrepos/rtk_cloud_frontend|docs/TEST_REPORT.md\nrepos/rtk_cloud_frontend|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_cloud_frontend|docs/READINESS_TEST_REPORT.md\nrepos/rtk_cloud_frontend|docs/LOAD_TEST_REPORT.md\nrepos/rtk_cloud_frontend|docs/HARDWARE_TEST_REPORT.md\nrepos/rtk_cloud_admin|docs/TEST_REPORT.md\nrepos/rtk_cloud_admin|docs/RELEASE_TEST_REPORT.md\nrepos/rtk_cloud_admin|docs/READINESS_TEST_REPORT.md\nrepos/rtk_cloud_admin|docs/LOAD_TEST_REPORT.md\nrepos/rtk_cloud_admin|docs/HARDWARE_TEST_REPORT.md\nREPORTS\n\n  refs_file=${RTK_EVIDENCE_REPORT_ARTIFACT_REFS_FILE:-}\n  if [ -n \"$refs_file\" ] && [ -f \"$refs_file\" ]; then\n    redact_sensitive < \"$refs_file\" > \"$ARTIFACT_DIR/reports/artifact-references.txt\"\n    record PASS report_artifact_refs \"sanitized report artifact references captured\"\n  elif [ -n \"$refs_file\" ]; then\n    printf 'status=BLOCKED\\nreason=RTK_EVIDENCE_REPORT_ARTIFACT_REFS_FILE not found\\npath=%s\\n' \"$refs_file\" | redact_sensitive > \"$ARTIFACT_DIR/reports/artifact-references.txt\"\n    record BLOCKED report_artifact_refs \"configured report artifact reference file missing\"\n  else\n    printf 'status=SKIP\\nreason=RTK_EVIDENCE_REPORT_ARTIFACT_REFS_FILE not configured\\n' > \"$ARTIFACT_DIR/reports/artifact-references.txt\"\n    record SKIP report_artifact_refs \"report artifact references not configured\"\n  fi\n}\n\ncollect_url() {\n  name=$1\n  url=$2\n  target_dir=$3\n  required=$4\n  file=\"$target_dir/$(safe_name \"$name\").txt\"\n  if [ -z \"$url\" ]; then\n    if [ \"$required\" = required ]; then\n      record FAIL \"$name\" \"URL not configured\"\n    else\n      record SKIP \"$name\" \"URL not configured\"\n    fi\n    printf 'status=SKIP\\nreason=URL not configured\\n' > \"$file\"\n    return\n  fi\n  if ! command -v curl >/dev/null 2>&1; then\n    record SKIP \"$name\" \"curl unavailable\"\n    printf 'status=SKIP\\nreason=curl unavailable\\nurl=%s\\n' \"$url\" | redact_sensitive > \"$file\"\n    return\n  fi\n  tmp=\"$file.tmp\"\n  if curl -fsS --max-time 10 \"$url\" > \"$tmp\" 2>&1; then\n    redact_sensitive < \"$tmp\" > \"$file\"\n    rm -f \"$tmp\"\n    record PASS \"$name\" \"HTTP probe succeeded\"\n  else\n    code=$?\n    redact_sensitive < \"$tmp\" > \"$file\" 2>/dev/null || true\n    rm -f \"$tmp\"\n    record FAIL \"$name\" \"HTTP probe failed with curl exit $code\"\n  fi\n}\n\ncollect_health() {\n  collect_url frontend_health \"${RTK_EVIDENCE_FRONTEND_HEALTH_URL:-}\" \"$ARTIFACT_DIR/health\" optional\n  collect_url admin_health \"${RTK_EVIDENCE_ADMIN_HEALTH_URL:-}\" \"$ARTIFACT_DIR/health\" optional\n  collect_url account_manager_health \"${RTK_EVIDENCE_ACCOUNT_MANAGER_HEALTH_URL:-}\" \"$ARTIFACT_DIR/health\" optional\n  collect_url video_cloud_health \"${RTK_EVIDENCE_VIDEO_CLOUD_HEALTH_URL:-}\" \"$ARTIFACT_DIR/health\" optional\n}\n\ncollect_metrics() {\n  urls=${RTK_EVIDENCE_METRICS_URLS:-}\n  if [ -z \"$urls\" ]; then\n    record SKIP metrics \"RTK_EVIDENCE_METRICS_URLS not configured\"\n    printf 'status=SKIP\\nreason=RTK_EVIDENCE_METRICS_URLS not configured\\n' > \"$ARTIFACT_DIR/metrics/metrics.txt\"\n    return\n  fi\n  for url in $urls; do\n    collect_url \"metrics:$url\" \"$url\" \"$ARTIFACT_DIR/metrics\" optional\n  done\n}\n\ncollect_brokers() {\n  {\n    printf 'emqx_required=%s\\n' \"${RTK_EVIDENCE_EMQX_REQUIRED:-auto}\"\n    printf 'emqx_status_url=%s\\n' \"${RTK_EVIDENCE_EMQX_STATUS_URL:-}\"\n    printf 'nats_required=%s\\n' \"${RTK_EVIDENCE_NATS_REQUIRED:-auto}\"\n    printf 'nats_url=%s\\n' \"${RTK_EVIDENCE_NATS_URL:-}\"\n  } | redact_sensitive > \"$ARTIFACT_DIR/brokers/config.txt\"\n\n  collect_url emqx_status \"${RTK_EVIDENCE_EMQX_STATUS_URL:-}\" \"$ARTIFACT_DIR/brokers\" optional\n\n  if [ -n \"${RTK_EVIDENCE_NATS_URL:-}\" ]; then\n    record PASS nats_config \"NATS JetStream URL configured; smoke test is service/operator-owned\"\n  else\n    record SKIP nats_config \"RTK_EVIDENCE_NATS_URL not configured; cross-service channel may be disabled\"\n  fi\n\n  if [ -n \"${RTK_EVIDENCE_BROKER_SMOKE_REF:-}\" ]; then\n    printf '%s\\n' \"$RTK_EVIDENCE_BROKER_SMOKE_REF\" | redact_sensitive > \"$ARTIFACT_DIR/brokers/smoke-reference.txt\"\n    record PASS broker_smoke_reference \"broker smoke evidence reference captured\"\n  else\n    printf 'status=SKIP\\nreason=RTK_EVIDENCE_BROKER_SMOKE_REF not configured\\n' > \"$ARTIFACT_DIR/brokers/smoke-reference.txt\"\n    record SKIP broker_smoke_reference \"broker smoke evidence reference not configured\"\n  fi\n}\n\ncollect_backups() {\n  out=\"$ARTIFACT_DIR/backups/references.txt\"\n  {\n    printf 'postgres_backup_ref=%s\\n' \"${RTK_EVIDENCE_POSTGRES_BACKUP_REF:-}\"\n    printf 'object_storage_backup_ref=%s\\n' \"${RTK_EVIDENCE_OBJECT_STORAGE_BACKUP_REF:-}\"\n    printf 'frontend_sqlite_backup_ref=%s\\n' \"${RTK_EVIDENCE_FRONTEND_BACKUP_REF:-}\"\n    printf 'emqx_backup_ref=%s\\n' \"${RTK_EVIDENCE_EMQX_BACKUP_REF:-}\"\n    printf 'nats_backup_ref=%s\\n' \"${RTK_EVIDENCE_NATS_BACKUP_REF:-}\"\n  } | redact_sensitive > \"$out\"\n\n  found=0\n  for var in RTK_EVIDENCE_POSTGRES_BACKUP_REF RTK_EVIDENCE_OBJECT_STORAGE_BACKUP_REF RTK_EVIDENCE_FRONTEND_BACKUP_REF RTK_EVIDENCE_EMQX_BACKUP_REF RTK_EVIDENCE_NATS_BACKUP_REF; do\n    eval value=\\${$var:-}\n    [ -n \"$value\" ] && found=1\n  done\n  if [ \"$found\" = 1 ]; then\n    record PASS backup_refs \"backup evidence references captured\"\n  else\n    record SKIP backup_refs \"no backup evidence references configured\"\n  fi\n}\n\ncollect_service_artifacts() {\n  if [ \"$RUN_SERVICE_COLLECTORS\" != 1 ]; then\n    record SKIP service_collectors \"RTK_EVIDENCE_RUN_SERVICE_COLLECTORS=0\"\n    return\n  fi\n\n  vc_script=\"$ROOT_DIR/repos/rtk_video_cloud/deploy/collect-readiness-evidence.sh\"\n  if [ -x \"$vc_script\" ]; then\n    vc_status=0\n    VIDEO_CLOUD_EVIDENCE_OUTPUT_DIR=\"$ARTIFACT_DIR/services\" \"$vc_script\" > \"$ARTIFACT_DIR/services/video-cloud-collector.txt\" 2>&1 || vc_status=$?\n    redact_sensitive < \"$ARTIFACT_DIR/services/video-cloud-collector.txt\" > \"$ARTIFACT_DIR/services/video-cloud-collector.redacted.txt\"\n    rm -f \"$ARTIFACT_DIR/services/video-cloud-collector.txt\"\n    if [ \"$vc_status\" -eq 0 ]; then\n      record PASS video_cloud_collector \"video cloud evidence collector completed\"\n    else\n      record FAIL video_cloud_collector \"service collector exited non-zero\"\n    fi\n  else\n    record SKIP video_cloud_collector \"video cloud collector unavailable\"\n  fi\n\n  for name in account_manager admin frontend; do\n    var=$(printf 'RTK_EVIDENCE_%s_COLLECTOR_CMD' \"$(printf '%s' \"$name\" | tr '[:lower:]' '[:upper:]')\")\n    eval cmd=\\${$var:-}\n    if [ -z \"$cmd\" ]; then\n      record SKIP \"${name}_collector\" \"$var not configured\"\n      continue\n    fi\n    collector_status=0\n    sh -c \"$cmd\" > \"$ARTIFACT_DIR/services/${name}-collector.txt\" 2>&1 || collector_status=$?\n    redact_sensitive < \"$ARTIFACT_DIR/services/${name}-collector.txt\" > \"$ARTIFACT_DIR/services/${name}-collector.redacted.txt\"\n    rm -f \"$ARTIFACT_DIR/services/${name}-collector.txt\"\n    if [ \"$collector_status\" -eq 0 ]; then\n      record PASS \"${name}_collector\" \"collector command completed\"\n    else\n      record FAIL \"${name}_collector\" \"collector command exited non-zero\"\n    fi\n  done\n}\n\nwrite_summary() {\n  {\n    printf '# Realtek Connect+ Private Cloud Evidence Summary\\n\\n'\n    printf '%s\\n' \"- Environment: \\`$ENVIRONMENT\\`\"\n    printf '%s\\n' \"- Created UTC: \\`$TIMESTAMP\\`\"\n    printf '%s\\n' \"- Pass: \\`$passes\\`\"\n    printf '%s\\n' \"- Fail: \\`$failures\\`\"\n    printf '%s\\n' \"- Skip: \\`$skips\\`\"\n    printf '%s\\n' \"- Blocked: \\`$blocked\\`\"\n    printf '\\n## Status\\n\\n'\n    awk -F '\\t' '{ printf \"- `%s` `%s` - %s\\n\", $1, $2, $3 }' \"$STATUS_FILE\"\n  } > \"$SUMMARY_FILE\"\n}\n\npackage_artifact() {\n  if [ \"$PACKAGE_TARBALL\" != 1 ]; then\n    return\n  fi\n  tarball=\"$OUTPUT_ROOT/$ARTIFACT_NAME.tar.gz\"\n  (cd \"$OUTPUT_ROOT\" && tar -czf \"$tarball\" \"$ARTIFACT_NAME\")\n  printf 'tarball=%s\\n' \"$tarball\" > \"$ARTIFACT_DIR/tarball.txt\"\n}\n\nmain() {\n  cd \"$ROOT_DIR\"\n  write_manifest\n  collect_commits\n  collect_versions\n  collect_canonical_reports\n  collect_health\n  collect_metrics\n  collect_brokers\n  collect_backups\n  collect_device_production_evidence\n  collect_service_artifacts\n  write_summary\n  package_artifact\n\n  echo \"artifact_dir=$ARTIFACT_DIR\"\n  if [ \"$PACKAGE_TARBALL\" = 1 ]; then\n    echo \"tarball=$OUTPUT_ROOT/$ARTIFACT_NAME.tar.gz\"\n  fi\n  echo \"passes=$passes\"\n  echo \"failures=$failures\"\n  echo \"skips=$skips\"\n  echo \"blocked=$blocked\"\n\n  if [ \"$STRICT\" = 1 ] && [ $((failures + blocked)) -gt 0 ]; then\n    exit 1\n  fi\n}\n\nmain \"$@\"\n",
	"docs-check.sh":                             "#!/usr/bin/env sh\nset -eu\n\nroot=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\ncd \"$root\"\n\nfailures=0\n\nfail() {\n  echo \"FAIL: $*\" >&2\n  failures=$((failures + 1))\n}\n\npass() {\n  echo \"OK: $*\"\n}\n\nrequire_file() {\n  if [ -f \"$1\" ]; then\n    pass \"found $1\"\n  else\n    fail \"missing $1\"\n  fi\n}\n\nrequire_dir() {\n  if [ -d \"$1\" ]; then\n    pass \"found $1\"\n  else\n    fail \"missing $1\"\n  fi\n}\n\necho \"== workspace documentation entries ==\"\nrequire_file README.md\nrequire_file docs/README.md\nrequire_file docs/architecture.md\nrequire_file docs/documentation-governance.md\nrequire_file docs/deployment-secrets-governance.md\nrequire_file docs/linode-ci-runners.md\nrequire_file docs/examples/secrets-manifest.example.json\nrequire_file docs/testing.md\nrequire_file docs/LOAD_TEST_REPORT.md\nrequire_file e2e_test/README.md\nrequire_file e2e_test/go.mod\nrequire_file e2e_test/fixtures/README.md\nrequire_file e2e_test/factory_enroll/README.md\nrequire_file e2e_test/factory_enroll/cmd/rtk-factory-enroll-test/main.go\nrequire_file e2e_test/factory_enroll/scripts/run_factory_enroll_local.sh\nrequire_file e2e_test/provisioning/account_video_smoke/README.md\nrequire_file e2e_test/provisioning/account_video_smoke/cmd/rtk-account-video-smoke/main.go\nrequire_file e2e_test/provisioning/bulk_bind_validation/README.md\nrequire_file e2e_test/provisioning/bulk_bind_validation/cmd/rtk-bulk-bind-validate/main.go\nrequire_file e2e_test/admin_bff/README.md\nrequire_file e2e_test/video_cloud/load/cmd/rtk-video-loadtest/main.go\nrequire_file e2e_test/video_cloud/load/scripts/run_video_loadtest.sh\nrequire_file e2e_test/video_cloud/load/scripts/deploy_video_loadtest_two_host.sh\nrequire_file docs/adr/README.md\nrequire_file docs/product-level-evidence.md\nrequire_file docs/cross-service-broker-packaging.md\nrequire_file repos/rtk_cloud_contracts_doc/README.md\nrequire_file scripts/collect-private-cloud-evidence.sh\nrequire_file scripts/secrets-check.sh\nrequire_file scripts/cloud-bind-devices.sh\nrequire_file scripts/cloud-validate-device-bind.sh\nrequire_file scripts/linode-ci-runners/runner-specs.sh\nrequire_file scripts/linode-ci-runners/provision-ci-runners.sh\nrequire_file scripts/linode-ci-runners/power-ci-runners.sh\nrequire_file scripts/linode-ci-runners/wait-runners-online.sh\nrequire_file scripts/linode-ci-runners/list-ci-runners.sh\nrequire_file scripts/linode-ci-runners/archive-ci-artifacts.sh\nrequire_file tests/linode-ci-runners/runner-specs.test.sh\nrequire_file tests/staging-bind-devices.test.sh\nrequire_file tests/staging-bind-validation.test.sh\n\nif grep -q 'repos/rtk_mqtt' README.md docs/architecture.md scripts/test-matrix.sh; then\n  fail \"workspace README, architecture, or test matrix still references repos/rtk_mqtt\"\nelse\n  pass \"removed repos/rtk_mqtt workspace references\"\nfi\n\necho\necho \"== submodule registry ==\"\npaths=$(git config --file .gitmodules --get-regexp '^submodule\\..*\\.path$' | awk '{print $2}')\nfor path in $paths; do\n  require_dir \"$path\"\n  if grep -q \"\\`$path\\`\" README.md; then\n    pass \"README documents $path\"\n  else\n    fail \"README does not document $path\"\n  fi\ndone\n\necho\necho \"== service documentation entry points ==\"\nrequire_file repos/rtk_cloud_client/docs/README.md\nrequire_file repos/rtk_video_cloud/docs/architecture.md\nrequire_file repos/rtk_account_manager/docs/SPEC.md\nrequire_file repos/rtk_cloud_frontend/README.md\nrequire_file repos/rtk_cloud_admin/README.md\n\necho\necho \"== contracts submodule alignment ==\"\ncontract_paths=\"\nrepos/rtk_cloud_contracts_doc\nrepos/rtk_account_manager/contracts\nrepos/rtk_cloud_client/docs/rtk_cloud_contracts_doc\nrepos/rtk_video_cloud/docs/rtk_cloud_contracts_doc\nrepos/rtk_cloud_admin/rtk_cloud_contracts_doc\n\"\n\nexpected=\"\"\nfor path in $contract_paths; do\n  require_dir \"$path\"\n  commit=$(git -C \"$path\" rev-parse HEAD)\n  echo \"$path $commit\"\n  if [ -z \"$expected\" ]; then\n    expected=$commit\n  elif [ \"$commit\" != \"$expected\" ]; then\n    fail \"$path is pinned to $commit, expected $expected\"\n  fi\ndone\n\nif [ \"$failures\" -eq 0 ]; then\n  echo\n  echo \"Documentation checks passed.\"\n  exit 0\nfi\n\necho\necho \"Documentation checks failed: $failures\" >&2\nexit 1\n",
	"secrets-check.sh":                          "#!/usr/bin/env sh\nset -eu\n\nroot=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\ncd \"$root\"\n\nfailures=0\n\nfail() {\n  echo \"FAIL: $*\" >&2\n  failures=$((failures + 1))\n}\n\npass() {\n  echo \"OK: $*\"\n}\n\ncheck_ignored() {\n  path=$1\n  if git check-ignore -q \"$path\"; then\n    pass \"$path is ignored\"\n  else\n    fail \"$path is not ignored\"\n  fi\n}\n\ncheck_no_match() {\n  label=$1\n  pattern=$2\n  shift 2\n  if git grep -n -E \"$pattern\" -- \"$@\" >/tmp/rtk_secret_check_matches.$$ 2>/dev/null; then\n    echo \"Potential $label found:\" >&2\n    cat /tmp/rtk_secret_check_matches.$$ >&2\n    rm -f /tmp/rtk_secret_check_matches.$$\n    fail \"$label present in tracked workspace files\"\n  else\n    rm -f /tmp/rtk_secret_check_matches.$$\n    pass \"no $label in tracked workspace files\"\n  fi\n}\n\ncheck_file_no_match() {\n  file=$1\n  label=$2\n  pattern=$3\n  if [ ! -f \"$file\" ]; then\n    fail \"missing $file\"\n    return\n  fi\n  if grep -n -E \"$pattern\" \"$file\" >/tmp/rtk_secret_check_file_matches.$$ 2>/dev/null; then\n    echo \"Potential $label found in $file:\" >&2\n    cat /tmp/rtk_secret_check_file_matches.$$ >&2\n    rm -f /tmp/rtk_secret_check_file_matches.$$\n    fail \"$label present in $file\"\n  else\n    rm -f /tmp/rtk_secret_check_file_matches.$$\n    pass \"no $label in $file\"\n  fi\n}\n\nworkspace_paths=\".gitignore README.md docs scripts e2e_test\"\nmanifest_example='docs/examples/secrets-manifest.example.json'\n\necho \"== ignore rules ==\"\ncheck_ignored .secrets\ncheck_ignored .secrets.backup\ncheck_ignored .secrets/staging/linode/admin/env/admin.env\ncheck_ignored cloud_env\ncheck_ignored cloud_env/staging/linode/env/operator.env\ncheck_ignored cloud_env/staging/linode/keys/root-ca.key.pem\n\necho\necho \"== tracked workspace secret scan ==\"\ncheck_no_match \"private key block\" '-----BEGIN ([A-Z0-9 ]+ )?PRIVATE KEY-----' $workspace_paths\ncheck_no_match \"bearer token literal\" 'Bearer[[:space:]]+[A-Za-z0-9._~+/-]{24,}' $workspace_paths\ncheck_no_match \"JWT-like token\" 'eyJ[A-Za-z0-9_-]{20,}\\.[A-Za-z0-9_-]{20,}\\.[A-Za-z0-9_-]{20,}' $workspace_paths\ncheck_no_match \"hard-coded password assignment\" '(^|[^A-Za-z0-9_])(PASSWORD|PASS|TOKEN|SECRET|PRIVATE_KEY)[A-Za-z0-9_]*=[^[:space:]<>$][^[:space:]]{7,}' $workspace_paths\n\necho\necho \"== manifest example ==\"\ncheck_file_no_match \"$manifest_example\" \"private key block\" '-----BEGIN ([A-Z0-9 ]+ )?PRIVATE KEY-----'\ncheck_file_no_match \"$manifest_example\" \"JWT-like token\" 'eyJ[A-Za-z0-9_-]{20,}\\.[A-Za-z0-9_-]{20,}\\.[A-Za-z0-9_-]{20,}'\ncheck_file_no_match \"$manifest_example\" \"production staging reference\" '\"environment\"[[:space:]]*:[[:space:]]*\"production\"|video-cloud-staging|staging-token|factory-linode-certset|example.invalid'\n\nif [ \"$failures\" -gt 0 ]; then\n  echo \"Secrets checks failed: $failures\" >&2\n  exit 1\nfi\n\necho \"Secrets checks passed.\"\n",
	"status-all.sh":                             "#!/usr/bin/env sh\nset -eu\n\nroot=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\ncd \"$root\"\n\necho \"workspace:\"\ngit status --short --branch\necho\n\ngit submodule foreach --recursive '\n  echo\n  echo \"[$name] $path\"\n  git status --short --branch\n  git log -1 --oneline --decorate\n'\n\n",
	"sync-all.sh":                               "#!/usr/bin/env sh\nset -eu\n\nroot=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\ncd \"$root\"\n\ngit fetch origin\ngit submodule sync --recursive\ngit submodule update --init --recursive\ngit submodule foreach --recursive 'git fetch --all --prune'\n\necho \"Fetched workspace and submodule remotes. Pinned commits were not changed.\"\n\n",
	"test-matrix.sh":                            "#!/usr/bin/env sh\nset -eu\n\nroot=$(CDPATH= cd -- \"$(dirname -- \"$0\")/..\" && pwd)\ncd \"$root\"\n\necho \"== workspace status ==\"\ngit status --short --branch\ngit submodule status --recursive\n\necho\necho \"== rtk_cloud_client quick validation ==\"\nif [ -d repos/rtk_cloud_client ]; then\n  (\n    cd repos/rtk_cloud_client\n    git diff --check\n    git submodule status -- docs/rtk_cloud_contracts_doc || true\n  )\nelse\n  echo \"SKIP: repos/rtk_cloud_client is missing\"\nfi\n\necho\necho \"== repository status checks ==\"\nrepos=$(git config --file .gitmodules --get-regexp '^submodule\\..*\\.path$' | awk '{print $2}')\nfor repo in $repos; do\n  if [ -d \"$repo\" ]; then\n    echo \"-- $repo\"\n    git -C \"$repo\" status --short --branch\n  else\n    echo \"SKIP: $repo is missing\"\n  fi\ndone\n",
	"lib/cloud-env.sh":                          "#!/usr/bin/env bash\n\ncloud_env_default_root() {\n\tlocal workspace=\"$1\"\n\tprintf '%s/cloud_env/staging/linode\\n' \"$workspace\"\n}\n\ncloud_env_abs_path() {\n\tlocal path=\"$1\"\n\tif [[ -d \"$path\" ]]; then\n\t\t(cd \"$path\" && pwd)\n\t\treturn\n\tfi\n\tlocal parent base\n\tparent=\"$(dirname \"$path\")\"\n\tbase=\"$(basename \"$path\")\"\n\tif [[ -d \"$parent\" ]]; then\n\t\tprintf '%s/%s\\n' \"$(cd \"$parent\" && pwd)\" \"$base\"\n\telse\n\t\tprintf '%s\\n' \"$path\"\n\tfi\n}\n\ncloud_env_init() {\n\tlocal workspace=\"$1\"\n\tlocal env_root=\"${2:-}\"\n\tif [[ -z \"$env_root\" ]]; then\n\t\tenv_root=\"$(cloud_env_default_root \"$workspace\")\"\n\tfi\n\tenv_root=\"$(cloud_env_abs_path \"$env_root\")\"\n\tif [[ \"$(basename \"$env_root\")\" == \"staging\" && ! -d \"$env_root/services\" && ! -d \"$env_root/env\" && ! -d \"$env_root/topology\" ]]; then\n\t\tenv_root=\"$(cloud_env_abs_path \"$env_root/linode\")\"\n\telif [[ -d \"$env_root/linode\" && ! -d \"$env_root/services\" && ! -d \"$env_root/env\" && ! -d \"$env_root/topology\" ]]; then\n\t\tenv_root=\"$(cloud_env_abs_path \"$env_root/linode\")\"\n\tfi\n\tprintf '%s\\n' \"$env_root\"\n}\n\ncloud_env_operator_env() {\n\tprintf '%s/env/operator.env\\n' \"$1\"\n}\n\ncloud_env_stack_env() {\n\tprintf '%s/env/stack.env\\n' \"$1\"\n}\n\ncloud_env_first_existing() {\n\tlocal first=\"$1\"\n\tlocal second=\"${2:-}\"\n\tif [[ -n \"$first\" && -e \"$first\" ]]; then\n\t\tprintf '%s\\n' \"$first\"\n\telif [[ -n \"$second\" ]]; then\n\t\tprintf '%s\\n' \"$second\"\n\telse\n\t\tprintf '%s\\n' \"$first\"\n\tfi\n}\n\ncloud_env_video_config() {\n\tcloud_env_first_existing \"$1/topology/video-cloud.yaml\" \"$1/topology/video-cloud-staging.yaml\"\n}\n\ncloud_env_video_env() {\n\tcloud_env_first_existing \"$1/services/video-cloud/video-cloud.env\" \"$1/services/video-cloud/video-cloud-staging.env\"\n}\n\ncloud_env_account_manager_env() {\n\tcloud_env_first_existing \"$1/services/account-manager/account-manager.env\" \"$1/services/account-manager/account-manager-public-staging.env\"\n}\n\ncloud_env_account_manager_platform_admin_env() {\n\tcloud_env_first_existing \"$1/services/account-manager/platform-admin.env\" \"$1/services/account-manager/account-manager-platform-admin.env\"\n}\n\ncloud_env_admin_env() {\n\tcloud_env_first_existing \"$1/services/cloud-admin/admin.env\" \"$1/services/cloud-admin/admin-staging.env\"\n}\n\ncloud_env_video_state() {\n\tcloud_env_first_existing \"$1/state/video-cloud.state.json\" \"$1/state/video-cloud-staging.state.json\"\n}\n\ncloud_env_account_manager_state() {\n\tcloud_env_first_existing \"$1/state/account-manager.env\" \"$1/state/account-manager-staging.env\"\n}\n\ncloud_env_admin_state() {\n\tcloud_env_first_existing \"$1/state/cloud-admin.env\" \"$1/state/cloud-admin-staging.env\"\n}\n\ncloud_env_artifacts_dir() {\n\tprintf '%s/artifacts\\n' \"$1\"\n}\n\ncloud_env_keys_dir() {\n\tprintf '%s/keys\\n' \"$1\"\n}\n\ncloud_env_certificates_dir() {\n\tprintf '%s/certificates\\n' \"$1\"\n}\n\ncloud_env_test_devices_dir() {\n\tprintf '%s/devices/test_device\\n' \"$1\"\n}\n\ncloud_env_name_from_root() {\n\tlocal env_root=\"$1\"\n\tif [[ \"$(basename \"$env_root\")\" == \"linode\" ]]; then\n\t\tbasename \"$(dirname \"$env_root\")\"\n\telse\n\t\tbasename \"$env_root\"\n\tfi\n}\n\ncloud_env_die() {\n\tprintf 'error: %s\\n' \"$*\" >&2\n\treturn 1\n}\n\ncloud_env_require_var() {\n\tlocal name=\"$1\"\n\tlocal value=\"${!name:-}\"\n\t[[ -n \"$value\" ]] || cloud_env_die \"required environment metadata missing: $name\"\n}\n\ncloud_env_load_environment() {\n\tlocal env_root=\"$1\"\n\tlocal dns_override=\"${2:-}\"\n\tlocal metadata_file\n\tmetadata_file=\"$(cloud_env_stack_env \"$env_root\")\"\n\tlocal metadata_dns=\"\"\n\tif [[ -f \"$metadata_file\" ]]; then\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$metadata_file\"\n\t\tset +a\n\t\tmetadata_dns=\"${CLOUD_DNS_ROOT_DOMAIN:-}\"\n\tfi\n\n\tCLOUD_ENV_NAME=\"${CLOUD_ENV_NAME:-$(cloud_env_name_from_root \"$env_root\")}\"\n\tCLOUD_PROVIDER=\"${CLOUD_PROVIDER:-linode}\"\n\tCLOUD_REGION=\"${CLOUD_REGION:-us-sea}\"\n\tif [[ -n \"$dns_override\" && -n \"$metadata_dns\" && \"$dns_override\" != \"$metadata_dns\" ]]; then\n\t\tcloud_env_die \"--dns-root-domain $dns_override does not match $(cloud_env_stack_env \"$env_root\") CLOUD_DNS_ROOT_DOMAIN=$metadata_dns\"\n\t\treturn 1\n\tfi\n\tCLOUD_DNS_ROOT_DOMAIN=\"${metadata_dns:-${dns_override:-${CLOUD_DNS_ROOT_DOMAIN:-realtekconnect.com}}}\"\n\tCLOUD_STACK_NAME=\"${CLOUD_STACK_NAME:-video-cloud-$CLOUD_ENV_NAME}\"\n\tVIDEO_CLOUD_DOMAIN=\"${VIDEO_CLOUD_DOMAIN:-$CLOUD_STACK_NAME.$CLOUD_DNS_ROOT_DOMAIN}\"\n\tVIDEO_CLOUD_CERTISSUER_DOMAIN=\"${VIDEO_CLOUD_CERTISSUER_DOMAIN:-certissuer.$CLOUD_STACK_NAME.$CLOUD_DNS_ROOT_DOMAIN}\"\n\tACCOUNT_MANAGER_DOMAIN=\"${ACCOUNT_MANAGER_DOMAIN:-account-manager.$CLOUD_STACK_NAME.$CLOUD_DNS_ROOT_DOMAIN}\"\n\tCLOUD_ADMIN_DOMAIN=\"${CLOUD_ADMIN_DOMAIN:-admin.$CLOUD_STACK_NAME.$CLOUD_DNS_ROOT_DOMAIN}\"\n\tVIDEO_CLOUD_LABEL_PREFIX=\"${VIDEO_CLOUD_LABEL_PREFIX:-$CLOUD_STACK_NAME}\"\n\tVIDEO_CLOUD_VPC_LABEL=\"${VIDEO_CLOUD_VPC_LABEL:-$VIDEO_CLOUD_LABEL_PREFIX-vpc}\"\n\tVIDEO_CLOUD_SUBNET_LABEL=\"${VIDEO_CLOUD_SUBNET_LABEL:-$VIDEO_CLOUD_LABEL_PREFIX-subnet}\"\n\tACCOUNT_MANAGER_LINODE_LABEL=\"${ACCOUNT_MANAGER_LINODE_LABEL:-rtk-account-manager-$CLOUD_ENV_NAME}\"\n\tACCOUNT_MANAGER_LINODE_FIREWALL_LABEL=\"${ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL:-$ACCOUNT_MANAGER_LINODE_LABEL-fw}\"\n\tADMIN_LINODE_LABEL=\"${ADMIN_LINODE_LABEL:-rtk-cloud-admin-$CLOUD_ENV_NAME}\"\n\tADMIN_LINODE_FIREWALL_LABEL=\"${ADMIN_LINODE_FIREWALL_LABEL:-$ADMIN_LINODE_LABEL-firewall}\"\n\n\tif [[ -f \"$metadata_file\" ]]; then\n\t\tfor name in \\\n\t\t\tCLOUD_ENV_NAME CLOUD_PROVIDER CLOUD_REGION CLOUD_DNS_ROOT_DOMAIN CLOUD_STACK_NAME \\\n\t\t\tVIDEO_CLOUD_DOMAIN VIDEO_CLOUD_CERTISSUER_DOMAIN ACCOUNT_MANAGER_DOMAIN CLOUD_ADMIN_DOMAIN \\\n\t\t\tVIDEO_CLOUD_LABEL_PREFIX VIDEO_CLOUD_VPC_LABEL VIDEO_CLOUD_SUBNET_LABEL \\\n\t\t\tACCOUNT_MANAGER_LINODE_LABEL ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL \\\n\t\t\tADMIN_LINODE_LABEL ADMIN_LINODE_FIREWALL_LABEL\n\t\tdo\n\t\t\tcloud_env_require_var \"$name\" || return 1\n\t\tdone\n\tfi\n\t[[ \"$CLOUD_PROVIDER\" == \"linode\" ]] || {\n\t\tcloud_env_die \"unsupported CLOUD_PROVIDER=$CLOUD_PROVIDER\"\n\t\treturn 1\n\t}\n}\n\ncloud_env_file_var() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\t(\n\t\tset -a\n\t\t# shellcheck source=/dev/null\n\t\t. \"$file\"\n\t\tset +a\n\t\tprintf '%s\\n' \"${!key:-}\"\n\t)\n}\n\ncloud_env_yaml_top_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk -F ':' -v key=\"$key\" '$1 == key {sub(/^[[:space:]]+/, \"\", $2); print $2; exit}' \"$file\"\n}\n\ncloud_env_yaml_path_value() {\n\tlocal file=\"$1\"\n\tlocal path=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk -v path=\"$path\" '\n\tBEGIN {\n\t\tn = split(path, want, \".\")\n\t}\n\t/^[[:space:]]*#/ || /^[[:space:]]*$/ { next }\n\t{\n\t\tmatch($0, /^[ ]*/)\n\t\tindent = RLENGTH / 2\n\t\tline = $0\n\t\tsub(/^[ ]*/, \"\", line)\n\t\tkey = line\n\t\tsub(/:.*/, \"\", key)\n\t\tstack[indent + 1] = key\n\t\tfor (i = indent + 2; i <= 16; i++) {\n\t\t\tdelete stack[i]\n\t\t}\n\t\tif (line !~ /^[^:]+:[[:space:]]*[^[:space:]]/) {\n\t\t\tnext\n\t\t}\n\t\tif (indent + 1 != n) {\n\t\t\tnext\n\t\t}\n\t\tfor (i = 1; i <= n; i++) {\n\t\t\tif (stack[i] != want[i]) {\n\t\t\t\tnext\n\t\t\t}\n\t\t}\n\t\tsub(/^[^:]+:[[:space:]]*/, \"\", line)\n\t\tprint line\n\t\texit\n\t}' \"$file\"\n}\n\ncloud_env_video_gateway_domain() {\n\tlocal file=\"$1\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk '\n\t\t/^instances:/ {in_instances=1}\n\t\tin_instances && /^  edge:/ {in_edge=1; next}\n\t\tin_edge && /^  [A-Za-z0-9_-]+:/ && $0 !~ /^  edge:/ {in_edge=0; in_le=0}\n\t\tin_edge && /^    letsencrypt:/ {in_le=1; next}\n\t\tin_le && /^    [A-Za-z0-9_-]+:/ && $0 !~ /^    letsencrypt:/ {in_le=0}\n\t\tin_edge && in_le && /^      domain:/ {sub(/^[^:]+:[[:space:]]*/, \"\"); print; exit}\n\t' \"$file\"\n}\n\ncloud_env_video_deploy_value() {\n\tlocal file=\"$1\"\n\tlocal key=\"$2\"\n\t[[ -f \"$file\" ]] || return 0\n\tawk -F ':' -v key=\"$key\" '\n\t\t/^deploy:/ {in_deploy=1; next}\n\t\tin_deploy && /^[^[:space:]]/ {in_deploy=0}\n\t\tin_deploy && $1 ~ \"^[[:space:]]*\" key \"$\" {\n\t\t\tsub(/^[[:space:]]+/, \"\", $2)\n\t\t\tprint $2\n\t\t\texit\n\t\t}\n\t' \"$file\"\n}\n\ncloud_env_assert_equal_if_set() {\n\tlocal label=\"$1\"\n\tlocal expected=\"$2\"\n\tlocal actual=\"$3\"\n\t[[ -z \"$actual\" || \"$actual\" == \"null\" || \"$actual\" == \"$expected\" ]] && return 0\n\tcloud_env_die \"$label mismatch: expected $expected, got $actual\"\n}\n\ncloud_env_validate_environment() {\n\tlocal env_root=\"$1\"\n\tlocal video_config am_env admin_env value\n\tvideo_config=\"$(cloud_env_video_config \"$env_root\")\"\n\tam_env=\"$(cloud_env_account_manager_env \"$env_root\")\"\n\tadmin_env=\"$(cloud_env_admin_env \"$env_root\")\"\n\n\tvalue=\"$(cloud_env_yaml_top_value \"$video_config\" stack)\"\n\tcloud_env_assert_equal_if_set \"topology stack\" \"$CLOUD_STACK_NAME\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_yaml_top_value \"$video_config\" region)\"\n\tcloud_env_assert_equal_if_set \"topology region\" \"$CLOUD_REGION\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_yaml_path_value \"$video_config\" vpc.label)\"\n\tcloud_env_assert_equal_if_set \"topology VPC label\" \"$VIDEO_CLOUD_VPC_LABEL\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_yaml_path_value \"$video_config\" vpc.subnet.label)\"\n\tcloud_env_assert_equal_if_set \"topology subnet label\" \"$VIDEO_CLOUD_SUBNET_LABEL\" \"$value\" || return 1\n\tfor role in edge api infra mqtt coturn; do\n\t\tvalue=\"$(cloud_env_yaml_path_value \"$video_config\" \"instances.$role.label\")\"\n\t\tcloud_env_assert_equal_if_set \"topology $role label\" \"$(cloud_env_video_role_label \"$role\")\" \"$value\" || return 1\n\tdone\n\tvalue=\"$(cloud_env_video_gateway_domain \"$video_config\")\"\n\tcloud_env_assert_equal_if_set \"video gateway domain\" \"$VIDEO_CLOUD_DOMAIN\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_video_deploy_value \"$video_config\" certissuer_domain)\"\n\tcloud_env_assert_equal_if_set \"video certissuer domain\" \"$VIDEO_CLOUD_CERTISSUER_DOMAIN\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$am_env\" ACCOUNT_MANAGER_LINODE_DOMAIN)\"\n\tcloud_env_assert_equal_if_set \"Account Manager domain\" \"$ACCOUNT_MANAGER_DOMAIN\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$am_env\" ACCOUNT_MANAGER_LINODE_LABEL)\"\n\tcloud_env_assert_equal_if_set \"Account Manager label\" \"$ACCOUNT_MANAGER_LINODE_LABEL\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$am_env\" ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL)\"\n\tcloud_env_assert_equal_if_set \"Account Manager firewall label\" \"$ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$admin_env\" ADMIN_LINODE_DOMAIN)\"\n\tcloud_env_assert_equal_if_set \"Cloud Admin domain\" \"$CLOUD_ADMIN_DOMAIN\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$admin_env\" ADMIN_LINODE_LABEL)\"\n\tcloud_env_assert_equal_if_set \"Cloud Admin label\" \"$ADMIN_LINODE_LABEL\" \"$value\" || return 1\n\tvalue=\"$(cloud_env_file_var \"$admin_env\" ADMIN_LINODE_FIREWALL_LABEL)\"\n\tcloud_env_assert_equal_if_set \"Cloud Admin firewall label\" \"$ADMIN_LINODE_FIREWALL_LABEL\" \"$value\" || return 1\n}\n\ncloud_env_export_filter_vars() {\n\texport CLOUD_STACK_NAME VIDEO_CLOUD_LABEL_PREFIX VIDEO_CLOUD_VPC_LABEL VIDEO_CLOUD_SUBNET_LABEL\n\texport ACCOUNT_MANAGER_LINODE_LABEL ACCOUNT_MANAGER_LINODE_FIREWALL_LABEL\n\texport ADMIN_LINODE_LABEL ADMIN_LINODE_FIREWALL_LABEL\n}\n\ncloud_env_video_role_label() {\n\tlocal role=\"$1\"\n\tprintf '%s-%s\\n' \"$VIDEO_CLOUD_LABEL_PREFIX\" \"$role\"\n}\n",
	"linode-ci-runners/archive-ci-artifacts.sh": "#!/usr/bin/env bash\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nWORKSPACE=\"$(cd \"$SCRIPT_DIR/../..\" && pwd)\"\nOBJECT_STORAGE_BIN=\"\"\n\nusage() {\n  cat <<'USAGE'\nUsage:\n  scripts/linode-ci-runners/archive-ci-artifacts.sh --repo OWNER/REPO --run-id RUN_ID [--prefix PREFIX]\n\nDownloads all GitHub Actions artifacts for one completed run and uploads them to\nLinode Object Storage using the S3-compatible endpoint.\nUSAGE\n}\n\nrepo=\"\"\nrun_id=\"\"\nprefix=\"\"\nwhile [[ $# -gt 0 ]]; do\n  case \"$1\" in\n    --repo) repo=\"$2\"; shift 2 ;;\n    --run-id) run_id=\"$2\"; shift 2 ;;\n    --prefix) prefix=\"$2\"; shift 2 ;;\n    -h|--help) usage; exit 0 ;;\n    *) echo \"unknown argument: $1\" >&2; usage >&2; exit 2 ;;\n  esac\ndone\n\n[[ -n \"$repo\" ]] || { echo \"--repo is required\" >&2; exit 2; }\n[[ -n \"$run_id\" ]] || { echo \"--run-id is required\" >&2; exit 2; }\n: \"${LINODE_OBJ_BUCKET:?LINODE_OBJ_BUCKET is required}\"\n: \"${LINODE_OBJ_ENDPOINT:?LINODE_OBJ_ENDPOINT is required}\"\n: \"${LINODE_OBJ_ACCESS_KEY_ID:?LINODE_OBJ_ACCESS_KEY_ID is required}\"\n: \"${LINODE_OBJ_SECRET_ACCESS_KEY:?LINODE_OBJ_SECRET_ACCESS_KEY is required}\"\n\ncommand -v gh >/dev/null 2>&1 || { echo \"gh is required\" >&2; exit 1; }\ncommand -v go >/dev/null 2>&1 || { echo \"go is required\" >&2; exit 1; }\n\nobject_storage_go() {\n  if [[ -z \"$OBJECT_STORAGE_BIN\" ]]; then\n    OBJECT_STORAGE_BIN=\"${TMPDIR:-/tmp}/rtk-linode-object-storage\"\n    if [[ ! -x \"$OBJECT_STORAGE_BIN\" || \"$WORKSPACE/scripts/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n      (\n        lock=\"$OBJECT_STORAGE_BIN.lock\"\n        while ! mkdir \"$lock\" 2>/dev/null; do\n          sleep 0.2\n        done\n        trap 'rmdir \"$lock\" 2>/dev/null || true' EXIT\n        if [[ -x \"$OBJECT_STORAGE_BIN\" && ! \"$WORKSPACE/scripts/go/linode-object-storage/main.go\" -nt \"$OBJECT_STORAGE_BIN\" ]]; then\n          exit 0\n        fi\n        cd \"$WORKSPACE/scripts/go/linode-object-storage\"\n        go build -o \"$OBJECT_STORAGE_BIN.$$\" .\n        mv \"$OBJECT_STORAGE_BIN.$$\" \"$OBJECT_STORAGE_BIN\"\n      )\n    fi\n  fi\n  \"$OBJECT_STORAGE_BIN\" \"$@\"\n}\n\nsafe_repo=\"${repo//\\//_}\"\nworkdir=\"$WORKSPACE/.artifacts/ci-runs/$safe_repo/$run_id\"\nmkdir -p \"$workdir/artifacts\"\n\ngh run view \"$run_id\" --repo \"$repo\" --json databaseId,status,conclusion,headSha,headBranch,event,url,createdAt,updatedAt > \"$workdir/run.json\"\ngh run download \"$run_id\" --repo \"$repo\" --dir \"$workdir/artifacts\" || true\n\nif [[ -z \"$prefix\" ]]; then\n  prefix=\"ci-runs/$safe_repo/$run_id\"\nfi\n\nobject_storage_go upload-dir --source \"$workdir\" --prefix \"$prefix\"\nprintf 'uploaded artifacts to s3://%s/%s/ via %s\\n' \"$LINODE_OBJ_BUCKET\" \"$prefix\" \"$LINODE_OBJ_ENDPOINT\"\n",
	"linode-ci-runners/list-ci-runners.sh":      "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../..\" && pwd)\"\nsource \"$ROOT_DIR/scripts/linode-ci-runners/runner-specs.sh\"\nload_runner_specs\n\nseen=\"|\"\nfor spec in \"${RUNNER_SPECS[@]}\"; do\n  IFS='|' read -r _host_label _runner_name repo _type _custom_label <<<\"$spec\"\n  case \"$seen\" in\n    *\"|$repo|\"*) continue ;;\n  esac\n  seen=\"$seen$repo|\"\n  printf '== %s ==\\n' \"$repo\"\n  gh api \"repos/$repo/actions/runners\" \\\n    --jq '.runners[] | {name:.name,status:.status,busy:.busy,labels:[.labels[].name]}'\n  printf '\\n'\ndone\n",
	"linode-ci-runners/power-ci-runners.sh":     "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../..\" && pwd)\"\nsource \"$ROOT_DIR/scripts/linode-ci-runners/runner-specs.sh\"\nload_runner_specs\nLINODE_API_BASE=\"${LINODE_API_BASE:-https://api.linode.com/v4}\"\nWORKSPACE=\"${WORKSPACE:-$ROOT_DIR}\"\n\nusage() {\n  cat <<'USAGE'\nUsage:\n  scripts/linode-ci-runners/power-ci-runners.sh start|stop|status\n\nStarts, shuts down, or lists the Linode VMs that host repo-scoped CI runners.\nThis script does not create VMs; run provision-ci-runners.sh first.\nUSAGE\n}\n\ndie() { printf 'error: %s\\n' \"$*\" >&2; exit 1; }\nneed() { command -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"; }\nload_env_file() {\n  local file=\"$1\"\n  if [[ -f \"$file\" ]]; then\n    set -a\n    # shellcheck disable=SC1090\n    . \"$file\"\n    set +a\n  fi\n}\n\nload_env_file \"$WORKSPACE/.secrets/shared/linode/env/ci-runners.env\"\nneed curl\nneed jq\n[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n\naction=\"${1:-}\"\ncase \"$action\" in\n  start|stop|status) ;;\n  -h|--help) usage; exit 0 ;;\n  *) usage >&2; exit 2 ;;\nesac\n\napi() {\n  local method=\"$1\" path=\"$2\" data=\"${3:-}\"\n  if [[ -n \"$data\" ]]; then\n    curl -fsS -X \"$method\" \"$LINODE_API_BASE$path\" \\\n      -H \"Authorization: Bearer $LINODE_TOKEN\" \\\n      -H 'Content-Type: application/json' \\\n      --data-binary \"$data\"\n  else\n    curl -fsS -X \"$method\" \"$LINODE_API_BASE$path\" \\\n      -H \"Authorization: Bearer $LINODE_TOKEN\" \\\n      -H 'Content-Type: application/json'\n  fi\n}\n\nlinode_by_label() {\n  local label=\"$1\"\n  api GET \"/linode/instances?page_size=500\" | jq -c --arg label \"$label\" '.data[] | select(.label == $label)' | head -n 1\n}\n\nseen_hosts=\"|\"\nfor spec in \"${RUNNER_SPECS[@]}\"; do\n  IFS='|' read -r host_label _runner_name repo _type custom_label <<<\"$spec\"\n  case \"$seen_hosts\" in\n    *\"|$host_label|\"*) continue ;;\n  esac\n  seen_hosts=\"$seen_hosts$host_label|\"\n  vm=\"$(linode_by_label \"$host_label\" || true)\"\n  if [[ -z \"$vm\" ]]; then\n    printf '%s\\t%s\\tmissing\\n' \"$host_label\" \"$repo\"\n    continue\n  fi\n  id=\"$(jq -r '.id' <<<\"$vm\")\"\n  status=\"$(jq -r '.status' <<<\"$vm\")\"\n  ipv4=\"$(jq -r '.ipv4[0] // \"\"' <<<\"$vm\")\"\n  case \"$action\" in\n    start)\n      if [[ \"$status\" == \"running\" ]]; then\n        printf '%s\\talready-running\\t%s\\n' \"$host_label\" \"$ipv4\"\n      else\n        api POST \"/linode/instances/$id/boot\" '{}' >/dev/null\n        printf '%s\\tboot-requested\\t%s\\n' \"$host_label\" \"$ipv4\"\n      fi\n      ;;\n    stop)\n      if [[ \"$status\" == \"offline\" ]]; then\n        printf '%s\\talready-offline\\t%s\\n' \"$host_label\" \"$ipv4\"\n      else\n        api POST \"/linode/instances/$id/shutdown\" '{}' >/dev/null\n        printf '%s\\tshutdown-requested\\t%s\\n' \"$host_label\" \"$ipv4\"\n      fi\n      ;;\n    status)\n      printf '%s\\t%s\\t%s\\n' \"$host_label\" \"$status\" \"$ipv4\"\n      ;;\n  esac\ndone\n",
	"linode-ci-runners/provision-ci-runners.sh": "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../..\" && pwd)\"\nWORKSPACE=\"${WORKSPACE:-$ROOT_DIR}\"\n\ndie() { printf 'error: %s\\n' \"$*\" >&2; exit 1; }\nneed() { command -v \"$1\" >/dev/null 2>&1 || die \"$1 is required\"; }\n\nload_env_file() {\n  local file=\"$1\"\n  if [[ -f \"$file\" ]]; then\n    set -a\n    # shellcheck disable=SC1090\n    . \"$file\"\n    set +a\n  fi\n}\n\nload_env_file \"$WORKSPACE/.secrets/shared/linode/env/ci-runners.env\"\nload_env_file \"$WORKSPACE/.secrets/shared/github/env/runner-registration.env\"\n\nLINODE_API_BASE=\"${LINODE_API_BASE:-https://api.linode.com/v4}\"\nGITHUB_API_BASE=\"${GITHUB_API_BASE:-https://api.github.com}\"\nREGION=\"${CI_RUNNER_REGION:-us-sea}\"\nIMAGE=\"${CI_RUNNER_IMAGE:-linode/ubuntu24.04}\"\nPUBLIC_KEY_PATH=\"${CI_RUNNER_PUBLIC_KEY_PATH:-$HOME/.ssh/id_ed25519_rtkcloud.pub}\"\nSSH_KEY=\"${CI_RUNNER_SSH_KEY:-$HOME/.ssh/id_ed25519_rtkcloud}\"\nGITHUB_WORK_KEY=\"${CI_RUNNER_GITHUB_WORK_KEY_PATH:-$HOME/.ssh/id_ed25519_github_work}\"\nSSH_USER=\"${CI_RUNNER_SSH_USER:-root}\"\nALLOWED_SSH_CIDRS=\"${CI_RUNNER_ALLOWED_SSH_CIDRS:-}\"\nSTATE_DIR=\"${CI_RUNNER_STATE_DIR:-}\"\nSTATE_DIR=\"${STATE_DIR:-$WORKSPACE/.secrets/shared/linode/state/ci-runners}\"\nif [[ \"$STATE_DIR\" == \"$WORKSPACE/.secrets/\"* && ! -d \"$WORKSPACE/.secrets\" ]]; then\n  STATE_DIR=\"$WORKSPACE/.artifacts/linode-ci-runners/state\"\nfi\n\nsource \"$ROOT_DIR/scripts/linode-ci-runners/runner-specs.sh\"\nload_runner_specs\n\nneed curl\nneed jq\nneed openssl\nneed ssh\nneed scp\n\n[[ -n \"${LINODE_TOKEN:-}\" ]] || die \"LINODE_TOKEN is required\"\n[[ -n \"${GITHUB_TOKEN:-}\" ]] || die \"GITHUB_TOKEN is required\"\n[[ -n \"$ALLOWED_SSH_CIDRS\" ]] || die \"CI_RUNNER_ALLOWED_SSH_CIDRS is required\"\n[[ -s \"$PUBLIC_KEY_PATH\" ]] || die \"CI_RUNNER_PUBLIC_KEY_PATH not found: $PUBLIC_KEY_PATH\"\n[[ -s \"$SSH_KEY\" ]] || die \"CI_RUNNER_SSH_KEY not found: $SSH_KEY\"\n[[ -s \"$GITHUB_WORK_KEY\" ]] || die \"CI_RUNNER_GITHUB_WORK_KEY_PATH not found: $GITHUB_WORK_KEY\"\n\nlinode_api() {\n  local method=\"$1\" path=\"$2\" data=\"${3:-}\"\n  if [[ -n \"$data\" ]]; then\n    curl -fsS -X \"$method\" \"$LINODE_API_BASE$path\" \\\n      -H \"Authorization: Bearer $LINODE_TOKEN\" \\\n      -H 'Content-Type: application/json' \\\n      --data-binary \"$data\"\n  else\n    curl -fsS -X \"$method\" \"$LINODE_API_BASE$path\" \\\n      -H \"Authorization: Bearer $LINODE_TOKEN\" \\\n      -H 'Content-Type: application/json'\n  fi\n}\n\ngithub_api() {\n  local method=\"$1\" path=\"$2\" data=\"${3:-}\"\n  if [[ -n \"$data\" ]]; then\n    curl -fsS -X \"$method\" \"$GITHUB_API_BASE$path\" \\\n      -H \"Authorization: Bearer $GITHUB_TOKEN\" \\\n      -H 'Accept: application/vnd.github+json' \\\n      -H 'X-GitHub-Api-Version: 2022-11-28' \\\n      --data-binary \"$data\"\n  else\n    curl -fsS -X \"$method\" \"$GITHUB_API_BASE$path\" \\\n      -H \"Authorization: Bearer $GITHUB_TOKEN\" \\\n      -H 'Accept: application/vnd.github+json' \\\n      -H 'X-GitHub-Api-Version: 2022-11-28'\n  fi\n}\n\nlinode_by_label() {\n  local label=\"$1\"\n  linode_api GET \"/linode/instances?page_size=500\" | jq -c --arg label \"$label\" '.data[] | select(.label == $label)' | head -n 1\n}\n\nfirewall_by_label() {\n  local label=\"$1\"\n  linode_api GET \"/networking/firewalls?page_size=500\" | jq -c --arg label \"$label\" '.data[] | select(.label == $label)' | head -n 1\n}\n\ncreate_runner_vm() {\n  local label=\"$1\" type=\"$2\"\n  local existing ssh_key root_pass payload created\n  existing=\"$(linode_by_label \"$label\" || true)\"\n  if [[ -n \"$existing\" ]]; then\n    printf '%s\\n' \"$existing\"\n    return\n  fi\n\n  ssh_key=\"$(cat \"$PUBLIC_KEY_PATH\")\"\n  root_pass=\"$(openssl rand -base64 36)\"\n  payload=\"$(jq -cn \\\n    --arg label \"$label\" \\\n    --arg region \"$REGION\" \\\n    --arg type \"$type\" \\\n    --arg image \"$IMAGE\" \\\n    --arg root_pass \"$root_pass\" \\\n    --arg ssh_key \"$ssh_key\" \\\n    '{label:$label, region:$region, type:$type, image:$image, root_pass:$root_pass, authorized_keys:[$ssh_key], tags:[\"rtk-cloud-ci\",\"github-runner\"]}')\"\n  printf '[linode-ci] creating %s (%s)\\n' \"$label\" \"$type\" >&2\n  created=\"$(linode_api POST /linode/instances \"$payload\")\"\n  printf '%s\\n' \"$created\"\n}\n\nensure_firewall() {\n  local label=\"$1\"\n  local linode_id=\"$2\"\n  local firewall_label=\"${label}-firewall\"\n  local existing firewall_id payload created\n  existing=\"$(firewall_by_label \"$firewall_label\" || true)\"\n  if [[ -n \"$existing\" ]]; then\n    firewall_id=\"$(jq -r '.id' <<<\"$existing\")\"\n  else\n    payload=\"$(jq -cn --arg label \"$firewall_label\" --arg cidrs \"$ALLOWED_SSH_CIDRS\" '{\n      label: $label,\n      rules: {\n        inbound_policy: \"DROP\",\n        outbound_policy: \"ACCEPT\",\n        inbound: [\n          {label:\"ssh\", action:\"ACCEPT\", protocol:\"TCP\", ports:\"22\", addresses:{ipv4:($cidrs|split(\",\"))}}\n        ],\n        outbound: []\n      }\n    }')\"\n    printf '[linode-ci] creating firewall %s\\n' \"$firewall_label\" >&2\n    created=\"$(linode_api POST /networking/firewalls \"$payload\")\"\n    firewall_id=\"$(jq -r '.id' <<<\"$created\")\"\n  fi\n\n  if ! linode_api GET \"/networking/firewalls/$firewall_id/devices\" | jq -e --argjson id \"$linode_id\" '.data[] | select(.entity.id == $id)' >/dev/null; then\n    linode_api POST \"/networking/firewalls/$firewall_id/devices\" \"$(jq -cn --argjson id \"$linode_id\" '{id:$id,type:\"linode\"}')\" >/dev/null\n  fi\n  printf '%s\\n' \"$firewall_id\"\n}\n\nwait_for_ssh() {\n  local host=\"$1\"\n  local label=\"$2\"\n  local attempt\n  local ssh_opts=(-i \"$SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile=/dev/null -o ConnectTimeout=10)\n  printf '[linode-ci] waiting for SSH: %s (%s)\\n' \"$label\" \"$host\" >&2\n  for attempt in $(seq 1 60); do\n    if ssh \"${ssh_opts[@]}\" \"$SSH_USER@$host\" true >/dev/null 2>&1; then\n      return 0\n    fi\n    sleep 10\n  done\n  die \"SSH did not become ready for $label ($host)\"\n}\n\nrunner_registration_token() {\n  local repo=\"$1\"\n  github_api POST \"/repos/$repo/actions/runners/registration-token\" | jq -r '.token'\n}\n\nbootstrap_runner() {\n  local host=\"$1\"\n  local runner_name=\"$2\"\n  local repo=\"$3\"\n  local custom_label=\"$4\"\n  local token=\"$5\"\n  local ssh_opts=(-i \"$SSH_KEY\" -o BatchMode=yes -o StrictHostKeyChecking=accept-new -o UserKnownHostsFile=/dev/null)\n  printf '[linode-ci] bootstrapping runner %s for %s\\n' \"$runner_name\" \"$repo\" >&2\n  scp \"${ssh_opts[@]}\" \"$GITHUB_WORK_KEY\" \"$SSH_USER@$host:/tmp/github-work-key\" >/dev/null\n  ssh \"${ssh_opts[@]}\" \"$SSH_USER@$host\" bash -s -- \"$runner_name\" \"$repo\" \"$custom_label\" \"$token\" \"${CI_RUNNER_VERSION:-}\" <<'REMOTE'\nset -euo pipefail\nrunner_name=\"$1\"\nrepo=\"$2\"\ncustom_label=\"$3\"\ntoken=\"$4\"\nrunner_version=\"${5:-}\"\nrunner_user=\"github-runner\"\nrunner_root=\"/opt/actions-runner/${runner_name}\"\n\nexport DEBIAN_FRONTEND=noninteractive\napt-get update -y\napt-get install -y ca-certificates curl gnupg jq tar gzip git build-essential pkg-config unzip zip make docker.io docker-compose-v2 golang-go cmake ninja-build\n\nif ! command -v node >/dev/null 2>&1 || [[ \"$(node --version | sed 's/^v//' | cut -d. -f1)\" != \"22\" ]]; then\n  curl -fsSL https://deb.nodesource.com/setup_22.x | bash -\n  apt-get install -y nodejs\nfi\n\nif ! command -v google-chrome >/dev/null 2>&1 && ! command -v chromium >/dev/null 2>&1 && ! command -v chromium-browser >/dev/null 2>&1; then\n  install -d -m 0755 /etc/apt/keyrings\n  rm -f /etc/apt/keyrings/google-linux.gpg\n  curl -fsSL https://dl.google.com/linux/linux_signing_key.pub | gpg --dearmor -o /etc/apt/keyrings/google-linux.gpg\n  chmod 0644 /etc/apt/keyrings/google-linux.gpg\n  printf 'deb [arch=amd64 signed-by=/etc/apt/keyrings/google-linux.gpg] http://dl.google.com/linux/chrome/deb/ stable main\\n' >/etc/apt/sources.list.d/google-chrome.list\n  apt-get update -y\n  apt-get install -y google-chrome-stable || true\nfi\n\nsystemctl enable --now docker\nif ! id \"$runner_user\" >/dev/null 2>&1; then\n  useradd -m -s /bin/bash \"$runner_user\"\nfi\nusermod -aG docker \"$runner_user\"\ninstall -d -m 0750 -o \"$runner_user\" -g \"$runner_user\" /etc/github-runner\ninstall -m 0600 -o \"$runner_user\" -g \"$runner_user\" /tmp/github-work-key /etc/github-runner/github-work\nrm -f /tmp/github-work-key\ninstall -d -m 0755 /etc/ssh/ssh_config.d\ncat >/etc/ssh/ssh_config.d/github-work.conf <<EOF\nHost github.com-work\n  HostName github.com\n  User git\n  IdentityFile /etc/github-runner/github-work\n  IdentitiesOnly yes\n  StrictHostKeyChecking accept-new\nEOF\nmkdir -p \"$runner_root\"\nchown \"$runner_user:$runner_user\" \"$runner_root\"\nif [[ -z \"$runner_version\" ]]; then\n  runner_version=\"$(curl -fsS https://api.github.com/repos/actions/runner/releases/latest | jq -r '.tag_name | sub(\"^v\"; \"\")')\"\nfi\narch=\"x64\"\narchive=\"actions-runner-linux-${arch}-${runner_version}.tar.gz\"\nurl=\"https://github.com/actions/runner/releases/download/v${runner_version}/${archive}\"\nif [[ ! -x \"$runner_root/config.sh\" ]]; then\n  tmp=\"$(mktemp -d)\"\n  curl -fsSL \"$url\" -o \"$tmp/$archive\"\n  tar -xzf \"$tmp/$archive\" -C \"$runner_root\"\n  rm -rf \"$tmp\"\n  chown -R \"$runner_user:$runner_user\" \"$runner_root\"\nfi\nif [[ -f \"$runner_root/.runner\" ]]; then\n  systemctl stop \"actions.runner.hkt999rtk-${repo##*/}.${runner_name}.service\" >/dev/null 2>&1 || true\n  sudo -u \"$runner_user\" bash -lc \"cd '$runner_root' && ./config.sh remove --unattended --token '$token'\" >/dev/null 2>&1 || true\nfi\nrepo_url=\"https://github.com/${repo}\"\nsudo -u \"$runner_user\" bash -lc \"cd '$runner_root' && ./config.sh --unattended --replace --url '$repo_url' --token '$token' --name '$runner_name' --labels '$custom_label' --work _work\"\n(cd \"$runner_root\" && ./svc.sh install \"$runner_user\")\n(cd \"$runner_root\" && ./svc.sh start)\nREMOTE\n}\n\nmkdir -p \"$STATE_DIR\"\nchmod 0700 \"$STATE_DIR\" 2>/dev/null || true\n\nfor spec in \"${RUNNER_SPECS[@]}\"; do\n  IFS='|' read -r host_label runner_name repo type custom_label <<<\"$spec\"\n  vm=\"$(create_runner_vm \"$host_label\" \"$type\")\"\n  linode_id=\"$(jq -r '.id // .[0].id' <<<\"$vm\")\"\n  public_ipv4=\"$(jq -r '(.ipv4[0] // .[0].ipv4[0])' <<<\"$vm\")\"\n  [[ -n \"$linode_id\" && \"$linode_id\" != null ]] || die \"failed to read Linode id for $host_label\"\n  [[ -n \"$public_ipv4\" && \"$public_ipv4\" != null ]] || die \"failed to read public IPv4 for $host_label\"\n  firewall_id=\"$(ensure_firewall \"$host_label\" \"$linode_id\")\"\n  wait_for_ssh \"$public_ipv4\" \"$host_label\"\n  token=\"$(runner_registration_token \"$repo\")\"\n  [[ -n \"$token\" && \"$token\" != null ]] || die \"failed to get registration token for $repo\"\n  bootstrap_runner \"$public_ipv4\" \"$runner_name\" \"$repo\" \"$custom_label\" \"$token\"\n  state_file=\"$STATE_DIR/$runner_name.json\"\n  jq -n \\\n    --arg host_label \"$host_label\" \\\n    --arg runner_name \"$runner_name\" \\\n    --arg repo \"$repo\" \\\n    --arg type \"$type\" \\\n    --arg custom_label \"$custom_label\" \\\n    --argjson linode_id \"$linode_id\" \\\n    --arg public_ipv4 \"$public_ipv4\" \\\n    --arg firewall_id \"$firewall_id\" \\\n    --arg updated_at \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\" \\\n    '{host_label:$host_label, runner_name:$runner_name, repo:$repo, type:$type, labels:([\"self-hosted\",\"Linux\",\"X64\"] + ($custom_label | split(\",\"))), linode_id:$linode_id, public_ipv4:$public_ipv4, firewall_id:$firewall_id, updated_at:$updated_at}' \\\n    > \"$state_file\"\n  chmod 0600 \"$state_file\"\ndone\n\nprintf '[linode-ci] provisioned runner VM registrations. State dir: %s\\n' \"$STATE_DIR\"\n",
	"linode-ci-runners/run-ci-session.sh":       "#!/usr/bin/env bash\nset -euo pipefail\n\nusage() {\n  cat <<'USAGE'\nUsage:\n  scripts/linode-ci-runners/run-ci-session.sh \\\n    [--account-run-id RUN_ID] \\\n    [--admin-run-id RUN_ID] \\\n    [--frontend-run-id RUN_ID] \\\n    [--client-run-id RUN_ID] \\\n    [--logger-run-id RUN_ID] \\\n    [--rerun true|false] \\\n    [--shutdown-policy always|on-success|never] \\\n    [--smoke-only true|false]\n\nBoots the shared Linode Linux CI runner VM, waits for repo-scoped GitHub\nrunners to become online, optionally reruns the selected GitHub Actions runs,\nwatches them to completion, archives run metadata/artifacts to Linode Object\nStorage, and shuts the VM down according to the shutdown policy.\n\nWith --smoke-only true, the script only boots the shared Linux CI VM, waits for\nGitHub runners to become online, and shuts the VM down. It does not require run\nids and does not archive artifacts.\nUSAGE\n}\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../..\" && pwd)\"\naccount_run_id=\"\"\nadmin_run_id=\"\"\nfrontend_run_id=\"\"\nclient_run_id=\"\"\nlogger_run_id=\"\"\nrerun=\"true\"\nshutdown_policy=\"always\"\nsmoke_only=\"false\"\n\nwhile [[ $# -gt 0 ]]; do\n  case \"$1\" in\n    --account-run-id) account_run_id=\"$2\"; shift 2 ;;\n    --admin-run-id) admin_run_id=\"$2\"; shift 2 ;;\n    --frontend-run-id) frontend_run_id=\"$2\"; shift 2 ;;\n    --client-run-id) client_run_id=\"$2\"; shift 2 ;;\n    --logger-run-id) logger_run_id=\"$2\"; shift 2 ;;\n    --rerun) rerun=\"$2\"; shift 2 ;;\n    --shutdown-policy) shutdown_policy=\"$2\"; shift 2 ;;\n    --smoke-only) smoke_only=\"$2\"; shift 2 ;;\n    -h|--help) usage; exit 0 ;;\n    *) echo \"unknown argument: $1\" >&2; usage >&2; exit 2 ;;\n  esac\ndone\n\ncase \"$rerun\" in true|false) ;; *) echo \"--rerun must be true or false\" >&2; exit 2 ;; esac\ncase \"$shutdown_policy\" in always|on-success|never) ;; *) echo \"--shutdown-policy must be always, on-success, or never\" >&2; exit 2 ;; esac\ncase \"$smoke_only\" in true|false) ;; *) echo \"--smoke-only must be true or false\" >&2; exit 2 ;; esac\n\nif [[ \"$smoke_only\" == \"false\" && -z \"$account_run_id\" && -z \"$admin_run_id\" && -z \"$frontend_run_id\" && -z \"$client_run_id\" && -z \"$logger_run_id\" ]]; then\n  echo \"at least one run id is required\" >&2\n  usage >&2\n  exit 2\nfi\n\n: \"${LINODE_TOKEN:?LINODE_TOKEN is required}\"\n: \"${LINODE_OBJ_BUCKET:=}\"\n: \"${LINODE_OBJ_ENDPOINT:=}\"\ncommand -v gh >/dev/null 2>&1 || { echo \"gh is required\" >&2; exit 1; }\n\nif [[ \"$smoke_only\" == \"false\" ]]; then\n  : \"${LINODE_OBJ_BUCKET:?LINODE_OBJ_BUCKET is required}\"\n  : \"${LINODE_OBJ_ENDPOINT:?LINODE_OBJ_ENDPOINT is required}\"\nfi\n\noverall=0\n\nshutdown_runners() {\n  \"$ROOT_DIR/scripts/linode-ci-runners/power-ci-runners.sh\" stop || true\n}\n\nif [[ \"$shutdown_policy\" == \"always\" ]]; then\n  trap shutdown_runners EXIT\nfi\n\n\"$ROOT_DIR/scripts/linode-ci-runners/power-ci-runners.sh\" start\n\"$ROOT_DIR/scripts/linode-ci-runners/wait-runners-online.sh\"\n\nif [[ \"$smoke_only\" == \"true\" ]]; then\n  echo \"[linode-ci-session] smoke-only lifecycle completed\"\n  if [[ \"$shutdown_policy\" == \"always\" ]]; then\n    trap - EXIT\n    shutdown_runners\n  elif [[ \"$shutdown_policy\" == \"on-success\" ]]; then\n    shutdown_runners\n  fi\n  exit 0\nfi\n\nwatch_and_archive() {\n  local repo=\"$1\"\n  local run_id=\"$2\"\n  [[ -n \"$run_id\" ]] || return 0\n\n  echo \"[linode-ci-session] processing $repo run $run_id\"\n  if [[ \"$rerun\" == \"true\" ]]; then\n    gh run rerun \"$run_id\" --repo \"$repo\"\n  fi\n\n  if ! gh run watch \"$run_id\" --repo \"$repo\" --exit-status; then\n    overall=1\n  fi\n\n  if ! \"$ROOT_DIR/scripts/linode-ci-runners/archive-ci-artifacts.sh\" --repo \"$repo\" --run-id \"$run_id\"; then\n    overall=1\n  fi\n}\n\nwatch_and_archive hkt999rtk/rtk_account_manager \"$account_run_id\"\nwatch_and_archive hkt999rtk/rtk_cloud_admin \"$admin_run_id\"\nwatch_and_archive hkt999rtk/rtk_cloud_frontend \"$frontend_run_id\"\nwatch_and_archive hkt999rtk/rtk_cloud_client \"$client_run_id\"\nwatch_and_archive hkt999rtk/rtk_cloud_logger \"$logger_run_id\"\n\nif [[ \"$shutdown_policy\" == \"on-success\" && \"$overall\" -eq 0 ]]; then\n  shutdown_runners\nelif [[ \"$shutdown_policy\" == \"always\" ]]; then\n  trap - EXIT\n  shutdown_runners\nfi\n\nexit \"$overall\"\n",
	"linode-ci-runners/runner-specs.sh":         "#!/usr/bin/env bash\n# shellcheck shell=bash\n\nload_runner_specs() {\n  if [[ -n \"${CI_RUNNER_PROFILE:-}\" && \"${CI_RUNNER_PROFILE:-}\" != \"shared-linux\" ]]; then\n    printf 'error: only shared-linux CI runner profile is supported\\n' >&2\n    return 2\n  fi\n\n  RUNNER_SPECS=(\n    \"rtk-shared-linux-ci|rtk-ci-account-manager|hkt999rtk/rtk_account_manager|g6-standard-4|account-manager-ci\"\n    \"rtk-shared-linux-ci|rtk-ci-cloud-admin|hkt999rtk/rtk_cloud_admin|g6-standard-4|rtk-cloud-admin-ci\"\n    \"rtk-shared-linux-ci|rtk-ci-cloud-frontend|hkt999rtk/rtk_cloud_frontend|g6-standard-4|rtk_cloud_frontend,go\"\n    \"rtk-shared-linux-ci|rtk-ci-cloud-client-linux|hkt999rtk/rtk_cloud_client|g6-standard-4|client-sdk-ci\"\n    \"rtk-shared-linux-ci|rtk-ci-cloud-logger|hkt999rtk/rtk_cloud_logger|g6-standard-4|rtk-cloud-logger-ci\"\n  )\n}\n",
	"linode-ci-runners/wait-runners-online.sh":  "#!/usr/bin/env bash\nset -euo pipefail\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/../..\" && pwd)\"\nsource \"$ROOT_DIR/scripts/linode-ci-runners/runner-specs.sh\"\nload_runner_specs\nTIMEOUT_SECONDS=\"${CI_RUNNER_ONLINE_TIMEOUT_SECONDS:-900}\"\nSLEEP_SECONDS=\"${CI_RUNNER_ONLINE_POLL_SECONDS:-15}\"\n\ndeadline=$(( $(date +%s) + TIMEOUT_SECONDS ))\n\nwhile true; do\n  missing=0\n  for spec in \"${RUNNER_SPECS[@]}\"; do\n    IFS='|' read -r _host_label runner_name repo _type custom_label <<<\"$spec\"\n    status=\"$(gh api \"repos/$repo/actions/runners\" --jq \".runners[] | select(.name == \\\"$runner_name\\\") | .status\" 2>/dev/null || true)\"\n    if [[ \"$status\" == \"online\" ]]; then\n      printf 'online: %s (%s)\\n' \"$runner_name\" \"$custom_label\"\n    else\n      printf 'waiting: %s (%s), current=%s\\n' \"$runner_name\" \"$custom_label\" \"${status:-missing}\"\n      missing=$((missing + 1))\n    fi\n  done\n  if [[ \"$missing\" -eq 0 ]]; then\n    exit 0\n  fi\n  if [[ \"$(date +%s)\" -ge \"$deadline\" ]]; then\n    printf 'timed out waiting for CI runners to become online\\n' >&2\n    exit 1\n  fi\n  sleep \"$SLEEP_SECONDS\"\ndone\n",
}
